    // === NORMALIZE DATA ROW (NEW FUNCTION - ADD THIS) ===
    function normalizeDataRow($row, &$errors, &$warnings, $index) {
        $normalized = [];
        $rowNum = $index + 1;
        
        foreach ($row as $key => $value) {
            $keyLower = strtolower(trim($key));
            $value = trim($value);
            
            if (in_array($keyLower, ['eid', 'employee_id', 'emp_id', 'id', '2023103048'])) {
                $normalized['employee_id'] = validateEmployeeID($value, $rowNum, $errors);
            }
            if (in_array($keyLower, ['name', 'employee_name', 'full_name'])) {
                $normalized['name'] = validateName($value, $rowNum, $warnings);
            }
            if (in_array($keyLower, ['calendar date', 'date', 'attendance_date', 'work_date'])) {
                $normalized['date'] = validateAndNormalizeDate($value, $rowNum, $errors);
            }
            if (in_array($keyLower, ['si', 'check_in', 'time_in', 'clock_in'])) {
                $normalized['check_in'] = validateAndNormalizeTime($value, $rowNum, $errors);
            }
            if (in_array($keyLower, ['so', 'check_out', 'time_out', 'clock_out'])) {
                $normalized['check_out'] = validateAndNormalizeTime($value, $rowNum, $errors);
            }
            if (in_array($keyLower, ['shift type', 'shift', 'schedule shift'])) {
                $normalized['shift_type'] = $value;
            }
            if (in_array($keyLower, ['account/project', 'department', 'dept', 'account'])) {
                $normalized['department'] = $value;
            }
        }
        
        if (empty($normalized['employee_id'])) {
            $errors[] = "Row {$rowNum}: Missing employee_id";
            return null;
        }
        if (empty($normalized['date'])) {
            $errors[] = "Row {$rowNum}: Missing or invalid date";
            return null;
        }
        
        return array_filter($normalized);
    }

    // === VALIDATION HELPERS (NEW FUNCTIONS - ADD THESE) ===
    function validateEmployeeID($value, $rowNum, &$errors) {
        if (empty($value)) {
            $errors[] = "Row {$rowNum}: Empty employee ID";
            return null;
        }
        return strtoupper(trim($value));
    }

    function validateName($value, $rowNum, &$warnings) {
        if (empty($value)) {
            $warnings[] = "Row {$rowNum}: Missing employee name";
            return null;
        }
        return trim($value);
    }

    function validateAndNormalizeDate($value, $rowNum, &$errors) {
        if (empty($value)) return null;
        
        $formats = ['Y-m-d', 'm/d/Y', 'd/m/Y', 'F j, Y', 'M j, Y', 'Y/m/d'];
        
        foreach ($formats as $format) {
            $date = DateTime::createFromFormat($format, $value);
            if ($date && $date->format($format) === $value) {
                return $date->format('Y-m-d');
            }
        }
        
        $timestamp = strtotime($value);
        if ($timestamp) return date('Y-m-d', $timestamp);
        
        $errors[] = "Row {$rowNum}: Invalid date format '{$value}'";
        return null;
    }

    function validateAndNormalizeTime($value, $rowNum, &$errors) {
        if (empty($value)) return null;
        
        $value = trim(str_replace(['AM', 'PM', 'am', 'pm'], '', $value));
        $formats = ['H:i:s', 'H:i', 'g:i:s', 'g:i'];
        
        foreach ($formats as $format) {
            $time = DateTime::createFromFormat($format, $value);
            if ($time) return $time->format('H:i:s');
        }
        
        $errors[] = "Row {$rowNum}: Invalid time format '{$value}'";
        return null;
    }

    // === COMPREHENSIVE COLUMN MAPPING - ALL 40+ COLUMNS ===
    function mapCSVColumns($headers, $mapping = null) {
        // Complete mapping for ALL columns in your CSV
        $standardColumns = [
            // Core Employee Info
            'employee_id' => ['eid', 'employee_id', 'emp_id', 'id', 'employee code', '2023103048'],
            'name' => ['name', 'employee_name', 'full_name', 'employee'],
            'department' => ['account/project', 'department', 'dept', 'account', 'project', 'division', 'team'],
            'supervisor' => ['is', 'immediate supervisor', 'supervisor', 'manager', 'tl', 'team leader'],
            
            // Date & Shift
            'date' => ['calendar date', 'date', 'attendance_date', 'work_date', 'day', 'log date'],
            'shift_type' => ['shift type', 'shift', 'schedule shift', 'shift_type'],
            'scheduled_in' => ['si', 'shift in', 'scheduled in', 'schedule in', 'time in scheduled'],
            'scheduled_out' => ['so', 'shift out', 'scheduled out', 'schedule out', 'time out scheduled'],
            
            // Actual Times
            'check_in' => ['li', 'log in', 'actual in', 'clock in', 'check_in', 'time_in', 'in_time', 'actual check in'],
            'check_out' => ['lo', 'log out', 'actual out', 'clock out', 'check_out', 'time_out', 'out_time', 'actual check out'],
            
            // Attendance Status
            'absent' => ['absent', 'absence'],
            'late_hours' => ['late (hour)', 'late hours', 'late'],
            'undertime_hours' => ['ut(hour)', 'undertime', 'ut hours', 'undert time'],
            'total_hours' => ['total hours', 'worked hours', 'hours worked', 'total worked'],
            
            // Overtime
            'projected_ot' => ['projected ot (hours)', 'projected overtime', 'ot projected', 'proj ot'],
            'regular_ot' => ['reg ot', 'regular ot', 'regular overtime'],
            'rest_day_ot' => ['rdot (8 hours)', 'rest day ot', 'rd ot', 'r dot'],
            'rdot_excess' => ['rdot (8 hours excess)', 'rd ot excess'],
            'lh_ot' => ['lh ot', 'legal holiday ot'],
            'lh_ot_excess' => ['lh ot (8 hours excess)'],
            'spl_hol_ot' => ['spl hol ot', 'special holiday ot'],
            'sh_ot_excess' => ['sh ot (8 hours excess)'],
            'rd_lh_ot' => ['rd-lh ot', 'rd lh ot'],
            'rd_sh_ot' => ['rd-sh ot', 'rd sh ot'],
            'rd_lh_ot_excess' => ['rd-lh ot (8 hours excess)'],
            'rd_sh_ot_excess' => ['rd-sh ot (8 hours excess)'],
            
            // Leave Types
            'vl_hours' => ['vl (hr use)', 'vacation leave', 'vl', 'vacation'],
            'sl_hours' => ['sl (hr use)', 'sick leave', 'sl', 'sick'],
            'ncns_hours' => ['ncns (hr use)', 'ncns', 'no call no show'],
            'ob_hours' => ['ob (hr use)', 'obligatory leave', 'ob'],
            'cto_used' => ['cto - used (hr use)', 'cto used', 'comp time off used'],
            'cto_acquired' => ['cto - acquired(hr use)', 'cto acquired', 'comp time off acquired'],
            
            // Night Differential
            'nd_hours' => ['nd (hr use)', 'night differential', 'nd', 'night diff'],
            'rd_nd' => ['rd nd', 'rest day night diff'],
            'lh_nd' => ['lh nd', 'legal holiday night diff'],
            'sh_nd' => ['sh nd', 'special holiday night diff'],
            'rd_lh_nd' => ['rd-lh nd', 'rd lh nd'],
            'rd_sh_nd' => ['rd-sh nd', 'rd sh nd'],
            
            // Other
            'remarks' => ['tl schedule vaidation / remarks', 'remarks', 'validation', 'tl remarks', 'schedule validation'],
            'payout_schedule' => ['pay out schedule', 'payout', 'pay schedule', 'payment schedule']
        ];
        
        $mappedColumns = [];
        
        foreach ($headers as $index => $header) {
            $headerLower = strtolower(trim($header));
            
            foreach ($standardColumns as $standard => $aliases) {
                foreach ($aliases as $alias) {
                    // Exact match or contains match
                    if ($headerLower === $alias || stripos($headerLower, $alias) !== false) {
                        $mappedColumns[$standard] = $index;
                        break 2;
                    }
                }
            }
        }
        
        if ($mapping) {
            $mappedColumns = array_merge($mappedColumns, $mapping);
        }
        
        return $mappedColumns;
    }

