    function getHolidayInfo($pdo, $date) {
        try {
            $stmt = $pdo->prepare("SELECT * FROM holidays WHERE date = ?");
            $stmt->execute([$date]);
            return $stmt->fetch(PDO::FETCH_ASSOC);
        } catch (Exception $e) {
            return null;
        }
    }

    function isEmployeeAssignedToHoliday($pdo, $employeeId, $date) {
        try {
            $stmt = $pdo->prepare("SELECT ha.required_to_work FROM holiday_assignments ha
                                JOIN holidays h ON ha.holiday_id = h.id
                                WHERE ha.employee_id = ? AND h.date = ?");
            $stmt->execute([$employeeId, $date]);
            return $stmt->fetch(PDO::FETCH_ASSOC);
        } catch (Exception $e) {
            return null;
        }
    }

    function calculateHolidayPayHours($workedHours, $holidayType, $worked) {
        // Rules:
        // Regular: Worked = 2x, Not Worked = 8hrs
        // Special Non-Working: Worked = 1.3x (Actual + 30%), Not Worked = 0
        // Special Working: Worked = 1x, Not Worked = 0

        if (!$worked) {
            if ($holidayType === 'regular') return 8.0;
            return 0.0;
        }

        switch ($holidayType) {
            case 'regular':
                return $workedHours * 2.0;
            case 'special_non_working':
                return $workedHours + ($workedHours * 0.3); // e.g., 8 + 2.4 = 10.4
            case 'special_working':
            default:
                return $workedHours;
        }
    }

    function getHolidayBonusHours($workedHours, $holidayType, $worked) {
        $totalPaid = calculateHolidayPayHours($workedHours, $holidayType, $worked);
        return $totalPaid - $workedHours;
    }
