    function maskEmail($email) {
        $email = trim((string)$email);
        if ($email === '' || strpos($email, '@') === false) {
            return 'your registered email';
        }
        [$local, $domain] = explode('@', $email, 2);
        $localMasked = strlen($local) <= 2 ? substr($local, 0, 1) . '*' : substr($local, 0, 2) . str_repeat('*', max(1, strlen($local) - 2));
        return $localMasked . '@' . $domain;
    }
    function send2FACodeEmail($toEmail, $employeeName, $code, $ttlMinutes = 10) {
        $toEmail = trim((string)$toEmail);
        if ($toEmail === '') return false;
        $subject = 'Your HELPORT verification code';
        $safeName = $employeeName ?: 'Employee';
        $message = "Hello {$safeName},\r\n\r\n" .
                   "Your verification code is: {$code}\r\n\r\n" .
                   "This code expires in {$ttlMinutes} minutes and can only be used once.\r\n" .
                   "If you did not try to log in, please contact your administrator immediately.\r\n\r\n" .
                   "HELPORT Security";
        $headers = "MIME-Version: 1.0\r\n";
        $headers .= "Content-Type: text/plain; charset=UTF-8\r\n";
        $headers .= "From: no-reply@helport.local\r\n";
        return @mail($toEmail, $subject, $message, $headers);
    }
    function createAndSend2FACode($pdo, $user, $ipAddress) {
        $ttlMinutes = 10;
        $code = (string)random_int(100000, 999999);
        $codeHash = hash('sha256', $code);
        $stmt = $pdo->prepare("INSERT INTO employee_2fa_codes (employee_id, code_hash, expires_at, ip_address) VALUES (?, ?, DATE_ADD(NOW(), INTERVAL ? MINUTE), ?)");
        $stmt->execute([$user['id'], $codeHash, $ttlMinutes, $ipAddress]);
        $sent = send2FACodeEmail($user['twofa_email'] ?? '', $user['name'] ?? 'Employee', $code, $ttlMinutes);
        if (!$sent) {
            throw new Exception('Unable to send verification code. Please contact your administrator.');
        }
    }
    function verify2FACode($pdo, $employeeNumericId, $submittedCode) {
        $submittedCode = trim((string)$submittedCode);
        if ($submittedCode === '') {
            return ['ok' => false, 'message' => 'Please enter the verification code.'];
        }
        $stmt = $pdo->prepare("SELECT * FROM employee_2fa_codes WHERE employee_id = ? AND used_at IS NULL ORDER BY id DESC LIMIT 1");
        $stmt->execute([$employeeNumericId]);
        $row = $stmt->fetch(PDO::FETCH_ASSOC);
        if (!$row) {
            return ['ok' => false, 'message' => 'No active verification code found. Please request a new code.'];
        }
        if (strtotime($row['expires_at']) < time()) {
            return ['ok' => false, 'message' => 'Verification code expired. Please request a new code.'];
        }
        if ((int)$row['attempts'] >= 5) {
            return ['ok' => false, 'message' => 'Too many invalid attempts. Please request a new code.'];
        }
        $isValid = hash_equals($row['code_hash'], hash('sha256', $submittedCode));
        if (!$isValid) {
            $pdo->prepare("UPDATE employee_2fa_codes SET attempts = attempts + 1 WHERE id = ?")->execute([$row['id']]);
            return ['ok' => false, 'message' => 'Invalid verification code.'];
        }
        $pdo->prepare("UPDATE employee_2fa_codes SET used_at = NOW(), attempts = attempts + 1 WHERE id = ?")->execute([$row['id']]);
        return ['ok' => true];
    }
    function calculateDistance($lat1, $lon1, $lat2, $lon2) {
        $earthRadius = 6371000;
        $dLat = deg2rad($lat2 - $lat1);
        $dLon = deg2rad($lon2 - $lon1);
        $a = sin($dLat/2) * sin($dLat/2) + cos(deg2rad($lat1)) * cos(deg2rad($lat2)) * sin($dLon/2) * sin($dLon/2);
        $c = 2 * atan2(sqrt($a), sqrt(1-$a));
        return $earthRadius * $c;
    }
// === LEAVE BALANCE FUNCTIONS (FIXED WITH LOGGING) ===
function getLeaveBalance($pdo, $employeeId) {
    if (!$pdo) {
        error_log("Leave Balance Error: PDO connection is null");
        return ['vl_credits' => 0, 'sl_credits' => 0, 'used_vl' => 0, 'used_sl' => 0, 'total_paid' => 0];
    }
    try {
        error_log("Leave Balance: Searching for employee_id = " . $employeeId);
        
        // PRIMARY: Search by numeric employee_id (this matches your leave_balances table)
        $stmt = $pdo->prepare("SELECT vl_credits, sl_credits, used_vl, used_sl FROM leave_balances WHERE employee_id = ?");
        $stmt->execute([$employeeId]);
        $balance = $stmt->fetch(PDO::FETCH_ASSOC);
        
        if ($balance) {
            // Cap leave credits to a maximum of 12 for display/reporting purposes
            $balance['vl_credits'] = min(12, floatval($balance['vl_credits']));
            $balance['sl_credits'] = min(12, floatval($balance['sl_credits']));

            error_log("Leave Balance FOUND: VL=" . $balance['vl_credits'] . ", SL=" . $balance['sl_credits']);
            $balance['total_paid'] = ($balance['vl_credits'] + $balance['sl_credits']) - ($balance['used_vl'] + $balance['used_sl']);
            return $balance;
        }
        
        // FALLBACK: Try joining with employees table in case of ID mismatch
        error_log("Leave Balance: Primary search failed, trying fallback join...");
        $stmt2 = $pdo->prepare("SELECT lb.vl_credits, lb.sl_credits, lb.used_vl, lb.used_sl 
                                FROM leave_balances lb 
                                JOIN employees e ON lb.employee_id = e.id 
                                WHERE e.id = ? OR e.employee_id = ?");
        $stmt2->execute([$employeeId, $employeeId]);
        $balance2 = $stmt2->fetch(PDO::FETCH_ASSOC);
        
        if ($balance2) {
            // Cap leave credits to a maximum of 12 for display/reporting purposes
            $balance2['vl_credits'] = min(12, floatval($balance2['vl_credits']));
            $balance2['sl_credits'] = min(12, floatval($balance2['sl_credits']));

            error_log("Leave Balance FOUND via fallback: VL=" . $balance2['vl_credits']);
            $balance2['total_paid'] = ($balance2['vl_credits'] + $balance2['sl_credits']) - ($balance2['used_vl'] + $balance2['used_sl']);
            return $balance2;
        }
        
        error_log("Leave Balance: NO RECORD FOUND for employee_id = " . $employeeId);
        return ['vl_credits' => 0, 'sl_credits' => 0, 'used_vl' => 0, 'used_sl' => 0, 'total_paid' => 0];
        
    } catch (Exception $e) {
        error_log("Leave Balance Exception: " . $e->getMessage());
        return ['vl_credits' => 0, 'sl_credits' => 0, 'used_vl' => 0, 'used_sl' => 0, 'total_paid' => 0];
    }
}

function deductLeaveCredit($pdo, $employeeId, $leaveType, $days) {
    if (!$pdo) return false;
    try {
        if ($leaveType === 'VL') {
            $stmt = $pdo->prepare("UPDATE leave_balances SET used_vl = used_vl + ?, updated_at = NOW() WHERE employee_id = ?");
        } elseif ($leaveType === 'SL') {
            $stmt = $pdo->prepare("UPDATE leave_balances SET used_sl = used_sl + ?, updated_at = NOW() WHERE employee_id = ?");
        } else {
            return true;
        }
        $stmt->execute([$days, $employeeId]);
        return true;
    } catch (Exception $e) {
        return false;
    }
}

function restoreLeaveCredit($pdo, $employeeId, $leaveType, $days) {
    if (!$pdo) return false;
    try {
        if ($leaveType === 'VL') {
            $stmt = $pdo->prepare("UPDATE leave_balances SET used_vl = GREATEST(used_vl - ?, 0), updated_at = NOW() WHERE employee_id = ?");
        } elseif ($leaveType === 'SL') {
            $stmt = $pdo->prepare("UPDATE leave_balances SET used_sl = GREATEST(used_sl - ?, 0), updated_at = NOW() WHERE employee_id = ?");
        } else {
            return true;
        }
        $stmt->execute([$days, $employeeId]);
        return true;
    } catch (Exception $e) {
        return false;
    }
}

function uploadLeaveAttachment($file, $employeeId) {
    $allowedTypes = ['pdf', 'jpg', 'jpeg', 'png'];
    $maxSize = 5 * 1024 * 1024;
    
    if ($file['error'] !== UPLOAD_ERR_OK) {
        return ['success' => false, 'error' => 'Upload error occurred: ' . $file['error']];
    }
    
    if ($file['size'] > $maxSize) {
        return ['success' => false, 'error' => 'File size exceeds 5MB limit'];
    }
    
    $fileExt = strtolower(pathinfo($file['name'], PATHINFO_EXTENSION));
    if (!in_array($fileExt, $allowedTypes)) {
        return ['success' => false, 'error' => 'Invalid file type. Only PDF, JPG, PNG allowed'];
    }
    
    $uploadDir = __DIR__ . '/uploads/leave_documents/';
    if (!is_dir($uploadDir)) {
        if (!mkdir($uploadDir, 0755, true)) {
            return ['success' => false, 'error' => 'Failed to create upload directory'];
        }
    }
    
    $safeFileName = preg_replace('/[^a-zA-Z0-9._-]/', '', $file['name']);
    $newFileName = 'leave_' . $employeeId . '_' . time() . '_' . $safeFileName;
    $uploadPath = $uploadDir . $newFileName;
    
    if (!move_uploaded_file($file['tmp_name'], $uploadPath)) {
        return ['success' => false, 'error' => 'Failed to save file to: ' . $uploadPath];
    }
    
    return ['success' => true, 'path' => 'uploads/leave_documents/' . $newFileName, 'filename' => $newFileName];
}
    // Update Function Signature
    function calculatePayrollHours($checkIn, $checkOut, $pdo = null, $employeeId = null, $lunchOut = null, $lunchIn = null) {
        if (!$checkIn || !$checkOut) return ['regular' => 0, 'overtime' => 0, 'night_diff' => 0, 'holiday_paid' => 0, 'holiday_bonus' => 0, 'holiday_type' => null, 'worked_hours' => 0];
        
        $in = new DateTime($checkIn);
        $out = new DateTime($checkOut);
        $date = $in->format('Y-m-d');
        
        // 1. Calculate Gross Worked Hours
        $interval = $in->diff($out);
        $grossWorkedHours = $interval->h + ($interval->i / 60) + ($interval->s / 3600);
        
        // 2. Calculate & Deduct Lunch Duration
        $lunchDurationMinutes = 0;
        if ($lunchOut && $lunchIn) {
            $lOut = new DateTime($lunchOut);
            $lIn = new DateTime($lunchIn);
            // Validate sequence
            if ($lIn > $lOut) {
                $lunchInterval = $lOut->diff($lIn);
                $lunchDurationMinutes = ($lunchInterval->h * 60) + $lunchInterval->i;
            }
        }
        
        $totalWorkedHours = $grossWorkedHours - ($lunchDurationMinutes / 60);
        if ($totalWorkedHours < 0) $totalWorkedHours = 0;

        // 3. Check for Holiday (Existing Logic)
        $holidayPaidHours = $totalWorkedHours;
        $holidayBonus = 0;
        $holidayType = null;
        if ($pdo && $employeeId) {
            $holiday = getHolidayInfo($pdo, $date);
            if ($holiday) {
                $holidayType = $holiday['type'];
                $holidayPaidHours = calculateHolidayPayHours($totalWorkedHours, $holidayType, true);
                $holidayBonus = $holidayPaidHours - $totalWorkedHours;
            }
        }

        // 4. Standard Calculations (Regular vs OT)
        $regular = min(8, $totalWorkedHours);
        $overtime = max(0, $totalWorkedHours - 8);

        // 5. Night Differential (Existing Logic)
        $nightDiff = 0;
        $nightStart = clone $in; $nightStart->setTime(22, 0, 0);
        $nightEnd = clone $in; $nightEnd->setTime(6, 0, 0);
        if ($nightEnd < $in) $nightEnd->modify('+1 day');
        if ($in < $nightEnd && $out > $nightStart) {
            $nightIn = max($in, $nightStart);
            $nightOut = min($out, $nightEnd);
            if ($nightOut > $nightIn) {
                $nightInterval = $nightIn->diff($nightOut);
                $nightDiff = $nightInterval->h + ($nightInterval->i / 60);
            }
        }

        return [
            'regular' => round($regular, 2),
            'overtime' => round($overtime, 2),
            'night_diff' => round($nightDiff, 2),
            'holiday_paid' => round($holidayPaidHours, 2),
            'holiday_bonus' => round($holidayBonus, 2),
            'holiday_type' => $holidayType,
            'worked_hours' => round($totalWorkedHours, 2),
            'lunch_duration_minutes' => $lunchDurationMinutes
        ];
    }


    // === NEW: AUTOMATIC OVERTIME REQUEST CREATION (WITH SCHEDULE AWARENESS) ===
    function processOvertimeRequest($pdo, $userId, $attendanceId, $checkIn, $checkOut) {
        if (!$checkIn || !$checkOut) return;
        
        // 1. Get Schedule for that specific date
        $date = date('Y-m-d', strtotime($checkIn));
        $schedule = getEmployeeDailySchedule($pdo, $userId, $date);
        
        $in = new DateTime($checkIn);
        $out = new DateTime($checkOut);
        
        // Default end time if no schedule found
        $scheduledEnd = new DateTime($checkIn);
        $scheduledEnd->setTime(17, 0, 0); 
        
        if ($schedule && $schedule['end']) {
            $scheduledEnd = new DateTime($date . ' ' . $schedule['end']);
            // Handle overnight shifts (e.g., 22:00 to 07:00)
            if ($scheduledEnd < $in) {
                $scheduledEnd->modify('+1 day');
            }
        }
        
        // Calculate Overtime only if worked past scheduled end time
        if ($out > $scheduledEnd) {
            $diff = $scheduledEnd->diff($out);
            $overtimeHours = $diff->h + ($diff->i / 60);
            
            if ($overtimeHours >= 1.0) { // Minimum 1 hour OT
                $stmt = $pdo->prepare("SELECT id FROM overtime_requests WHERE attendance_id = ?");
                $stmt->execute([$attendanceId]);
                if (!$stmt->fetch()) {
                    $insert = $pdo->prepare("INSERT INTO overtime_requests (employee_id, attendance_id, overtime_hours, status, created_at) VALUES (?, ?, ?, 'Pending', NOW())");
                    $insert->execute([$userId, $attendanceId, floor($overtimeHours)]);
                }
            }
        }
    }

    function isLateCheckIn($checkInTime, $officeStartTime = '08:00:00', $gracePeriodMinutes = 5) {
        $checkIn = new DateTime($checkInTime);
        $officeStart = clone $checkIn;
        $officeStart->setTime(...explode(':', $officeStartTime));
        $gracePeriod = new DateInterval("PT{$gracePeriodMinutes}M");
        $officeStart->add($gracePeriod);
        return $checkIn > $officeStart;
    }
    function logAudit($pdo, $action, $user = null, $tableName = null, $recordId = null, $beforeValue = null, $afterValue = null) {
        if (!$pdo) return;
        if (!$user && isset($_SESSION['employee_id'])) {
            $user = $_SESSION['employee_id'];
        } elseif (!$user) {
            $user = 'System';
        }
        $ip = $_SERVER['REMOTE_ADDR'] ?? 'unknown';
        $stmt = $pdo->prepare("INSERT INTO audit_trail (action, user, table_name, record_id, before_value, after_value, ip_address, timestamp)
        VALUES (?, ?, ?, ?, ?, ?, ?, NOW())");
        $stmt->execute([$action, $user, $tableName, $recordId,
            $beforeValue ? json_encode($beforeValue) : null,
            $afterValue ? json_encode($afterValue) : null,
            $ip]);
    }

    // === TIME FORMATTING HELPER ===
    function getTimeAgo($dateString) {
        try {
            $timezone = new DateTimeZone('Asia/Manila');
            $created = new DateTime($dateString, $timezone);
            $now = new DateTime('now', $timezone);
            $diff = $now->diff($created);
            
            if ($diff->y > 0) return $diff->y . " year" . ($diff->y > 1 ? "s" : "") . " ago";
            if ($diff->m > 0) return $diff->m . " month" . ($diff->m > 1 ? "s" : "") . " ago";
            if ($diff->d > 0) return $diff->d . " day" . ($diff->d > 1 ? "s" : "") . " ago";
            if ($diff->h > 0) return $diff->h . " hour" . ($diff->h > 1 ? "s" : "") . " ago";
            if ($diff->i > 0) return $diff->i . " minute" . ($diff->i > 1 ? "s" : "") . " ago";
            return "Just now";
        } catch (Exception $e) {
            return "Recently";
        }
    }

    function createNotification($pdo, $userId, $title, $message, $link = null, $type = 'info') {
        if (!$pdo) return;
        try {
            // Get current time in correct timezone
            $timezone = new DateTimeZone('Asia/Manila');
            $now = new DateTime('now', $timezone);
            $createdAt = $now->format('Y-m-d H:i:s');
            
            $stmt = $pdo->prepare("INSERT INTO notifications (user_id, title, message, link, type, created_at) VALUES (?, ?, ?, ?, ?, ?)");
            $stmt->execute([$userId, $title, $message, $link, $type, $createdAt]);
        } catch (Exception $e) {}
    }

// === ENHANCED NOTIFICATION FOR LEAVE/DAY-OFF (REPLACEMENT) ===
function createLeaveNotification($pdo, $employeeId, $requestType, $startDate, $endDate, $requestId) {
    if (!$pdo) return;
    try {
        // Get employee info
        $stmt = $pdo->prepare("SELECT name, employee_id, department FROM employees WHERE id = ?");
        $stmt->execute([$employeeId]);
        $employee = $stmt->fetch(PDO::FETCH_ASSOC);
        if (!$employee) return;
        
        // Get all admins
        $adminStmt = $pdo->prepare("SELECT id FROM employees WHERE role = 'Admin' AND status = 'active'");
        $adminStmt->execute();
        $admins = $adminStmt->fetchAll(PDO::FETCH_ASSOC);
        
        // Get current time in correct timezone
        $timezone = new DateTimeZone('Asia/Manila');
        $now = new DateTime('now', $timezone);
        $createdAt = $now->format('Y-m-d H:i:s');
        
        // Create notification for each admin
        foreach ($admins as $admin) {
            $message = "{$employee['name']} requested {$requestType} for " .
            date('M d, Y', strtotime($startDate));
            if ($startDate !== $endDate) {
                $message .= " - " . date('M d, Y', strtotime($endDate));
            }
            
            // Set correct type and link based on request type
            $notifType = ($requestType === 'Leave') ? 'leave_request' : 'day_off_request';
            $link = ($requestType === 'Leave') ? '?view=leaveadministration' : '?view=dayoff';
            
            $stmt = $pdo->prepare("INSERT INTO notifications
                (user_id, title, message, link, type, created_at)
                VALUES (?, ?, ?, ?, ?, ?)");
            $stmt->execute([
                $admin['id'],
                "{$requestType} Request Submitted",
                $message,
                $link,
                $notifType,
                $createdAt
            ]);
        }
        
        // Also notify the employee
        $empNotifType = ($requestType === 'Leave') ? 'leave_request' : 'day_off_request';
        $empLink = ($requestType === 'Leave') ? '?emp_view=leave' : '?emp_view=leaves';
        
        $empNotifStmt = $pdo->prepare("INSERT INTO notifications
            (user_id, title, message, link, type, created_at)
            VALUES (?, ?, ?, ?, ?, ?)");
        $empNotifStmt->execute([
            $employeeId,
            "{$requestType} Request Submitted",
            "Your {$requestType} request has been submitted successfully and is pending approval.",
            $empLink,
            $empNotifType,
            $createdAt
        ]);
    } catch (Exception $e) {
        error_log("Notification Creation Error: " . $e->getMessage());
    }
}

