            $stmt = $pdo->query("SELECT COUNT(*) FROM employees WHERE status = 'active'");
            $totalEmployees = (int)$stmt->fetchColumn();
            $attendanceRate = $totalEmployees > 0 ? round(($presentCount / $totalEmployees) * 100) : 0;

