            $stmt = $pdo->prepare("SELECT AVG(TIMESTAMPDIFF(HOUR, check_in, check_out)) FROM attendance WHERE DATE(check_in) BETWEEN ? AND ? AND check_out IS NOT NULL");
            $stmt->execute([$startDate, $endDate]);
