   // === SUBMIT LEAVE REQUEST (EMPLOYEE) - UPDATED ===
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['action']) && $_POST['action'] === 'submit_leave_request' && isLoggedIn()) {
    ob_start();
    header('Content-Type: application/json');
    $response = ['success' => false, 'message' => 'Unknown error'];
    try {
        if (!validateCSRFToken($_POST['csrf_token'] ?? '')) {
            throw new Exception('Invalid security token');
        }
        $startDate = $_POST['startDate'] ?? '';
        $endDate = $_POST['endDate'] ?? $startDate;
        $leaveType = $_POST['leave_type'] ?? 'VL';
        $reason = $_POST['reason'] ?? '';
        $empId = $_SESSION['user_id'];
        $attachmentPath = '';
        
        // Calculate total days
        $start = new DateTime($startDate);
        $end = new DateTime($endDate);
        $totalDays = $start->diff($end)->days + 1;
        
        // Check leave balance ONLY for VL and SL
        if ($leaveType === 'VL') {
            $balance = getLeaveBalance($pdo, $empId);
            if ($balance['vl_credits'] - $balance['used_vl'] < $totalDays) {
                throw new Exception('Insufficient Vacation Leave credits. Available: ' . ($balance['vl_credits'] - $balance['used_vl']) . ' days');
            }
        } elseif ($leaveType === 'SL') {
            $balance = getLeaveBalance($pdo, $empId);
            if ($balance['sl_credits'] - $balance['used_sl'] < $totalDays) {
                throw new Exception('Insufficient Sick Leave credits. Available: ' . ($balance['sl_credits'] - $balance['used_sl']) . ' days');
            }
        }
        
        // ✅ HANDLE FILE UPLOAD
        if (isset($_FILES['attachment']) && $_FILES['attachment']['error'] === 0) {
            $uploadResult = uploadLeaveAttachment($_FILES['attachment'], $empId);
            if (!$uploadResult['success']) {
                throw new Exception($uploadResult['error']);
            }
            $attachmentPath = $uploadResult['path'];
        }
        
        if (empty($startDate)) {
            throw new Exception('Please select a start date');
        }
        if (strlen($reason) < 20) {
            throw new Exception('Reason must be at least 20 characters');
        }
        
        $stmt = $pdo->prepare("INSERT INTO day_off_requests
        (employee_id, start_date, end_date, type, reason, status, request_category, created_at, attachment_path)
        VALUES (?, ?, ?, ?, ?, 'Pending', 'leave', NOW(), ?)");
        $stmt->execute([$empId, $startDate, $endDate, $leaveType, $reason, $attachmentPath]);
        $requestId = $pdo->lastInsertId();
        
        createLeaveNotification($pdo, $empId, 'Leave', $startDate, $endDate, $requestId);
        $response = ['success' => true, 'message' => 'Leave request submitted successfully!', 'request_id' => $requestId];
    } catch (Exception $e) {
        $response = ['success' => false, 'message' => 'Error: ' . $e->getMessage()];
    }
    ob_end_clean();
    echo json_encode($response);
    exit;
}
 // === SUBMIT DAY OFF REQUEST - UPDATED FOR MULTI-DATE ===
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['action']) && $_POST['action'] === 'submit_day_off' && isLoggedIn()) {
    header('Content-Type: application/json');
    ob_start();
    try {
        if (!validateCSRFToken($_POST['csrf_token'] ?? '')) {
            throw new Exception('Invalid security token');
        }
        
        // ✅ NEW: Handle multiple dates (comma-separated string)
        $dates = [];
        if (isset($_POST['dates']) && !empty($_POST['dates'])) {
            // Dates come as comma-separated string: "2026-03-14,2026-03-17"
            $dates = array_map('trim', explode(',', $_POST['dates']));
        } elseif (isset($_POST['date']) && !empty($_POST['date'])) {
            // Fallback to single date for backward compatibility
            $dates = [$_POST['date']];
        }
        
        // Validate dates
        if (empty($dates)) {
            throw new Exception('Please select at least one date');
        }
        
        // Validate each date is in the future
        $today = date('Y-m-d');
        foreach ($dates as $date) {
            if ($date < $today) {
                throw new Exception("Date {$date} is in the past. Please select future dates only.");
            }
        }
        
        $type = $_POST['type'] ?? 'Full Day';
        $reason = $_POST['reason'] ?? '';
        $empId = $_SESSION['user_id'];
        
        // Calculate total days for display
        $totalDays = count($dates);
        $startDate = min($dates);
        $endDate = max($dates);
        
        // ✅ Create main request record
        $stmt = $pdo->prepare("INSERT INTO day_off_requests
            (employee_id, start_date, end_date, type, reason, status, request_category, created_at)
            VALUES (?, ?, ?, ?, ?, 'Pending', 'day_off', NOW())");
        
        $stmt->execute([$empId, $startDate, $endDate, $type, $reason]);
        $requestId = $pdo->lastInsertId();
        
        // ✅ Insert individual dates into new table
        $dateStmt = $pdo->prepare("INSERT INTO day_off_request_dates 
            (request_id, request_date, status) VALUES (?, ?, 'Pending')");
        
        foreach ($dates as $date) {
            $dateStmt->execute([$requestId, $date]);
        }
        
        // ✅ CREATE NOTIFICATIONS
        createLeaveNotification($pdo, $empId, 'Day-Off', $startDate, $endDate, $requestId);
        
        ob_end_clean();
        echo json_encode([
            'success' => true, 
            'message' => 'Day off request submitted successfully!',
            'request_id' => $requestId,
            'dates_count' => count($dates)
        ]);
        exit;
        
    } catch (Exception $e) {
        ob_end_clean();
        echo json_encode(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
        exit;
    }
}

