        $employee = null;
    }

    // === BIRTHDAY CHECK ===
    $isBirthday = false;
    $birthdayAge = 0;
    if ($employee && !empty($employee['birthday'])) {
        $today = new DateTime();
        $birthDate = new DateTime($employee['birthday']);
        $nextBirthday = clone $birthDate;
        $nextBirthday->setDate($today->format('Y'), $today->format('m'), $today->format('d'));
        
        if ($nextBirthday < $today) {
            $nextBirthday->modify('+1 year');
        }
        
        if ($today->format('m-d') === $birthDate->format('m-d')) {
            $isBirthday = true;
            $birthdayAge = $today->format('Y') - $birthDate->format('Y');
        }
    }

    if ($employee && $employee['joined_date']) {
