        header('Content-Type: application/json'); // Ensure JSON response
        
        // 1. Security Checks
        if (!validateCSRFToken($_POST['csrf_token'] ?? '')) {
            echo json_encode(['success' => false, 'message' => 'Security token invalid. Please refresh.']);
            exit;
        }

        // 2. Check if Feature Enabled
        $stmt = $pdo->query("SELECT setting_value FROM settings WHERE setting_key = 'allow_manual_checkin'");
        $isAllowed = $stmt->fetchColumn();
        if ($isAllowed != '1') {
            echo json_encode(['success' => false, 'message' => 'Manual check-in is disabled by admin.']);
            exit;
        }

        $type = $_POST['type'] ?? ''; // 'IN' or 'OUT'
        $userId = $_SESSION['user_id'];
        $empId = $_SESSION['employee_id'];
        $now = date('Y-m-d H:i:s');
        $today = date('Y-m-d'); // ✅ FIX: Define $today here!

        try {
            if ($type === 'IN') {
                // Check if already checked in
                $check = $pdo->prepare("SELECT id FROM attendance WHERE employee_id = ? AND DATE(check_in) = ? AND check_out IS NULL");
                $check->execute([$userId, $today]);
                if ($check->fetch()) {
                    echo json_encode(['success' => false, 'message' => 'You have already checked in today.']);
                    exit;
                }

                // Get Schedule for Late Detection
                $todaysSchedule = getEmployeeDailySchedule($pdo, $userId, $today);
                $isLate = 0;
                $nowTimeStr = date('H:i:s');
                if ($todaysSchedule && $todaysSchedule['start'] !== '00:00:00') {
                    if ($nowTimeStr > $todaysSchedule['start']) {
                        $isLate = 1;
                    }
                }

                // Insert Record
                $stmt = $pdo->prepare("INSERT INTO attendance (employee_id, check_in, is_late, scan_method) VALUES (?, ?, ?, 'manual')");
                $stmt->execute([$userId, $now, $isLate]);
                
                updateAttendanceStreak($pdo, $userId, true);
                logAudit($pdo, "Manual Check In", $empId, 'attendance');
                
                echo json_encode(['success' => true, 'message' => 'Checked in successfully!', 'time' => date('g:i:s A')]);

            } elseif ($type === 'OUT') {
                // Update Record
                $stmt = $pdo->prepare("UPDATE attendance SET check_out = ?, scan_method = 'manual' WHERE employee_id = ? AND DATE(check_in) = ? AND check_out IS NULL ORDER BY id DESC LIMIT 1");
                $stmt->execute([$now, $userId, $today]);
                
                if ($stmt->rowCount() > 0) {
                    // Recalculate Hours
                    $fetchStmt = $pdo->prepare("SELECT id, check_in FROM attendance WHERE employee_id = ? AND DATE(check_in) = ? ORDER BY id DESC LIMIT 1");
                    $fetchStmt->execute([$userId, $today]);
                    $record = $fetchStmt->fetch();
                    
                    if($record) {
                        processOvertimeRequest($pdo, $userId, $record['id'], $record['check_in'], $now);
                        $attendance = getTodayAttendance($pdo, $userId, $office_start_time, $grace_period_minutes);
                        if ($attendance && $attendance['check_in'] && $now) {
                            $hours = calculatePayrollHours($attendance['check_in'], $now, $pdo, $userId, $attendance['lunch_out'] ?? null, $attendance['lunch_in'] ?? null);
                            $updateStmt = $pdo->prepare("UPDATE attendance SET overtime_hours = ?, night_diff_hours = ? WHERE id = ?");
                            $updateStmt->execute([$hours['overtime'], $hours['night_diff'], $attendance['id']]);
                        }
                    }
                    logAudit($pdo, "Manual Check Out", $empId, 'attendance');
                    echo json_encode(['success' => true, 'message' => 'Checked out successfully!', 'time' => date('H:i:s')]);
                } else {
                    echo json_encode(['success' => false, 'message' => 'No active check-in found.']);
                }
            }
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
        }
        exit;
    }

    // === HANDLE LUNCH LOGGING ===
    if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['action']) && $_POST['action'] === 'log_lunch' && isLoggedIn()) {
        header('Content-Type: application/json');
        
        if (!validateCSRFToken($_POST['csrf_token'] ?? '')) {
            echo json_encode(['success' => false, 'message' => 'Security token invalid.']);
            exit;
        }

        $type = $_POST['type'] ?? ''; // 'LUNCH_OUT' or 'LUNCH_IN'
        $userId = $_SESSION['user_id'];
        $now = date('Y-m-d H:i:s');
        $today = date('Y-m-d');

        try {
            // Get Today's Attendance Record
            $stmt = $pdo->prepare("SELECT * FROM attendance WHERE employee_id = ? AND DATE(check_in) = ?");
            $stmt->execute([$userId, $today]);
            $record = $stmt->fetch(PDO::FETCH_ASSOC);
            
            if (!$record || !$record['check_in']) {
                echo json_encode(['success' => false, 'message' => 'Please check in before logging lunch.']);
                exit;
            }

            if ($type === 'LUNCH_OUT') {
                if (!empty($record['lunch_out'])) {
                    echo json_encode(['success' => false, 'message' => 'Lunch Out already logged.']);
                    exit;
                }
                if (!empty($record['lunch_in'])) {
                    echo json_encode(['success' => false, 'message' => 'Cannot log Lunch Out after Lunch In.']);
                    exit;
                }
                $update = $pdo->prepare("UPDATE attendance SET lunch_out = ? WHERE id = ?");
                $update->execute([$now, $record['id']]);
                echo json_encode(['success' => true, 'message' => 'Lunch Out logged.', 'time' => date('g:i A')]);
                
            } elseif ($type === 'LUNCH_IN') {
                if (empty($record['lunch_out'])) {
                    echo json_encode(['success' => false, 'message' => 'Please log Lunch Out first.']);
                    exit;
                }
                if (!empty($record['lunch_in'])) {
                    echo json_encode(['success' => false, 'message' => 'Lunch In already logged.']);
                    exit;
                }
                $update = $pdo->prepare("UPDATE attendance SET lunch_in = ? WHERE id = ?");
                $update->execute([$now, $record['id']]);
                
                // Recalculate Hours immediately if checked out, or just save for now
                // If they check out later, the Check Out handler will use these values.
                echo json_encode(['success' => true, 'message' => 'Lunch In logged.', 'time' => date('g:i A')]);
            }
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
        }
        exit;
    }


    // === 12-HOUR TIME FORMAT HELPERS ===
    function formatTime12Hour($time24, $includeSeconds = false) {
        if (empty($time24)) return '';
        $datetime = DateTime::createFromFormat('H:i:s', $time24) ?: 
                    DateTime::createFromFormat('H:i', $time24);
        if (!$datetime) return $time24;
        return $includeSeconds 
            ? $datetime->format('g:i:s A') 
            : $datetime->format('g:i A');
    }

    function formatDateTime12Hour($datetime, $showDate = true) {
        if (empty($datetime)) return '';
        $dt = new DateTime($datetime);
        return $showDate 
            ? $dt->format('M j, Y g:i A') 
            : $dt->format('g:i A');
    }

