        exit;
    }
    
    $userId = $_SESSION['user_id'];
    
    try {
        // Get unread count
        $stmt = $pdo->prepare("SELECT COUNT(*) FROM notifications WHERE user_id = ? AND is_read = FALSE");
        $stmt->execute([$userId]);
        $unreadCount = (int)$stmt->fetchColumn();
        
        // Get notifications - NEWEST FIRST with proper timestamp
        $stmt = $pdo->prepare("
            SELECT id, title, message, type, link, is_read, created_at 
            FROM notifications 
            WHERE user_id = ? 
            ORDER BY created_at DESC 
            LIMIT 20
        ");
        $stmt->execute([$userId]);
        $notifications = $stmt->fetchAll(PDO::FETCH_ASSOC);
        
        // Format each notification with correct timezone
        $timezone = new DateTimeZone('Asia/Manila');
        foreach ($notifications as &$notif) {
            $created = new DateTime($notif['created_at'], $timezone);
            $notif['formatted_date'] = $created->format('M d, Y – g:i A'); // Mar 09, 2026 – 2:35 PM
            $notif['time_ago'] = getTimeAgo($notif['created_at']); // Also show relative time
            
            // Determine redirect module based on type/title
            if (stripos($notif['type'], 'leave') !== false || stripos($notif['title'], 'Leave') !== false) {
                $notif['redirect_module'] = 'leaveadministration';
            } elseif (stripos($notif['type'], 'day') !== false || stripos($notif['title'], 'Day-Off') !== false) {
                $notif['redirect_module'] = 'dayoff';
            } elseif (stripos($notif['type'], 'overtime') !== false || stripos($notif['title'], 'Overtime') !== false) {
                $notif['redirect_module'] = 'overtime';
            } elseif (stripos($notif['type'], 'report') !== false || stripos($notif['title'], 'Report') !== false) {
                $notif['redirect_module'] = 'reports';
            } elseif (stripos($notif['type'], 'audit') !== false || stripos($notif['title'], 'Audit') !== false) {
                $notif['redirect_module'] = 'audittrail';
            } elseif (stripos($notif['type'], 'attendance') !== false || stripos($notif['title'], 'Attendance') !== false) {
                $notif['redirect_module'] = 'attendance';
            } elseif (stripos($notif['type'], 'fingerprint') !== false || stripos($notif['title'], 'Fingerprint') !== false) {
                $notif['redirect_module'] = 'fingerprint';
            } else {
                $notif['redirect_module'] = 'overview';
            }
        }
        
        echo json_encode([
            'success' => true,
            'count' => $unreadCount,
            'notifications' => $notifications
        ]);
    } catch (Exception $e) {
        echo json_encode(['success' => false, 'count' => 0, 'notifications' => []]);
