// === ADMIN: ASSIGN LEAVE CREDITS TO EMPLOYEE ===
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['action']) && $_POST['action'] === 'assign_leave_credits' && isLoggedIn() && $_SESSION['role'] === 'Admin') {
    header('Content-Type: application/json');
    try {
        if (!validateCSRFToken($_POST['csrf_token'] ?? '')) {
            throw new Exception('Invalid security token');
        }
        
        $employeeId = (int)$_POST['employee_id'];
        $leaveType = $_POST['leave_type']; // VL, SL, or BOTH
        $days = (int)$_POST['days'];
        
        if ($days < 1 || $days > 30) {
            throw new Exception('Days must be between 1 and 30');
        }
        
        // Verify employee exists
        $empStmt = $pdo->prepare("SELECT id, name, employee_id FROM employees WHERE id = ? AND status = 'active'");
        $empStmt->execute([$employeeId]);
        $employee = $empStmt->fetch();
        
        if (!$employee) {
            throw new Exception('Employee not found');
        }
        
        // Clamp assignment to max 12 days
        if ($days > 12) {
            $days = 12;
        }

        // Check if balance record exists, create if not
        $checkStmt = $pdo->prepare("SELECT id, vl_credits, sl_credits FROM leave_balances WHERE employee_id = ?");
        $checkStmt->execute([$employeeId]);
        $existing = $checkStmt->fetch(PDO::FETCH_ASSOC);

        if (!$existing) {
            // Create balance record (start at 0 and then apply assignment)
            $insertStmt = $pdo->prepare("INSERT INTO leave_balances (employee_id, vl_credits, sl_credits, used_vl, used_sl) VALUES (?, 0, 0, 0, 0)");
            $insertStmt->execute([$employeeId]);
            $existing = ['vl_credits' => 0, 'sl_credits' => 0];
        }

        // Compute next values (cap at 12)
        $nextVl = $existing['vl_credits'];
        $nextSl = $existing['sl_credits'];

        if ($leaveType === 'VL' || $leaveType === 'BOTH') {
            $nextVl = min(12, $existing['vl_credits'] + $days);
        }
        if ($leaveType === 'SL' || $leaveType === 'BOTH') {
            $nextSl = min(12, $existing['sl_credits'] + $days);
        }

        // Update credits based on type (only if changed)
        if ($nextVl !== $existing['vl_credits']) {
            $updateStmt = $pdo->prepare("UPDATE leave_balances SET vl_credits = ?, updated_at = NOW() WHERE employee_id = ?");
            $updateStmt->execute([$nextVl, $employeeId]);
        }
        if ($nextSl !== $existing['sl_credits']) {
            $updateStmt = $pdo->prepare("UPDATE leave_balances SET sl_credits = ?, updated_at = NOW() WHERE employee_id = ?");
            $updateStmt->execute([$nextSl, $employeeId]);
        }

        // Log the action
        $actionDesc = "Assigned {$days} days of " . ($leaveType === 'BOTH' ? 'VL & SL' : $leaveType) . " to {$employee['name']} ({$employee['employee_id']})";
        logAudit($pdo, $actionDesc, $_SESSION['employee_id'], 'leave_balances', $employeeId);

        // Get updated balance
        $balanceStmt = $pdo->prepare("SELECT vl_credits, sl_credits, used_vl, used_sl FROM leave_balances WHERE employee_id = ?");
        $balanceStmt->execute([$employeeId]);
        $balance = $balanceStmt->fetch();

        $vl_remaining = max(0, $balance['vl_credits'] - $balance['used_vl']);
        $sl_remaining = max(0, $balance['sl_credits'] - $balance['used_sl']);
        $total_paid = $vl_remaining + $sl_remaining;

        echo json_encode([
            'success' => true,
            'message' => "Successfully assigned {$days} days to {$employee['name']}",
            'balance' => [
                'vl_remaining' => $vl_remaining,
                'sl_remaining' => $sl_remaining,
                'total_paid' => $total_paid
            ]
        ]);
        
    } catch (Exception $e) {
        echo json_encode(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
    }
    exit;
}
