            $joined_date  = !empty($_POST['joined_date']) ? $_POST['joined_date'] : date('Y-m-d');

            // password: hash it (your DB expects varchar 255)
            $rawPassword = trim($_POST['password'] ?? '');
            if ($rawPassword === '') $rawPassword = 'password123';
            $password = password_hash($rawPassword, PASSWORD_DEFAULT);

            $photo_path = '';

            // Handle file upload
            if (isset($_FILES['photo']) && $_FILES['photo']['error'] === 0) {
                $allowed = ['jpg', 'jpeg', 'png', 'gif'];
                $filename = $_FILES['photo']['name'];
                $ext = strtolower(pathinfo($filename, PATHINFO_EXTENSION));

                if (!in_array($ext, $allowed)) {
                    throw new Exception("Invalid photo file type.");
                }

                $new_filename = uniqid('emp_', true) . '.' . $ext;
                $upload_path = $upload_dir . $new_filename;

                if (!move_uploaded_file($_FILES['photo']['tmp_name'], $upload_path)) {
                    throw new Exception("Failed to upload photo.");
                }
                $photo_path = $upload_path;
            }

            // Handle base64 photo data
            if ($photo_path === '' && !empty($_POST['photo_data'])) {
                $photoData = $_POST['photo_data'];
                if (preg_match('/^data:image\/(\w+);base64,/', $photoData, $type)) {
                    $photoData = substr($photoData, strpos($photoData, ',') + 1);
                    $type = strtolower($type[1]);
                    if (!in_array($type, ['jpg','jpeg','png','gif'])) {
                        throw new Exception("Invalid base64 image type.");
                    }
                    $photo_path = $upload_dir . uniqid('emp_', true) . '.' . $type;
                    if (file_put_contents($photo_path, base64_decode($photoData)) === false) {
                        throw new Exception("Failed to save base64 photo.");
                    }
                }
            }

            if ($name === '' || $employee_id === '' || $position === '' || $department === '' || $role === '' || $twofa_email === '') {
                throw new Exception("All fields are required.");
            }
            if (!filter_var($twofa_email, FILTER_VALIDATE_EMAIL)) {
                throw new Exception("Please enter a valid registered 2FA email address.");
            }

            // Check duplicate employee_id
            $check = $pdo->prepare("SELECT id FROM employees WHERE employee_id = ?");
            $check->execute([$employee_id]);
            if ($check->fetch()) {
                throw new Exception("Employee ID already exists.");
            }

            // IMPORTANT: This assumes your table has joined_date column already (you confirmed it does)
// IMPORTANT: This assumes your table has joined_date column already (you confirmed it does)
$stmt = $pdo->prepare("
INSERT INTO employees
(name, employee_id, joined_date, position, department, role, password, twofa_email, birthday, finger_id, photo_path)
VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
");
$stmt->execute([
$name, $employee_id, $joined_date, $position, $department,
$role, $password, $twofa_email, $birthday, $finger_id, $photo_path
]);
$newId = (int)$pdo->lastInsertId();

// === NEW: Initialize Leave Balance for New Employee ===
$balanceStmt = $pdo->prepare("INSERT INTO leave_balances (employee_id, vl_credits, sl_credits) VALUES (?, 15, 15)");
$balanceStmt->execute([$newId]);
// =======================================================

logAudit($pdo, "Added new employee: {$name} ({$employee_id})", $_SESSION['employee_id'], 'employees', $newId);

            ob_end_clean();
