            exit;
        }
        if ($photo_path && $password) {
            $stmt = $pdo->prepare("UPDATE employees SET name = ?, employee_id = ?, position = ?, department = ?, role = ?, password = ?, twofa_email = ?, birthday = ?, finger_id = ?, photo_path = ? WHERE id = ?");
            $stmt->execute([$name, $employee_id, $position, $department, $role, $password, $twofa_email, $birthday, $finger_id, $photo_path, $id]);
        } elseif ($photo_path) {
