    // === HOLIDAY MODULE: DATABASE MIGRATION ===
    if ($pdo) {
        try {
            // 1. Create Holidays Table if it doesn't exist
            $pdo->exec("CREATE TABLE IF NOT EXISTS holidays (
                id INT AUTO_INCREMENT PRIMARY KEY,
                date DATE NOT NULL,
                name VARCHAR(255) NOT NULL,
                type ENUM('regular', 'special_non_working', 'special_working') NOT NULL,
                year INT NOT NULL,
                UNIQUE KEY unique_holiday_date (date)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

            // 2. FIX: Add 'year' column if it's missing from existing tables
            $pdo->exec("ALTER TABLE holidays ADD COLUMN IF NOT EXISTS year INT NOT NULL AFTER type");
            
            // 3. Update existing records to 2026 if year is empty
            $pdo->exec("UPDATE holidays SET year = 2026 WHERE year IS NULL OR year = 0");

            // 4. Create Holiday Assignments Table
            $pdo->exec("CREATE TABLE IF NOT EXISTS holiday_assignments (
                id INT AUTO_INCREMENT PRIMARY KEY,
                holiday_id INT NOT NULL,
                employee_id INT NOT NULL,
                required_to_work TINYINT DEFAULT 1,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                FOREIGN KEY (holiday_id) REFERENCES holidays(id) ON DELETE CASCADE,
                FOREIGN KEY (employee_id) REFERENCES employees(id) ON DELETE CASCADE,
                UNIQUE KEY unique_assignment (holiday_id, employee_id)
            ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4");

            // 5. Update Attendance Table
            $pdo->exec("ALTER TABLE attendance ADD COLUMN IF NOT EXISTS holiday_type VARCHAR(50) DEFAULT NULL");
            $pdo->exec("ALTER TABLE attendance ADD COLUMN IF NOT EXISTS holiday_assigned TINYINT DEFAULT 0");
            $pdo->exec("ALTER TABLE attendance ADD COLUMN IF NOT EXISTS holiday_paid_hours DECIMAL(5,2) DEFAULT 0.00");

