                ['2026-12-30', 'Rizal Day', 'regular'],
                ['2026-12-31', 'New Years Eve', 'special_non_working']
            ];

            $stmt = $pdo->prepare("INSERT IGNORE INTO holidays (date, name, type, year) VALUES (?, ?, ?, 2026)");
