        header('Content-Type: application/json');
        
        $id = (int)$_POST['id'];
        try {
            // 1. Fetch Employee Data first
            $empStmt = $pdo->prepare("SELECT * FROM employees WHERE id = ?");
            $empStmt->execute([$id]);
            $emp = $empStmt->fetch(PDO::FETCH_ASSOC);
            
            if ($emp) {
                // 2. Insert into Archives
                $archiveStmt = $pdo->prepare("INSERT INTO employee_archives 
                (original_id, name, employee_id, position, department, role, password, finger_id, birthday, status, photo_path, archived_by, archived_at) 
                VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'archived', ?, ?, NOW())");
                $archiveStmt->execute([
                    $emp['id'],
                    $emp['name'],
                    $emp['employee_id'],
                    $emp['position'],
                    $emp['department'],
                    $emp['role'],
                    $emp['password'],
                    $emp['finger_id'],
                    $emp['birthday'],
                    $emp['photo_path'],
                    $_SESSION['employee_id']
                ]);

                // 3. Delete from Active Employees
                $deleteStmt = $pdo->prepare("DELETE FROM employees WHERE id = ?");
                $deleteStmt->execute([$id]);

                // 4. Log Audit
                logAudit($pdo, "Archived employee: {$emp['employee_id']}", $_SESSION['employee_id'], 'employees', $id);
                
                echo json_encode(['success' => true, 'message' => 'Employee moved to archives successfully']);
            } else {
                echo json_encode(['success' => false, 'message' => 'Employee not found']);
            }
        } catch (Exception $e) {
            echo json_encode(['success' => false, 'message' => 'Error: ' . $e->getMessage()]);
        }
        exit; // ⚠️ CRITICAL - Stop execution
    }


    // === RESTORE ARCHIVED EMPLOYEE ===
    if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['action']) && $_POST['action'] === 'restore_employee' && isLoggedIn() && $_SESSION['role'] === 'Admin') {
        if (ob_get_length()) ob_end_clean(); // ⚠️ CLEAR BUFFER FIRST
        header('Content-Type: application/json');
        
        $archivedId = (int)$_POST['archived_id'];
        try {
            // 1. Get Archive Data
            $stmt = $pdo->prepare("SELECT * FROM employee_archives WHERE id = ?");
            $stmt->execute([$archivedId]);
            $archive = $stmt->fetch(PDO::FETCH_ASSOC);

            if (!$archive) {
                throw new Exception("Archive record not found");
            }

            // 2. Insert back into Active Employees
            $insertStmt = $pdo->prepare("INSERT INTO employees (name, employee_id, position, department, role, password, finger_id, birthday, status, photo_path, created_at) 
                                        VALUES (?, ?, ?, ?, ?, ?, ?, ?, 'active', ?, NOW())");
            $insertStmt->execute([
                $archive['name'],
                $archive['employee_id'],
                $archive['position'],
                $archive['department'],
                $archive['role'],
                $archive['password'],
                $archive['finger_id'],
                $archive['birthday'],
                $archive['photo_path']
            ]);

            // 3. Delete from Archive
            $deleteStmt = $pdo->prepare("DELETE FROM employee_archives WHERE id = ?");
            $deleteStmt->execute([$archivedId]);

            logAudit($pdo, "Restored employee from archive: {$archive['name']}", $_SESSION['employee_id']);
            echo json_encode(['success' => true, 'message' => 'Employee restored successfully!']);
