        $days = ['monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday', 'sunday'];
        $updates = [];
        $values = [];
        foreach ($days as $day) {
            $shiftType = trim($_POST["{$day}_shift"] ?? 'Off');
            // Always update the shift type
            $updates[] = "$day = ?";
            $values[] = $shiftType;
            // Handle custom time fields
            $startTime = !empty($_POST["{$day}_start"]) ? trim($_POST["{$day}_start"]) : null;
            $endTime = !empty($_POST["{$day}_end"]) ? trim($_POST["{$day}_end"]) : null;
