                // Clear custom times when using preset shifts
                $updates[] = "{$day}_start = NULL";
                $updates[] = "{$day}_end = NULL";
                $updates[] = "{$day}_break = NULL";
            }
        }
        // Add effective_from and employee_id to values
        $values[] = $effectiveFrom;
        $values[] = $empId;
        // Build the SQL query
        $sql = "UPDATE employee_schedules SET " . implode(', ', $updates) . ", effective_from = ?, updated_at = NOW() WHERE employee_id = ?";
        $stmt = $pdo->prepare($sql);
