            $liveMorning = 0;
            $liveAfternoon = 0;
            $liveNight = 0;
            $liveFlexible = 0;
            
            foreach ($liveScans as $time) {
                $hour = (int)substr($time, 0, 2);
                if ($hour >= 6 && $hour < 12) {
                    $liveMorning++;
                } elseif ($hour >= 12 && $hour < 18) {
                    $liveAfternoon++;
                } elseif ($hour >= 18 || $hour < 6) {
                    $liveNight++;
                } else {
                    $liveFlexible++;
                }
            }
            
            echo json_encode([
                'success' => true,
                'present' => $present,
                'absent' => $absent,
                'late' => $late,
                'total' => $total,
                'live_total' => $liveTotal,
