            $fileExt = strtolower(pathinfo($fileName, PATHINFO_EXTENSION));
            
            if (!in_array($fileExt, ['csv', 'pdf'])) {
                throw new Exception('Only CSV and PDF files are supported');
            }
            
            if ($_FILES['import_file']['size'] > 10 * 1024 * 1024) {
                throw new Exception('File size exceeds 10MB limit');
            }
            
            $results = [
                'success' => 0,
                'skipped' => 0,
                'errors' => [],
                'warnings' => [],
                'records' => [],
                'updates' => [],
                'extracted_fields' => []
            ];
            
            // === LOAD ALL EMPLOYEES FIRST ===
            $empStmt = $pdo->query("SELECT id, employee_id, name, department, status FROM employees WHERE status = 'active'");
            $employees = $empStmt->fetchAll(PDO::FETCH_ASSOC);
            $employeeMap = [];
            foreach ($employees as $emp) {
                $employeeMap[strtoupper($emp['employee_id'])] = $emp;
            }
            
            // === PREPARE STATEMENTS ===
            $insertStmt = $pdo->prepare("INSERT INTO attendance (employee_id, check_in, check_out, is_late, scan_method, overtime_hours, night_diff_hours, created_at) VALUES (?, ?, ?, ?, 'import', ?, ?, NOW())");
            $updateStmt = $pdo->prepare("UPDATE attendance SET check_in = ?, check_out = ?, is_late = ?, scan_method = 'import', overtime_hours = ?, night_diff_hours = ?, updated_at = NOW() WHERE employee_id = ? AND DATE(check_in) = ?");
            
            if ($fileExt === 'csv') {
                $handle = fopen($file, 'r');
                if (!$handle) throw new Exception('Cannot open file');
                
                // === CRITICAL FIX: Read headers with proper CSV parsing ===
                // Parameters: handle, length (0=unlimited), delimiter, enclosure, escape
                $headers = fgetcsv($handle, 0, ',', '"', '\\');
                if (!$headers) throw new Exception('Empty CSV file');
                
                // === DEBUG: Log headers ===
                error_log("CSV Headers: " . json_encode($headers));
                
                // === MAP COLUMNS ===
                $columnMap = [];
                foreach ($headers as $index => $header) {
                    $headerLower = strtolower(trim($header));
                    
                    // ✅ FIX: Check for EID specifically
                    if ($headerLower === 'eid' || $headerLower === 'employee_id' || $headerLower === 'emp_id') {
                        $columnMap['employee_id'] = $index;
                    }
                    if ($headerLower === 'name') {
                        $columnMap['name'] = $index;
                    }
                    if ($headerLower === 'calendar date' || $headerLower === 'date') {
                        $columnMap['date'] = $index;
                    }
                    if ($headerLower === 'li' || $headerLower === 'log in' || $headerLower === 'check_in') {
                        $columnMap['check_in'] = $index;
                    }
                    if ($headerLower === 'lo' || $headerLower === 'log out' || $headerLower === 'check_out') {
                        $columnMap['check_out'] = $index;
                    }
                    if ($headerLower === 'si' || $headerLower === 'shift in') {
                        $columnMap['scheduled_in'] = $index;
                    }
                    if ($headerLower === 'so' || $headerLower === 'shift out') {
                        $columnMap['scheduled_out'] = $index;
                    }
                    if ($headerLower === 'shift type') {
                        $columnMap['shift_type'] = $index;
                    }
                    if ($headerLower === 'account/project' || $headerLower === 'department') {
                        $columnMap['department'] = $index;
                    }
                }
                
                $results['extracted_fields'] = array_keys($columnMap);
                error_log("Column Map: " . json_encode($columnMap));
                
                if (!isset($columnMap['employee_id'])) {
                    throw new Exception('Cannot find Employee ID column. Expected: EID, employee_id, or emp_id. Found: ' . implode(', ', $headers));
                }
                if (!isset($columnMap['date'])) {
                    throw new Exception('Cannot find Date column. Expected: Calendar Date or date');
                }
                if (!isset($columnMap['check_in'])) {
                    throw new Exception('Cannot find Check-in column. Expected: LI, log in, or check_in');
                }
                
                $pdo->beginTransaction();
                $rowNum = 0;
                $batchSize = 100;
                $batchCount = 0;
                
                while (($data = fgetcsv($handle, 0, ',', '"', '\\')) !== FALSE) {
                    $rowNum++;
                    
                    // === SKIP HEADER ROW ===
                    if ($rowNum === 1) continue;
                    
                    // === SKIP EMPTY ROWS ===
                    if (empty($data) || count(array_filter($data)) === 0) {
                        continue;
                    }
                    
                    // === EXTRACT DATA ===
                    $empIdStr = isset($columnMap['employee_id']) && isset($data[$columnMap['employee_id']]) ? trim($data[$columnMap['employee_id']]) : '';
                    $dateStr = isset($columnMap['date']) && isset($data[$columnMap['date']]) ? trim($data[$columnMap['date']]) : '';
                    $checkInTime = isset($columnMap['check_in']) && isset($data[$columnMap['check_in']]) ? trim($data[$columnMap['check_in']]) : '';
                    $checkOutTime = isset($columnMap['check_out']) && isset($data[$columnMap['check_out']]) ? trim($data[$columnMap['check_out']]) : '';
                    $shiftType = isset($columnMap['shift_type']) && isset($data[$columnMap['shift_type']]) ? trim($data[$columnMap['shift_type']]) : '';
                    $scheduledIn = isset($columnMap['scheduled_in']) && isset($data[$columnMap['scheduled_in']]) ? trim($data[$columnMap['scheduled_in']]) : '';
                    
                    // === DEBUG FIRST FEW ROWS ===
                    if ($rowNum <= 5) {
                        error_log("Row {$rowNum} - EID: '{$empIdStr}', Date: '{$dateStr}', CheckIn: '{$checkInTime}'");
                    }
                    
                    // === VALIDATE REQUIRED FIELDS ===
                    if (empty($empIdStr)) {
                        $results['errors'][] = "Row {$rowNum}: Missing Employee ID";
                        $results['skipped']++;
                        continue;
                    }
                    
                    if (empty($dateStr)) {
                        $results['errors'][] = "Row {$rowNum}: Missing Date";
                        $results['skipped']++;
                        continue;
                    }
                    
                    if (empty($checkInTime)) {
                        $results['errors'][] = "Row {$rowNum}: Missing Check-in Time";
                        $results['skipped']++;
                        continue;
                    }
                    
                    // === FIND EMPLOYEE ===
                    $empIdUpper = strtoupper($empIdStr);
                    if (!isset($employeeMap[$empIdUpper])) {
                        $results['errors'][] = "Row {$rowNum}: Employee '{$empIdStr}' not found in database";
                        $results['skipped']++;
                        continue;
                    }
                    
                    $emp = $employeeMap[$empIdUpper];
                    
                    // === NORMALIZE DATE ===
                    $normalizedDate = null;
                    $dateFormats = ['l, F j, Y', 'Y-m-d', 'm/d/Y', 'd/m/Y', 'F j, Y'];
                    foreach ($dateFormats as $format) {
                        $dateObj = DateTime::createFromFormat($format, $dateStr);
                        if ($dateObj && $dateObj->format($format) === $dateStr) {
                            $normalizedDate = $dateObj->format('Y-m-d');
                            break;
                        }
                    }
                    if (!$normalizedDate) {
                        $timestamp = strtotime($dateStr);
                        if ($timestamp) {
                            $normalizedDate = date('Y-m-d', $timestamp);
                        }
                    }
                    if (!$normalizedDate) {
                        $results['errors'][] = "Row {$rowNum}: Invalid date format '{$dateStr}'";
                        $results['skipped']++;
                        continue;
                    }
                    
                    // === NORMALIZE TIME ===
                    $normalizedCheckIn = normalizeTimeFormat($checkInTime);
                    $normalizedCheckOut = !empty($checkOutTime) ? normalizeTimeFormat($checkOutTime) : null;
                    
                    if (!$normalizedCheckIn) {
                        $results['errors'][] = "Row {$rowNum}: Invalid check-in time format '{$checkInTime}'";
                        $results['skipped']++;
                        continue;
                    }
                    
                    // === CALCULATE LATENESS ===
                    $isLate = 0;
                    if (!empty($scheduledIn)) {
                        $schedStart = normalizeTimeFormat($scheduledIn);
                        if ($schedStart && $normalizedCheckIn > $schedStart) {
                            $isLate = 1;
                        }
                    }
                    
                    // === BUILD DATETIME ===
                    $checkIn = $normalizedDate . ' ' . $normalizedCheckIn;
                    $checkOut = $normalizedCheckOut ? $normalizedDate . ' ' . $normalizedCheckOut : null;
                    
                    // === CHECK IF EXISTS ===
                    $dupStmt = $pdo->prepare("SELECT id FROM attendance WHERE employee_id = ? AND DATE(check_in) = ?");
                    $dupStmt->execute([$emp['id'], $normalizedDate]);
                    $existing = $dupStmt->fetch(PDO::FETCH_ASSOC);
                    
                    if ($existing) {
                        $updateStmt->execute([$checkIn, $checkOut, $isLate, 0, 0, $emp['id'], $normalizedDate]);
                        $results['updates'][] = $empIdStr;
                        $results['warnings'][] = "Updated existing record for {$empIdStr} on {$normalizedDate}";
                    } else {
                        $insertStmt->execute([$emp['id'], $checkIn, $checkOut, $isLate, 0, 0]);
                    }
                    
                    $results['success']++;
                    $results['records'][] = [
                        'employee_id' => $empIdStr,
                        'name' => $emp['name'],
                        'date' => $normalizedDate,
                        'check_in' => $normalizedCheckIn,
                        'check_out' => $normalizedCheckOut
                    ];
                    
                    $batchCount++;
                    if ($batchCount >= $batchSize) {
                        $pdo->commit();
                        $pdo->beginTransaction();
                        $batchCount = 0;
                    }
                }
                
                fclose($handle);
                $pdo->commit();
                
            } elseif ($fileExt === 'pdf') {
                // PDF processing (existing code)
                $tempPdf = __DIR__ . '/temp_import_' . uniqid() . '.pdf';
                move_uploaded_file($file, $tempPdf);
                $extraction = extractDataFromPDF($tempPdf);
                
                if (!$extraction['success']) {
                    throw new Exception(implode(', ', $extraction['errors']));
                }
                
                $pdo->beginTransaction();
                foreach ($extraction['data'] as $row) {
                    $empIdStr = strtoupper(trim($row['employee_id'] ?? ''));
                    if (!isset($employeeMap[$empIdStr])) {
                        $results['errors'][] = "Employee '{$empIdStr}' not found";
                        $results['skipped']++;
                        continue;
                    }
                    $emp = $employeeMap[$empIdStr];
                    $dateStr = trim($row['date'] ?? '');
                    $checkInTime = normalizeTimeFormat($row['check_in'] ?? '');
                    $checkOutTime = normalizeTimeFormat($row['check_out'] ?? '');
                    if (!$checkInTime || empty($dateStr)) {
                        $results['errors'][] = "Invalid data for {$empIdStr}";
                        $results['skipped']++;
                        continue;
                    }
                    $normalizedDate = date('Y-m-d', strtotime($dateStr));
                    $checkIn = $normalizedDate . ' ' . $checkInTime;
                    $checkOut = $checkOutTime ? $normalizedDate . ' ' . $checkOutTime : null;
                    $dupStmt = $pdo->prepare("SELECT id FROM attendance WHERE employee_id = ? AND DATE(check_in) = ?");
                    $dupStmt->execute([$emp['id'], $normalizedDate]);
                    $existing = $dupStmt->fetch();
                    if ($existing) {
                        $updateStmt->execute([$checkIn, $checkOut, 0, 0, 0, $emp['id'], $normalizedDate]);
                        $results['updates'][] = $empIdStr;
                    } else {
                        $insertStmt->execute([$emp['id'], $checkIn, $checkOut, 0, 0, 0]);
                    }
                    $results['success']++;
                    $results['records'][] = ['employee_id' => $empIdStr, 'name' => $emp['name'], 'date' => $normalizedDate];
                }
                $pdo->commit();
                unlink($tempPdf);
            }
            
            // Trigger system-wide sync
            triggerSystemSync($pdo, $results);
            
            echo json_encode([
                'success' => true,
                'message' => "✅ Import Complete! {$results['success']} records imported in " . round(microtime(true) - $_SERVER['REQUEST_TIME'], 2) . " seconds",
                'details' => [
                    'successful' => $results['success'],
                    'skipped' => $results['skipped'],
                    'errors' => array_slice($results['errors'], 0, 50),
                    'warnings' => array_slice($results['warnings'], 0, 50),
                    'records' => array_slice($results['records'], 0, 20),
                    'updates' => $results['updates'],
                    'fields_extracted' => $results['extracted_fields']
                ],
                'sync_status' => 'completed',
                'processing_time' => round(microtime(true) - $_SERVER['REQUEST_TIME'], 2) . 's'
            ]);
            
        } catch (Exception $e) {
            if ($pdo->inTransaction()) $pdo->rollBack();
            echo json_encode([
                'success' => false,
                'message' => '❌ Import Failed: ' . $e->getMessage(),
                'error_code' => $e->getCode()
            ]);
        }
        exit;
    }

    // === HELPER: NORMALIZE TIME FORMAT ===
    function normalizeTimeFormat($timeStr) {
        if (empty($timeStr)) return null;
        
        $timeStr = trim($timeStr);
        
        // Remove AM/PM and normalize
        $timeUpper = strtoupper($timeStr);
        $isPM = strpos($timeUpper, 'PM') !== false;
        $isAM = strpos($timeUpper, 'AM') !== false;
        
        // Remove AM/PM markers
        $timeStr = preg_replace('/\s*(AM|PM)\s*/i', '', $timeStr);
        
        // Parse time
        $parts = explode(':', $timeStr);
        if (count($parts) >= 2) {
            $hour = intval($parts[0]);
            $minute = intval($parts[1]);
            $second = isset($parts[2]) ? intval($parts[2]) : 0;
            
            // Convert to 24-hour format
            if ($isPM && $hour < 12) {
                $hour += 12;
            } elseif ($isAM && $hour == 12) {
                $hour = 0;
            }
            
            return sprintf('%02d:%02d:%02d', $hour, $minute, $second);
        }
        
        return null;
    }


    // === HELPER FUNCTIONS FOR IMPORT ===
    function extractRowByMap($data, $columnMap) {
        $row = [];
        foreach ($columnMap as $field => $index) {
            $row[$field] = isset($data[$index]) ? trim($data[$index]) : null;
        }
        return $row;
    }

    function validateImportRow($row, $rowNum, $pdo) {
        $validation = ['valid' => true, 'errors' => [], 'warnings' => []];
        
        if (empty($row['employee_id'])) {
            $validation['errors'][] = "Row {$rowNum}: Missing employee_id";
            $validation['valid'] = false;
        }
        if (empty($row['date'])) {
            $validation['errors'][] = "Row {$rowNum}: Missing date";
            $validation['valid'] = false;
        }
        if (empty($row['check_in'])) {
            $validation['errors'][] = "Row {$rowNum}: Missing check_in time";
            $validation['valid'] = false;
        }
        
        if (!empty($row['employee_id'])) {
            $stmt = $pdo->prepare("SELECT id, status FROM employees WHERE employee_id = ?");
            $stmt->execute([$row['employee_id']]);
            $emp = $stmt->fetch(PDO::FETCH_ASSOC);
            
            if (!$emp) {
                $validation['errors'][] = "Row {$rowNum}: Employee ID '{$row['employee_id']}' not found";
                $validation['valid'] = false;
            } elseif ($emp['status'] !== 'active') {
                $validation['warnings'][] = "Row {$rowNum}: Employee '{$row['employee_id']}' is not active";
            }
        }
        
        return $validation;
    }

    function processImportRecord($row, $pdo, &$warnings) {
        $result = ['success' => false, 'errors' => [], 'record' => null, 'updated' => false];
        
        try {
            $stmt = $pdo->prepare("SELECT id, name, department FROM employees WHERE employee_id = ? AND status = 'active'");
            $stmt->execute([$row['employee_id']]);
            $emp = $stmt->fetch(PDO::FETCH_ASSOC);
            
            if (!$emp) {
                $result['errors'][] = "Employee not found: {$row['employee_id']}";
                return $result;
            }
            
            $employeeId = $emp['id'];
            $checkIn = $row['date'] . ' ' . $row['check_in'];
            $checkOut = !empty($row['check_out']) ? $row['date'] . ' ' . $row['check_out'] : null;
            
            $isLate = 0;
            if (!empty($row['shift_type'])) {
                $shiftStart = getShiftStartTime($row['shift_type']);
                if ($shiftStart && $row['check_in'] > $shiftStart) $isLate = 1;
            }
            
            $stmt = $pdo->prepare("SELECT id FROM attendance WHERE employee_id = ? AND DATE(check_in) = ?");
            $stmt->execute([$employeeId, $row['date']]);
            $existing = $stmt->fetch(PDO::FETCH_ASSOC);
            
            if ($existing) {
                $stmt = $pdo->prepare("UPDATE attendance SET check_in = ?, check_out = ?, is_late = ?, scan_method = 'import', updated_at = NOW() WHERE id = ?");
                $stmt->execute([$checkIn, $checkOut, $isLate, $existing['id']]);
                $attendanceId = $existing['id'];
                $result['updated'] = true;
                $warnings[] = "Updated existing record for {$row['employee_id']} on {$row['date']}";
            } else {
                $stmt = $pdo->prepare("INSERT INTO attendance (employee_id, check_in, check_out, is_late, scan_method, created_at) VALUES (?, ?, ?, ?, 'import', NOW())");
                $stmt->execute([$employeeId, $checkIn, $checkOut, $isLate]);
                $attendanceId = $pdo->lastInsertId();
            }
            
            if ($checkOut) {
                $hours = calculatePayrollHours($checkIn, $checkOut);
                $stmt = $pdo->prepare("UPDATE attendance SET overtime_hours = ?, night_diff_hours = ? WHERE id = ?");
                $stmt->execute([$hours['overtime'], $hours['night_diff'], $attendanceId]);
                processOvertimeRequest($pdo, $employeeId, $attendanceId, $checkIn, $checkOut);
            }
            
            updateAttendanceStreak($pdo, $employeeId, true);
            logAudit($pdo, "Imported attendance record", $row['employee_id'], 'attendance', $attendanceId);
            
            $result['success'] = true;
            $result['record'] = [
                'employee_id' => $row['employee_id'],
                'name' => $emp['name'],
                'date' => $row['date'],
                'check_in' => $row['check_in'],
                'check_out' => $row['check_out'] ?? null,
                'attendance_id' => $attendanceId
            ];
            
        } catch (Exception $e) {
            $result['errors'][] = "Processing error: " . $e->getMessage();
        }
        
        return $result;
    }

    function getShiftStartTime($shiftType) {
        $shiftMap = [
            'morning shift' => '08:00:00',
            'day shift' => '08:00:00',
            'early shift' => '07:00:00',
            'mid shift' => '09:00:00',
            'afternoon shift' => '14:00:00',
            'night shift' => '22:00:00',
            'flexible' => '00:00:00',
            'schedule shift' => '07:00:00'
        ];
        $shiftKey = strtolower(trim($shiftType));
        return $shiftMap[$shiftKey] ?? '08:00:00';
    }

    function triggerSystemSync($pdo, $importResults) {
        try {
            clearSystemCaches();
            updateAnalyticsCache($pdo);
            
            if (!empty($importResults['records'])) {
                foreach ($importResults['records'] as $record) {
                    recalculateEmployeeMetrics($pdo, $record['employee_id']);
                }
            }
            
            $adminStmt = $pdo->prepare("SELECT id FROM employees WHERE role = 'Admin' AND status = 'active'");
            $adminStmt->execute();
            $admins = $adminStmt->fetchAll(PDO::FETCH_ASSOC);
            
            foreach ($admins as $admin) {
                createNotification($pdo, $admin['id'], 
                    "Import Completed: {$importResults['success']} Records",
                    "Successfully imported {$importResults['success']} attendance records.",
                    '/?view=reports', 'success');
            }
            
            logAudit($pdo, "Bulk Import: {$importResults['success']} successful", 'System', 'import');
            file_put_contents(__DIR__ . '/.sync_trigger', time());
            
        } catch (Exception $e) {
            error_log("System Sync Error: " . $e->getMessage());
        }
    }

    function clearSystemCaches() {
        $cacheFiles = [
            __DIR__ . '/.cache_analytics',
            __DIR__ . '/.cache_reports',
            __DIR__ . '/.cache_dashboard'
        ];
        foreach ($cacheFiles as $file) {
            if (file_exists($file)) unlink($file);
        }
    }

    function updateAnalyticsCache($pdo) {
        try {
            $cache = [
                'timestamp' => time(),
                'total_employees' => $pdo->query("SELECT COUNT(*) FROM employees WHERE status = 'active'")->fetchColumn(),
                'today_present' => $pdo->query("SELECT COUNT(DISTINCT employee_id) FROM attendance WHERE DATE(check_in) = CURDATE()")->fetchColumn(),
                'today_late' => $pdo->query("SELECT COUNT(*) FROM attendance WHERE DATE(check_in) = CURDATE() AND is_late = 1")->fetchColumn()
            ];
            file_put_contents(__DIR__ . '/.cache_analytics', json_encode($cache));
        } catch (Exception $e) {
            error_log("Cache Update Error: " . $e->getMessage());
        }
    }

    function recalculateEmployeeMetrics($pdo, $employeeId) {
        try {
            $stmt = $pdo->prepare("SELECT COUNT(DISTINCT DATE(check_in)) as days FROM attendance WHERE employee_id = ? AND check_out IS NOT NULL");
            $stmt->execute([$employeeId]);
            $days = $stmt->fetchColumn();
            
            $stmt = $pdo->prepare("UPDATE attendance_streaks SET current_streak = ?, updated_at = NOW() WHERE employee_id = ?");
            $stmt->execute([$days, $employeeId]);
            
            $stmt = $pdo->prepare("SELECT SUM(overtime_hours) FROM attendance WHERE employee_id = ?");
            $stmt->execute([$employeeId]);
            $totalOT = $stmt->fetchColumn() ?? 0;
            
            $metrics = ['employee_id' => $employeeId, 'total_overtime' => $totalOT, 'last_updated' => time()];
            file_put_contents(__DIR__ . "/.cache_emp_{$employeeId}", json_encode($metrics));
            
        } catch (Exception $e) {
            error_log("Metrics Recalculation Error: " . $e->getMessage());
        }
    }

