/* === BODY & GLOBAL STYLES === */
body {
    background: linear-gradient(135deg, #0a0e1a 0%, #1a1f3a 25%, #0f1729 50%, #1a1a3a 75%, #0a0e1a 100%);
    min-height: 100vh;
    position: relative;
    overflow-x: hidden;
}

body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: 
        radial-gradient(circle at 20% 30%, rgba(100, 50, 200, 0.15) 0%, transparent 50%),
        radial-gradient(circle at 80% 70%, rgba(25, 211, 197, 0.1) 0%, transparent 50%),
        radial-gradient(circle at 40% 80%, rgba(100, 150, 255, 0.1) 0%, transparent 50%),
        radial-gradient(circle at 60% 20%, rgba(200, 50, 150, 0.1) 0%, transparent 50%);
    animation: nebulaPulse 15s ease-in-out infinite;
    pointer-events: none;
    z-index: 0;
}

body::after {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background-image: 
        radial-gradient(2px 2px at 20% 30%, rgba(255, 255, 255, 0.8), transparent),
        radial-gradient(2px 2px at 40% 70%, rgba(255, 255, 255, 0.6), transparent),
        radial-gradient(1px 1px at 60% 20%, rgba(255, 255, 255, 0.7), transparent),
        radial-gradient(1px 1px at 80% 50%, rgba(255, 255, 255, 0.5), transparent),
        radial-gradient(2px 2px at 30% 60%, rgba(255, 255, 255, 0.6), transparent),
        radial-gradient(1px 1px at 70% 80%, rgba(255, 255, 255, 0.7), transparent),
        radial-gradient(2px 2px at 90% 40%, rgba(255, 255, 255, 0.5), transparent),
        radial-gradient(1px 1px at 10% 90%, rgba(255, 255, 255, 0.6), transparent);
    background-size: 200% 200%;
    animation: starsTwinkle 8s ease-in-out infinite;
    pointer-events: none;
    z-index: 0;
}

/* Add more stars */
.stars-layer {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    z-index: 0;
    background-image: 
        radial-gradient(1px 1px at 15% 25%, white, transparent),
        radial-gradient(1px 1px at 35% 45%, white, transparent),
        radial-gradient(1px 1px at 55% 65%, white, transparent),
        radial-gradient(1px 1px at 75% 85%, white, transparent),
        radial-gradient(1px 1px at 95% 15%, white, transparent),
        radial-gradient(1px 1px at 25% 55%, white, transparent),
