        radial-gradient(1px 1px at 65% 95%, white, transparent),
        radial-gradient(1px 1px at 85% 35%, white, transparent),
        radial-gradient(1px 1px at 5% 65%, white, transparent);
    background-size: 300% 300%;
    animation: starsTwinkle 12s ease-in-out infinite reverse;
