            transform: translate(-50%, -50%) scale(1);
            opacity: 0.5;
        }
        100% {
            transform: translate(-50%, -50%) scale(1.3);
            opacity: 0;
        }
    }

    /* === MODERN COLOR SCHEME & GRADIENTS === */
    :root {
        /* Primary Colors */
        --primary-color: #00D4AA;
        --primary-dark: #00B894;
        --primary-light: #00FFE0;
        
        /* Typography */
        --font-sans: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
        
        /* Background Colors */
        --bg-primary: #0a0e0d;
        --bg-secondary: #111817;
        --bg-card: rgba(17, 24, 23, 0.8);
        --bg-glass: rgba(17, 24, 23, 0.6);
        
        /* Text Colors */
        --text-primary: #ffffff;
        --text-secondary: #a0a0a0;
        --text-muted: #6b7280;
        
        /* Accent Colors */
        --accent-success: #00D4AA;
        --accent-warning: #F59E0B;
        --accent-error: #EF4444;
        --accent-info: #3B82F6;
        
        /* Gradients */
        --gradient-primary: linear-gradient(135deg, #00D4AA 0%, #00FFE0 100%);
        --gradient-secondary: linear-gradient(135deg, #00B894 0%, #00D4AA 100%);
        --gradient-dark: linear-gradient(135deg, #0a0e0d 0%, #111817 100%);
        --gradient-card: linear-gradient(145deg, rgba(17, 24, 23, 0.9) 0%, rgba(10, 14, 13, 0.9) 100%);
        --gradient-glow: radial-gradient(circle, rgba(0, 212, 170, 0.15) 0%, transparent 70%);
        
        /* Borders & Shadows */
        --border-color: rgba(0, 212, 170, 0.2);
        --border-glass: rgba(255, 255, 255, 0.1);
        --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.3);
        --shadow-md: 0 4px 16px rgba(0, 0, 0, 0.4);
        --shadow-lg: 0 8px 32px rgba(0, 0, 0, 0.5);
        --shadow-glow: 0 0 20px rgba(0, 212, 170, 0.3);
        --shadow-glow-lg: 0 0 40px rgba(0, 212, 170, 0.4);
        
        /* Spacing & Radius */
        --radius-sm: 8px;
        --radius-md: 12px;
        --radius-lg: 16px;
        --radius-xl: 24px;
        --radius-full: 9999px;
    }

    /* === MODERN ATTENDANCE SECTION STYLES === */
    #attendanceSection {
        background: linear-gradient(135deg, rgba(15, 23, 42, 0.95) 0%, rgba(30, 41, 59, 0.95) 100%);
        border-radius: 24px;
        padding: 30px;
        border: 1px solid rgba(25, 211, 197, 0.1);
        backdrop-filter: blur(10px);
    }

    /* Section Header */
    #attendanceSection .section-header {
        display: flex;
        justify-content: space-between;
        align-items: center;
        margin-bottom: 30px;
        padding-bottom: 20px;
        border-bottom: 2px solid rgba(25, 211, 197, 0.2);
    }

    #attendanceSection .section-title {
        font-size: 24px;
        font-weight: 800;
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        letter-spacing: -0.5px;
        display: flex;
        align-items: center;
        gap: 10px;
    }

    #attendanceSection .section-subtitle {
        font-size: 14px;
        color: #64748b;
        margin-top: 5px;
    }

    /* Modern Filter Bar */
    #attendanceSection .modern-filter-bar {
        background: rgba(30, 41, 59, 0.6);
        border: 1px solid rgba(25, 211, 197, 0.15);
        border-radius: 16px;
        padding: 25px;
        margin-bottom: 25px;
        backdrop-filter: blur(10px);
    }

    #attendanceSection .modern-filter-bar .filter-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
        gap: 20px;
        align-items: end;
    }

    #attendanceSection .filter-group {
        display: flex;
        flex-direction: column;
        gap: 8px;
    }

    #attendanceSection .filter-label {
        font-size: 12px;
        font-weight: 600;
        color: #94a3b8;
        text-transform: uppercase;
        letter-spacing: 0.5px;
        display: flex;
        align-items: center;
        gap: 6px;
    }

    #attendanceSection .filter-label i {
        color: #19D3C5;
        font-size: 14px;
    }

    /* Modern Inputs */
    #attendanceSection .modern-input {
        width: 100%;
        padding: 14px 16px;
        background: rgba(15, 23, 42, 0.6);
        border: 1px solid rgba(25, 211, 197, 0.2);
        border-radius: 12px;
        color: #ffffff;
        font-size: 14px;
        transition: all 0.3s ease;
        outline: none;
    }

    #attendanceSection .modern-input:focus {
        border-color: #19D3C5;
        box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
        background: rgba(15, 23, 42, 0.8);
    }

    #attendanceSection .modern-input::placeholder {
        color: #64748b;
    }

    /* Action Buttons Container */
    #attendanceSection .action-buttons-group {
        display: flex;
        gap: 12px;
        align-items: flex-end;
        justify-content: flex-end;
    }

    /* Modern Action Buttons */
    #attendanceSection .action-button {
        padding: 14px 24px;
        border-radius: 12px;
        font-weight: 700;
        font-size: 14px;
        cursor: pointer;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        display: inline-flex;
        align-items: center;
        gap: 8px;
        border: none;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    #attendanceSection .action-button.primary {
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
        color: #0f172a;
        box-shadow: 0 4px 15px rgba(25, 211, 197, 0.3);
    }

    #attendanceSection .action-button.primary:hover {
        transform: translateY(-2px);
        box-shadow: 0 6px 20px rgba(25, 211, 197, 0.5);
    }

    #attendanceSection .action-button.secondary {
        background: rgba(25, 211, 197, 0.1);
        color: #19D3C5;
        border: 1px solid rgba(25, 211, 197, 0.3);
    }

    #attendanceSection .action-button.secondary:hover {
        background: rgba(25, 211, 197, 0.2);
        transform: translateY(-2px);
        box-shadow: 0 4px 12px rgba(25, 211, 197, 0.2);
    }

    /* Stats Cards Grid */
    #attendanceSection .attendance-stats-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
        gap: 20px;
        margin-bottom: 30px;
    }

    #attendanceSection .attendance-stat-card {
        background: linear-gradient(145deg, rgba(30, 41, 59, 0.8) 0%, rgba(15, 23, 42, 0.8) 100%);
        border: 1px solid rgba(25, 211, 197, 0.15);
        border-radius: 16px;
        padding: 24px;
        display: flex;
        align-items: center;
        gap: 20px;
        transition: all 0.3s ease;
        backdrop-filter: blur(10px);
        position: relative;
        overflow: hidden;
    }

    #attendanceSection .attendance-stat-card::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        width: 4px;
        height: 100%;
        background: linear-gradient(180deg, #19D3C5, #00FFE0);
    }

    #attendanceSection .attendance-stat-card:hover {
        transform: translateY(-3px);
        border-color: rgba(25, 211, 197, 0.3);
        box-shadow: 0 8px 25px rgba(25, 211, 197, 0.15);
    }

    #attendanceSection .attendance-stat-card.present::before {
        background: linear-gradient(180deg, #22c55e, #4ade80);
    }

    #attendanceSection .attendance-stat-card.late::before {
        background: linear-gradient(180deg, #f59e0b, #fbbf24);
    }

    #attendanceSection .attendance-stat-card.absent::before {
        background: linear-gradient(180deg, #ef4444, #f87171);
    }

    #attendanceSection .stat-icon-box {
        width: 56px;
        height: 56px;
        border-radius: 14px;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 24px;
        flex-shrink: 0;
    }

    #attendanceSection .stat-icon-box.present {
        background: rgba(34, 197, 94, 0.15);
        color: #22c55e;
    }

    #attendanceSection .stat-icon-box.late {
        background: rgba(245, 158, 11, 0.15);
        color: #f59e0b;
    }

    #attendanceSection .stat-icon-box.absent {
        background: rgba(239, 68, 68, 0.15);
        color: #ef4444;
    }

    #attendanceSection .stat-info {
        flex: 1;
    }

    #attendanceSection .stat-info h4 {
        font-size: 13px;
        color: #94a3b8;
        margin: 0 0 8px 0;
        font-weight: 600;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    #attendanceSection .stat-info .count {
        font-size: 32px;
        font-weight: 800;
        color: #ffffff;
        line-height: 1;
    }

    /* Attendance List Container */
    #attendanceSection .attendance-list-container {
        background: rgba(30, 41, 59, 0.6);
        border: 1px solid rgba(25, 211, 197, 0.1);
        border-radius: 16px;
        padding: 25px;
        backdrop-filter: blur(10px);
        min-height: 400px;
    }

    /* Modern Attendance Cards */
    #attendanceSection .modern-attendance-card {
        background: linear-gradient(145deg, rgba(30, 41, 59, 0.8) 0%, rgba(15, 23, 42, 0.8) 100%);
        border: 1px solid rgba(25, 211, 197, 0.1);
        border-radius: 14px;
        padding: 20px;
        display: flex;
        align-items: center;
        justify-content: space-between;
        transition: all 0.3s ease;
        margin-bottom: 12px;
    }

    #attendanceSection .modern-attendance-card:hover {
        border-color: rgba(25, 211, 197, 0.3);
        background: rgba(30, 41, 59, 0.9);
        transform: translateX(4px);
    }

    #attendanceSection .emp-identity {
        display: flex;
        align-items: center;
        gap: 16px;
        flex: 1;
    }

    #attendanceSection .emp-avatar-small {
        width: 48px;
        height: 48px;
        border-radius: 12px;
        background: linear-gradient(135deg, #19D3C5, #00FFE0);
        color: #0f172a;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: 700;
        font-size: 18px;
        flex-shrink: 0;
    }

    #attendanceSection .emp-details h5 {
        margin: 0 0 4px 0;
        font-size: 15px;
        color: #ffffff;
        font-weight: 600;
    }

    #attendanceSection .emp-details span {
        font-size: 12px;
        color: #64748b;
    }

    #attendanceSection .attendance-meta {
        display: flex;
        align-items: center;
        gap: 24px;
    }

    #attendanceSection .time-badge {
        font-size: 14px;
        color: #94a3b8;
        font-family: 'Courier New', monospace;
        font-weight: 600;
        min-width: 140px;
        text-align: right;
    }

    #attendanceSection .status-pill {
        padding: 8px 16px;
        border-radius: 20px;
        font-size: 12px;
        font-weight: 700;
        display: flex;
        align-items: center;
        gap: 6px;
        min-width: 100px;
        justify-content: center;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    #attendanceSection .status-pill.present {
        background: rgba(34, 197, 94, 0.15);
        color: #22c55e;
        border: 1px solid rgba(34, 197, 94, 0.3);
    }

    #attendanceSection .status-pill.late {
        background: rgba(245, 158, 11, 0.15);
        color: #f59e0b;
        border: 1px solid rgba(245, 158, 11, 0.3);
    }

    #attendanceSection .status-pill.absent {
        background: rgba(239, 68, 68, 0.15);
        color: #ef4444;
        border: 1px solid rgba(239, 68, 68, 0.3);
    }

    /* Empty State */
    #attendanceSection .empty-state {
        text-align: center;
        padding: 60px 20px;
        background: rgba(30, 41, 59, 0.6);
        border-radius: 16px;
        border: 2px dashed rgba(25, 211, 197, 0.2);
    }

    #attendanceSection .empty-state i {
        font-size: 64px;
        color: #64748b;
        opacity: 0.5;
        margin-bottom: 20px;
    }

    #attendanceSection .empty-state h3 {
        font-size: 18px;
        color: #ffffff;
        margin-bottom: 8px;
    }

    #attendanceSection .empty-state p {
        font-size: 14px;
        color: #64748b;
    }

    /* Responsive */
    @media (max-width: 1024px) {
        #attendanceSection .modern-filter-bar .filter-grid {
            grid-template-columns: repeat(2, 1fr);
        }
        
        #attendanceSection .action-buttons-group {
            grid-column: 1 / -1;
            justify-content: center;
            margin-top: 10px;
        }
    }

    @media (max-width: 768px) {
        #attendanceSection .modern-filter-bar .filter-grid {
            grid-template-columns: 1fr;
        }
        
        #attendanceSection .action-buttons-group {
            flex-direction: column;
            width: 100%;
        }
        
        #attendanceSection .action-button {
            width: 100%;
            justify-content: center;
        }
        
        #attendanceSection .attendance-stats-grid {
            grid-template-columns: 1fr;
        }
        
        #attendanceSection .modern-attendance-card {
            flex-direction: column;
            align-items: flex-start;
            gap: 16px;
        }
        
        #attendanceSection .attendance-meta {
            width: 100%;
            justify-content: space-between;
        }
    }

    /* Loading Animation */
    @keyframes shimmer {
        0% { background-position: -1000px 0; }
        100% { background-position: 1000px 0; }
    }

    #attendanceSection .loading-skeleton {
        background: linear-gradient(90deg, rgba(30, 41, 59, 0.8) 0%, rgba(45, 55, 72, 0.8) 50%, rgba(30, 41, 59, 0.8) 100%);
        background-size: 1000px 100%;
        animation: shimmer 2s infinite;
        border-radius: 12px;
        height: 80px;
        margin-bottom: 12px;
    }

    /* === GLOBAL STYLES === */
    * {
        margin: 0;
        padding: 0;
        box-sizing: border-box;
    }

    body {
        font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        background: var(--gradient-dark);
        color: var(--text-primary);
        min-height: 100vh;
        line-height: 1.6;
        overflow-x: hidden;
    }

    /* === BACKGROUNDS === */
    /* === ENHANCED LANDING PAGE LAYOUT & BACKGROUND === */
body.landing-page {
    /* Flexbox to ensure footer stays at bottom */
    display: flex;
    flex-direction: column;
    min-height: 100vh;
    margin: 0;
    
    /* Modern Deep Gradient Background */
    background: linear-gradient(135deg, #020617 0%, #0f172a 40%, #1e1b4b 100%);
    background-attachment: fixed;
    color: #ffffff;
    font-family: 'Inter', system-ui, -apple-system, sans-serif;
    overflow-x: hidden;
    position: relative;
}

/* Animated Background Orbs (Modern Mesh Effect) */
body.landing-page::before {
    content: '';
    position: fixed;
    top: -20%;
    left: -10%;
    width: 50vw;
    height: 50vw;
    background: radial-gradient(circle, rgba(25, 211, 197, 0.15) 0%, transparent 70%);
    border-radius: 50%;
    filter: blur(80px);
    z-index: 0;
    animation: floatOrb 20s infinite ease-in-out;
    pointer-events: none;
}

body.landing-page::after {
    content: '';
    position: fixed;
    bottom: -20%;
    right: -10%;
    width: 60vw;
    height: 60vw;
    background: radial-gradient(circle, rgba(99, 102, 241, 0.15) 0%, transparent 70%);
    border-radius: 50%;
    filter: blur(100px);
    z-index: 0;
    animation: floatOrb 25s infinite ease-in-out reverse;
    pointer-events: none;
}

@keyframes floatOrb {
    0%, 100% { transform: translate(0, 0); }
    50% { transform: translate(30px, 50px); }
}

/* Wrapper to push footer down */
.landing-content-wrapper {
    flex: 1;
    position: relative;
    z-index: 1;
    width: 100%;
}

/* === HERO SECTION ENHANCEMENTS === */
.landing-hero {
    text-align: center;
    padding: 120px 40px 80px 40px;
    position: relative;
    z-index: 1;
    /* Subtle glass overlay */
    background: radial-gradient(circle at center, rgba(255,255,255,0.03) 0%, transparent 70%);
}

.landing-hero-heading {
    font-weight: 800;
    font-size: clamp(2.8rem, 5vw, 4rem);
    line-height: 1.12;
    margin-bottom: 18px;
    letter-spacing: -0.5px;
    color: #ffffff;
    text-shadow: 0 14px 32px rgba(0, 0, 0, 0.5);
    max-width: 880px;
    margin-left: auto;
    margin-right: auto;
}

.landing-hero-subheading {
    font-size: 18px;
    color: #94a3b8;
    margin-bottom: 40px;
    max-width: 600px;
    margin-left: auto;
    margin-right: auto;
    line-height: 1.6;
}

/* === FOOTER FIX === */
.landing-footer {
    background: rgba(8, 14, 28, 0.75);
    backdrop-filter: blur(18px);
    border-top: 1px solid rgba(255, 255, 255, 0.08);
    padding: 18px 26px;
    display: flex;
    justify-content: center;
    align-items: center;
    color: rgba(255, 255, 255, 0.7);
    font-size: 13px;
    position: relative;
    width: 100%;
}

.landing-footer .footer-center {
    display: flex;
    align-items: center;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
    max-width: 920px;
    width: 100%;
}

.landing-footer .footer-center a {
    color: rgba(255, 255, 255, 0.78);
    text-decoration: none;
    transition: color 0.2s ease;
}

.landing-footer .footer-center a:hover {
    color: rgba(255, 255, 255, 0.95);
}

.landing-footer .footer-sep {
    color: rgba(255, 255, 255, 0.45);
}

/* Responsive Adjustments */
@media (max-width: 768px) {
    .landing-hero { padding: 80px 20px; }
    .landing-hero-heading { font-size: 32px; }
    .landing-footer { padding: 30px 20px; }
}

    /* === NAVIGATION === */
    .landing-nav {
        background: rgba(10, 14, 13, 0.8);
        backdrop-filter: blur(12px);
        border-bottom: 1px solid var(--border-glass);
        padding: 16px 40px;
        position: sticky;
        top: 0;
        z-index: 1000;
    }

    .landing-nav-brand {
        display: flex;
        align-items: center;
        gap: 12px;
        font-size: 24px;
        font-weight: 700;
        background: var(--gradient-primary);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
    }

    /* === BUTTONS === */
    .btn-primary-saas,
    .btn-primary,
    .action-button.primary,
    .chat-send-btn {
        background: var(--gradient-primary);
        color: #0a0e0d;
        border: none;
        border-radius: var(--radius-md);
        padding: 12px 24px;
        font-weight: 600;
        font-size: 14px;
        cursor: pointer;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        box-shadow: var(--shadow-glow);
        display: inline-flex;
        align-items: center;
        gap: 8px;
    }

    .btn-primary-saas:hover,
    .btn-primary:hover,
    .action-button.primary:hover,
    .chat-send-btn:hover {
        transform: translateY(-2px);
        box-shadow: var(--shadow-glow-lg);
    }

    .btn-outline-saas,
    .action-button.secondary {
        background: transparent;
        color: var(--primary-color);
        border: 2px solid var(--primary-color);
        border-radius: var(--radius-md);
        padding: 12px 24px;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
    }

    .btn-outline-saas:hover,
    .action-button.secondary:hover {
        background: rgba(0, 212, 170, 0.1);
        box-shadow: var(--shadow-glow);
        transform: translateY(-2px);
    }

    /* === CARDS & PANELS === */
    .card,
    .glass-card,
    .admin-section,
    .stat-card,
    .dept-card,
    .record-item {
        background: var(--gradient-card);
        backdrop-filter: blur(12px);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-lg);
        padding: 24px;
        box-shadow: var(--shadow-md);
        transition: all 0.3s ease;
    }

    .card:hover,
    .glass-card:hover {
        border-color: var(--border-color);
        box-shadow: var(--shadow-lg), var(--shadow-glow);
        transform: translateY(-2px);
    }

    /* === HEADERS & TITLES === */
    .landing-hero-heading {
        font-size: 48px;
        font-weight: 800;
        line-height: 1.2;
        margin-bottom: 20px;
        background: linear-gradient(135deg, #ffffff 0%, var(--primary-color) 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
    }

    .section-title,
    .modal-header h3 {
        font-size: 20px;
        font-weight: 700;
        color: var(--text-primary);
        margin-bottom: 8px;
    }

    /* === INPUTS & FORMS === */
    input,
    select,
    textarea,
    .form-input-modern,
    .chat-input-field {
        background: rgba(17, 24, 23, 0.6);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-md);
        padding: 12px 16px;
        color: var(--text-primary);
        font-size: 14px;
        transition: all 0.3s ease;
        outline: none;
    }

    input:focus,
    select:focus,
    textarea:focus,
    .form-input-modern:focus,
    .chat-input-field:focus {
        border-color: var(--primary-color);
        box-shadow: 0 0 0 3px rgba(0, 212, 170, 0.1);
        background: rgba(17, 24, 23, 0.8);
    }

    input::placeholder,
    textarea::placeholder {
        color: var(--text-muted);
    }

    /* === MODALS === */
    .modal-content {
        background: var(--gradient-card);
        backdrop-filter: blur(16px);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-xl);
        box-shadow: var(--shadow-lg);
    }

    .modal-header {
        border-bottom: 1px solid var(--border-glass);
        padding-bottom: 20px;
        margin-bottom: 24px;
    }

    /* === STATISTICS CARDS === */
    .stat-card {
        background: linear-gradient(145deg, rgba(17, 24, 23, 0.9) 0%, rgba(10, 14, 13, 0.9) 100%);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-lg);
        padding: 24px;
        position: relative;
        overflow: hidden;
    }

    .stat-card::before {
        content: '';
        position: absolute;
        top: 0;
        left: 0;
        right: 0;
        height: 3px;
        background: var(--gradient-primary);
    }

    .stat-card-value {
        font-size: 32px;
        font-weight: 700;
        background: var(--gradient-primary);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        margin: 8px 0;
    }

    /* === NAVIGATION TABS === */
    .nav-tab,
    .nav-tab-modern {
        background: transparent;
        border: 1px solid transparent;
        border-radius: var(--radius-md);
        padding: 12px 20px;
        color: var(--text-secondary);
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
        display: flex;
        align-items: center;
        gap: 8px;
    }

    .nav-tab:hover,
    .nav-tab-modern:hover {
        background: rgba(0, 212, 170, 0.1);
        color: var(--primary-color);
    }

    .nav-tab.active,
    .nav-tab-modern.active {
        background: var(--gradient-primary);
        color: #0a0e0d;
        box-shadow: var(--shadow-glow);
    }

    /* === BADGES & STATUS === */
    .status-badge,
    .record-badge {
        background: rgba(0, 212, 170, 0.15);
        color: var(--primary-color);
        padding: 4px 12px;
        border-radius: var(--radius-full);
        font-size: 12px;
        font-weight: 600;
        border: 1px solid rgba(0, 212, 170, 0.3);
    }

    .status-badge.present,
    .record-badge.present {
        background: rgba(0, 212, 170, 0.2);
        color: var(--primary-color);
    }

    .status-badge.late,
    .record-badge.late {
        background: rgba(245, 158, 11, 0.2);
        color: var(--accent-warning);
    }

    .status-badge.absent,
    .record-badge.absent {
        background: rgba(239, 68, 68, 0.2);
        color: var(--accent-error);
    }

    /* === CHATBOT STYLES === */
    .ai-panel {
        background: var(--gradient-card);
        backdrop-filter: blur(16px);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-xl);
        box-shadow: var(--shadow-lg), var(--shadow-glow);
    }

    .panel-header {
        background: linear-gradient(135deg, rgba(0, 212, 170, 0.1) 0%, rgba(0, 184, 148, 0.1) 100%);
        border-bottom: 1px solid var(--border-glass);
        padding: 20px;
    }

    .message.assistant {
        background: rgba(17, 24, 23, 0.6);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-lg);
        padding: 16px;
    }

    .message.user {
        background: var(--gradient-primary);
        color: #0a0e0d;
        border-radius: var(--radius-lg);
        padding: 16px;
    }

    /* === ANIMATIONS === */
    @keyframes fadeIn {
        from { opacity: 0; transform: translateY(10px); }
        to { opacity: 1; transform: translateY(0); }
    }

    @keyframes slideUp {
        from { opacity: 0; transform: translateY(20px); }
        to { opacity: 1; transform: translateY(0); }
    }

    @keyframes glow {
        0%, 100% { box-shadow: 0 0 20px rgba(0, 212, 170, 0.3); }
        50% { box-shadow: 0 0 40px rgba(0, 212, 170, 0.6); }
    }

    /* === UTILITIES === */
    .text-gradient {
        background: var(--gradient-primary);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
    }

    .glass-effect {
        background: var(--bg-glass);
        backdrop-filter: blur(12px);
        border: 1px solid var(--border-glass);
    }

    /* === LOGIN MODAL === */
    .login-modal-container {
        background: rgba(10, 14, 13, 0.9);
        backdrop-filter: blur(16px);
    }

    .login-box {
        background: var(--gradient-card);
        border: 1px solid var(--border-glass);
        border-radius: var(--radius-xl);
        box-shadow: var(--shadow-lg), var(--shadow-glow-lg);
    }

    /* === SCROLLBAR === */
    ::-webkit-scrollbar {
        width: 8px;
        height: 8px;
    }

    ::-webkit-scrollbar-track {
        background: var(--bg-secondary);
    }

    ::-webkit-scrollbar-thumb {
        background: var(--primary-color);
        border-radius: var(--radius-full);
    }

    ::-webkit-scrollbar-thumb:hover {
        background: var(--primary-light);
    }

    /* === RESPONSIVE === */
    @media (max-width: 768px) {
        .landing-hero-heading {
            font-size: 32px;
        }
        
        .card,
        .glass-card {
            padding: 16px;
        }
    }
    /* Compact Refresh Button */
    .refresh-btn {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border: none;
    border-radius: 8px;
    width: 36px;
    height: 36px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    color: white;
    font-size: 14px;
    box-shadow: 0 2px 10px rgba(102, 126, 234, 0.3);
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    position: relative;
    overflow: hidden;
    padding: 0;
    }

    .refresh-btn::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.3), transparent);
    transition: left 0.5s;
    }

    .refresh-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 15px rgba(102, 126, 234, 0.5);
    }

    .refresh-btn:hover::before {
    left: 100%;
    }

    .refresh-btn:active {
    transform: translateY(0) scale(0.95);
    }

    .refresh-btn.spinning i {
    animation: spin 1s linear infinite;
    }

    @keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
    }

    /* === BIRTHDAY MODAL STYLES === */
    .birthday-modal {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.8);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 10000;
    animation: fadeIn 0.5s ease;
    }

    .birthday-modal-content {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border-radius: 30px;
    padding: 50px;
    text-align: center;
    max-width: 500px;
    width: 90%;
    position: relative;
    box-shadow: 0 20px 60px rgba(102, 126, 234, 0.5);
    animation: bounceIn 0.8s ease;
    border: 4px solid rgba(255, 255, 255, 0.2);
    }

    .birthday-header {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 20px;
    margin-bottom: 30px;
    }

    .birthday-header h2 {
    color: #fff;
    font-size: 32px;
    font-weight: 700;
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);
    margin: 0;
    }

    .birthday-cake {
    font-size: 50px;
    animation: bounce 1s infinite;
    }

    .birthday-message {
    color: #fff;
    margin-bottom: 30px;
    }

    .birthday-name {
    font-size: 28px;
    font-weight: 700;
    margin-bottom: 15px;
    text-shadow: 2px 2px 4px rgba(0, 0, 0, 0.3);
    }

    .birthday-wish {
    font-size: 16px;
    line-height: 1.6;
    opacity: 0.95;
    margin-bottom: 15px;
    }

    .birthday-age {
    font-size: 18px;
    font-weight: 600;
    background: rgba(255, 255, 255, 0.2);
    padding: 10px 20px;
    border-radius: 20px;
    display: inline-block;
    }

    .birthday-decorations {
    display: flex;
    justify-content: center;
    gap: 15px;
    margin-bottom: 30px;
    font-size: 40px;
    }

    .balloon {
    display: inline-block;
    animation: float 3s ease-in-out infinite;
    }

    .balloon:nth-child(1) { animation-delay: 0s; }
    .balloon:nth-child(2) { animation-delay: 0.2s; }
    .balloon:nth-child(3) { animation-delay: 0.4s; }
    .balloon:nth-child(4) { animation-delay: 0.6s; }
    .balloon:nth-child(5) { animation-delay: 0.8s; }

    .birthday-btn {
    background: #fff;
    color: #667eea;
    border: none;
    padding: 15px 40px;
    font-size: 18px;
    font-weight: 600;
    border-radius: 50px;
    cursor: pointer;
    transition: all 0.3s ease;
    box-shadow: 0 5px 20px rgba(0, 0, 0, 0.2);
    }

    .birthday-btn:hover {
    transform: scale(1.1);
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.3);
    }

    .birthday-confetti {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    pointer-events: none;
    overflow: hidden;
    border-radius: 30px;
    }

    @keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
    }

    @keyframes bounceIn {
    0% { transform: scale(0.3); opacity: 0; }
    50% { transform: scale(1.05); }
    70% { transform: scale(0.9); }
    100% { transform: scale(1); opacity: 1; }
    }

    @keyframes bounce {
    0%, 100% { transform: translateY(0); }
    50% { transform: translateY(-10px); }
    }

    @keyframes float {
    0%, 100% { transform: translateY(0) rotate(0deg); }
    50% { transform: translateY(-15px) rotate(10deg); }
    }

    @keyframes confettiFall {
    0% { transform: translateY(-100vh) rotate(0deg); opacity: 1; }
    100% { transform: translateY(100vh) rotate(720deg); opacity: 0; }
    }

    .confetti-piece {
    position: absolute;
    width: 10px;
    height: 10px;
    top: -10px;
    animation: confettiFall 3s linear forwards;
    }

    @media (max-width: 600px) {
    .birthday-modal-content {
    padding: 30px 20px;
    width: 95%;
    }
    .birthday-header h2 {
    font-size: 24px;
    }
    .birthday-name {
    font-size: 22px;
    }
    .birthday-cake {
    font-size: 35px;
    }
    }

    /* Responsive */
    @media (max-width: 768px) {
    .refresh-btn {
    width: 32px;
    height: 32px;
    font-size: 12px;
    }
    }

    /* Compact Filter Controls */
    .filter-select {
    padding: 8px 12px !important;
    font-size: 13px !important;
    border-radius: 8px !important;
    border: 1px solid rgba(25, 211, 197, 0.3) !important;
    background: #1a1a2e !important;
    color: #ffffff !important;
    cursor: pointer;
    transition: all 0.3s ease;
    }

    .filter-select:hover {
    border-color: rgba(25, 211, 197, 0.6) !important;
    background: #242840 !important;
    }

    .filter-select:focus {
    outline: none;
    border-color: #19D3C5 !important;
    box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.2) !important;
    background: #242840 !important;
    }

    .search-input {
    padding: 8px 12px !important;
    font-size: 13px !important;
    border-radius: 8px !important;
    border: 1px solid var(--border-color) !important;
    background: rgba(255,255,255,0.05) !important;
    color: var(--text-primary) !important;
    transition: all 0.3s ease;
    }

    .search-input:focus {
    outline: none;
    border-color: var(--primary-accent) !important;
    box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1) !important;
    background: rgba(255,255,255,0.08) !important;
    }

    .search-input::placeholder {
    color: var(--text-muted);
    opacity: 0.7;
    }

    .action-button.secondary {
    padding: 8px 12px !important;
    font-size: 13px !important;
    border-radius: 8px !important;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    transition: all 0.3s ease;
    }

    .action-button.secondary:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(25, 211, 197, 0.2);
    }

    /* Responsive adjustments */
    @media (max-width: 768px) {
    .section-header > div:last-child {
    flex-direction: column;
    width: 100%;
    gap: 8px;
    }
    .filter-select, .search-input {
    width: 100% !important;
    }
    }

    /* Live Timer Animation */
    .live-timer {
    font-family: 'Courier New', monospace;
    animation: pulse 2s infinite;
    }

    @keyframes pulse {
    0%, 100% {
    opacity: 1;
    transform: scale(1);
    }
    50% {
    opacity: 0.5;
    transform: scale(1.2);
    }
    }

    /* === MODERN SCHEDULE CALENDAR STYLES === */
    /* === REDESIGNED CALENDAR HEADER === */
    .calendar-nav-container {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 20px 30px;
    /* Enhanced Gradient Background */
    background: linear-gradient(135deg, #19D3C5 0%, #00b8a8 100%);
    border-radius: 16px 16px 0 0;
    box-shadow: 0 4px 20px rgba(25, 211, 197, 0.25);
    margin-bottom: 0;
    border-bottom: 1px solid rgba(255,255,255,0.2);
    position: relative;
    overflow: hidden;
    }

    /* Subtle shine effect */
    .calendar-nav-container::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background: linear-gradient(90deg, transparent, rgba(255,255,255,0.1), transparent);
    pointer-events: none;
    }

    .calendar-header-info {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    z-index: 2;
    }

    .calendar-month-year {
    font-family: 'Montserrat', sans-serif; /* Premium Font */
    font-size: 32px;
    font-weight: 800; /* Extra Bold */
    color: #ffffff;
    letter-spacing: 2px;
    text-transform: uppercase;
    margin: 0;
    text-shadow: 0 2px 10px rgba(0,0,0,0.15);
    line-height: 1.2;
    }

    .calendar-subtitle {
    font-family: 'Poppins', sans-serif;
    font-size: 11px;
    font-weight: 500;
    color: rgba(255, 255, 255, 0.9);
    margin-top: 6px;
    text-transform: uppercase;
    letter-spacing: 3px; /* Wide tracking for elegance */
    background: rgba(0,0,0,0.1);
    padding: 4px 12px;
    border-radius: 20px;
    backdrop-filter: blur(5px);
    }

    /* Navigation Buttons */
    .calendar-nav-btn {
    background: rgba(255, 255, 255, 0.2);
    border: 1px solid rgba(255, 255, 255, 0.3);
    color: #fff;
    width: 42px;
    height: 42px;
    border-radius: 12px;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    backdrop-filter: blur(5px);
    z-index: 2;
    }

    .calendar-nav-btn:hover {
    background: #fff;
    color: #19D3C5;
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(0,0,0,0.2);
    }

    /* Refresh Button Specifics */
    .calendar-nav-btn.refresh-btn {
    width: auto;
    padding: 0 16px;
    gap: 8px;
    font-family: 'Poppins', sans-serif;
    font-weight: 600;
    font-size: 13px;
    background: rgba(255,255,255,0.25);
    }

    .calendar-nav-btn.refresh-btn:hover {
    background: #fff;
    color: #19D3C5;
    }

    /* Responsive */
    @media (max-width: 768px) {
    .calendar-month-year { font-size: 24px; }
    .calendar-subtitle { font-size: 9px; letter-spacing: 1px; }
    .calendar-nav-container { padding: 15px 20px; }
    }

    /* Grid Layout */
    /* === MODERN SCHEDULE CALENDAR STYLES === */
    .schedule-calendar-grid {
    display: grid;
    /* Grid is handled by JS inline styles now for flexibility */
    gap: 15px;
    margin: 20px 0;
    width: 100%;
    }

    .schedule-day-card {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.05);
    border-radius: 16px;
    padding: 15px;
    min-height: 140px;
    display: flex;
    flex-direction: column;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
    backdrop-filter: blur(5px);
    }

    .schedule-day-card:hover {
    background: rgba(255, 255, 255, 0.06);
    border-color: rgba(25, 211, 197, 0.3);
    transform: translateY(-5px);
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
    }

    /* Today Highlight */
    .schedule-day-card.is-today {
    background: linear-gradient(135deg, rgba(25, 211, 197, 0.15), rgba(0, 224, 208, 0.05));
    border: 1px solid var(--primary-accent);
    box-shadow: 0 0 20px rgba(25, 211, 197, 0.2);
    }

    .schedule-day-card.is-today .day-number {
    color: var(--primary-accent);
    text-shadow: 0 0 10px rgba(25, 211, 197, 0.5);
    }

    /* Day Number */
    .day-number {
    font-size: 20px;
    font-weight: 800;
    color: var(--text-primary);
    margin-bottom: 8px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    }

    .today-badge {
    font-size: 10px;
    background: var(--primary-accent);
    color: #00110f;
    padding: 2px 6px;
    border-radius: 4px;
    font-weight: 700;
    text-transform: uppercase;
    }

    /* Shift Info */
    .shift-info {
    flex: 1;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    text-align: center;
    gap: 6px;
    }

    .shift-icon {
    font-size: 24px;
    margin-bottom: 5px;
    filter: drop-shadow(0 0 5px currentColor);
    }

    .shift-name {
    font-size: 13px;
    font-weight: 700;
    color: var(--text-primary);
    line-height: 1.2;
    }

    .shift-time {
    font-size: 11px;
    color: var(--text-muted);
    font-family: 'Courier New', monospace;
    background: rgba(0, 0, 0, 0.3);
    padding: 4px 8px;
    border-radius: 6px;
    border: 1px solid rgba(255, 255, 255, 0.05);
    }

    /* Status Colors */
    .status-working { color: #00ff88; }
    .status-off { color: #6c757d; opacity: 0.6; }
    .status-leave { color: #ffc107; }
    .status-holiday { color: #ff4757; }

    /* Responsive */
    @media (max-width: 1024px) {
    .schedule-calendar-grid {
    grid-template-columns: repeat(4, 1fr);
    }
    }

    @media (max-width: 768px) {
    .schedule-calendar-grid {
    grid-template-columns: repeat(2, 1fr);
    }
    .calendar-month-year {
    font-size: 24px;
    }
    }

    /* Department Card Styles */
    .dept-card {
    background: var(--panel-bg);
    border: 1px solid var(--border-color);
    border-radius: 12px;
    padding: 20px;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
    }

    .dept-card:hover {
    border-color: var(--primary-accent);
    transform: translateY(-3px);
    box-shadow: 0 8px 25px rgba(0,0,0,0.3);
    }

    .dept-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    margin-bottom: 20px;
    padding-bottom: 15px;
    border-bottom: 1px solid rgba(255,255,255,0.05);
    }

    .dept-icon {
    width: 40px;
    height: 40px;
    background: rgba(25, 211, 197, 0.1);
    color: var(--primary-accent);
    border-radius: 10px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    }

    .dept-name {
    flex: 1;
    min-width: 0; /* Important for text truncation */
    display: flex;
    align-items: center;
    gap: 12px;
    overflow: hidden;
    }

    /* Fix department name text */
    .dept-name > div:last-child,
    .dept-name .department-name {
    font-size: 16px;
    font-weight: 700;
    color: var(--text-primary);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
    min-width: 0;
    align-items: center; /* <--- ADD THIS LINE */
    }

    .dept-name-wrap {
    word-break: break-word;
    line-height: 1.3;
    max-width: calc(100% - 60px); /* Leave space for icon and buttons */
    }

    .dept-stats {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 15px;
    margin-bottom: 20px;
    }

    .dept-stat-item {
    text-align: center;
    background: rgba(255,255,255,0.02);
    padding: 10px;
    border-radius: 8px;
    }

    .dept-stat-value {
    font-size: 20px;
    font-weight: 700;
    color: var(--text-primary);
    display: block;
    }

    .dept-stat-label {
    font-size: 11px;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    }

    .dept-attendance-rate {
    font-size: 12px;
    font-weight: 600;
    color: var(--text-secondary);
    }

    .dept-progress {
    height: 6px;
    background: rgba(255,255,255,0.05);
    border-radius: 3px;
    overflow: hidden;
    margin-top: 10px;
    }

    .dept-progress-bar {
    height: 100%;
    background: var(--gradient-primary);
    border-radius: 3px;
    transition: width 1s ease-in-out;
    }

    /* Calendar Navigation Styles */
    .calendar-nav-container {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px 25px;
    background: linear-gradient(135deg, var(--primary-accent), var(--secondary-accent));
    border-radius: 16px 16px 0 0;
    box-shadow: 0 8px 30px rgba(25,211,197,0.3);
    }

    .calendar-nav-btn {
    background: rgba(255,255,255,0.2);
    border: none;
    color: #00110f;
    width: 40px;
    height: 40px;
    border-radius: 50%;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    transition: all 0.3s ease;
    font-weight: bold;
    }

    .calendar-nav-btn:hover {
    background: rgba(255,255,255,0.3);
    transform: scale(1.1);
    }

    .calendar-nav-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
    }

    .calendar-month-year {
    font-size: 28px;
    font-weight: 800;
    color: #00110f;
    letter-spacing: 2px;
    text-align: center;
    flex: 1;
    }

    .calendar-subtitle {
    font-size: 13px;
    opacity: 0.9;
    text-align: center;
    margin-top: 4px;
    }

    .calendar-header-info {
    display: flex;
    flex-direction: column;
    align-items: center;
    flex: 1;
    }

    /* Status Colors */
    .schedule-day-card.working { border-bottom: 4px solid #28a745; }
    .schedule-day-card.off { border-bottom: 4px solid #6c757d; opacity: 0.7; }
    .schedule-day-card.leave { border-bottom: 4px solid #ffc107; background: rgba(255, 193, 7, 0.05); }
    .schedule-day-card.today {
    border: 2px solid var(--primary-accent);
    box-shadow: 0 0 15px rgba(25, 211, 197, 0.2);
    }

    .schedule-day-label {
    font-size: 12px;
    text-transform: uppercase;
    color: var(--text-muted);
    font-weight: 700;
    letter-spacing: 1px;
    margin-bottom: 10px;
    }

    .schedule-day-type {
    font-size: 16px;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 5px;
    }

    .schedule-day-time {
    font-size: 12px;
    color: var(--text-secondary);
    font-family: 'Courier New', monospace;
    margin-bottom: 10px;
    }

    .schedule-status-badge.working { background: rgba(40, 167, 69, 0.15); color: #28a745; }
    .schedule-status-badge.off { background: rgba(108, 117, 125, 0.15); color: #6c757d; }
    .schedule-status-badge.leave { background: rgba(255, 193, 7, 0.15); color: #ffc107; }

    /* === RESPONSIVE CALENDAR FIXES === */

    /* Override inline grid styles for day headers and calendar grid */
    #scheduleCalendarGrid > div[style*="display: grid"] {
        grid-template-columns: repeat(7, 1fr) !important;
        overflow-x: auto !important;
        width: 100% !important;
    }

    /* Tablet Responsive (1024px and below) */
    @media (max-width: 1024px) {
        .schedule-calendar-grid {
            gap: 12px !important;
        }

        #scheduleCalendarGrid > div[style*="display: grid"] {
            grid-template-columns: repeat(7, 1fr) !important;
        }

        .schedule-day-card {
            min-height: 130px;
            padding: 12px;
            font-size: 14px;
        }

        .day-number {
            font-size: 18px !important;
        }

        .shift-icon {
            font-size: 20px !important;
        }

        .shift-name {
            font-size: 12px !important;
        }

        .shift-time {
            font-size: 10px !important;
            padding: 3px 6px !important;
        }

        .calendar-month-year {
            font-size: 24px !important;
        }

        .calendar-nav-btn {
            width: 36px !important;
            height: 36px !important;
            font-size: 16px !important;
        }

        .calendar-subtitle {
            font-size: 11px !important;
        }
    }

    /* Mobile Responsive (768px and below) */
    @media (max-width: 768px) {
        .schedule-calendar-grid {
            gap: 10px !important;
            margin: 10px 0 !important;
            width: 100% !important;
            overflow-x: hidden !important;
        }

        /* Force all inline grids to 4 columns on tablets */
        #scheduleCalendarGrid > div[style*="display: grid"],
        .schedule-calendar-grid > div[style*="grid-template-columns"] {
            grid-template-columns: repeat(4, 1fr) !important;
            gap: 10px !important;
            margin-bottom: 10px !important;
        }

        /* Hide day labels if needed, keep day numbers visible */
        #scheduleCalendarGrid > div:first-child {
            display: none !important;
        }

        .schedule-day-card {
            min-height: 110px !important;
            padding: 10px !important;
            border-radius: 12px !important;
        }

        .day-number {
            font-size: 16px !important;
            margin-bottom: 6px !important;
        }

        .today-badge {
            font-size: 9px !important;
            padding: 1px 4px !important;
        }

        .shift-info {
            gap: 4px !important;
        }

        .shift-icon {
            font-size: 18px !important;
            margin-bottom: 3px !important;
        }

        .shift-name {
            font-size: 11px !important;
            line-height: 1.1 !important;
        }

        .shift-time {
            font-size: 9px !important;
            padding: 2px 5px !important;
        }

        .schedule-day-label {
            font-size: 10px !important;
        }

        .calendar-month-year {
            font-size: 20px !important;
            letter-spacing: 1px !important;
        }

        .calendar-nav-btn {
            width: 32px !important;
            height: 32px !important;
            font-size: 14px !important;
        }

        .calendar-nav-container {
            padding: 10px 15px !important;
            gap: 8px !important;
            flex-wrap: wrap !important;
        }

        .calendar-subtitle {
            font-size: 10px !important;
            margin-top: 2px !important;
        }

        .calendar-header-info {
            flex: 1 !important;
        }
    }

    /* Small Mobile (480px and below) */
    @media (max-width: 480px) {
        .schedule-calendar-grid {
            gap: 8px !important;
            margin: 8px 0 !important;
        }

        /* Force 4-column grid on small mobile */
        #scheduleCalendarGrid > div[style*="display: grid"],
        .schedule-calendar-grid > div[style*="grid-template-columns"] {
            grid-template-columns: repeat(4, 1fr) !important;
            gap: 8px !important;
            margin-bottom: 8px !important;
        }

        .schedule-day-card {
            min-height: 100px !important;
            padding: 8px !important;
            border-radius: 10px !important;
        }

        .day-number {
            font-size: 14px !important;
            margin-bottom: 4px !important;
        }

        .today-badge {
            font-size: 8px !important;
            padding: 1px 3px !important;
        }

        .shift-icon {
            font-size: 16px !important;
            margin-bottom: 2px !important;
        }

        .shift-name {
            font-size: 10px !important;
        }

        .shift-time {
            font-size: 8px !important;
            padding: 2px 4px !important;
        }

        .calendar-month-year {
            font-size: 18px !important;
            letter-spacing: 0.5px !important;
        }

        .calendar-nav-btn {
            width: 28px !important;
            height: 28px !important;
            font-size: 12px !important;
        }

        .calendar-nav-container {
            padding: 8px 10px !important;
            gap: 6px !important;
        }

        .calendar-subtitle {
            font-size: 9px !important;
        }

        .calendar-header-info {
            flex: 1 !important;
        }
    }

    /* Extra Small Mobile (360px and below) */
    @media (max-width: 360px) {
        .schedule-calendar-grid {
            gap: 6px !important;
            margin: 6px 0 !important;
        }

        /* Super tight fit on extra small screens */
        #scheduleCalendarGrid > div[style*="display: grid"],
        .schedule-calendar-grid > div[style*="grid-template-columns"] {
            grid-template-columns: repeat(4, 1fr) !important;
            gap: 6px !important;
            margin-bottom: 6px !important;
        }

        .schedule-day-card {
            min-height: 90px !important;
            padding: 6px !important;
        }

        .day-number {
            font-size: 12px !important;
            margin-bottom: 3px !important;
        }

        .shift-icon {
            font-size: 14px !important;
            margin-bottom: 1px !important;
        }

        .shift-name {
            font-size: 9px !important;
        }

        .shift-time {
            font-size: 7px !important;
            padding: 1px 3px !important;
        }

        .calendar-month-year {
            font-size: 16px !important;
        }

        .calendar-nav-btn {
            width: 24px !important;
            height: 24px !important;
            font-size: 10px !important;
        }

        .calendar-nav-container {
            padding: 6px 8px !important;
        }
    }

    /* Mobile Responsive */
    @media (max-width: 900px) {
    .schedule-calendar-grid { grid-template-columns: repeat(4, 1fr) !important; }
    }

    @media (max-width: 600px) {
    .schedule-calendar-grid { grid-template-columns: repeat(2, 1fr) !important; }
    .schedule-day-card { min-height: 120px; }
    }

    /* === COOL SCAN MODAL STYLES === */
    .scan-modal-overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0, 0, 0, 0.85); backdrop-filter: blur(10px);
    z-index: 9999; display: none; justify-content: center; align-items: center;
    opacity: 0; transition: opacity 0.3s ease;
    }

    .scan-modal-overlay.active { display: flex; opacity: 1; }

    .scan-modal-card {
    background: linear-gradient(145deg, rgba(6, 26, 31, 0.98), rgba(0, 0, 0, 0.98));
    border: 2px solid var(--primary-accent);
    width: 90%; max-width: 550px; border-radius: 24px; padding: 40px;
    text-align: center; box-shadow: 0 0 50px rgba(25, 211, 197, 0.3);
    transform: scale(0.9); transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
    position: relative; overflow: hidden;
    }

    .scan-modal-overlay.active .scan-modal-card { transform: scale(1); }

    .scan-modal-icon {
    width: 100px; height: 100px; margin: 0 auto 25px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center; font-size: 45px;
    background: rgba(25, 211, 197, 0.1); color: var(--primary-accent);
    border: 2px solid var(--primary-accent);
    box-shadow: 0 0 40px rgba(25, 211, 197, 0.3);
    }

    .scan-modal-title { font-size: 28px; font-weight: 800; color: #fff; margin-bottom: 5px; }
    .scan-modal-subtitle { font-size: 16px; color: var(--text-muted); margin-bottom: 30px; }

    .scan-modal-profile {
    background: rgba(255, 255, 255, 0.03); border: 1px solid var(--border-color);
    border-radius: 16px; padding: 20px; display: flex; align-items: center; gap: 20px;
    margin-bottom: 25px; text-align: left;
    }

    .scan-modal-pic {
    width: 100px; height: 100px; border-radius: 50%; object-fit: cover;
    border: 3px solid var(--primary-accent); box-shadow: 0 0 20px rgba(25, 211, 197, 0.3);
    }

    .scan-modal-details h3 { color: #fff; font-size: 24px; margin-bottom: 5px; }
    .scan-modal-details p { color: var(--text-muted); font-size: 14px; margin-bottom: 2px; }

    .scan-modal-time {
    font-family: 'Courier New', monospace; font-size: 48px; font-weight: 700;
    color: var(--primary-accent); text-shadow: 0 0 20px rgba(25, 211, 197, 0.3);
    letter-spacing: 4px;
    }

    /* === LEAVE MANAGEMENT SECTION STYLES === */
    
    /* Modern Header Section */
    .leave-management-header {
        background: linear-gradient(135deg, rgba(25, 211, 197, 0.08) 0%, rgba(0, 224, 208, 0.04) 100%);
        border: 1px solid rgba(25, 211, 197, 0.15);
        border-radius: 16px;
        padding: 32px;
        margin-bottom: 32px;
        backdrop-filter: blur(10px);
    }

    .header-top {
        margin-bottom: 24px;
    }

    .header-content {
        display: flex;
        align-items: center;
        gap: 16px;
    }

    .header-title {
        margin: 0;
        font-size: 32px;
        font-weight: 800;
        background: linear-gradient(135deg, #19D3C5 0%, #00E0D0 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        display: flex;
        align-items: center;
        gap: 12px;
    }

    .header-subtitle {
        margin: 8px 0 0 0;
        font-size: 14px;
        color: #94a3b8;
        font-weight: 400;
    }

    /* Search & Filter Bar */
    .leave-controls {
        display: flex;
        align-items: center;
        gap: 12px;
        background: rgba(0, 0, 0, 0.2);
        padding: 14px 16px;
        border-radius: 12px;
        border: 1px solid rgba(25, 211, 197, 0.1);
        flex-wrap: wrap;
    }

    .search-wrapper {
        flex: 1;
        min-width: 250px;
        display: flex;
        align-items: center;
        gap: 8px;
        background: rgba(255, 255, 255, 0.05);
        padding: 10px 14px;
        border-radius: 8px;
        border: 1px solid rgba(25, 211, 197, 0.2);
    }

    .search-wrapper i {
        color: #94a3b8;
        font-size: 14px;
    }

    .search-wrapper .search-input {
        background: transparent;
        border: none;
        color: #e2e8f0;
        font-size: 14px;
        width: 100%;
        outline: none;
    }

    .search-wrapper .search-input::placeholder {
        color: #64748b;
    }

    .status-filter {
        padding: 10px 14px;
        background: #1a1a2e;
        border: 1px solid rgba(25, 211, 197, 0.3);
        border-radius: 8px;
        color: #ffffff;
        font-size: 13px;
        cursor: pointer;
        transition: all 0.3s ease;
    }

    .status-filter:hover {
        border-color: rgba(25, 211, 197, 0.6);
        background: #242840;
    }

    .status-filter:focus {
        outline: none;
        border-color: #19D3C5;
        background: #242840;
        box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.2);
    }

    .btn-icon-refresh, .btn-icon-history {
        width: 40px;
        height: 40px;
        padding: 0;
        border: 1px solid rgba(25, 211, 197, 0.2);
        background: rgba(25, 211, 197, 0.08);
        color: #19D3C5;
        border-radius: 8px;
        cursor: pointer;
        transition: all 0.3s ease;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 16px;
    }

    .btn-icon-refresh:hover, .btn-icon-history:hover {
        background: rgba(25, 211, 197, 0.15);
        border-color: rgba(25, 211, 197, 0.4);
        transform: scale(1.05);
    }

    /* Stats Grid */
    .leave-stats-grid {
        display: grid;
        grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
        gap: 20px;
        margin-bottom: 32px;
    }

    .leave-stat-card {
        padding: 24px;
        border-radius: 14px;
        display: flex;
        gap: 16px;
        align-items: center;
        border: 1px solid;
        background: linear-gradient(135deg, rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.05));
        backdrop-filter: blur(5px);
        transition: all 0.3s ease;
        cursor: default;
    }

    .leave-stat-card:hover {
        transform: translateY(-4px);
    }

    .leave-stat-card.pending-card {
        border-color: rgba(255, 193, 7, 0.3);
    }

    .leave-stat-card.pending-card .stat-icon {
        background: rgba(255, 193, 7, 0.15);
        color: #ffc107;
    }

    .leave-stat-card.approved-card {
        border-color: rgba(34, 197, 94, 0.3);
    }

    .leave-stat-card.approved-card .stat-icon {
        background: rgba(34, 197, 94, 0.15);
        color: #22c55e;
    }

    .leave-stat-card.rejected-card {
        border-color: rgba(239, 68, 68, 0.3);
    }

    .leave-stat-card.rejected-card .stat-icon {
        background: rgba(239, 68, 68, 0.15);
        color: #ef4444;
    }

    .stat-icon {
        width: 56px;
        height: 56px;
        border-radius: 12px;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 28px;
        flex-shrink: 0;
    }

    .stat-info {
        flex: 1;
    }

    .stat-value {
        font-size: 32px;
        font-weight: 800;
        color: #e2e8f0;
        margin-bottom: 4px;
    }

    .stat-label {
        font-size: 14px;
        font-weight: 700;
        color: #94a3b8;
        margin-bottom: 2px;
    }

    .stat-subtext {
        font-size: 12px;
        color: #64748b;
        font-style: italic;
    }

    /* Leave Requests Container */
    .leave-requests-container {
        display: flex;
        flex-direction: column;
        gap: 16px;
    }

    .leave-empty-state {
        text-align: center;
        padding: 60px 40px;
        background: linear-gradient(135deg, rgba(0, 0, 0, 0.1), rgba(0, 0, 0, 0.05));
        border: 1px dashed rgba(25, 211, 197, 0.2);
        border-radius: 12px;
        color: #94a3b8;
    }

    .leave-empty-state i {
        font-size: 56px;
        margin-bottom: 16px;
        opacity: 0.4;
        color: #64748b;
    }

    .leave-empty-state h3 {
        margin: 0 0 8px 0;
        font-size: 18px;
        color: #e2e8f0;
    }

    .leave-empty-state p {
        margin: 0;
        font-size: 14px;
    }
/* === FIXED LEAVE CARD LAYOUT === */
.leave-card {
    background: linear-gradient(135deg, rgba(0, 0, 0, 0.2), rgba(0, 0, 0, 0.1));
    border: 1px solid rgba(25, 211, 197, 0.15);
    border-radius: 14px;
    padding: 20px;
    /* CHANGE: Use Flexbox instead of Grid for better flow */
    display: flex;
    flex-wrap: wrap; /* Allows wrapping on smaller screens */
    align-items: center; /* Vertically center items */
    gap: 20px;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    backdrop-filter: blur(10px);
}

.leave-card:hover {
    border-color: rgba(25, 211, 197, 0.4);
    box-shadow: 0 8px 32px rgba(25, 211, 197, 0.12);
    transform: translateY(-2px);
    background: linear-gradient(135deg, rgba(25, 211, 197, 0.05), rgba(0, 0, 0, 0.1));
}

/* Left Section: Employee Info (Takes available space) */
.leave-card-left {
    display: flex;
    gap: 16px;
    align-items: flex-start;
    flex: 1 1 300px; /* Grows, shrinks, base width 300px */
    min-width: 250px;
}

/* === FIXED ATTACHMENT SECTION STYLES === */
.leave-card-attachment {
    flex: 0 0 auto;
    width: 180px; /* Fixed width for consistency */
    display: flex;
    flex-direction: column;
    gap: 10px;
    background: rgba(0, 0, 0, 0.2); /* Darker background to pop against card */
    padding: 12px;
    border-radius: 12px;
    border: 1px solid rgba(255, 255, 255, 0.08);
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.leave-card-attachment:hover {
    border-color: rgba(25, 211, 197, 0.3);
    background: rgba(0, 0, 0, 0.3);
}

.leave-card-attachment img {
    width: 100%;
    height: 120px;
    object-fit: cover;
    border-radius: 8px;
    border: 1px solid rgba(255, 255, 255, 0.1);
    cursor: pointer;
    transition: transform 0.2s;
}

.leave-card-attachment img:hover {
    transform: scale(1.05);
}

/* New Class for Compact Action Buttons */
.attachment-actions {
    display: flex;
    gap: 6px;
    width: 100%;
    justify-content: center;
}

.attachment-btn {
    flex: 1;
    padding: 6px 4px;
    font-size: 10px;
    background: rgba(255, 255, 255, 0.05);
    border: 1px solid rgba(255, 255, 255, 0.1);
    color: var(--text-muted);
    border-radius: 6px;
    cursor: pointer;
    text-decoration: none;
    text-align: center;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 4px;
    transition: all 0.2s;
    white-space: nowrap;
    overflow: hidden;
}

.attachment-btn:hover {
    background: rgba(25, 211, 197, 0.15);
    border-color: rgba(25, 211, 197, 0.3);
    color: var(--primary-accent);
}

/* PDF Box Styling */
.attachment-pdf-box {
    width: 100%;
    background: rgba(239, 68, 68, 0.1);
    border: 1px solid rgba(239, 68, 68, 0.3);
    border-radius: 8px;
    padding: 15px 10px;
    text-align: center;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
}
/* Responsive Fix for Mobile */
@media (max-width: 1024px) {
    .leave-card {
        flex-direction: column;
        align-items: stretch;
    }
    .leave-card-left, .leave-card-middle, .leave-card-actions, .leave-card-attachment {
        width: 100%;
        min-width: unset;
    }
    .leave-card-attachment {
        max-width: 100%;
        flex-direction: row;
        overflow-x: auto;
    }
    .leave-card-attachment img {
        height: 100px;
        width: 100px;
        flex-shrink: 0;
    }
    .leave-card-actions {
        justify-content: flex-end;
    }
}

    /* Card Status Classes */
