        border-left: 4px solid #ffc107;
    }

    .leave-card.status-approved {
        border-left: 4px solid #22c55e;
    }

    .leave-card.status-rejected {
        border-left: 4px solid #ef4444;
    }

    .leave-card-left {
        display: flex;
        gap: 16px;
