    }

    .user-name, .admin-user-name {
    font-weight: 600;
    color: var(--text-primary);
    }

    .user-role, .admin-user-role {
    font-size: 12px;
    color: var(--text-muted);
    }

    .logout-btn {
    padding: 8px 16px;
    border: none; /* ✅ REMOVED BORDER */
    border-radius: 10px;
    font-size: 12px;
    font-weight: 600;
    cursor: pointer;
    background: transparent;
    color: var(--primary-accent);
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    display: inline-flex;
    align-items: center;
    gap: 6px;
    text-decoration: none !important;
    }

    .logout-btn:hover {
    background: var(--primary-accent);
    color: #00110f;
    transform: translateY(-2px);
    text-decoration: none !important;
    }

    /* ✅ GLOBAL FIX FOR ALL LOGOUT LINKS */
    a.logout-btn, .logout-btn, button.logout-btn {
    text-decoration: none !important;
    }

    a.logout-btn:hover, .logout-btn:hover, button.logout-btn:hover {
    text-decoration: none !important;
    }

    /* === GLOBAL STYLES === */
    * {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
    }

    a {
    color: var(--primary-accent);
    text-decoration: none;
    }

    /* ✅ REMOVE ALL OUTLINES FROM LOGOUT BUTTONS */
    a.logout-btn:focus,
    .logout-btn:focus,
    button.logout-btn:focus {
    outline: none !important;
    border: none !important;
    box-shadow: none !important;
    }

    /* ✅ GLOBAL FIX - Remove ALL outlines */
    a.logout-btn,
    .logout-btn,
    button.logout-btn,
    a[href*="logout"] {
    border: none !important;
    outline: none !important;
    text-decoration: none !important;
    }

    a.logout-btn:hover,
    .logout-btn:hover,
    button.logout-btn:hover,
    a[href*="logout"]:hover {
    border: none !important;
    outline: none !important;
    text-decoration: none !important;
    }

