    border: 1px solid var(--border-color);
    border-radius: 12px;
    background: var(--panel-bg);
    }

    .requests-header, .quick-info-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
    }

    .requests-title, .quick-info-title {
    font-size: 18px;
    font-weight: 600;
    color: var(--text-primary);
    }

    .quick-info-icon {
