    border-radius: 4px;
    background: var(--primary-accent);
    color: var(--text-primary);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    margin-right: 10px;
    }

    .requests-subtitle, .quick-info-content {
    font-size: 14px;
    color: var(--text-primary);
    line-height: 1.5;
    }

    .quick-info-content {
    text-align: center;
    }

    /* === SMOOTH REFRESH TRANSITIONS === */
    .smooth-content {
    transition: opacity 0.3s ease-in-out, transform 0.3s ease;
    }

    .is-refreshing {
    opacity: 0.6;
    pointer-events: none;
    }

    .request-item {
    background: var(--panel-bg);
    padding: 15px;
    border-radius: 8px;
    margin-bottom: 15px;
    border: 1px solid var(--border-color);
    }

    .request-date {
    font-size: 16px;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 5px;
    }

    .request-duration, .request-status {
    font-size: 12px;
    color: var(--text-muted);
    margin-bottom: 10px;
    }

    .request-reason {
    font-size: 14px;
    color: var(--text-primary);
    margin-bottom: 5px;
    }

    .request-badge {
    padding: 4px 8px;
    border-radius: 4px;
    font-size: 12px;
    font-weight: 600;
    background: rgba(255,179,25,0.12);
    color: #FFD580;
    display: inline-block;
    }

    .form-row {
    margin-bottom: 15px;
    text-align: left;
    }

    .form-label {
    display: block;
    margin-bottom: 5px;
    color: var(--text-secondary);
    font-weight: 500;
    font-size: 14px;
    }

    .form-select, .form-textarea {
    width: 100%;
    padding: 12px;
    border: 1px solid var(--border-color);
    border-radius: 8px;
    font-size: 14px;
    }

    .form-textarea {
    min-height: 80px;
    resize: vertical;
    }

    .form-select:focus, .form-textarea:focus {
    outline: none;
    border-color: var(--primary-accent);
    box-shadow: 0 0 0 2px rgba(25,211,197,0.08);
    }

    .admin-nav {
    display: flex;
    background: var(--panel-bg);
    border-radius: 16px;
    box-shadow: var(--shadow-sm);
    padding: 12px 20px; /* Slightly reduced horizontal padding */
    margin-bottom: 24px;
    overflow: visible !important;
    gap: 16px; /* Increased gap for better spacing */
    justify-content: space-between; /* Distribute evenly across full width */
    border: 1px solid var(--border-color);
    }

    /* Make the menu button match the size of other nav tabs */
    .admin-nav .filter-group {
        flex: 1;
        display: flex;
        justify-content: flex-end;
    }

    .admin-nav .admin-menu-toggle.nav-tab {
        flex: 1;
    }

    
    .nav-tab {
    padding: 14px 0;
    border-radius: 10px;
    font-weight: 700;
    font-size: 15px;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    white-space: nowrap;
    min-width: 0;
    flex: 1;
    margin: 0;
    max-width: none;
    border: 1px solid transparent;
}

    .nav-tab:hover {
    background: rgba(255,255,255,0.05);
    border-color: rgba(25, 211, 197, 0.3);
    transform: translateY(-1px);
    }

    .nav-tab.active {
    background: var(--primary-accent);
    color: #eeeeee;
    box-shadow: 0 4px 12px rgba(25, 211, 197, 0.3);
    border-color: var(--primary-accent);
    }

    /* Icon sizing */
    .nav-tab i {
    font-size: 16px;
    }

    .dashboard-stat-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
    }

    .stat-card {
    padding: 20px;
    border-radius: 16px;
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    min-height: 140px;
    box-shadow: 0 4px 15px rgba(0,0,0,0.05);
    transition: transform 0.2s;
    }

    .stat-card:hover {
    transform: translateY(-3px);
    }

    .stat-card.present {
    background: #f0fdf4;
