/* === DAY OFF REQUEST UI - MATCHES LEAVE REQUEST EXACTLY === */

/* Modern Leave Management Styles */
.leave-management-container {
background: var(--panel-bg);
border-radius: 16px;
padding: 30px;
border: 1px solid var(--border-color);
}

.leave-header {
display: flex;
justify-content: space-between;
align-items: center;
margin-bottom: 30px;
padding-bottom: 20px;
border-bottom: 2px solid rgba(25, 211, 197, 0.1);
}

.leave-title {
font-size: 24px;
font-weight: 700;
color: var(--text-primary);
margin: 0 0 5px 0;
display: flex;
align-items: center;
gap: 10px;
}

.leave-title i {
color: var(--primary-accent);
}

.leave-subtitle {
font-size: 14px;
color: var(--text-muted);
margin: 0;
}

.btn-new-request {
background: linear-gradient(135deg, var(--primary-accent), var(--secondary-accent));
color: #00110f;
border: none;
padding: 12px 24px;
border-radius: 10px;
font-weight: 600;
font-size: 14px;
cursor: pointer;
display: flex;
align-items: center;
gap: 8px;
transition: all 0.3s ease;
box-shadow: 0 4px 15px rgba(25, 211, 197, 0.3);
}

.btn-new-request:hover {
transform: translateY(-2px);
box-shadow: 0 6px 20px rgba(25, 211, 197, 0.4);
}

/* Form Container */
.leave-form-container {
background: rgba(255, 255, 255, 0.02);
border: 1px solid var(--border-color);
border-radius: 12px;
padding: 30px;
margin-bottom: 30px;
animation: slideDown 0.3s ease;
}

@keyframes slideDown {
from {
opacity: 0;
transform: translateY(-20px);
}
to {
opacity: 1;
transform: translateY(0);
}
}

.form-header {
display: flex;
justify-content: space-between;
align-items: flex-start;
margin-bottom: 25px;
padding-bottom: 20px;
border-bottom: 1px solid var(--border-color);
}

.form-header h3 {
font-size: 18px;
font-weight: 600;
color: var(--text-primary);
margin: 0 0 5px 0;
}

.form-header p {
font-size: 13px;
color: var(--text-muted);
margin: 0;
display: flex;
align-items: center;
gap: 5px;
}

.btn-close-form {
background: rgba(255, 255, 255, 0.05);
border: 1px solid var(--border-color);
color: var(--text-muted);
width: 36px;
height: 36px;
border-radius: 8px;
cursor: pointer;
display: flex;
align-items: center;
justify-content: center;
transition: all 0.3s ease;
}

.btn-close-form:hover {
background: rgba(239, 68, 68, 0.1);
border-color: #ef4444;
color: #ef4444;
}

/* Form Grid */
.form-grid {
display: grid;
gap: 20px;
}

.form-row {
display: grid;
grid-template-columns: 1fr 1fr;
gap: 20px;
}

.form-group {
display: flex;
flex-direction: column;
gap: 8px;
}

.form-label {
font-size: 14px;
font-weight: 600;
color: var(--text-secondary);
display: flex;
align-items: center;
gap: 6px;
}

.form-label i {
color: var(--primary-accent);
font-size: 12px;
}

.required {
color: #ef4444;
}

.optional {
color: var(--text-muted);
font-weight: 400;
font-size: 12px;
}

.form-input,
.form-select,
.form-textarea {
background: rgba(0, 0, 0, 0.2);
border: 1px solid var(--border-color);
border-radius: 8px;
padding: 12px 16px;
color: var(--text-primary);
font-size: 14px;
transition: all 0.3s ease;
outline: none;
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
border-color: var(--primary-accent);
box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
}

.form-textarea {
resize: vertical;
min-height: 100px;
font-family: inherit;
}

/* Select Wrapper */
.select-wrapper {
position: relative;
}

.select-icon {
position: absolute;
right: 16px;
top: 50%;
transform: translateY(-50%);
color: var(--text-muted);
pointer-events: none;
font-size: 12px;
}

/* Form Actions */
.form-actions {
display: flex;
justify-content: flex-end;
gap: 12px;
margin-top: 30px;
padding-top: 25px;
border-top: 1px solid var(--border-color);
}

.btn-cancel,
.btn-submit {
padding: 12px 24px;
border-radius: 8px;
font-weight: 600;
font-size: 14px;
cursor: pointer;
display: flex;
align-items: center;
gap: 8px;
transition: all 0.3s ease;
border: none;
}

.btn-cancel {
background: rgba(255, 255, 255, 0.05);
color: var(--text-secondary);
border: 1px solid var(--border-color);
}

.btn-cancel:hover {
background: rgba(239, 68, 68, 0.1);
border-color: #ef4444;
color: #ef4444;
}

.btn-submit {
background: linear-gradient(135deg, #22c55e, #16a34a);
color: white;
box-shadow: 0 4px 15px rgba(34, 197, 94, 0.3);
}

.btn-submit:hover {
transform: translateY(-2px);
box-shadow: 0 6px 20px rgba(34, 197, 94, 0.4);
}

.btn-submit:disabled {
opacity: 0.6;
cursor: not-allowed;
transform: none;
}

/* Leave Requests List */
.leave-list-container {
margin-top: 30px;
}

.list-header {
display: flex;
justify-content: space-between;
align-items: center;
margin-bottom: 20px;
}

.list-header h3 {
font-size: 18px;
font-weight: 600;
color: var(--text-primary);
margin: 0;
display: flex;
align-items: center;
gap: 10px;
}

.list-header h3 i {
color: var(--primary-accent);
}

.filter-select {
background: rgba(0, 0, 0, 0.2);
border: 1px solid var(--border-color);
border-radius: 8px;
padding: 8px 16px;
color: var(--text-primary);
font-size: 13px;
cursor: pointer;
outline: none;
}

.filter-select:focus {
border-color: var(--primary-accent);
}

.leave-requests-list {
display: flex;
flex-direction: column;
gap: 12px;
}

.loading-state {
text-align: center;
padding: 40px;
color: var(--text-muted);
}

.loading-state i {
font-size: 32px;
margin-bottom: 10px;
color: var(--primary-accent);
}

/* Leave Request Card */
.leave-request-card {
background: rgba(255, 255, 255, 0.02);
border: 1px solid var(--border-color);
border-radius: 12px;
padding: 20px;
transition: all 0.3s ease;
animation: slideIn 0.3s ease;
}

@keyframes slideIn {
from {
opacity: 0;
transform: translateX(-20px);
}
to {
opacity: 1;
transform: translateX(0);
}
}

.leave-request-card:hover {
border-color: rgba(25, 211, 197, 0.3);
background: rgba(25, 211, 197, 0.02);
}

.leave-card-header {
display: flex;
justify-content: space-between;
align-items: flex-start;
margin-bottom: 15px;
}

.leave-type-badge {
display: flex;
align-items: center;
gap: 8px;
}

.leave-type {
font-weight: 600;
color: var(--text-primary);
font-size: 15px;
}

.leave-status {
padding: 6px 12px;
border-radius: 20px;
font-size: 11px;
font-weight: 700;
text-transform: uppercase;
letter-spacing: 0.5px;
}

.leave-status.pending {
background: rgba(255, 193, 7, 0.15);
color: #ffc107;
border: 1px solid rgba(255, 193, 7, 0.3);
}

.leave-status.approved {
background: rgba(34, 197, 94, 0.15);
color: #22c55e;
border: 1px solid rgba(34, 197, 94, 0.3);
}

.leave-status.rejected {
background: rgba(239, 68, 68, 0.15);
color: #ef4444;
border: 1px solid rgba(239, 68, 68, 0.3);
}

.leave-card-body {
display: grid;
grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
gap: 15px;
margin-bottom: 15px;
}

.leave-info-item {
display: flex;
align-items: center;
gap: 10px;
padding: 10px;
background: rgba(0, 0, 0, 0.1);
border-radius: 8px;
}

.leave-info-item i {
color: var(--primary-accent);
font-size: 16px;
width: 20px;
}

.leave-info-label {
font-size: 11px;
color: var(--text-muted);
text-transform: uppercase;
letter-spacing: 0.5px;
}

.leave-info-value {
font-size: 13px;
color: var(--text-primary);
font-weight: 600;
}

.leave-reason-box {
background: rgba(0, 0, 0, 0.1);
border-left: 3px solid var(--primary-accent);
padding: 12px;
border-radius: 6px;
margin-bottom: 12px;
}

.leave-reason-label {
font-size: 11px;
color: var(--text-muted);
margin-bottom: 5px;
display: flex;
align-items: center;
gap: 5px;
}

.leave-reason-text {
font-size: 13px;
color: var(--text-secondary);
line-height: 1.5;
}

.leave-footer {
display: flex;
justify-content: space-between;
align-items: center;
padding-top: 12px;
border-top: 1px solid var(--border-color);
font-size: 11px;
color: var(--text-muted);
}

/* Empty State */
.empty-state {
text-align: center;
padding: 60px 20px;
background: rgba(255, 255, 255, 0.02);
border: 2px dashed var(--border-color);
border-radius: 12px;
}

.empty-state i {
font-size: 64px;
color: var(--text-muted);
opacity: 0.5;
margin-bottom: 20px;
}

.empty-state h4 {
font-size: 16px;
color: var(--text-primary);
margin: 0 0 8px 0;
}

.empty-state p {
font-size: 13px;
color: var(--text-muted);
margin: 0;
}

/* Responsive */
@media (max-width: 768px) {
.leave-header {
flex-direction: column;
align-items: flex-start;
gap: 15px;
}

.form-row {
grid-template-columns: 1fr;
}

.form-actions {
flex-direction: column-reverse;
}

.btn-cancel,
.btn-submit {
width: 100%;
justify-content: center;
}

.leave-card-body {
grid-template-columns: 1fr;
}
}

/* === DAY OFF MODULE: HEADER CONTAINER FIX === */

/* 1. Expand the Main Container Padding */
.leave-management-container {
    padding: 40px 40px !important; /* Increased from 30px */
    margin-bottom: 20px !important; /* Add space below the whole section */
}

/* 2. Expand the Header Block */
.leave-header {
    padding-bottom: 30px !important; /* More space before the border line */
    margin-bottom: 40px !important;  /* More space before the form/list */
}

/* 3. Fix Title & Subtitle Spacing */
.leave-title {
    margin-bottom: 12px !important; /* Push subtitle down */
    line-height: 1.3 !important;
}

.leave-subtitle {
    margin-top: 0 !important;
    line-height: 1.6 !important; /* Prevent text from feeling squashed vertically */
    opacity: 0.9; /* Slight transparency for better hierarchy */
}

/* 4. Mobile Responsiveness */
@media (max-width: 768px) {
    .leave-management-container {
        padding: 25px 20px !important;
    }
    .leave-header {
        flex-direction: column; /* Stack title and button on mobile */
        align-items: flex-start !important;
        gap: 20px;
    }
    .leave-title {
        font-size: 24px !important;
    }
}
