    #reportsSection .stat-card-mini .stat-label {
        font-size: 13px;
        color: #94a3b8;
        margin-bottom: 8px;
        font-weight: 600;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    #reportsSection .stat-card-mini .stat-value {
        font-size: 36px;
        font-weight: 800;
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
