        backdrop-filter: blur(10px);
        min-height: 300px;
    }

    #reportsSection .preview-header {
        display: flex;
        align-items: center;
        gap: 10px;
        margin-bottom: 20px;
        padding-bottom: 15px;
        border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    }

    #reportsSection .preview-header i {
        color: #19D3C5;
        font-size: 18px;
    }

    #reportsSection .preview-header span {
        font-size: 14px;
        font-weight: 600;
        color: #ffffff;
    }

    #reportsSection .preview-subtitle {
        font-size: 12px;
        color: #64748b;
        margin-left: 28px;
    }

    #reportPreview {
        display: flex;
        flex-direction: column;
        gap: 12px;
        max-height: 400px;
        overflow-y: auto;
    }

    #reportPreview::-webkit-scrollbar {
        width: 8px;
