    /* Action Buttons Container */
    #reportsSection .action-buttons-container {
        display: flex;
        gap: 15px;
        justify-content: flex-end;
        align-items: center;
        margin-top: 25px;
        padding-top: 25px;
        border-top: 1px solid rgba(255, 255, 255, 0.05);
    }

    /* Modern Action Buttons */
    #reportsSection .action-button {
        padding: 14px 28px;
        border-radius: 12px;
        font-weight: 700;
        font-size: 14px;
        cursor: pointer;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        display: inline-flex;
        align-items: center;
        gap: 10px;
        border: none;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    #reportsSection .action-button.primary {
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
        color: #0f172a;
        box-shadow: 0 4px 15px rgba(25, 211, 197, 0.3);
    }

    #reportsSection .action-button.primary:hover {
        transform: translateY(-2px);
        box-shadow: 0 6px 20px rgba(25, 211, 197, 0.5);
    }

    #reportsSection .action-button.secondary {
        background: rgba(25, 211, 197, 0.1);
        color: #19D3C5;
        border: 1px solid rgba(25, 211, 197, 0.3);
    }

    #reportsSection .action-button.secondary:hover {
        background: rgba(25, 211, 197, 0.2);
        transform: translateY(-2px);
        box-shadow: 0 4px 12px rgba(25, 211, 197, 0.2);
    }

    #reportsSection .action-button.success {
        background: linear-gradient(135deg, #22c55e 0%, #4ade80 100%);
        color: #0f172a;
        box-shadow: 0 4px 15px rgba(34, 197, 94, 0.3);
    }

    #reportsSection .action-button.success:hover {
        transform: translateY(-2px);
        box-shadow: 0 6px 20px rgba(34, 197, 94, 0.5);
    }

    /* Export Format Selector */
    #reportsSection .export-format-selector {
        display: flex;
        gap: 10px;
        margin-right: 20px;
    }

    #reportsSection .format-option {
        padding: 10px 16px;
        background: rgba(15, 23, 42, 0.6);
        border: 1px solid rgba(25, 211, 197, 0.2);
        border-radius: 8px;
        color: #94a3b8;
        font-size: 13px;
        font-weight: 600;
        cursor: pointer;
        transition: all 0.3s ease;
        display: flex;
        align-items: center;
        gap: 6px;
    }

    #reportsSection .format-option:hover {
        border-color: #19D3C5;
        color: #19D3C5;
    }

    #reportsSection .format-option.active {
        background: rgba(25, 211, 197, 0.15);
        border-color: #19D3C5;
        color: #19D3C5;
    }

    #reportsSection .format-option i {
        font-size: 14px;
    }

    /* Record Items in Preview */
    #reportsSection .record-item {
        background: linear-gradient(145deg, rgba(30, 41, 59, 0.8) 0%, rgba(15, 23, 42, 0.8) 100%);
        border: 1px solid rgba(25, 211, 197, 0.1);
        border-radius: 12px;
        padding: 16px 20px;
        display: flex;
        justify-content: space-between;
        align-items: center;
        transition: all 0.3s ease;
    }

    #reportsSection .record-item:hover {
        border-color: rgba(25, 211, 197, 0.3);
        background: rgba(30, 41, 59, 0.9);
        transform: translateX(4px);
    }

    #reportsSection .record-item.present {
        border-left: 3px solid #22c55e;
    }

    #reportsSection .record-item.late {
        border-left: 3px solid #f59e0b;
    }

    #reportsSection .record-info {
        display: flex;
        align-items: center;
        gap: 15px;
        flex: 1;
    }

    #reportsSection .record-icon {
        width: 40px;
        height: 40px;
        border-radius: 10px;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 18px;
        flex-shrink: 0;
    }

    #reportsSection .record-icon.present {
        background: rgba(34, 197, 94, 0.15);
        color: #22c55e;
    }

    #reportsSection .record-icon.late {
        background: rgba(245, 158, 11, 0.15);
        color: #f59e0b;
    }

    #reportsSection .record-details {
        display: flex;
        flex-direction: column;
    }

    #reportsSection .record-name {
        font-size: 15px;
        font-weight: 600;
        color: #ffffff;
        margin-bottom: 4px;
    }

    #reportsSection .record-id {
        font-size: 12px;
        color: #64748b;
    }

    #reportsSection .record-time {
        display: flex;
        flex-direction: column;
        align-items: flex-end;
        gap: 4px;
        font-size: 13px;
        color: #94a3b8;
        white-space: nowrap;
    }

    #reportsSection .record-badge {
        padding: 6px 14px;
        border-radius: 20px;
        font-size: 11px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 0.5px;
    }

    #reportsSection .record-badge.present {
        background: rgba(34, 197, 94, 0.15);
        color: #22c55e;
    }

    #reportsSection .record-badge.late {
        background: rgba(245, 158, 11, 0.15);
        color: #f59e0b;
    }

    /* Empty State */
    #reportsSection .empty-state {
        text-align: center;
        padding: 60px 20px;
        background: rgba(30, 41, 59, 0.6);
        border-radius: 16px;
        border: 2px dashed rgba(25, 211, 197, 0.2);
    }

    #reportsSection .empty-state i {
        font-size: 64px;
        color: #64748b;
        opacity: 0.5;
        margin-bottom: 20px;
    }

    #reportsSection .empty-state h3 {
        font-size: 18px;
        color: #ffffff;
        margin-bottom: 8px;
    }

    #reportsSection .empty-state p {
        font-size: 14px;
        color: #64748b;
    }

    /* Loading State */
    #reportsSection .loading-state {
        text-align: center;
        padding: 40px;
    }

    #reportsSection .loading-state i {
        font-size: 32px;
        color: #19D3C5;
        animation: spin 1s linear infinite;
    }

    #reportsSection .loading-state p {
        color: #64748b;
        margin-top: 15px;
        font-size: 14px;
    }

    @keyframes spin {
        from { transform: rotate(0deg); }
        to { transform: rotate(360deg); }
    }

    /* Responsive */
    @media (max-width: 1024px) {
        #reportsSection .modern-filter-bar .filter-grid {
            grid-template-columns: repeat(2, 1fr);
        }
        
        #reportsSection .action-buttons-container {
            flex-direction: column;
            width: 100%;
        }
        
        #reportsSection .export-format-selector {
            width: 100%;
            justify-content: center;
            margin-right: 0;
            margin-bottom: 15px;
        }
    }

    @media (max-width: 768px) {
        #reportsSection .modern-filter-bar .filter-grid {
            grid-template-columns: 1fr;
        }
        
        #reportsSection .stats-grid {
            grid-template-columns: 1fr;
        }
        
        #reportsSection .action-button {
            width: 100%;
            justify-content: center;
        }
    }

    #leaveadministrationSection .record-item {
    position: relative;
    }

    #leaveadministrationSection label {
    display: flex;
    align-items: center;
