    /* === ENHANCED AUDIT TRAIL SECTION === */
    #audittrailSection {
        background: linear-gradient(135deg, rgba(15, 23, 42, 0.95) 0%, rgba(30, 41, 59, 0.95) 100%);
        border-radius: 20px;
        padding: 30px;
        border: 1px solid rgba(25, 211, 197, 0.1);
    }

    #audittrailSection .section-header {
        margin-bottom: 30px;
        padding-bottom: 20px;
        border-bottom: 2px solid rgba(25, 211, 197, 0.2);
    }

    #audittrailSection .section-title {
        font-size: 28px;
        font-weight: 800;
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
        -webkit-background-clip: text;
        -webkit-text-fill-color: transparent;
        background-clip: text;
        letter-spacing: -0.5px;
    }

    #audittrailSection .section-subtitle {
        color: #94a3b8;
        font-size: 14px;
        margin-top: 5px;
    }

    /* Modern Audit Trail Cards */
    #audittrailSection .record-item {
        background: linear-gradient(145deg, rgba(30, 41, 59, 0.8) 0%, rgba(15, 23, 42, 0.8) 100%);
        border: 1px solid rgba(25, 211, 197, 0.15);
        border-radius: 16px;
        padding: 20px 24px;
        margin-bottom: 16px;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        backdrop-filter: blur(10px);
        box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    }

    #audittrailSection .record-item:hover {
        transform: translateY(-2px);
        border-color: rgba(25, 211, 197, 0.3);
        box-shadow: 0 8px 25px rgba(25, 211, 197, 0.15);
    }

    /* Icon Styling */
    #audittrailSection .record-avatar {
        width: 48px;
        height: 48px;
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
        border-radius: 12px;
        display: flex;
        align-items: center;
        justify-content: center;
        font-size: 20px;
        box-shadow: 0 4px 12px rgba(25, 211, 197, 0.3);
    }

    #audittrailSection .record-info {
        display: flex;
        align-items: center;
        gap: 16px;
    }

    #audittrailSection .record-details {
        flex: 1;
    }

    #audittrailSection .record-name {
        font-size: 16px;
        font-weight: 700;
        color: #ffffff;
        margin-bottom: 4px;
        letter-spacing: -0.3px;
    }

    #audittrailSection .record-id {
        font-size: 13px;
        color: #94a3b8;
        font-weight: 500;
    }

    /* Action Badge */
    #audittrailSection .record-badge {
        padding: 8px 16px;
        border-radius: 20px;
        font-size: 12px;
        font-weight: 700;
        text-transform: uppercase;
        letter-spacing: 0.5px;
        background: rgba(25, 211, 197, 0.15);
        color: #19D3C5;
        border: 1px solid rgba(25, 211, 197, 0.3);
    }

    /* Filter Section */
    #audittrailSection .filter-section {
        background: rgba(15, 23, 42, 0.5);
        padding: 20px;
        border-radius: 12px;
        margin-bottom: 25px;
        border: 1px solid rgba(25, 211, 197, 0.1);
    }

    #audittrailSection .filter-input {
        background: rgba(30, 41, 59, 0.6);
        border: 1px solid rgba(25, 211, 197, 0.2);
        border-radius: 10px;
        padding: 12px 16px;
        color: #ffffff;
        font-size: 14px;
        transition: all 0.3s ease;
    }

    #audittrailSection .filter-input:focus {
        outline: none;
        border-color: #19D3C5;
        box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
        background: rgba(30, 41, 59, 0.8);
    }

    /* Search Bar */
    #audittrailSection .search-bar {
        background: rgba(15, 23, 42, 0.5);
        border: 1px solid rgba(25, 211, 197, 0.1);
        border-radius: 12px;
        padding: 12px 16px;
        margin-bottom: 25px;
    }

    #audittrailSection .search-input {
        background: transparent;
        border: none;
        color: #ffffff;
        font-size: 14px;
        padding: 8px;
    }

    #audittrailSection .search-input:focus {
        outline: none;
    }

    #audittrailSection .search-input::placeholder {
        color: #64748b;
    }

    /* Refresh Button */
    #audittrailSection .action-button.primary {
        background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
        color: #0f172a;
        border: none;
        border-radius: 10px;
        padding: 12px 24px;
        font-weight: 700;
        font-size: 14px;
        cursor: pointer;
        transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
        box-shadow: 0 4px 15px rgba(25, 211, 197, 0.3);
    }

    #audittrailSection .action-button.primary:hover {
        transform: translateY(-2px);
        box-shadow: 0 6px 20px rgba(25, 211, 197, 0.5);
    }

    /* Empty State */
    #audittrailSection .record-item:empty {
        text-align: center;
        padding: 60px 20px;
        color: #64748b;
        font-style: italic;
    }

    /* Animation */
    @keyframes slideInAudit {
        from {
            opacity: 0;
            transform: translateY(20px);
        }
        to {
            opacity: 1;
            transform: translateY(0);
        }
    }

    #audittrailSection .record-item {
        animation: slideInAudit 0.4s ease-out;
    }

    /* Responsive */
    @media (max-width: 768px) {
        #audittrailSection {
            padding: 20px;
        }
        
        #audittrailSection .section-title {
            font-size: 22px;
        }
        
        #audittrailSection .record-item {
            padding: 16px;
        }
    }

    .loading-spinner {
    display: inline-block;
    width: 16px;
    height: 16px;
    border: 2px solid rgba(255,255,255,0.06);
    border-top: 2px solid var(--primary-accent);
    border-radius: 50%;
    animation: spin 1s linear infinite;
    margin-right: 6px;
    vertical-align: middle;
    }

    @keyframes spin {
    0% { transform: rotate(0deg); }
    100% { transform: rotate(360deg); }
    }

    .fingerprint-module {
    background: linear-gradient(135deg, rgba(255,255,255,0.02) 0%, rgba(255,255,255,0.01) 100%);
    border-left: 4px solid var(--primary-1);
    padding: 25px;
    border-radius: 12px;
    margin-top: 20px;
    box-shadow: 0 4px 12px var(--shadow-prim);
    }

    .fingerprint-header {
    display: flex;
    align-items: center;
    gap: 15px;
    margin-bottom: 20px;
    }

    .fingerprint-icon {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: rgba(255,255,255,0.02);
    color: var(--primary-accent);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 24px;
    margin-right: 10px;
    box-shadow: 0 6px 14px rgba(0,0,0,0.6);
    }

    .fingerprint-title h3 {
    color: var(--primary-accent);
    margin-bottom: 5px;
    font-size: 1.4em;
    }

    .fingerprint-title p {
    color: var(--text-secondary);
    font-size: 0.95em;
    }

    .fingerprint-instructions {
    background: var(--panel-bg);
    padding: 20px;
    border-radius: 10px;
    margin-top: 15px;
    border: 1px solid var(--border-color);
    }

    .fingerprint-instructions h4 {
    color: var(--text-primary);
    margin-bottom: 15px;
    display: flex;
    align-items: center;
    gap: 8px;
    }

    .fingerprint-steps {
    list-style: none;
    padding-left: 0;
    }

    .fingerprint-steps li {
    padding: 10px 0 10px 35px;
    position: relative;
    color: var(--text-muted);
    border-bottom: 1px solid var(--border-color);
    font-size: 0.95em;
    }

    .fingerprint-steps li:last-child {
    border-bottom: none;
    }

    .fingerprint-steps li:before {
    content: "✓";
    position: absolute;
    left: 0;
    top: 10px;
    width: 24px;
    height: 24px;
    background: #28a745;
    color: var(--text-primary);
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.9em;
    font-weight: bold;
    }

    .scanner-status {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-top: 15px;
    padding: 12px;
    background: rgba(255,255,255,0.02);
    border-radius: 8px;
    border-left: 4px solid var(--primary-accent);
    }

    .scanner-status i {
    font-size: 1.5em;
    color: var(--primary-accent);
    }

    .scanner-status span {
    font-weight: 600;
    color: var(--primary-accent);
    }

    .historical-record-card {
    background: var(--panel-bg);
    border: 1px solid var(--border-color);
    border-radius: 12px;
    padding: 20px;
    margin-bottom: 15px;
    transition: all 0.3s ease;
    position: relative;
    overflow: hidden;
    animation: slideIn 0.3s ease;
    }

    .historical-record-card:hover {
    border-color: var(--primary-accent);
    transform: translateY(-2px);
    box-shadow: 0 8px 25px rgba(0,0,0,0.3);
    }

    .historical-record-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 4px;
    height: 100%;
    background: var(--primary-accent);
    }

    .historical-record-card.present::before {
    background: #28a745;
    }

    .historical-record-card.late::before {
    background: #ffc107;
    }

    .historical-record-card.absent::before {
    background: #dc3545;
    }

    .record-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
    padding-bottom: 12px;
    border-bottom: 1px solid rgba(255,255,255,0.05);
    }

    .record-date {
    font-size: 16px;
    font-weight: 700;
    color: var(--text-primary);
    display: flex;
    align-items: center;
    gap: 8px;
    }

    .record-status-badge {
    padding: 6px 14px;
    border-radius: 20px;
    font-size: 12px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    }

    .record-status-badge.present {
    background: rgba(40,167,69,0.15);
    color: #28a745;
    }

    .record-status-badge.late {
    background: rgba(255,193,7,0.15);
    color: #ffc107;
    }

    .record-status-badge.absent {
    background: rgba(220,53,69,0.15);
    color: #dc3545;
    }

    .record-body {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
    }

    .record-info-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px;
    background: rgba(255,255,255,0.03);
    border-radius: 8px;
    }

    .record-info-item i {
    color: var(--primary-accent);
    font-size: 16px;
    width: 20px;
    }

    .record-info-label {
    font-size: 11px;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    }

    .record-info-value {
    font-size: 14px;
    color: var(--text-primary);
    font-weight: 600;
    }

    .record-footer {
    margin-top: 15px;
    padding-top: 12px;
    border-top: 1px solid rgba(255,255,255,0.05);
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 12px;
    color: var(--text-muted);
    }

    .fingerprint-success {
    position: fixed;
    top: 20px;
    right: 20px;
    background: linear-gradient(135deg, #28a745 0%, #20c997 100%);
    color: var(--text-primary);
    padding: 20px 25px;
    border-radius: 12px;
    box-shadow: 0 8px 25px rgba(40, 167, 69, 0.4);
    z-index: 9999;
    display: none;
    animation: slideInRight 0.3s ease-out, slideOutRight 0.3s ease-in 4.7s;
    min-width: 300px;
    }

    @keyframes slideInRight {
    from { transform: translateX(400px); opacity: 0; }
    to { transform: translateX(0); opacity: 1; }
    }

    @keyframes slideOutRight {
    from { transform: translateX(0); opacity: 1; }
    to { transform: translateX(400px); opacity: 0; }
    }

    @keyframes slideInLeft {
    from { transform: translateX(-400px); opacity: 0; }
    to { transform: translateX(0); opacity: 1; }
    }

    .fingerprint-success-icon {
    font-size: 48px;
    margin-bottom: 10px;
    }

    .fingerprint-success-name {
