    /* === TOGGLEABLE FOOTER - FIXED === */
    .system-footer {
    position: fixed;
    bottom: 0;
    left: 0;
    right: 0;
    background: var(--panel-bg);
    border-top: 1px solid var(--border-color);
    padding: 12px 20px;
    z-index: 1000;
    transition: all 0.3s ease;
    overflow: visible; /* Changed from hidden to visible */
    }

    /* Collapsed State */
    .system-footer.collapsed {
    padding: 8px 20px;
    }

    .system-footer.collapsed .footer-content {
    opacity: 0;
    max-height: 0;
    pointer-events: none;
    }

    .system-footer .footer-content {
    opacity: 1;
    max-height: 100px;
    transition: all 0.3s ease;
    }

    /* Toggle Button (Arrow) - FIXED */
    .footer-toggle-btn {
    position: absolute;
    top: -12px; /* Increased from -10px */
    left: 50%;
    transform: translateX(-50%);
    width: 24px; /* Increased from 20px */
    height: 24px; /* Increased from 20px */
    background: var(--primary-accent);
    border-radius: 6px 6px 0 0; /* Increased radius */
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: pointer;
    transition: all 0.3s ease;
    z-index: 1001;
    box-shadow: 0 -2px 8px rgba(0,0,0,0.2); /* Added shadow for visibility */
    }

    .footer-toggle-btn:hover {
    background: var(--secondary-accent);
    transform: translateX(-50%) translateY(-2px);
    }

    .footer-toggle-btn i {
    color: #00110f;
    font-size: 12px; /* Increased from 10px */
    transition: transform 0.3s ease;
    font-weight: 900; /* Make icon bolder */
    }

    /* Rotate Arrow When Collapsed */
    .system-footer.collapsed .footer-toggle-btn i {
    transform: rotate(180deg);
    }

    /* Footer Content */
    .footer-content {
    display: flex;
    justify-content: space-between;
    align-items: center;
    max-width: 1400px;
    margin: 0 auto;
    transition: all 0.3s ease;
    opacity: 1;
    max-height: 100px;
    }

    .footer-left {
    display: flex;
    align-items: center;
    gap: 10px;
    }

    .footer-info {
    color: var(--text-muted);
    font-size: 12px;
    display: flex;
    align-items: center;
    gap: 6px;
    }

    .footer-right {
    display: flex;
    gap: 10px;
    }

    .footer-btn {
    padding: 6px 14px;
    border: 1px solid var(--primary-accent);
    border-radius: 6px;
    background: transparent;
    color: var(--primary-accent);
    font-size: 11px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s;
    display: flex;
    align-items: center;
    gap: 6px;
    }

    .footer-btn:hover {
    background: var(--primary-accent);
    color: #00110f;
    }

    body:not(.landing-page) {
    padding-bottom: 70px;
    }

    .system-footer {
    margin-bottom: 0;
    }

