    /* Password Change Modal Styles */
    .password-section {
    background: var(--panel-bg);
    padding: 20px;
    border-radius: 12px;
    margin-top: 20px;
    border: 1px solid var(--border-color);
    }

    .password-section h4 {
    color: var(--text-primary);
    margin-bottom: 15px;
    font-size: 16px;
    }

    /* === MODERN EMPLOYEE MODAL STYLES === */
    .modern-employee-modal {
    max-width: 900px;
    border: 1px solid var(--border-color);
    box-shadow: 0 20px 50px rgba(0,0,0,0.5);
    }

    .modern-employee-modal .modal-header {
    border-bottom: 1px solid var(--border-color);
    padding-bottom: 20px;
    margin-bottom: 25px;
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    }

    .modal-body-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 30px;
    margin-bottom: 25px;
    }

    .section-title {
    font-size: 14px;
    text-transform: uppercase;
    letter-spacing: 1px;
    color: var(--primary-accent);
    margin-bottom: 15px;
    font-weight: 700;
    display: flex;
    align-items: center;
    gap: 8px;
    border-bottom: 1px solid rgba(25, 211, 197, 0.2);
    padding-bottom: 8px;
    }

    .form-group {
    margin-bottom: 15px;
    }

    .form-label {
    display: block;
    margin-bottom: 8px;
    font-size: 13px;
    font-weight: 600;
    color: var(--text-secondary);
    }

    .form-input-modern {
    width: 100%;
    padding: 12px 15px;
    background: rgba(255,255,255,0.03);
    border: 1px solid var(--border-color);
    border-radius: 8px;
    color: var(--text-primary);
    font-size: 14px;
    transition: all 0.3s ease;
    box-sizing: border-box; /* Fixes padding issues */
    }

    .form-input-modern:focus {
    background: rgba(255,255,255,0.05);
    border-color: var(--primary-accent);
    box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
    outline: none;
    }

    .select-wrapper {
    position: relative;
    }

    .select-icon {
    position: absolute;
    right: 15px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--text-muted);
    pointer-events: none;
    font-size: 12px;
    }

    /* Photo Upload Styling */
    .photo-preview-wrapper {
    position: relative;
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid var(--primary-accent);
    box-shadow: 0 0 20px rgba(25, 211, 197, 0.3);
    background: rgba(0, 0, 0, 0.3);
    cursor: pointer;
    transition: all 0.3s ease;
    }

    .photo-preview-wrapper:hover {
    transform: scale(1.05);
    box-shadow: 0 0 30px rgba(25, 211, 197, 0.5);
    }

    .photo-preview {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
    }

    .photo-preview-overlay {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(25, 211, 197, 0.8);
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.3s ease;
    }

    .photo-preview-wrapper:hover .photo-preview-overlay {
    opacity: 1;
    }

    .photo-preview-overlay i {
    color: #00110f;
    font-size: 32px;
    }

    .photo-upload-container {
    display: flex;
    align-items: center;
    gap: 25px;
    flex-wrap: wrap;
    }

    .photo-controls {
    display: flex;
    gap: 12px;
    flex-direction: column;
    }

    .btn-upload, .btn-remove {
    padding: 10px 20px;
    border-radius: 8px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: all 0.2s;
    border: none;
    width: 100%;
    justify-content: center;
    }

    .btn-upload {
    background: rgba(25, 211, 197, 0.15);
    color: var(--primary-accent);
    border: 1px solid var(--primary-accent);
    }

    .btn-upload:hover {
    background: var(--primary-accent);
    color: #00110f;
    transform: translateY(-2px);
    }

    .btn-remove {
    background: rgba(239, 68, 68, 0.15);
    color: #ef4444;
    border: 1px solid #ef4444;
    }

    .btn-remove:hover {
    background: #ef4444;
    color: white;
    transform: translateY(-2px);
    }

    /* Footer Buttons */
    .modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 15px;
    padding-top: 20px;
    border-top: 1px solid var(--border-color);
    }

    .btn-primary-modern {
    background: var(--gradient-primary);
    color: #00110f;
    padding: 12px 30px;
    border-radius: 8px;
    font-weight: 700;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: transform 0.2s;
    }

    .btn-primary-modern:hover {
    transform: translateY(-2px);
    box-shadow: 0 5px 15px rgba(25, 211, 197, 0.3);
    }

    .btn-secondary-modern {
    background: transparent;
    color: var(--text-muted);
    padding: 12px 30px;
    border-radius: 8px;
    font-weight: 600;
    border: 1px solid var(--border-color);
    cursor: pointer;
    transition: all 0.2s;
    }

    .btn-secondary-modern:hover {
    border-color: var(--text-secondary);
    color: var(--text-primary);
    }

    /* Mobile Responsiveness */
    @media (max-width: 768px) {
    .modal-body-grid {
    grid-template-columns: 1fr;
    gap: 20px;
    }
    .photo-upload-container {
    flex-direction: column;
    text-align: center;
    }
    .photo-controls {
    justify-content: center;
    width: 100%;
    }
    .btn-upload, .btn-remove {
    flex: 1;
    justify-content: center;
    }
    }

    /* === COOL SCAN MODAL STYLES === */
    .scan-modal-overlay {
    position: fixed; top: 0; left: 0; width: 100%; height: 100%;
    background: rgba(0, 0, 0, 0.85); backdrop-filter: blur(10px);
    z-index: 9999; display: none; justify-content: center; align-items: center;
    opacity: 0; transition: opacity 0.3s ease;
    }

    .scan-modal-overlay.active { display: flex; opacity: 1; }

    .scan-modal-card {
    background: linear-gradient(145deg, rgba(6, 26, 31, 0.98), rgba(0, 0, 0, 0.98));
    border: 2px solid var(--primary-accent);
    width: 90%; max-width: 550px; border-radius: 24px; padding: 40px;
    text-align: center; box-shadow: 0 0 50px rgba(25, 211, 197, 0.3);
    transform: scale(0.9); transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
    position: relative; overflow: hidden;
    }

    .scan-modal-overlay.active .scan-modal-card { transform: scale(1); }

    .scan-modal-card::before {
    content: ''; position: absolute; top: -50%; left: -50%; width: 200%; height: 200%;
    background: radial-gradient(circle, rgba(25, 211, 197, 0.1) 0%, transparent 70%);
    animation: rotateGlow 10s linear infinite; z-index: -1; pointer-events: none;
    }

    @keyframes rotateGlow { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }

    .scan-modal-icon {
    width: 100px; height: 100px; margin: 0 auto 25px; border-radius: 50%;
    display: flex; align-items: center; justify-content: center; font-size: 45px;
    background: rgba(25, 211, 197, 0.1); color: var(--primary-accent);
    border: 2px solid var(--primary-accent);
    box-shadow: 0 0 40px rgba(25, 211, 197, 0.3);
    animation: popIn 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275);
    }

    @keyframes popIn { 0% { transform: scale(0); opacity: 0; } 80% { transform: scale(1.1); opacity: 1; } 100% { transform: scale(1); opacity: 1; } }

    .scan-modal-title { font-size: 28px; font-weight: 800; color: #fff; margin-bottom: 5px; text-transform: uppercase; letter-spacing: 2px; }
    .scan-modal-subtitle { font-size: 16px; color: var(--text-muted); margin-bottom: 30px; font-family: 'Courier New', monospace; }

    .scan-modal-profile {
    background: rgba(255, 255, 255, 0.03); border: 1px solid var(--border-color);
    border-radius: 16px; padding: 20px; display: flex; align-items: center; gap: 20px;
    margin-bottom: 25px; text-align: left;
    }

    .scan-modal-pic {
    width: 100px; height: 100px; border-radius: 50%; object-fit: cover;
    border: 3px solid var(--primary-accent); box-shadow: 0 0 20px rgba(25, 211, 197, 0.3);
    }

    .scan-modal-details h3 { color: #fff; font-size: 24px; margin-bottom: 5px; }
    .scan-modal-details p { color: var(--text-muted); font-size: 14px; margin-bottom: 2px; }

    .scan-modal-time {
    font-family: 'Courier New', monospace; font-size: 48px; font-weight: 700;
    color: var(--primary-accent); text-shadow: 0 0 20px rgba(25, 211, 197, 0.3);
    letter-spacing: 4px;
    }

    /* Contact Admin Button */
    .contact-admin-btn {
    position: fixed; bottom: 30px; right: 30px;
    background: rgba(0, 0, 0, 0.6); backdrop-filter: blur(10px);
    border: 1px solid var(--warning); color: var(--warning);
    padding: 12px 24px; border-radius: 50px; font-size: 14px; font-weight: 700;
    text-transform: uppercase; letter-spacing: 1px; cursor: pointer;
    display: flex; align-items: center; gap: 10px; transition: all 0.3s ease;
    z-index: 100; box-shadow: 0 0 15px rgba(255, 170, 0, 0.2);
    }

    .contact-admin-btn:hover { background: var(--warning); color: #000; box-shadow: 0 0 30px rgba(255, 170, 0, 0.6); transform: translateY(-2px); }

    /* === ENHANCED DEPARTMENTS MODULE STYLES === */

    /* Department Grid Layout */
    .departments-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(350px, 1fr));
    gap: 25px;
    margin-top: 25px;
    }

    /* Department Card - Enhanced */
    .department-card {
    background: linear-gradient(145deg, rgba(6, 26, 31, 0.95), rgba(10, 35, 40, 0.95));
    border: 1px solid rgba(25, 211, 197, 0.2);
    border-radius: 16px;
    padding: 0;
    transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
    position: relative;
    overflow: hidden;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
    }

    .department-card::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 4px;
    background: var(--gradient-primary);
    transform: scaleX(0);
    transform-origin: left;
    transition: transform 0.4s ease;
    }

    .department-card:hover {
    transform: translateY(-8px);
    box-shadow: 0 15px 40px rgba(25, 211, 197, 0.2);
    border-color: rgba(25, 211, 197, 0.5);
    }

    .department-card:hover::before {
    transform: scaleX(1);
    }

    /* Department Card Header */
    .department-card-header {
    padding: 20px 25px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.05);
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: rgba(255, 255, 255, 0.02);
    }

    .department-info {
    display: flex;
    align-items: center;
    gap: 15px;
    flex: 1;
    }

    .department-icon-wrapper {
    width: 55px;
    height: 55px;
    border-radius: 14px;
    background: var(--gradient-primary);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 24px;
    color: #00110f;
    box-shadow: 0 5px 15px rgba(25, 211, 197, 0.3);
    flex-shrink: 0;
    }

    .department-name-wrapper {
    flex: 1;
    min-width: 0;
    }

    .department-name {
    font-size: 18px;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 4px;
    word-wrap: break-word;
    overflow: hidden;
    text-overflow: ellipsis;
    }

    .department-head {
    font-size: 12px;
    color: var(--text-muted);
    display: flex;
    align-items: center;
    gap: 5px;
    }

    .department-head i {
    color: var(--primary-accent);
    font-size: 10px;
    }

    /* Department Actions */
    .department-actions,
    .dept-header .action-buttons {
    flex-shrink: 0;
    display: flex;
    gap: 8px;
    margin-left: auto;
    }

    .department-action-btn {
    width: 36px;
    height: 36px;
    border-radius: 10px;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    transition: all 0.3s ease;
    background: rgba(255, 255, 255, 0.05);
    color: var(--text-muted);
    }

    /* Truncate long department names */
    .truncate-dept-name {
    max-width: 200px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    display: inline-block;
    vertical-align: bottom;
    }

    /* Or allow multi-line with max lines */
    .dept-name-multiline {
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
    max-width: 100%;
    }

    .department-action-btn.edit {
    color: var(--primary-accent);
    }

    .department-action-btn.edit:hover {
    background: rgba(25, 211, 197, 0.15);
    color: var(--primary-accent);
    transform: translateY(-2px);
    }

    .department-action-btn.delete {
    color: #ef4444;
    }

    .department-action-btn.delete:hover {
    background: rgba(239, 68, 68, 0.15);
    color: #ef4444;
    transform: translateY(-2px);
    }

    .department-action-btn.view {
    color: #6366f1;
    }

    .department-action-btn.view:hover {
    background: rgba(99, 102, 241, 0.15);
    color: #6366f1;
    transform: translateY(-2px);
    }

    /* Department Card Body */
    .department-card-body {
    padding: 20px 25px;
    }

    /* Employee Avatars Stack */
    .department-employees {
    display: flex;
    align-items: center;
    margin-bottom: 20px;
    }

    .employee-avatar-stack {
    display: flex;
    margin-right: 12px;
    }

    .employee-avatar-stack img,
    .employee-avatar-stack .avatar-placeholder {
    width: 38px;
    height: 38px;
    border-radius: 50%;
    border: 2px solid var(--panel-bg);
    margin-left: -10px;
    object-fit: cover;
    transition: transform 0.3s ease;
    }

    .employee-avatar-stack img:hover,
    .employee-avatar-stack .avatar-placeholder:hover {
    transform: scale(1.2);
    z-index: 10;
    }

    .employee-avatar-stack img:first-child,
    .employee-avatar-stack .avatar-placeholder:first-child {
    margin-left: 0;
    }

    .avatar-placeholder {
    background: var(--gradient-primary);
    color: #00110f;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px;
    font-weight: 700;
    }

    .employee-count-text {
    font-size: 13px;
    color: var(--text-muted);
    }

    .employee-count-text strong {
    color: var(--primary-accent);
    font-weight: 700;
    }

    /* Department Stats Grid */
    .department-stats-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
    margin-bottom: 20px;
    }

    .department-stat-box {
    background: rgba(255, 255, 255, 0.03);
    border-radius: 10px;
    padding: 12px;
    text-align: center;
    border: 1px solid rgba(255, 255, 255, 0.05);
    transition: all 0.3s ease;
    }

    .department-stat-box:hover {
    background: rgba(255, 255, 255, 0.05);
    border-color: rgba(25, 211, 197, 0.3);
    transform: translateY(-2px);
    }

    .department-stat-value {
    font-size: 22px;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 3px;
    }

    .department-stat-label {
    font-size: 10px;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    }

    /* Attendance Rate Section */
    .department-attendance-section {
    margin-top: 15px;
    padding-top: 15px;
    border-top: 1px solid rgba(255, 255, 255, 0.05);
    }

    .department-attendance-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 10px;
    }

    .department-attendance-label {
    font-size: 12px;
    color: var(--text-muted);
    font-weight: 600;
    }

    .department-attendance-percentage {
    font-size: 14px;
    font-weight: 700;
    color: var(--primary-accent);
    }

    .department-progress-bar-container {
    height: 8px;
    background: rgba(255, 255, 255, 0.05);
    border-radius: 4px;
    overflow: hidden;
    position: relative;
    }

    .department-progress-bar {
    height: 100%;
    border-radius: 4px;
    transition: width 1.5s cubic-bezier(0.34, 1.56, 0.64, 1);
    position: relative;
    overflow: hidden;
    }

    .department-progress-bar::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(
    90deg,
    transparent,
    rgba(255, 255, 255, 0.3),
    transparent
    );
    animation: shimmer 2s infinite;
    }

    @keyframes shimmer {
    0% { transform: translateX(-100%); }
    100% { transform: translateX(100%); }
    }

    /* Department Card Footer */
    .department-card-footer {
    padding: 15px 25px;
    background: rgba(0, 0, 0, 0.2);
    border-top: 1px solid rgba(255, 255, 255, 0.05);
    display: flex;
    justify-content: space-between;
    align-items: center;
    }

    .department-status {
    display: flex;
    align-items: center;
    gap: 6px;
    font-size: 11px;
    color: var(--text-muted);
    }

    .status-dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: #28a745;
    animation: pulse 2s infinite;
    }

    .status-dot.inactive {
    background: #6c757d;
    }

    .department-view-btn {
    padding: 8px 16px;
    background: rgba(25, 211, 197, 0.1);
    color: var(--primary-accent);
    border: 1px solid rgba(25, 211, 197, 0.3);
    border-radius: 8px;
    font-size: 12px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s ease;
    display: flex;
    align-items: center;
    gap: 6px;
    }

    .department-view-btn:hover {
    background: var(--primary-accent);
    color: #00110f;
    transform: translateY(-2px);
    }

    /* Add Department Button */
    .add-department-btn {
    background: var(--gradient-primary);
    color: #00110f;
    padding: 14px 28px;
    border-radius: 12px;
    font-weight: 700;
    border: none;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 10px;
    transition: all 0.3s ease;
    box-shadow: 0 5px 20px rgba(25, 211, 197, 0.3);
    font-size: 14px;
    }

    .add-department-btn:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 30px rgba(25, 211, 197, 0.5);
    }

    .add-department-btn i {
    font-size: 16px;
    }

    /* Department Modal */
    .department-modal {
    max-width: 600px;
    }

    .department-modal .modal-header {
    background: var(--gradient-primary);
    color: #00110f;
    border-radius: 16px 16px 0 0;
    padding: 25px;
    }

    .department-modal .modal-header h3 {
    color: #00110f;
    font-size: 20px;
    }

    .department-modal .modal-header p {
    color: rgba(0, 17, 15, 0.8);
    }

    .department-modal .modal-body {
    padding: 30px;
    }

    .department-form-row {
    margin-bottom: 22px;
    }

    .department-form-row label {
    display: block;
    margin-bottom: 8px;
    font-size: 13px;
    font-weight: 600;
    color: var(--text-secondary);
    display: flex;
    align-items: center;
    gap: 6px;
    }

    .department-form-row label i {
    color: var(--primary-accent);
    font-size: 12px;
    }

    .department-form-row input,
    .department-form-row select,
    .department-form-row textarea {
    width: 100%;
    padding: 14px 16px;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-color);
    border-radius: 10px;
    color: var(--text-primary);
    font-size: 14px;
    transition: all 0.3s ease;
    }

    .department-form-row input:focus,
    .department-form-row select:focus,
    .department-form-row textarea:focus {
    border-color: var(--primary-accent);
    background: rgba(255, 255, 255, 0.05);
    box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
    outline: none;
    }

    .department-form-row textarea {
    min-height: 100px;
    resize: vertical;
    }

    /* Department Detail Modal */
    .department-detail-modal {
    max-width: 800px;
    }

    .department-detail-header {
    display: flex;
    align-items: center;
    gap: 20px;
    padding: 25px;
    background: rgba(25, 211, 197, 0.05);
    border-bottom: 1px solid var(--border-color);
    }

    .department-detail-icon {
    width: 70px;
    height: 70px;
    border-radius: 16px;
    background: var(--gradient-primary);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 32px;
    color: #00110f;
    }

    .department-detail-info h3 {
    font-size: 24px;
    color: var(--text-primary);
    margin-bottom: 5px;
    }

    .department-detail-info p {
    font-size: 13px;
    color: var(--text-muted);
    }

    .department-employees-list {
    padding: 25px;
    max-height: 400px;
    overflow-y: auto;
    }

    .department-employee-item {
    display: flex;
    align-items: center;
    gap: 15px;
    padding: 15px;
    background: rgba(255, 255, 255, 0.02);
    border-radius: 10px;
    margin-bottom: 10px;
    transition: all 0.3s ease;
    border: 1px solid transparent;
    }

    .department-employee-item:hover {
    background: rgba(255, 255, 255, 0.04);
    border-color: rgba(25, 211, 197, 0.2);
    transform: translateX(5px);
    }

    .department-employee-avatar {
    width: 45px;
    height: 45px;
    border-radius: 50%;
    background: var(--gradient-primary);
    display: flex;
    align-items: center;
    justify-content: center;
    color: #00110f;
    font-weight: 700;
    font-size: 16px;
    flex-shrink: 0;
    overflow: hidden;
    }

    .department-employee-avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    }

    .department-employee-info {
    flex: 1;
    min-width: 0;
    }

    .department-employee-name {
    font-size: 15px;
    font-weight: 600;
    color: var(--text-primary);
    margin-bottom: 3px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    }

    .department-employee-position {
    font-size: 12px;
    color: var(--text-muted);
    }

    .department-employee-status {
    padding: 6px 12px;
    border-radius: 20px;
    font-size: 11px;
    font-weight: 600;
    text-transform: uppercase;
    }

    .department-employee-status.present {
    background: rgba(40, 167, 69, 0.15);
    color: #28a745;
    }

    .department-employee-status.absent {
    background: rgba(220, 53, 69, 0.15);
    color: #dc3545;
    }

    .department-employee-status.late {
    background: rgba(255, 193, 7, 0.15);
    color: #ffc107;
    }

    /* Search & Filter Bar */
    .departments-filter-bar {
    display: flex;
    gap: 15px;
    margin-bottom: 25px;
    flex-wrap: wrap;
    background: rgba(255, 255, 255, 0.02);
    padding: 20px;
    border-radius: 12px;
    border: 1px solid var(--border-color);
    }

    .departments-search-input {
    flex: 1;
    min-width: 250px;
    padding: 12px 16px;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-color);
    border-radius: 10px;
    color: var(--text-primary);
    font-size: 14px;
    }

    .departments-search-input:focus {
    border-color: var(--primary-accent);
    outline: none;
    }

    .departments-filter-select {
    padding: 12px 16px;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid var(--border-color);
    border-radius: 10px;
    color: var(--text-primary);
    font-size: 14px;
    min-width: 180px;
    }

    /* Stats Summary Cards */
    .departments-stats-summary {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
    }

    .department-summary-card {
    background: var(--panel-bg);
    border: 1px solid var(--border-color);
    border-radius: 14px;
    padding: 20px;
    text-align: center;
    transition: all 0.3s ease;
    }

    .department-summary-card:hover {
    transform: translateY(-5px);
    border-color: var(--primary-accent);
    box-shadow: 0 10px 30px rgba(25, 211, 197, 0.15);
    }

    .department-summary-icon {
    width: 50px;
    height: 50px;
    border-radius: 12px;
    background: var(--gradient-primary);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 22px;
    color: #00110f;
    margin: 0 auto 15px;
    }

    .department-summary-value {
    font-size: 32px;
    font-weight: 700;
    color: var(--text-primary);
    margin-bottom: 5px;
    }

    .department-summary-label {
    font-size: 12px;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
    }

    /* Empty State */
    .departments-empty-state {
    grid-column: 1/-1;
    text-align: center;
    padding: 60px 20px;
    background: rgba(255, 255, 255, 0.02);
    border-radius: 16px;
    border: 2px dashed var(--border-color);
    }

    .departments-empty-state i {
    font-size: 64px;
    color: var(--text-muted);
    opacity: 0.5;
    margin-bottom: 20px;
    }

    .departments-empty-state h3 {
    font-size: 20px;
    color: var(--text-primary);
    margin-bottom: 10px;
    }

    .departments-empty-state p {
    font-size: 14px;
    color: var(--text-muted);
    margin-bottom: 20px;
    }

    /* Loading State */
    .departments-loading {
    grid-column: 1/-1;
    text-align: center;
    padding: 60px 20px;
    }

    .departments-loading i {
    font-size: 48px;
    color: var(--primary-accent);
    margin-bottom: 15px;
    }

    .departments-loading p {
    font-size: 14px;
    color: var(--text-muted);
    }

    /* Responsive */
    @media (max-width: 768px) {
    .departments-grid {
    grid-template-columns: 1fr;
    }
    .department-card-header {
    flex-direction: column;
    align-items: flex-start;
    gap: 15px;
    }
    .department-actions {
    width: 100%;
    justify-content: flex-end;
    }
    .department-stats-grid {
    grid-template-columns: 1fr;
    }
    .departments-filter-bar {
    flex-direction: column;
    }
    .departments-search-input,
    .departments-filter-select {
    width: 100%;
    }
    }

    @keyframes pulse-ring {
    0% { transform: scale(0.8); opacity: 0.5; }
    100% { transform: scale(1.3); opacity: 0; }
    }

    @keyframes slideUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
    }

    /* Force Full Screen when active */
    body.kiosk-active { overflow: hidden; }

    /* === KIOSK MODE OVERLAY - FULL SCREEN === */
    #kioskModeOverlay {
    display: none; /* Hidden by default */
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: #0f172a; /* Dark background */
    z-index: 99999; /* Above everything */
    flex-direction: column;
    align-items: center;
    justify-content: center;
    color: white;
    font-family: 'Inter', sans-serif;
    overflow: hidden;
    }

    /* Kiosk Content Container */
    #kioskModeOverlay .kiosk-content {
    text-align: center;
    z-index: 10;
    max-width: 600px;
    padding: 20px;
    animation: fadeIn 0.5s ease;
    }

    /* Exit Button (Hidden by default, shown on hover or secret click) */
    .kiosk-exit-btn {
    position: absolute;
    top: 20px;
    right: 20px;
    background: rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.2);
    color: rgba(255, 255, 255, 0.3);
    padding: 8px 15px;
    border-radius: 6px;
    cursor: pointer;
    font-size: 12px;
    transition: all 0.3s;
    opacity: 0; /* Hidden normally */
    }

    /* Show exit button only when hovering top-right corner */
    #kioskModeOverlay:hover .kiosk-exit-btn {
    opacity: 1;
    }

    #kioskModeOverlay:hover .kiosk-exit-btn:hover {
    background: rgba(239, 68, 68, 0.2);
    color: #ef4444;
    }

    @keyframes pulse-ring {
    0% { transform: scale(0.8); opacity: 0.5; }
    100% { transform: scale(1.3); opacity: 0; }
    }

    @keyframes slideUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
    }

    /* Force Full Screen when active */
    body.kiosk-active { overflow: hidden; }

    /* Day Off Form Alignment */
    #employeeLeavesSection input,
    #employeeLeavesSection select,
    #employeeLeavesSection textarea {
    background: rgba(0, 0, 0, 0.2) !important;
    border: 1px solid rgba(255, 255, 255, 0.1) !important;
    color: var(--text-primary) !important;
    font-family: var(--font-stack);
    }

    #employeeLeavesSection input:focus,
    #employeeLeavesSection select:focus,
    #employeeLeavesSection textarea:focus {
    border-color: var(--primary-accent) !important;
    outline: none;
    }

    /* Scrollbar for request list */
    #dayOffList::-webkit-scrollbar {
    width: 8px;
    }

    #dayOffList::-webkit-scrollbar-track {
    background: rgba(0,0,0,0.1);
    border-radius: 4px;
    }

    #dayOffList::-webkit-scrollbar-thumb {
    background: var(--primary-accent);
    border-radius: 4px;
    }
    /* === NOTIFICATION PULSE ANIMATION === */
    @keyframes notificationPulse {
        0% { transform: scale(1); }
        50% { transform: scale(1.2); }
        100% { transform: scale(1); }
    }

    .notification-pulse {
        animation: notificationPulse 0.5s ease-in-out;
    }

    .notification-badge {
        position: absolute;
        top: -5px;
        right: -5px;
        background: #ff4757;
        color: var(--text-primary);
        font-size: 10px;
        font-weight: bold;
        width: 18px;
        height: 18px;
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
        animation: pulse 1.5s infinite;
    }

    @keyframes pulse {
        0% { box-shadow: 0 0 0 0 rgba(255, 71, 87, 0.7); }
        70% { box-shadow: 0 0 0 8px rgba(255, 71, 87, 0); }
        100% { box-shadow: 0 0 0 0 rgba(255, 71, 87, 0); }
    }
    /* === HOLIDAY EMPLOYEE ROW STYLES === */
    .holiday-employee-row {
        display: flex;
        align-items: center;
        gap: 12px;
        padding: 12px 15px;
        border-bottom: 1px solid rgba(255, 255, 255, 0.05);
        transition: background 0.2s;
    }

    .holiday-employee-row:hover {
        background: rgba(25, 211, 197, 0.05);
    }

    .holiday-employee-row:last-child {
        border-bottom: none;
    }

    .holiday-employee-row input[type="checkbox"] {
        width: 18px;
        height: 18px;
        cursor: pointer;
        accent-color: var(--primary-accent);
    }

    .holiday-employee-row label {
        flex: 1;
        cursor: pointer;
        margin: 0;
    }

    /* === HEADER RESPONSIVE STYLES === */
    .dashboard-header-modern {
        flex-wrap: wrap !important;
        gap: 15px !important;
    }

    .dashboard-header-modern > div:first-child {
        flex: 1 1 auto;
        min-width: 0;
    }

    .dashboard-header-modern > div:last-child {
        flex: 1 1 auto;
        justify-content: flex-end;
        min-width: 0;
    }

    .header-user-modern {
        flex-wrap: wrap;
        gap: 8px;
    }

    .user-info-modern {
        min-width: 0;
    }

    .user-info-modern span {
        white-space: nowrap;
        overflow: hidden;
        text-overflow: ellipsis;
    }

    /* Tablet Responsive */
    @media (max-width: 1024px) {
        .dashboard-header-modern {
            padding: 15px 20px !important;
            gap: 12px !important;
        }

        .header-title {
            font-size: 1.4em !important;
        }

        .header-logo img {
            height: 40px !important;
        }

        .user-avatar-modern {
            width: 40px !important;
            height: 40px !important;
        }

        .user-avatar-modern i {
            font-size: 24px !important;
        }

        .header-user-modern {
            gap: 10px !important;
        }
    }

    /* Mobile Responsive */
    @media (max-width: 768px) {
        .dashboard-header-modern {
            flex-direction: column !important;
            align-items: stretch !important;
            justify-content: flex-start !important;
            padding: 12px 15px !important;
            margin: 20px 0 15px 0 !important;
            gap: 12px !important;
        }

        .dashboard-header-modern > div:first-child {
            flex: 1 1 100%;
            display: flex;
            align-items: center;
            gap: 12px;
        }

        .dashboard-header-modern > div:last-child {
            flex: 1 1 100%;
            display: flex;
            align-items: center;
            justify-content: space-between;
            gap: 10px;
            min-width: 0;
        }

        .header-title {
            font-size: 1.2em !important;
            letter-spacing: 0 !important;
        }

        .header-subtitle {
            font-size: 12px !important;
        }

        .header-logo img {
            height: 36px !important;
            width: auto !important;
        }

        .user-avatar-modern {
            width: 36px !important;
            height: 36px !important;
            flex-shrink: 0;
        }

        .user-avatar-modern i {
            font-size: 20px !important;
        }

        .user-info-modern {
            font-size: 13px;
            min-width: 0;
        }

        .user-info-modern span:first-child {
            font-size: 13px;
            font-weight: 600;
        }

        .user-info-modern span:last-child {
            font-size: 11px;
        }

        .notification-bell-modern {
            flex-shrink: 0;
            font-size: 20px !important;
        }

        .notification-bell-modern i {
            font-size: 20px !important;
        }

        .notification-badge {
            top: -4px !important;
            right: -4px !important;
            padding: 1px 5px !important;
            font-size: 11px !important;
        }

        .notification-dropdown {
            top: 50px !important;
            right: 10px !important;
            left: auto !important;
            width: calc(100vw - 20px) !important;
            max-width: 350px;
        }

        /* Standard header for admin */
        .header, .admin-header {
            flex-direction: row !important;
            flex-wrap: wrap !important;
            align-items: center !important;
            text-align: left !important;
            padding: 12px 15px !important;
            gap: 10px !important;
        }

        .header-left, .admin-header-left {
            flex: 1 1 auto;
            min-width: 0;
            gap: 12px !important;
        }

        .header-logo, .admin-header-logo {
            font-size: 24px !important;
        }

        .header-title, .admin-header-title {
            font-size: 18px !important;
        }

        .admin-header-subtitle {
            font-size: 12px !important;
        }

        .header-user, .admin-header-user {
            flex: 1 1 100%;
            gap: 10px !important;
        }

        .user-avatar, .admin-user-avatar {
            width: 36px !important;
            height: 36px !important;
            font-size: 12px !important;
        }
    }

    /* Small Mobile Responsive */
    @media (max-width: 480px) {
        .dashboard-header-modern {
            padding: 10px 12px !important;
            margin: 15px 0 10px 0 !important;
            gap: 10px !important;
        }

        .dashboard-header-modern > div:first-child {
            gap: 10px;
        }

        .header-title {
            font-size: 1rem !important;
        }

        .header-subtitle {
            font-size: 11px !important;
        }

        .header-logo img {
            height: 32px !important;
        }

        .user-avatar-modern {
            width: 32px !important;
            height: 32px !important;
        }

        .user-avatar-modern i {
            font-size: 18px !important;
        }

        .user-info-modern {
            display: flex;
            flex-direction: column;
            gap: 2px;
        }

        .user-info-modern span:first-child {
            font-size: 12px;
        }

        .user-info-modern span:last-child {
            font-size: 10px;
        }

/* === EMPLOYEE PORTAL: NOTIFICATION BELL COLOR FIX === */

/* Find this section in your Employee Portal header (around line 1817) */
.notification-bell-modern {
    position: relative;
    cursor: pointer;
}

/* CHANGE THIS LINE - Update the bell icon color */
.notification-bell-modern i {
    font-size: 22px;
    color: #94a3b8 !important; /* Changed from #19D3C5 to gray */
