    document.addEventListener('DOMContentLoaded', function() {
        // Check if PHP passed a login error via session
        const errorDiv = document.getElementById('loginError');
        const loginModal = document.getElementById('loginModal');
        
        // If error div is visible (meaning PHP set it), open the modal
        if (errorDiv && errorDiv.style.display === 'block' && loginModal) {
            loginModal.style.display = 'flex';
            // Add animation class
            const loginBox = document.querySelector('.login-box');
            if(loginBox) {
                loginBox.style.animation = 'slideUp 0.4s ease forwards';
            }
        }
    });
