                                $redirectModule = 'overtime';
                            } elseif (stripos($notif['type'], 'report') !== false || stripos($notif['title'], 'Report') !== false) {
                                $redirectModule = 'reports';
                            } elseif (stripos($notif['type'], 'audit') !== false || stripos($notif['title'], 'Audit') !== false) {
                                $redirectModule = 'audittrail';
