                                $redirectModule = 'attendance';
                            } elseif (stripos($notif['type'], 'fingerprint') !== false || stripos($notif['title'], 'Fingerprint') !== false) {
                                $redirectModule = 'fingerprint';
                            }
                            $isRead = $notif['is_read'] == 1;
                            $created = new DateTime($notif['created_at']);
                            $formattedDate = $created->format('F j, Y – g:i A');
                        ?>
