    // Preload leave balance server-side so the dashboard never starts at 0
    $employeeKey = $_SESSION['user_id'] ?? $_SESSION['employee_id'] ?? null;
    $leaveBalance = ['vl_credits' => 0, 'sl_credits' => 0, 'used_vl' => 0, 'used_sl' => 0];
    if ($employeeKey && $pdo) {
        $leaveBalance = getLeaveBalance($pdo, $employeeKey);
    }
    $vlRemaining = max(0, floatval($leaveBalance['vl_credits']) - floatval($leaveBalance['used_vl']));
    $slRemaining = max(0, floatval($leaveBalance['sl_credits']) - floatval($leaveBalance['used_sl']));
    $totalPaid = $vlRemaining + $slRemaining;
