<!-- === LEAVE BALANCE LOADER (FIXED) === -->
<script>
function loadLeaveBalanceInModule() {
    console.log("🔄 Loading leave balance...");
    
    // Add timestamp to prevent browser caching
    fetch('?action=get_leave_balance&t=' + Date.now())
    .then(r => {
        if (!r.ok) throw new Error('HTTP ' + r.status);
        return r.json();
    })
    .then(data => {
        console.log("📦 Leave Balance Response:", data);
        
        if (data.success) {
            // Update the 3 balance cards
            const vlEl = document.getElementById('vlBalanceDisplay');
            const slEl = document.getElementById('slBalanceDisplay');
            const totalEl = document.getElementById('totalPaidBalanceDisplay');
            
            if (vlEl) {
                vlEl.textContent = data.vl_remaining;
                console.log("✅ VL Updated:", data.vl_remaining);
            }
            
            if (slEl) {
                slEl.textContent = data.sl_remaining;
                console.log("✅ SL Updated:", data.sl_remaining);
            }
            
            if (totalEl) {
                totalEl.textContent = data.total_paid;
                console.log("✅ Total Updated:", data.total_paid);
            }
        } else {
            console.error("❌ API Error:", data.message);
        }
    })
    .catch(e => {
        console.error("❌ Network Error:", e);
    });
}

// Auto-load when Leave Request tab is opened
function switchEmployeeTab(tabName) {
    // Hide all sections first
    document.querySelectorAll('.admin-section').forEach(sec => sec.style.display = 'none');
    document.querySelectorAll('.nav-tab').forEach(tab => tab.classList.remove('active'));
    
    // Show selected section
    if (tabName === 'overview') {
        document.getElementById('employeeOverviewSection').style.display = 'block';
    } else if (tabName === 'schedule') {
        document.getElementById('employeeScheduleSection').style.display = 'block';
    } else if (tabName === 'leaves') {
        document.getElementById('employeeDayOffSection').style.display = 'block';
    } else if (tabName === 'leave') {
        document.getElementById('employeeLeaveSection').style.display = 'block';
        console.log("📋 Leave tab opened, loading balance...");
        loadLeaveBalanceInModule(); // ← CRITICAL: Load balance when tab opens
        loadLeaveRequests();
    }
    
    // Set active tab
    document.querySelector(`.nav-tab[data-tab="${tabName}"]`)?.classList.add('active');
}

// Load balance on page load if already on leave tab
document.addEventListener('DOMContentLoaded', function() {
    const leaveSection = document.getElementById('employeeLeaveSection');
    if (leaveSection && leaveSection.style.display !== 'none') {
        loadLeaveBalanceInModule();
    }
});
