    min-height: 100px;
    font-family: inherit;
}

.form-hint {
    font-size: 12px;
    color: var(--text-muted);
    display: flex;
    align-items: center;
    gap: 5px;
}

.char-count {
    font-weight: 400;
    font-size: 12px;
    color: var(--text-muted);
    margin-left: auto;
}

.char-counter {
    font-size: 11px;
    color: var(--text-muted);
    text-align: right;
}

/* Select Wrapper */
.select-wrapper {
    position: relative;
}

.select-icon {
    position: absolute;
    right: 16px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--text-muted);
    pointer-events: none;
    font-size: 12px;
}

/* File Upload */
.file-upload-container {
    margin-top: 5px;
}

.file-upload-area {
    border: 2px dashed var(--border-color);
    border-radius: 10px;
    padding: 30px;
