}

.file-upload-area.dragover {
    border-color: var(--primary-accent);
    background: rgba(25, 211, 197, 0.1);
}

.file-input {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    opacity: 0;
    cursor: pointer;
}

.upload-icon {
    font-size: 40px;
    color: var(--primary-accent);
    margin-bottom: 10px;
}

.upload-text {
    color: var(--text-secondary);
}

.upload-text strong {
    display: block;
    color: var(--text-primary);
    margin-bottom: 5px;
}

.upload-text small {
    font-size: 12px;
    color: var(--text-muted);
}

/* File Preview */
.file-preview {
    background: rgba(0, 0, 0, 0.2);
    border: 1px solid var(--border-color);
    border-radius: 8px;
    padding: 15px;
}

.file-info {
    display: flex;
    align-items: center;
    gap: 12px;
}

.file-info i {
    font-size: 32px;
    color: var(--primary-accent);
}

.file-details {
    flex: 1;
}

.file-name {
    font-weight: 600;
    color: var(--text-primary);
    font-size: 14px;
    word-break: break-all;
}

.file-size {
    font-size: 12px;
    color: var(--text-muted);
}

.btn-remove-file {
    background: rgba(239, 68, 68, 0.1);
    border: 1px solid #ef4444;
    color: #ef4444;
    width: 32px;
    height: 32px;
    border-radius: 6px;
    cursor: pointer;
