    border: 1px solid rgba(34, 197, 94, 0.3);
}

.leave-status.rejected {
    background: rgba(239, 68, 68, 0.15);
    color: #ef4444;
    border: 1px solid rgba(239, 68, 68, 0.3);
}

.leave-card-body {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
    gap: 15px;
    margin-bottom: 15px;
}

.leave-info-item {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px;
    background: rgba(0, 0, 0, 0.1);
    border-radius: 8px;
}

.leave-info-item i {
    color: var(--primary-accent);
    font-size: 16px;
    width: 20px;
}

.leave-info-label {
    font-size: 11px;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.leave-info-value {
    font-size: 13px;
    color: var(--text-primary);
    font-weight: 600;
}

.leave-reason-box {
    background: rgba(0, 0, 0, 0.1);
    border-left: 3px solid var(--primary-accent);
    padding: 12px;
    border-radius: 6px;
    margin-bottom: 12px;
}

.leave-reason-label {
    font-size: 11px;
    color: var(--text-muted);
    margin-bottom: 5px;
    display: flex;
    align-items: center;
    gap: 5px;
}

.leave-reason-text {
    font-size: 13px;
    color: var(--text-secondary);
    line-height: 1.5;
}

.leave-attachment {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 12px;
    background: rgba(25, 211, 197, 0.05);
    border: 1px solid rgba(25, 211, 197, 0.2);
    border-radius: 6px;
    margin-top: 10px;
}

.leave-attachment i {
    color: var(--primary-accent);
    font-size: 16px;
}

.leave-attachment-text {
    font-size: 12px;
    color: var(--text-secondary);
}

.leave-footer {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding-top: 12px;
    border-top: 1px solid var(--border-color);
    font-size: 11px;
    color: var(--text-muted);
}

/* Empty State */
.empty-state {
    text-align: center;
    padding: 60px 20px;
    background: rgba(255, 255, 255, 0.02);
    border: 2px dashed var(--border-color);
    border-radius: 12px;
}

.empty-state i {
    font-size: 64px;
    color: var(--text-muted);
    opacity: 0.5;
    margin-bottom: 20px;
}

.empty-state h4 {
    font-size: 16px;
    color: var(--text-primary);
    margin: 0 0 8px 0;
}

.empty-state p {
    font-size: 13px;
    color: var(--text-muted);
    margin: 0;
}

/* Responsive */
@media (max-width: 768px) {
    .leave-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 15px;
    }

    .form-row {
        grid-template-columns: 1fr;
    }

    .form-actions {
        flex-direction: column-reverse;
    }

    .btn-cancel,
    .btn-submit {
        width: 100%;
        justify-content: center;
    }

    .leave-card-body {
        grid-template-columns: 1fr;
    }
}
</style>

<script>


// === FIXED: CHARACTER COUNTER ===
function updateCharCount(length) {
    document.getElementById('currentChars').textContent = length;
    const countEl = document.getElementById('charCount');
    if (length < 20) {
        countEl.textContent = `(Minimum 20 characters - ${20 - length} more needed)`;
        countEl.style.color = '#ef4444';
    } else if (length > 480) {
        countEl.textContent = `(${500 - length} characters remaining)`;
        countEl.style.color = '#ffc107';
    } else {
        countEl.textContent = `(Minimum 20 characters)`;
        countEl.style.color = 'var(--text-muted)';
    }
}
// === FIXED: FILTER BY STATUS ===
function filterLeaveRequestsByStatus(status) {
    const cards = document.querySelectorAll('.leave-request-card');
    cards.forEach(card => {
        const cardStatus = card.getAttribute('data-status');
        if (status === 'all' || cardStatus === status.toLowerCase()) {
            card.style.display = 'block';
            card.style.animation = 'slideIn 0.3s ease';
        } else {
            card.style.display = 'none';
        }
    });
}
// File Upload Handler
let uploadedFile = null;

function handleFileUpload(input) {
    const file = input.files[0];
    if (!file) return;

    // Validate file type
    const validTypes = ['application/pdf', 'image/jpeg', 'image/jpg', 'image/png'];
    if (!validTypes.includes(file.type)) {
        showToast('Please upload a PDF, JPG, or PNG file', 'error');
        input.value = '';
        return;
    }

    // Validate file size (5MB max)
    if (file.size > 5 * 1024 * 1024) {
        showToast('File size must be less than 5MB', 'error');
        input.value = '';
        return;
    }

    uploadedFile = file;
    showFilePreview(file);
}

function showFilePreview(file) {
    const preview = document.getElementById('filePreview');
    const uploadArea = document.getElementById('fileUploadArea');
    const fileName = document.getElementById('fileName');
    const fileSize = document.getElementById('fileSize');
    const fileIcon = document.getElementById('fileIcon');

    fileName.textContent = file.name;
    fileSize.textContent = formatFileSize(file.size);

    // Set icon based on file type
    if (file.type === 'application/pdf') {
        fileIcon.className = 'fas fa-file-pdf';
        fileIcon.style.color = '#ef4444';
    } else if (file.type.startsWith('image/')) {
        fileIcon.className = 'fas fa-file-image';
        fileIcon.style.color = '#19D3C5';
    }

    uploadArea.style.display = 'none';
    preview.style.display = 'block';
}

function removeFile() {
    uploadedFile = null;
    document.getElementById('leaveAttachment').value = '';
    document.getElementById('fileUploadArea').style.display = 'block';
    document.getElementById('filePreview').style.display = 'none';
}

function formatFileSize(bytes) {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return Math.round(bytes / Math.pow(k, i) * 100) / 100 + ' ' + sizes[i];
}

// Drag and Drop
const uploadArea = document.getElementById('fileUploadArea');
if (uploadArea) {
    ['dragenter', 'dragover', 'dragleave', 'drop'].forEach(eventName => {
        uploadArea.addEventListener(eventName, preventDefaults, false);
    });

    function preventDefaults(e) {
        e.preventDefault();
        e.stopPropagation();
    }

    ['dragenter', 'dragover'].forEach(eventName => {
        uploadArea.addEventListener(eventName, highlight, false);
    });

    ['dragleave', 'drop'].forEach(eventName => {
        uploadArea.addEventListener(eventName, unhighlight, false);
    });

    function highlight(e) {
        uploadArea.classList.add('dragover');
    }

    function unhighlight(e) {
        uploadArea.classList.remove('dragover');
    }

    uploadArea.addEventListener('drop', handleDrop, false);

    function handleDrop(e) {
        const dt = e.dataTransfer;
        const files = dt.files;
        document.getElementById('leaveAttachment').files = files;
        handleFileUpload(document.getElementById('leaveAttachment'));
    }
}

// Submit Leave Request
function submitLeaveRequest(event) {
    event.preventDefault();
    
    const btn = document.getElementById('leaveSubmitBtn');
    const originalText = btn.innerHTML;
    
    // Validate
    const startDate = document.getElementById('leaveStartDate').value;
    const endDate = document.getElementById('leaveEndDate').value;
    const reason = document.getElementById('leaveReason').value;
    
    if (!startDate || !endDate) {
        showToast('Please select start and end dates', 'error');
        return;
    }
    
    if (reason.length < 20) {
        showToast('Reason must be at least 20 characters', 'error');
        return;
    }
    
    // Disable button
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Submitting...';
    
// Create FormData
const formData = new FormData();
formData.append('action', 'submit_leave_request');
formData.append('csrf_token', document.querySelector('input[name="csrf_token"]')?.value || '');
formData.append('startDate', startDate);
formData.append('endDate', endDate);

// FIX: Get the actual value from the select box directly, don't split it
// Ensure your HTML <option> values are short codes like VL, SL, BWL, etc.
const selectedOption = document.getElementById('leaveTypeSelect');
const leaveTypeCode = selectedOption.value; 

formData.append('leave_type', leaveTypeCode);
formData.append('reason', reason);
    
    // Add file if exists
    if (uploadedFile) {
        formData.append('attachment', uploadedFile);
    }
    
    fetch('', {
        method: 'POST',
        body: formData,
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(r => r.json())
    .then(data => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        
        if (data.success) {
            showToast('Leave request submitted successfully!', 'success');
            // Clear form
            document.getElementById('leaveRequestForm').reset();
            removeFile();
            // Hide form
            toggleLeaveForm();
            // Reload leave requests list
            loadLeaveRequests();
        } else {
            showToast('Error: ' + (data.message || 'Failed to submit request'), 'error');
        }
    })
    .catch(e => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        showToast('Network error: ' + e.message, 'error');
        console.error('Leave request error:', e);
    });
}

// Load Leave Requests
function loadLeaveRequests() {
    const container = document.getElementById('leaveRequestsList');
    if (!container) return;
    
    container.innerHTML = `
        <div class="loading-state">
            <i class="fas fa-spinner fa-spin"></i>
            <span>Loading your requests...</span>
        </div>
    `;
    
    fetch('?action=get_leave_requests')
    .then(r => r.json())
    .then(data => {
        if (data.success && data.requests && data.requests.length > 0) {
            let html = '';
            data.requests.forEach(req => {
                const statusClass = req.status.toLowerCase();
                const statusIcon = statusClass === 'approved' ? 'fa-check-circle' : 
                                  (statusClass === 'rejected' ? 'fa-times-circle' : 'fa-clock');
                
                // Format dates
                const startDate = new Date(req.start_date).toLocaleDateString('en-US', { 
                    year: 'numeric', month: 'short', day: 'numeric' 
                });
                const endDate = new Date(req.end_date).toLocaleDateString('en-US', { 
                    year: 'numeric', month: 'short', day: 'numeric' 
                });
                
                // Calculate duration
                const start = new Date(req.start_date);
                const end = new Date(req.end_date);
                const diffTime = Math.abs(end - start);
                const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
                
                // Check for attachment
                const hasAttachment = req.attachment_path && req.attachment_path !== '';
                
               // In the loadLeaveRequests() function, update the card HTML generation:
html += `
<div class="leave-request-card" data-status="${statusClass}">
    <div class="leave-card-header">
        <div class="leave-type-badge">
            <span class="leave-type">${req.type || 'Leave'} Request</span>
        </div>
        <span class="leave-status ${statusClass}">
            <i class="fas ${statusIcon}"></i> ${req.status}
        </span>
    </div>
    <div class="leave-card-body">
        <div class="leave-info-item">
            <i class="fas fa-calendar-alt"></i>
            <div>
                <div class="leave-info-label">Start Date</div>
                <div class="leave-info-value">${startDate}</div>
            </div>
        </div>
        <div class="leave-info-item">
            <i class="fas fa-calendar-check"></i>
            <div>
                <div class="leave-info-label">End Date</div>
                <div class="leave-info-value">${endDate}</div>
            </div>
        </div>
        <div class="leave-info-item">
            <i class="fas fa-clock"></i>
            <div>
                <div class="leave-info-label">Duration</div>
                <div class="leave-info-value">${diffDays} day${diffDays > 1 ? 's' : ''}</div>
            </div>
        </div>
        <div class="leave-info-item">
            <i class="fas fa-calendar-day"></i>
            <div>
                <div class="leave-info-label">Submitted</div>
                <div class="leave-info-value">${new Date(req.created_at).toLocaleDateString()}</div>
            </div>
        </div>
    </div>
    ${req.reason ? `
    <div class="leave-reason-box">
        <div class="leave-reason-label">
            <i class="fas fa-comment-alt"></i> Reason
        </div>
        <div class="leave-reason-text">${req.reason}</div>
    </div>
    ` : ''}
    ${hasAttachment ? `
    <div class="leave-attachment" style="margin-top: 10px;">
        <a href="${req.attachment_path}" target="_blank" style="display: flex; align-items: center; gap: 8px; padding: 10px; background: rgba(25,211,197,0.1); border: 1px solid rgba(25,211,197,0.3); border-radius: 6px; text-decoration: none; color: var(--primary-accent);">
            <i class="fas fa-paperclip"></i>
            <span>View Attachment: ${req.attachment_path.split('/').pop()}</span>
        </a>
    </div>
    ` : ''}
    ${req.admin_remark ? `
    <div class="admin-remark-box" style="margin-top: 10px; background: rgba(25,211,197,0.1); border: 1px solid rgba(25,211,197,0.3); border-radius: 6px; padding: 10px;">
        <div style="font-size: 11px; color: var(--text-muted); margin-bottom: 5px;">
            <i class="fas fa-comment"></i> Admin Remark:
        </div>
        <div style="font-size: 12px; color: var(--text-primary);">${req.admin_remark}</div>
    </div>
    ` : ''}
    <div class="leave-footer">
        <span><i class="fas fa-info-circle"></i> Request ID: #${req.id}</span>
        ${req.admin_response ? `<span><i class="fas fa-comment"></i> ${req.admin_response}</span>` : ''}
    </div>
</div>
`;
            });
            container.innerHTML = html;
        } else {
            container.innerHTML = `
                <div class="empty-state">
                    <i class="fas fa-inbox"></i>
                    <h4>No leave requests found</h4>
                    <p>Click "New Leave Request" to submit your first request</p>
                </div>
            `;
        }
    })
    .catch(e => {
        console.error('Load leave requests error:', e);
        container.innerHTML = `
            <div class="empty-state">
                <i class="fas fa-exclamation-triangle"></i>
                <h4>Error loading requests</h4>
                <p>Please try again later</p>
            </div>
        `;
    });
}

// Filter Leave Requests
function filterLeaveRequests(status) {
    const cards = document.querySelectorAll('.leave-request-card');
    cards.forEach(card => {
        const cardStatus = card.getAttribute('data-status');
        if (status === 'all' || cardStatus === status.toLowerCase()) {
            card.style.display = 'block';
            card.style.animation = 'slideIn 0.3s ease';
        } else {
            card.style.display = 'none';
        }
    });
}

// Initialize on page load
document.addEventListener('DOMContentLoaded', function() {
    if (document.getElementById('employeeLeaveSection')) {
        loadLeaveRequests();
    }
});
</script>
