<!-- === DAY OFF REQUESTS SECTION (FIXED FOR LIVE DATA) === -->
<div id="employeeLeavesSection" class="admin-section" style="display:none;">
<div class="leave-management-container" style="max-width: 1200px; margin: 0 auto; padding: 0;">
<!-- Header -->
<div class="leave-header">
<div>
<h2 class="leave-title">
<i class="fas fa-calendar-alt"></i>
