 <script>
// === DAY OFF FORM TOGGLE FUNCTION ===
function toggleDayOffForm() {
    const form = document.getElementById('newDayOffForm');
    const btn = document.getElementById('dayOffNewRequestBtn');
    
    if (form.style.display === 'none' || form.style.display === '') {
        form.style.display = 'block';
        if (btn) {
            btn.innerHTML = '<i class="fas fa-times"></i> Cancel';
        }
        form.scrollIntoView({ behavior: 'smooth', block: 'start' });
    } else {
        form.style.display = 'none';
        if (btn) {
            btn.innerHTML = '<i class="fas fa-plus"></i> New Day Off Request';
        }
        const requestForm = document.getElementById('dayOffRequestForm');
        if(requestForm) requestForm.reset();
    }
}

// === FILTER DAY OFF REQUESTS BY STATUS ===
function filterDayOffRequestsByStatus(status) {
    const cards = document.querySelectorAll('#dayOffList .leave-request-card');
    cards.forEach(card => {
        const cardStatus = card.getAttribute('data-status');
        if (status === 'all' || cardStatus === status.toLowerCase()) {
            card.style.display = 'block';
            card.style.animation = 'slideIn 0.3s ease';
        } else {
            card.style.display = 'none';
        }
    });
}

// === SUBMIT DAY OFF REQUEST ===
function submitDayOffRequest(event) {
    event.preventDefault();
    const btn = document.getElementById('dayOffSubmitBtn');
    const originalText = btn.innerHTML;
    const date = document.getElementById('dayOffDate').value;
    const type = document.getElementById('dayOffType').value;
    
    if (!date || !type) {
        showToast('Please fill in all required fields', 'error');
        return;
    }
    
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Submitting...';
    
    const formData = new FormData();
    formData.append('action', 'submit_day_off');
    formData.append('csrf_token', document.querySelector('input[name="csrf_token"]')?.value || '');
    formData.append('date', date);
    formData.append('end_date', date);
    formData.append('type', type);
    formData.append('reason', document.getElementById('dayOffReason').value);
    
    fetch('', {
        method: 'POST',
        body: formData,
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(r => {
        const contentType = r.headers.get('content-type');
        if (contentType && contentType.includes('application/json')) {
            return r.json();
        } else {
            throw new Error('Server returned HTML instead of JSON.');
        }
    })
    .then(data => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        if (data.success) {
            showToast('Day off request submitted successfully!', 'success');
            document.getElementById('dayOffRequestForm').reset();
            toggleDayOffForm();
            loadDayOffRequests();
        } else {
            showToast('Error: ' + (data.message || 'Failed to submit request'), 'error');
        }
    })
    .catch(e => {
        console.error('Submit error:', e);
        btn.disabled = false;
        btn.innerHTML = originalText;
        showToast('Error submitting request: ' + e.message, 'error');
    });
}

// === LOAD DAY OFF REQUESTS ===
function loadDayOffRequests() {
    const container = document.getElementById('dayOffList');
    if(!container) {
        console.error('❌ dayOffList container not found!');
        return;
    }
    
    container.innerHTML = `
        <div class="loading-state">
            <i class="fas fa-spinner fa-spin"></i>
            <span>Loading your requests...</span>
        </div>
    `;
    
    fetch('?action=get_day_off_requests')
    .then(r => r.json())
    .then(data => {
        if (data.success && data.requests && data.requests.length > 0) {
            let html = '';
            data.requests.forEach(req => {
                const statusClass = req.status.toLowerCase();
                const statusIcon = statusClass === 'approved' ? 'fa-check-circle' :
                    (statusClass === 'rejected' ? 'fa-times-circle' : 'fa-clock');
                const startDate = new Date(req.start_date).toLocaleDateString('en-US', {
                    year: 'numeric', month: 'short', day: 'numeric'
                });
                let durationText = "1 Day";
                if (req.type && req.type.includes('Half')) {
                    durationText = "Half Day";
                }
                
                html += `
                <div class="leave-request-card" data-status="${statusClass}">
                    <div class="leave-card-header">
                        <div class="leave-type-badge">
                            <span class="leave-type">${req.type || 'Day Off'} Request</span>
                        </div>
                        <span class="leave-status ${statusClass}">
                            <i class="fas ${statusIcon}"></i> ${req.status}
                        </span>
                    </div>
                    <div class="leave-card-body">
                        <div class="leave-info-item">
                            <i class="fas fa-calendar-alt"></i>
                            <div>
                                <div class="leave-info-label">Date</div>
                                <div class="leave-info-value">${startDate}</div>
                            </div>
                        </div>
                        <div class="leave-info-item">
                            <i class="fas fa-clock"></i>
                            <div>
                                <div class="leave-info-label">Duration</div>
                                <div class="leave-info-value">${durationText}</div>
                            </div>
                        </div>
                        <div class="leave-info-item">
                            <i class="fas fa-calendar-day"></i>
                            <div>
                                <div class="leave-info-label">Submitted</div>
                                <div class="leave-info-value">${new Date(req.created_at).toLocaleDateString()}</div>
                            </div>
                        </div>
                    </div>
                    ${req.reason ? `
                    <div class="leave-reason-box">
                        <div class="leave-reason-label">
                            <i class="fas fa-comment-alt"></i> Reason
                        </div>
                        <div class="leave-reason-text">${req.reason}</div>
                    </div>
                    ` : ''}
                    <div class="leave-footer">
                        <span><i class="fas fa-info-circle"></i> Request ID: #${req.id}</span>
                        ${req.admin_remark ? `<span><i class="fas fa-comment"></i> ${req.admin_remark}</span>` : ''}
                    </div>
                </div>
                `;
            });
            container.innerHTML = html;
        } else {
            container.innerHTML = `
                <div class="empty-state">
                    <i class="fas fa-inbox"></i>
                    <h4>No day off requests found</h4>
                    <p>Click "New Day Off Request" to submit your first request</p>
                </div>
            `;
        }
    })
    .catch(e => {
        console.error('Load day off requests error:', e);
        container.innerHTML = `
            <div class="empty-state">
                <i class="fas fa-exclamation-triangle"></i>
                <h4>Error loading requests</h4>
                <p>Please try again later</p>
            </div>
        `;
    });
}

// === INITIALIZATION ===
document.addEventListener('DOMContentLoaded', function() {
    const dayOffSection = document.getElementById('employeeLeavesSection');
    if (dayOffSection && dayOffSection.style.display !== 'none') {
        loadDayOffRequests();
    }
});


// === MULTI-DATE SELECTION - FIXED ===
// IMPORTANT: This MUST be outside any function to persist across calls
window.selectedDates = window.selectedDates || [];

function addSelectedDate() {
    const dateInput = document.getElementById('dayOffDate');
    const selectedDate = dateInput.value;
    
    console.log('Adding date:', selectedDate); // Debug log
    
    if (!selectedDate) {
        showToast('Please select a date first', 'error');
        return;
    }
    
    // Check if date already selected
    if (window.selectedDates.includes(selectedDate)) {
        showToast('This date is already selected', 'warning');
        return;
    }
    
    // Check if date is in the past
    const today = new Date().toISOString().split('T')[0];
    if (selectedDate < today) {
        showToast('Cannot select past dates', 'error');
        return;
    }
    
    // Add to array
    window.selectedDates.push(selectedDate);
    
    // Sort dates
    window.selectedDates.sort();
    
    console.log('Current dates:', window.selectedDates); // Debug log
    
    // Update display
    updateSelectedDatesDisplay();
    
    // Clear date input
    dateInput.value = '';
    
    showToast('Date added successfully', 'success');
}

function removeSelectedDate(dateToRemove) {
    console.log('Removing date:', dateToRemove); // Debug log
    window.selectedDates = window.selectedDates.filter(d => d !== dateToRemove);
    updateSelectedDatesDisplay();
}

function updateSelectedDatesDisplay() {
    const container = document.getElementById('selectedDatesContainer');
    const noDatesMsg = document.getElementById('noDatesMessage');
    const hiddenInput = document.getElementById('allSelectedDates');
    
    console.log('Updating display, dates:', window.selectedDates); // Debug log
    
    if (!container) {
        console.error('selectedDatesContainer not found!');
        return;
    }
    
    // Update hidden input
    if (hiddenInput) {
        hiddenInput.value = window.selectedDates.join(',');
    }
    
    // Clear container
    container.innerHTML = '';
    
    if (window.selectedDates.length === 0) {
        container.innerHTML = '<span style="color: var(--text-muted); font-size: 13px;" id="noDatesMessage"><i class="fas fa-info-circle"></i> No dates selected yet</span>';
        if (noDatesMsg) noDatesMsg.style.display = 'inline';
    } else {
        if (noDatesMsg) noDatesMsg.style.display = 'none';
        
        window.selectedDates.forEach(date => {
            const dateObj = new Date(date);
            const formattedDate = dateObj.toLocaleDateString('en-US', { 
                month: 'short', 
                day: 'numeric', 
                year: 'numeric' 
            });
            
            const dateBadge = document.createElement('div');
            dateBadge.style.cssText = `
                background: rgba(25, 211, 197, 0.15);
                border: 1px solid rgba(25, 211, 197, 0.3);
                color: var(--primary-accent);
                padding: 6px 12px;
                border-radius: 20px;
                font-size: 12px;
                font-weight: 600;
                display: flex;
                align-items: center;
                gap: 6px;
                animation: slideIn 0.3s ease;
            `;
            
            dateBadge.innerHTML = `
                <i class="fas fa-calendar-check"></i>
                ${formattedDate}
                <button type="button" onclick="removeSelectedDate('${date}')" 
                    style="background: none; border: none; color: inherit; cursor: pointer; padding: 0; margin-left: 4px;">
                    <i class="fas fa-times"></i>
                </button>
            `;
            
            container.appendChild(dateBadge);
        });
    }
}

// === FIXED SUBMIT FUNCTION ===
function submitDayOffRequest(event) {
    event.preventDefault();
    
    console.log('Submitting request, dates:', window.selectedDates); // Debug log
    
    // Validate at least one date selected
    if (window.selectedDates.length === 0) {
        showToast('Please select at least one date', 'error');
        return;
    }
    
    const btn = document.getElementById('dayOffSubmitBtn');
    const originalText = btn.innerHTML;
    const type = document.getElementById('dayOffType').value;
    
    if (!type) {
        showToast('Please select a type', 'error');
        return;
    }
    
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Submitting...';
    
    const formData = new FormData();
    formData.append('action', 'submit_day_off');
    formData.append('csrf_token', document.querySelector('input[name="csrf_token"]')?.value || '');
    formData.append('dates', window.selectedDates.join(',')); // ✅ Send ALL dates
    formData.append('type', type);
    formData.append('reason', document.getElementById('dayOffReason').value);
    
    fetch('', {
        method: 'POST',
        body: formData,
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(r => {
        const contentType = r.headers.get('content-type');
        if (contentType && contentType.includes('application/json')) {
            return r.json();
        } else {
            throw new Error('Server returned HTML instead of JSON.');
        }
    })
    .then(data => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        if (data.success) {
            showToast(`Day off request submitted for ${window.selectedDates.length} date(s)!`, 'success');
            // Reset for next request
            window.selectedDates = [];
            updateSelectedDatesDisplay();
            document.getElementById('dayOffRequestForm').reset();
            toggleDayOffForm();
            loadDayOffRequests();
        } else {
            showToast('Error: ' + (data.message || 'Failed to submit request'), 'error');
        }
    })
    .catch(e => {
        console.error('Submit error:', e);
        btn.disabled = false;
        btn.innerHTML = originalText;
        showToast('Error submitting request: ' + e.message, 'error');
    });
}

// === UPDATED LOAD FUNCTION TO SHOW INDIVIDUAL DATES ===
function loadDayOffRequests() {
    const container = document.getElementById('dayOffList');
    if(!container) return;
    
    container.innerHTML = `
        <div class="loading-state">
            <i class="fas fa-spinner fa-spin"></i>
            <span>Loading your requests...</span>
        </div>
    `;
    
    fetch('?action=get_day_off_requests')
    .then(r => r.json())
    .then(data => {
        if (data.success && data.requests && data.requests.length > 0) {
            let html = '';
            data.requests.forEach(req => {
                const statusClass = req.status.toLowerCase();
                const statusIcon = statusClass === 'approved' ? 'fa-check-circle' :
                    (statusClass === 'rejected' ? 'fa-times-circle' : 'fa-clock');
                
                // ✅ Use individual dates if available
                let dateDisplay = '';
                if (req.individual_dates && req.individual_dates.length > 0) {
                    if (req.individual_dates.length === 1) {
                        dateDisplay = req.formatted_dates[0];
                    } else {
                        dateDisplay = req.formatted_dates.join(', ');
                    }
                } else {
                    // Fallback to old format
                    dateDisplay = new Date(req.start_date).toLocaleDateString('en-US', {
                        year: 'numeric', month: 'short', day: 'numeric'
                    });
                }
                
                let durationText = `${req.individual_dates ? req.individual_dates.length : 1} Day`;
                if (req.type && req.type.includes('Half')) {
                    durationText = "Half Day";
                }
                
                html += `
                <div class="leave-request-card" data-status="${statusClass}">
                    <div class="leave-card-header">
                        <div class="leave-type-badge">
                            <span class="leave-type">${req.type || 'Day Off'} Request</span>
                        </div>
                        <span class="leave-status ${statusClass}">
                            <i class="fas ${statusIcon}"></i> ${req.status}
                        </span>
                    </div>
                    <div class="leave-card-body">
                        <div class="leave-info-item">
                            <i class="fas fa-calendar-alt"></i>
                            <div>
                                <div class="leave-info-label">Date(s)</div>
                                <div class="leave-info-value">${dateDisplay}</div>
                            </div>
                        </div>
                        <div class="leave-info-item">
                            <i class="fas fa-clock"></i>
                            <div>
                                <div class="leave-info-label">Duration</div>
                                <div class="leave-info-value">${durationText}</div>
                            </div>
                        </div>
                        <div class="leave-info-item">
                            <i class="fas fa-calendar-day"></i>
                            <div>
                                <div class="leave-info-label">Submitted</div>
                                <div class="leave-info-value">${new Date(req.created_at).toLocaleDateString()}</div>
                            </div>
                        </div>
                    </div>
                    ${req.reason ? `
                    <div class="leave-reason-box">
                        <div class="leave-reason-label">
                            <i class="fas fa-comment-alt"></i> Reason
                        </div>
                        <div class="leave-reason-text">${req.reason}</div>
                    </div>
                    ` : ''}
                    <div class="leave-footer">
                        <span><i class="fas fa-info-circle"></i> Request ID: #${req.id}</span>
                        ${req.admin_remark ? `<span><i class="fas fa-comment"></i> ${req.admin_remark}</span>` : ''}
                    </div>
                </div>
                `;
            });
            container.innerHTML = html;
        } else {
            container.innerHTML = `
                <div class="empty-state">
                    <i class="fas fa-inbox"></i>
                    <h4>No day off requests found</h4>
                    <p>Click "New Day Off Request" to submit your first request</p>
                </div>
            `;
        }
    })
    .catch(e => {
        console.error('Load day off requests error:', e);
        container.innerHTML = `
            <div class="empty-state">
                <i class="fas fa-exclamation-triangle"></i>
                <h4>Error loading requests</h4>
                <p>Please try again later</p>
            </div>
        `;
    });
}

</script>


