                        } elseif (stripos($notif['type'], 'day') !== false || stripos($notif['title'], 'Day-Off') !== false) {
                            $redirectModule = 'dayoff';
                        } elseif (stripos($notif['type'], 'overtime') !== false || stripos($notif['title'], 'Overtime') !== false) {
                            $redirectModule = 'overtime';
                        } elseif (stripos($notif['type'], 'report') !== false || stripos($notif['title'], 'Report') !== false) {
                            $redirectModule = 'reports';
                        } elseif (stripos($notif['type'], 'audit') !== false || stripos($notif['title'], 'Audit') !== false) {
                            $redirectModule = 'audittrail';
                        } elseif (stripos($notif['type'], 'attendance') !== false || stripos($notif['title'], 'Attendance') !== false) {
                            $redirectModule = 'attendance';
                        } elseif (stripos($notif['type'], 'fingerprint') !== false || stripos($notif['title'], 'Fingerprint') !== false) {
                            $redirectModule = 'fingerprint';
                        }
                        $isRead = $notif['is_read'] == 1;
                        $created = new DateTime($notif['created_at']);
                        $formattedDate = $created->format('F j, Y – g:i A');
                    ?>
                    <div class="notification-item <?= $isRead ? 'read' : 'unread' ?>" 
                         data-id="<?= $notif['id'] ?>" 
                         data-module="<?= $redirectModule ?>">
                        <div class="notification-content" onclick="handleNotificationClick(<?= $notif['id'] ?>, '<?= $redirectModule ?>')">
                            <div class="notification-title" style="font-weight: 600; color: #00ffd0;"><?= htmlspecialchars($notif['title']) ?></div>
                            <div class="notification-message" style="color: #b6c2d1;"><?= htmlspecialchars($notif['message']) ?></div>
                            <div class="notification-time" style="color: #b6c2d1;">
                                <i class="far fa-clock"></i> <?= $formattedDate ?>
                            </div>
                        </div>
                        <button class="notification-clear" onclick="clearSingleNotification(<?= $notif['id'] ?>, event)" title="Clear">
                            <i class="fas fa-times"></i>
                        </button>
                    </div>
                    <?php endforeach; ?>
                    <?php endif; ?>
                </div>
            </div>
            <div style="padding: 8px 16px; background: #232b3a; border-radius: 8px; font-size: 13px; color: #00ffd0; min-width: 120px; text-align: right;">
                <strong><?= htmlspecialchars($_SESSION['name']) ?></strong><br>
                <small style="color: #b6c2d1;">Admin User</small>
            </div>
