        <?php
        // ✅ Fetch ONLY Leave requests (request_category = 'leave')
        $stmt = $pdo->query("SELECT * FROM day_off_requests WHERE request_category = 'leave' ORDER BY created_at DESC");
        $allRequests = $stmt->fetchAll(PDO::FETCH_ASSOC);
        
        // Initialize counters for stats
        $pendingCount = 0;
        $approvedCount = 0;
        $rejectedCount = 0;

        if (empty($allRequests)) {
            // Empty state
            echo '<div class="leave-empty-state">
                    <i class="fas fa-inbox"></i>
                    <h3>No leave requests yet</h3>
                    <p>Requests will appear here as employees submit them</p>
                </div>';
        } else {
            foreach ($allRequests as $request) {
                // Get Employee Details
                $empStmt = $pdo->prepare("SELECT * FROM employees WHERE id = ?");
                $empStmt->execute([$request['employee_id']]);
                $employee = $empStmt->fetch(PDO::FETCH_ASSOC);
                
                // Calculate Duration
                $startDate = new DateTime($request['start_date']);
                $endDate = new DateTime($request['end_date']);
                $duration = $startDate->diff($endDate)->days + 1;
                
                // Determine Status Styles
                $status = $request['status'];
                $statusLower = strtolower($status);
                $statusClass = 'status-' . $statusLower;
                
                // Update Counters (for stats cards)
                if($statusLower === 'pending') $pendingCount++;
                elseif($statusLower === 'approved') $approvedCount++;
                elseif($statusLower === 'rejected') $rejectedCount++;

                // Avatar Initials Logic
                $initials = strtoupper(substr($employee['name'], 0, 1));
                if (strpos($employee['name'], ' ') !== false) {
                    $initials .= strtoupper(substr($employee['name'], strpos($employee['name'], ' ') + 1, 1));
                }
                ?>
                
                <!-- Modern Leave Request Card -->
                <div class="leave-card <?= $statusClass ?>" 
                    data-status="<?= htmlspecialchars($statusLower) ?>" 
                    data-name="<?= htmlspecialchars(strtolower($employee['name'])) ?>" 
                    data-eid="<?= htmlspecialchars(strtolower($employee['employee_id'])) ?>">
                    
                    <!-- Left Section: Employee Info -->
                    <div class="leave-card-left">
                        <!-- Employee Avatar -->
                        <div class="leave-card-avatar">
                            <?php if (!empty($employee['photo_path']) && file_exists($employee['photo_path'])): ?>
                                <img src="<?= htmlspecialchars($employee['photo_path']) ?>" alt="<?= htmlspecialchars($employee['name']) ?>">
                            <?php else: ?>
                                <span><?= htmlspecialchars($initials) ?></span>
                            <?php endif; ?>
                        </div>
                        
                        <!-- Employee & Request Details -->
                        <div class="leave-card-info">
                            <div class="emp-name"><?= htmlspecialchars($employee['name']) ?></div>
                            <div class="emp-meta">
                                <?= htmlspecialchars($employee['employee_id']) ?> • <?= htmlspecialchars($employee['department'] ?? 'N/A') ?>
                            </div>
                            <div class="leave-dates">
                                <i class="fas fa-calendar-alt"></i>
                                <?= date('M d, Y', strtotime($request['start_date'])) ?> → <?= date('M d, Y', strtotime($request['end_date'])) ?>
                                <span class="duration-badge"><?= $duration ?> day<?= $duration !== 1 ? 's' : '' ?></span>
                            </div>
                            <div class="leave-reason-box">
                                <strong>Reason:</strong> <?= htmlspecialchars($request['reason']) ?>
                            </div>
                        </div>
                    </div>

<!-- === IMPROVED ATTACHMENT VIEWING === -->
