    // === SAVE SCHEDULE ===
    function saveSchedule(event) {
        event.preventDefault();
        
        // Validate form data
        const employeeId = document.getElementById('scheduleEmployeeId').value;
        if (!employeeId) {
            showToast('Error: Employee ID not set. Please close and reopen the schedule dialog.', 'error');
            return;
        }
        
        const formData = new FormData(document.getElementById('scheduleForm'));
        formData.append('action', 'update_employee_schedule');
        
        const btn = event.target.querySelector('button[type="submit"]');
        const originalText = btn.innerHTML;
        btn.disabled = true;
        btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Saving...';
        
        fetch('', {
            method: 'POST',
            body: formData,
            headers: { 'X-Requested-With': 'XMLHttpRequest' }
        })
        .then(r => {
            if (!r.ok) {
                throw new Error(`HTTP ${r.status}: ${r.statusText}`);
            }
            const contentType = r.headers.get('content-type');
            if (!contentType || !contentType.includes('application/json')) {
                throw new Error('Server returned non-JSON response');
            }
            return r.json();
        })
        .then(data => {
            btn.disabled = false;
            btn.innerHTML = originalText;
            if(data.success) {
                showToast(data.message, 'success');
                closeScheduleModal();
                if(typeof loadEmployeesList === 'function') loadEmployeesList();
                if(typeof loadFingerprintData === 'function') loadFingerprintData();
            } else {
                showToast('Error: ' + (data.message || 'Failed to save schedule'), 'error');
            }
        })
        .catch(e => {
            btn.disabled = false;
            btn.innerHTML = originalText;
            console.error('Schedule save error:', e);
            showToast('Error: ' + e.message, 'error');
        });
    }

