// === ✅ FIXED: DAY OFF REQUESTS LIVE FILTER (COMPLETE WORKING VERSION) ===
function filterDayOffRequests() {
    console.log('🔄 Filtering day off requests...');
    
    // 1. Get Filter Values (with safety checks)
    const statusFilter = document.getElementById('dayOffStatusFilter')?.value || 'All';
    const startDateFilter = document.getElementById('dayOffStartDate')?.value || '';
    const endDateFilter = document.getElementById('dayOffEndDate')?.value || '';
    const employeeSearch = document.getElementById('dayOffEmployeeSearch')?.value.toLowerCase().trim() || '';
    
    // 2. Get All Request Cards
    const records = document.querySelectorAll('#dayOffRecordsList .modern-request-card');
    
    if (records.length === 0) {
        console.log('⚠️ No request cards found!');
        return;
    }
    
    let visibleCount = 0;
    let pending = 0, approved = 0, rejected = 0;
    
    // 3. Remove Any Existing Empty State First
    const existingEmpty = document.querySelector('#dayOffRecordsList .filter-empty-state');
    if (existingEmpty) existingEmpty.remove();
    
    // 4. Filter Each Record
    records.forEach(record => {
        const status = record.getAttribute('data-status');
        const startDate = record.getAttribute('data-start');
        const endDate = record.getAttribute('data-end');
        const employee = record.getAttribute('data-employee')?.toLowerCase() || '';
        
        let show = true;
        
        // Status Filter
        if (statusFilter !== 'All' && status !== statusFilter) {
            show = false;
        }
        
        // Date Range Filter (From Date)
        if (startDateFilter && startDate) {
            if (startDate < startDateFilter) {
                show = false;
            }
        }
        
        // Date Range Filter (To Date)
        if (endDateFilter && endDate) {
            if (endDate > endDateFilter) {
                show = false;
            }
        }
        
        // Employee Search Filter
        if (employeeSearch && employee) {
            if (!employee.includes(employeeSearch)) {
                show = false;
            }
        }
        
        // Apply Display
        if (show) {
            record.style.display = 'flex';
            record.style.animation = 'slideIn 0.3s ease';
            record.style.opacity = '1';
            visibleCount++;
            
            // Count for Stats
            if (status === 'Pending') pending++;
            else if (status === 'Approved') approved++;
            else if (status === 'Rejected') rejected++;
        } else {
            record.style.display = 'none';
            record.style.animation = 'none';
            record.style.opacity = '0';
        }
    });
    
    // 5. Update Stat Cards with Animation
    animateValue('pendingCount', pending);
    animateValue('approvedCount', approved);
    animateValue('rejectedCount', rejected);
    animateValue('totalCount', visibleCount);
    
    // 6. Show Empty State if No Results
    const listContainer = document.getElementById('dayOffRecordsList');
    if (visibleCount === 0 && records.length > 0) {
        const emptyState = document.createElement('div');
        emptyState.className = 'filter-empty-state';
        emptyState.innerHTML = `
            <div style="text-align: center; padding: 60px 20px; grid-column: 1/-1;">
                <div style="font-size: 64px; margin-bottom: 20px; opacity: 0.3;">🔍</div>
                <div style="font-size: 18px; color: var(--text-primary); font-weight: 600; margin-bottom: 10px;">
                    No requests match your filters
                </div>
                <div style="font-size: 14px; color: var(--text-muted);">
                    Try adjusting your search criteria
                </div>
            </div>`;
        listContainer.appendChild(emptyState);
    }
    
    console.log(`✅ Filter applied: ${visibleCount}/${records.length} requests visible`);
}

// === ✅ CRITICAL: ATTACH EVENT LISTENERS ON PAGE LOAD ===
document.addEventListener('DOMContentLoaded', function() {
    console.log('🔧 Setting up Day Off filter event listeners...');
    
    // Status Filter
    const statusFilter = document.getElementById('dayOffStatusFilter');
    if (statusFilter) {
        statusFilter.addEventListener('change', function() {
            console.log('📊 Status filter changed to:', this.value);
            filterDayOffRequests();
        });
        console.log('✅ Status filter listener attached');
    } else {
        console.error('❌ dayOffStatusFilter element NOT found!');
    }
    
    // From Date Filter
    const fromDateFilter = document.getElementById('dayOffStartDate');
    if (fromDateFilter) {
        fromDateFilter.addEventListener('change', function() {
            console.log('📅 From date changed to:', this.value);
            filterDayOffRequests();
        });
        console.log('✅ From date filter listener attached');
    } else {
        console.error('❌ dayOffStartDate element NOT found!');
    }
    
    // To Date Filter
    const toDateFilter = document.getElementById('dayOffEndDate');
    if (toDateFilter) {
        toDateFilter.addEventListener('change', function() {
            console.log('📅 To date changed to:', this.value);
            filterDayOffRequests();
        });
        console.log('✅ To date filter listener attached');
    } else {
        console.error('❌ dayOffEndDate element NOT found!');
    }
    
    // Employee Search Filter (Live Typing)
    const employeeSearch = document.getElementById('dayOffEmployeeSearch');
    if (employeeSearch) {
        // Debounce for better performance
        let debounceTimer;
        employeeSearch.addEventListener('input', function() {
            clearTimeout(debounceTimer);
            debounceTimer = setTimeout(() => {
                console.log('🔍 Employee search changed to:', this.value);
                filterDayOffRequests();
            }, 300); // Wait 300ms after typing stops
        });
        console.log('✅ Employee search listener attached');
    } else {
        console.error('❌ dayOffEmployeeSearch element NOT found!');
    }
    
    // Initial Load - Run filter once on page load
    setTimeout(() => {
        console.log('🚀 Running initial filter...');
        filterDayOffRequests();
    }, 500);
});

// === ✅ HELPER: ANIMATE VALUE COUNTER ===
function animateValue(id, end, suffix = '') {
    const obj = document.getElementById(id);
    if (!obj) {
        console.warn('⚠️ Element not found:', id);
        return;
    }
    let start = 0;
    const duration = 1000;
    let startTimestamp = null;
    const step = (timestamp) => {
        if (!startTimestamp) startTimestamp = timestamp;
        const progress = Math.min((timestamp - startTimestamp) / duration, 1);
        const value = Math.floor(progress * (end - start) + start);
        obj.innerHTML = value + suffix;
        if (progress < 1) {
            window.requestAnimationFrame(step);
        } else {
            obj.innerHTML = end + suffix;
        }
    };
    window.requestAnimationFrame(step);
}
