.action-icon-btn.edit {
    color: var(--primary-accent);
    background: rgba(25, 211, 197, 0.1);
}

.action-icon-btn.edit:hover {
    background: rgba(25, 211, 197, 0.25);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(25, 211, 197, 0.3);
}

.action-icon-btn.delete {
    color: #ef4444;
    background: rgba(239, 68, 68, 0.1);
}

.action-icon-btn.delete:hover {
    background: rgba(239, 68, 68, 0.25);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(239, 68, 68, 0.3);
}

.action-icon-btn.schedule {
    color: #17a2b8;
    background: rgba(23, 162, 184, 0.1);
}

.action-icon-btn.schedule:hover {
    background: rgba(23, 162, 184, 0.25);
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(23, 162, 184, 0.3);
}

/* Empty State */
.empty-state {
    text-align: center;
    padding: 80px 20px;
    background: rgba(255, 255, 255, 0.02);
    border-radius: 16px;
    border: 2px dashed rgba(255, 255, 255, 0.1);
}

.empty-state i {
    font-size: 64px;
    color: var(--text-muted);
    opacity: 0.5;
    margin-bottom: 20px;
}

.empty-state h3 {
    color: #ffffff;
    font-size: 20px;
    margin-bottom: 10px;
}

.empty-state p {
    color: var(--text-muted);
    font-size: 14px;
    margin-bottom: 20px;
}

/* Responsive Design */
@media (max-width: 1200px) {
    .modern-employee-table {
        font-size: 13px;
    }
    
    .col-position, .col-birthday {
        display: none;
    }
}

@media (max-width: 992px) {
    #employeesSection {
        padding: 20px;
    }
    
    .employees-header {
        flex-direction: column;
        align-items: stretch;
    }
    
    .add-employee-btn {
        width: 100%;
        justify-content: center;
    }
    
    .modern-employee-table {
        font-size: 12px;
    }
    
    .col-dept {
        display: none;
    }
}

@media (max-width: 768px) {
    .employees-title h2 {
        font-size: 24px;
    }
    
    .employee-search-input {
        padding: 14px 16px 14px 45px;
        font-size: 14px;
    }
    
    .modern-employee-table thead {
        display: none;
    }
    
    .modern-employee-table tbody tr {
        display: block;
        margin-bottom: 16px;
        background: rgba(255, 255, 255, 0.03);
        border-radius: 12px;
        padding: 16px;
        border: 1px solid rgba(255, 255, 255, 0.05);
    }
    
    .modern-employee-table td {
        display: flex;
        justify-content: space-between;
        align-items: center;
        padding: 10px 0;
        border-bottom: 1px solid rgba(255, 255, 255, 0.05);
        white-space: normal;
        max-width: none;
    }
    
    .modern-employee-table td:last-child {
        border-bottom: none;
    }
    
    .modern-employee-table td::before {
        content: attr(data-label);
        font-weight: 700;
        color: var(--primary-accent);
        font-size: 12px;
        text-transform: uppercase;
        letter-spacing: 0.5px;
        margin-right: 10px;
    }
    
    .action-btn-group {
        width: 100%;
        justify-content: flex-end;
    }
    
    .emp-avatar-wrapper {
        flex-direction: column;
        text-align: center;
        gap: 10px;
    }
    
    .emp-name-text {
        max-width: none;
    }
}

@media (max-width: 480px) {
    .employees-title h2 {
        font-size: 20px;
    }
    
    .add-employee-btn {
        padding: 12px 20px;
        font-size: 13px;
    }
    
    .action-icon-btn {
        width: 32px;
        height: 32px;
        padding: 8px;
    }
}

/* Loading State */
.table-loading {
    text-align: center;
    padding: 60px 20px;
    color: var(--text-muted);
}

.table-loading i {
    font-size: 48px;
    color: var(--primary-accent);
    margin-bottom: 15px;
    animation: spin 1s linear infinite;
}

@keyframes spin {
    from { transform: rotate(0deg); }
    to { transform: rotate(360deg); }
}


/* 1. Force Table to Fit Container */
.table-container {
    overflow-x: hidden !important; /* Hides horizontal scrollbar */
    border-radius: 16px;
    width: 100%;
}

.modern-employee-table {
    width: 100% !important;
    table-layout: fixed !important; /* Ensures columns respect defined widths */
    border-collapse: separate;
    border-spacing: 0;
}

/* 2. Reduce Cell Padding for Compactness */
.modern-employee-table th, 
.modern-employee-table td {
    padding: 12px 10px !important; /* Reduced from 18px */
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

/* 3. Optimize Column Widths */
.col-id { width: 100px; }
.col-name { width: 200px; }
.col-position { width: 150px; }
.col-dept { width: 150px; }
.col-birthday { width: 110px; }
.col-finger { width: 80px; text-align: center; }
.col-role { width: 90px; text-align: center; }

/* 4. Compact Action Buttons (The Main Fix) */
.col-actions { 
    width: 110px !important; /* Reduced from 140px */
    text-align: center; 
    padding: 0 5px !important;
}

.action-btn-group {
    display: flex;
    justify-content: center;
    gap: 6px !important; /* Reduced gap between icons */
    align-items: center;
}

.action-icon-btn {
    width: 28px !important; /* Reduced from 36px */
    height: 28px !important;
    padding: 0 !important;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 14px; /* Slightly smaller icon */
}

/* 5. Ensure Section Padding Doesn't Squeeze Table */
#employeesSection {
    padding: 20px !important; /* Reduced from 30px */
}

/* 6. Fix Scrollbar Styling (Optional - makes it invisible if it does appear) */
.table-container::-webkit-scrollbar {
    height: 0px;
    background: transparent;
}


/* Modern Leave Management Styles */
.modern-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 32px;
    padding: 24px;
    background: linear-gradient(135deg, rgba(25, 211, 197, 0.05) 0%, rgba(0, 224, 208, 0.05) 100%);
    border-radius: 16px;
    border: 1px solid rgba(25, 211, 197, 0.1);
}

.header-content h2 {
    margin: 0 0 8px 0;
    font-size: 24px;
    font-weight: 700;
    color: #ffffff;
}

.section-subtitle {
    margin: 0;
    font-size: 14px;
    color: #94a3b8;
}

.header-actions {
    display: flex;
    gap: 12px;
}

.btn-icon {
    width: 40px;
    height: 40px;
    border-radius: 10px;
    border: 1px solid rgba(25, 211, 197, 0.2);
    background: rgba(25, 211, 197, 0.1);
    color: #19D3C5;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: all 0.3s ease;
}

.btn-icon:hover {
    background: rgba(25, 211, 197, 0.2);
    transform: translateY(-2px);
}

/* Stats Grid */
.stats-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 20px;
    margin-bottom: 32px;
}

.stat-card {
    padding: 24px;
    border-radius: 16px;
    display: flex;
    align-items: center;
    gap: 16px;
    transition: all 0.3s ease;
    border: 1px solid;
}

.stat-card.pending {
    background: linear-gradient(135deg, rgba(255, 193, 7, 0.1) 0%, rgba(255, 179, 0, 0.05) 100%);
    border-color: rgba(255, 193, 7, 0.2);
}

.stat-card.approved {
    background: linear-gradient(135deg, rgba(40, 167, 69, 0.1) 0%, rgba(34, 197, 94, 0.05) 100%);
    border-color: rgba(40, 167, 69, 0.2);
}

.stat-card.rejected {
    background: linear-gradient(135deg, rgba(220, 53, 69, 0.1) 0%, rgba(239, 68, 68, 0.05) 100%);
    border-color: rgba(220, 53, 69, 0.2);
}

.stat-icon {
    width: 56px;
    height: 56px;
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 24px;
}

.stat-card.pending .stat-icon {
    background: rgba(255, 193, 7, 0.15);
    color: #ffc107;
}

.stat-card.approved .stat-icon {
    background: rgba(40, 167, 69, 0.15);
    color: #28a745;
}

.stat-card.rejected .stat-icon {
    background: rgba(220, 53, 69, 0.15);
    color: #dc3545;
}

.stat-value {
    font-size: 32px;
    font-weight: 700;
    color: #ffffff;
    line-height: 1;
}

.stat-label {
    font-size: 14px;
    font-weight: 600;
    color: #e2e8f0;
    margin-top: 4px;
}

.stat-desc {
    font-size: 12px;
    color: #94a3b8;
}

/* Filter Bar */
.filter-bar {
    display: flex;
    gap: 16px;
    margin-bottom: 24px;
    flex-wrap: wrap;
}

.filter-group {
    min-width: 200px;
}

.modern-select {
    width: 100%;
    padding: 12px 16px;
    background: rgba(15, 23, 42, 0.6);
    border: 1px solid rgba(25, 211, 197, 0.2);
    border-radius: 10px;
    color: #ffffff;
    font-size: 14px;
    cursor: pointer;
    outline: none;
    transition: all 0.3s ease;
}

.modern-select:focus {
    border-color: #19D3C5;
    box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
}

.search-box {
    flex: 1;
    min-width: 300px;
    position: relative;
}

.modern-input {
    width: 100%;
    padding: 12px 44px 12px 16px;
    background: rgba(15, 23, 42, 0.6);
    border: 1px solid rgba(25, 211, 197, 0.2);
    border-radius: 10px;
    color: #ffffff;
    font-size: 14px;
    outline: none;
    transition: all 0.3s ease;
}

.modern-input:focus {
    border-color: #19D3C5;
    box-shadow: 0 0 0 3px rgba(25, 211, 197, 0.1);
}

.search-icon {
    position: absolute;
    right: 16px;
    top: 50%;
    transform: translateY(-50%);
    color: #94a3b8;
    font-size: 16px;
    pointer-events: none;
}

/* Leave Request Card */
.leave-request-card {
    background: linear-gradient(145deg, rgba(30, 41, 59, 0.8) 0%, rgba(15, 23, 42, 0.8) 100%);
    border: 1px solid rgba(25, 211, 197, 0.1);
    border-radius: 16px;
    padding: 24px;
    margin-bottom: 20px;
    transition: all 0.3s ease;
    animation: slideIn 0.3s ease;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.leave-request-card:hover {
    border-color: rgba(25, 211, 197, 0.3);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.3);
    transform: translateY(-2px);
}

.card-header {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 20px;
}

.employee-info {
    display: flex;
    align-items: center;
    gap: 16px;
}

.employee-avatar {
    width: 48px;
    height: 48px;
    border-radius: 12px;
    overflow: hidden;
    flex-shrink: 0;
}

.employee-avatar img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.employee-details {
    flex: 1;
}

.employee-name {
    margin: 0 0 6px 0;
    font-size: 16px;
    font-weight: 700;
    color: #ffffff;
}

.employee-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 13px;
    color: #94a3b8;
    flex-wrap: wrap;
}

.separator {
    color: #475569;
}

.status-badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    padding: 8px 16px;
    border-radius: 20px;
    font-size: 12px;
    font-weight: 600;
}

.status-badge.pending {
    background: rgba(255, 193, 7, 0.15);
    color: #ffc107;
    border: 1px solid rgba(255, 193, 7, 0.3);
}

.status-badge.approved {
    background: rgba(40, 167, 69, 0.15);
    color: #28a745;
    border: 1px solid rgba(40, 167, 69, 0.3);
}

.status-badge.rejected {
    background: rgba(220, 53, 69, 0.15);
    color: #dc3545;
    border: 1px solid rgba(220, 53, 69, 0.3);
}

.card-body {
    margin-bottom: 20px;
}

.reason-box {
    background: rgba(0, 0, 0, 0.2);
    padding: 16px;
    border-radius: 10px;
    margin-bottom: 12px;
    border-left: 3px solid #19D3C5;
}

.reason-label {
    font-weight: 600;
    color: #19D3C5;
    margin-right: 8px;
}

.reason-text {
    color: #e2e8f0;
    font-size: 14px;
}

.timestamp {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
    color: #64748b;
}

.card-actions {
    display: flex;
    gap: 12px;
    justify-content: flex-end;
}

.btn-approve, .btn-reject {
    padding: 10px 24px;
    border: none;
    border-radius: 8px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 8px;
    transition: all 0.3s ease;
}

.btn-approve {
    background: linear-gradient(135deg, #28a745 0%, #20c997 100%);
    color: #ffffff;
    box-shadow: 0 4px 12px rgba(40, 167, 69, 0.3);
}

.btn-approve:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(40, 167, 69, 0.4);
}

.btn-reject {
    background: linear-gradient(135deg, #dc3545 0%, #c82333 100%);
    color: #ffffff;
    box-shadow: 0 4px 12px rgba(220, 53, 69, 0.3);
}

.btn-reject:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(220, 53, 69, 0.4);
}

/* Responsive */
@media (max-width: 768px) {
    .modern-header {
        flex-direction: column;
        align-items: flex-start;
        gap: 16px;
    }
    
    .stats-grid {
        grid-template-columns: 1fr;
    }
    
    .filter-bar {
        flex-direction: column;
    }
    
    .search-box {
        min-width: 100%;
    }
    
    .card-header {
        flex-direction: column;
        gap: 16px;
    }
    
    .card-actions {
        justify-content: stretch;
    }
    
    .btn-approve, .btn-reject {
        flex: 1;
        justify-content: center;
    }
}
    /* === OVERVIEW PAGE UI FIX === */

/* Fix the attendance summary cards */
