    background: rgba(255, 255, 255, 0.95) !important;
    border: 1px solid rgba(25, 211, 197, 0.2) !important;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1) !important;
}

/* Fix the text labels (Present, Late, Absent) */
#overviewSection .record-name {
    color: #1e293b !important;
    font-weight: 600 !important;
    font-size: 15px !important;
}

/* Fix the record ID/text */
#overviewSection .record-id {
    color: #64748b !important;
    font-size: 13px !important;
}

/* Fix the count badges */
#overviewSection .record-badge {
    color: #1e293b !important;
    font-weight: 700 !important;
    background: rgba(25, 211, 197, 0.15) !important;
    border: 1px solid rgba(25, 211, 197, 0.3) !important;
}

/* Fix the icons */
#overviewSection .record-icon {
    background: rgba(25, 211, 197, 0.15) !important;
