/* === MODERN HOLIDAY MANAGEMENT UI === */

/* Section Header */
#holidaySection .section-header {
    background: linear-gradient(135deg, rgba(25, 211, 197, 0.1) 0%, rgba(0, 224, 208, 0.05) 100%);
    border: 1px solid rgba(25, 211, 197, 0.2);
    border-radius: 16px;
    padding: 24px 28px;
    margin-bottom: 24px;
    backdrop-filter: blur(10px);
}

#holidaySection .section-title {
    font-size: 20px;
    font-weight: 700;
    background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    margin-bottom: 8px;
    letter-spacing: -0.5px;
}

#holidaySection .section-subtitle {
    color: #94a3b8;
    font-size: 14px;
    font-weight: 400;
}

/* Holiday Cards Container */
#holidayList {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

/* Individual Holiday Card */
#holidayList .record-item {
    background: linear-gradient(145deg, rgba(30, 41, 59, 0.9) 0%, rgba(15, 23, 42, 0.9) 100%);
    border: 1px solid rgba(255, 255, 255, 0.08);
    border-radius: 16px;
    padding: 24px 28px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    position: relative;
    overflow: hidden;
    backdrop-filter: blur(10px);
}

/* Left border accent based on holiday type */
#holidayList .record-item::before {
    content: '';
    position: absolute;
    left: 0;
    top: 0;
    bottom: 0;
    width: 4px;
    background: linear-gradient(180deg, #19D3C5 0%, #00FFE0 100%);
    opacity: 0;
    transition: opacity 0.3s ease;
}

#holidayList .record-item:hover::before {
    opacity: 1;
}

#holidayList .record-item:hover {
    transform: translateX(4px);
    border-color: rgba(25, 211, 197, 0.3);
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4), 
                0 0 0 1px rgba(25, 211, 197, 0.1);
    background: linear-gradient(145deg, rgba(30, 41, 59, 0.95) 0%, rgba(15, 23, 42, 0.95) 100%);
}

/* Holiday Info Section */
#holidayList .record-info {
    display: flex;
    flex-direction: column;
    gap: 6px;
    flex: 1;
}

#holidayList .record-name {
    font-size: 16px;
    font-weight: 700;
    color: #ffffff;
    letter-spacing: -0.3px;
    line-height: 1.4;
}

#holidayList .record-id {
    font-size: 13px;
    color: #64748b;
    font-weight: 500;
    display: flex;
    align-items: center;
    gap: 8px;
}

/* Holiday Type Badges */
#holidayList .record-id span {
    padding: 4px 12px;
    border-radius: 20px;
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.5px;
    display: inline-flex;
    align-items: center;
    gap: 4px;
}

/* Regular Holiday - Red/Pink */
#holidayList .record-id span[style*="#dc3545"],
#holidayList .record-id span:contains("Regular") {
    background: rgba(239, 68, 68, 0.15);
    color: #f87171;
    border: 1px solid rgba(239, 68, 68, 0.3);
}

/* Special Holiday - Yellow/Orange */
#holidayList .record-id span[style*="#ffc107"],
#holidayList .record-id span:contains("Special") {
    background: rgba(251, 191, 36, 0.15);
    color: #fbbf24;
    border: 1px solid rgba(251, 191, 36, 0.3);
}

/* Special Working - Blue/Cyan */
#holidayList .record-id span[style*="#17a2b8"],
#holidayList .record-id span:contains("Working") {
    background: rgba(23, 162, 184, 0.15);
    color: #22d3ee;
    border: 1px solid rgba(23, 162, 184, 0.3);
}

/* Assign Employees Button */
#holidayList .action-button {
    background: linear-gradient(135deg, rgba(25, 211, 197, 0.1) 0%, rgba(0, 224, 208, 0.05) 100%);
    border: 1.5px solid rgba(25, 211, 197, 0.3);
    color: #19D3C5;
    padding: 12px 24px;
    border-radius: 12px;
    font-size: 13px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    display: flex;
    align-items: center;
    gap: 8px;
    white-space: nowrap;
    backdrop-filter: blur(10px);
}

#holidayList .action-button:hover {
    background: linear-gradient(135deg, rgba(25, 211, 197, 0.2) 0%, rgba(0, 224, 208, 0.1) 100%);
    border-color: rgba(25, 211, 197, 0.5);
    color: #00FFE0;
    transform: translateY(-2px);
    box-shadow: 0 8px 24px rgba(25, 211, 197, 0.25);
}

#holidayList .action-button i {
    font-size: 14px;
    transition: transform 0.3s ease;
}

#holidayList .action-button:hover i {
    transform: scale(1.1);
}

/* Refresh Button */
#holidaySection .action-button.primary {
    background: linear-gradient(135deg, #19D3C5 0%, #00FFE0 100%);
    border: none;
    color: #0f172a;
    padding: 12px 24px;
    border-radius: 12px;
    font-size: 13px;
    font-weight: 700;
    cursor: pointer;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    display: flex;
    align-items: center;
    gap: 8px;
    box-shadow: 0 4px 16px rgba(25, 211, 197, 0.3);
}

#holidaySection .action-button.primary:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 24px rgba(25, 211, 197, 0.4);
}

#holidaySection .action-button.primary i {
    transition: transform 0.5s ease;
}

#holidaySection .action-button.primary:hover i {
    transform: rotate(180deg);
}

/* Date Formatting */
#holidayList .record-id {
    font-family: 'Courier New', monospace;
    font-weight: 600;
}

/* Responsive Design */
@media (max-width: 768px) {
    #holidayList .record-item {
        flex-direction: column;
        align-items: flex-start;
        gap: 16px;
        padding: 20px;
    }
    
    #holidayList .action-button {
        width: 100%;
        justify-content: center;
    }
    
    #holidaySection .section-header {
        padding: 20px;
    }
}

/* Loading State */
#holidayList:has(.fa-spinner) {
    text-align: center;
    padding: 60px 20px;
}

/* Empty State */
#holidayList:empty::after {
    content: 'No holidays found';
    display: block;
    text-align: center;
    padding: 60px 20px;
    color: #64748b;
    font-size: 16px;
    background: rgba(255, 255, 255, 0.02);
    border-radius: 16px;
    border: 2px dashed rgba(255, 255, 255, 0.1);
}

/* Animation for new items */
@keyframes slideInHoliday {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

#holidayList .record-item {
    animation: slideInHoliday 0.4s ease-out;
}

