    <script>
    // === EXPORT FORMAT SELECTION ===
    let currentExportFormat = 'pdf';

    function setExportFormat(format) {
        currentExportFormat = format;
        
        // Update UI
        document.querySelectorAll('.format-option').forEach(opt => {
            opt.classList.remove('active');
        });
        
        if (format === 'pdf') {
            document.getElementById('formatPdf').classList.add('active');
        } else {
            document.getElementById('formatCsv').classList.add('active');
        }
        
        // Update button text
        const exportBtn = document.getElementById('exportBtn');
        if (exportBtn) {
            exportBtn.innerHTML = `<i class="fas fa-file-${format}"></i> Export as ${format.toUpperCase()}`;
        }
    }

    // === UPDATE GENERATE CUSTOM REPORT FUNCTION ===
    function generateCustomReport() {
        const startDate = document.getElementById('reportStartDate').value;
        const endDate = document.getElementById('reportEndDate').value;
        const reportType = document.getElementById('reportType').value;
        const scope = document.getElementById('reportScope').value;
        const filterValue = document.getElementById('reportFilterValue').value;
        
        // Validation
        if (!startDate || !endDate) {
            showToast('Please select both start and end dates.', 'error');
            return;
        }
        
        if ((scope === 'department' || scope === 'employee') && !filterValue) {
            showToast(`Please enter the ${scope === 'department' ? 'Department Name' : 'Employee ID'}.`, 'error');
            return;
        }
        
        // UI Feedback
        const button = document.getElementById('exportBtn');
        const originalText = button.innerHTML;
        button.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Generating...';
        button.disabled = true;
        
        // Build URL
        let url = `?action=get_export_data&type=${reportType}&start_date=${startDate}&end_date=${endDate}&format=${currentExportFormat}`;
        if(scope !== 'all') {
            url += `&scope=${scope}&filter_value=${encodeURIComponent(filterValue)}`;
        }
        
        fetch(url)
        .then(response => response.json())
        .then(data => {
            button.innerHTML = originalText;
            button.disabled = false;
            
            if (!data.success || !data.data || data.data.length === 0) {
                showToast('No data found for the selected filters.', 'warning');
                return;
            }
            
            // Generate report based on format
            if (currentExportFormat === 'csv') {
                exportToCSV(data.data, reportType, startDate, scope, filterValue);
            } else {
                exportToPDF(data.data, reportType, startDate, scope, filterValue);
            }
            
            showToast(`${currentExportFormat.toUpperCase()} report generated!`, 'success');
        })
        .catch(error => {
            console.error('Error:', error);
            button.innerHTML = originalText;
            button.disabled = false;
            showToast('Failed to generate report.', 'error');
        });
    }

    // === CSV EXPORT FUNCTION ===
    function exportToCSV(data, reportType, startDate, scope, filterValue) {
        let csvString = "";
        
        // Add header row based on report type
        if (reportType === 'attendance') {
            csvString += "Employee ID,Name,Department,Check In,Check Out,Lunch Out,Lunch In,Regular Hours,Overtime Hours,Night Diff Hours,Status\n";
            data.forEach(record => {
                const checkIn = record.check_in ? new Date(record.check_in).toLocaleString('en-US', {
                    year: 'numeric', month: '2-digit', day: '2-digit',
                    hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true
                }) : '';
                const checkOut = record.check_out ? new Date(record.check_out).toLocaleString('en-US', {
                    year: 'numeric', month: '2-digit', day: '2-digit',
                    hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true
                }) : '';
                const lunchOut = record.lunch_out ? new Date(record.lunch_out).toLocaleTimeString('en-US', {
                    hour: 'numeric', minute: '2-digit', hour12: true
                }) : '';
                const lunchIn = record.lunch_in ? new Date(record.lunch_in).toLocaleTimeString('en-US', {
                    hour: 'numeric', minute: '2-digit', hour12: true
                }) : '';
                
                csvString += `${record.employee_id},"${record.name.replace(/"/g, '""')}","${record.department.replace(/"/g, '""')}",${checkIn},${checkOut},${lunchOut},${lunchIn},${record.regular_hours},${record.overtime_hours},${record.night_diff_hours},"${record.status}"\n`;
            });
        } else if (reportType === 'leave') {
            csvString += "Employee ID,Name,Department,Start Date,End Date,Type,Status,Reason\n";
            data.forEach(record => {
                csvString += `${record.employee_id},"${record.name.replace(/"/g, '""')}","${record.department.replace(/"/g, '""')}",${record.start_date},${record.end_date},${record.type},${record.status},"${record.reason.replace(/"/g, '""')}"\n`;
            });
        } else if (reportType === 'payroll') {
            csvString += "Employee ID,Name,Department,Check In,Check Out,Regular Hours,Overtime Hours,Night Diff Hours,Holiday Bonus,Total Paid Hours\n";
            data.forEach(record => {
                csvString += `${record.employee_id},"${record.name.replace(/"/g, '""')}","${record.department.replace(/"/g, '""')}",${record.check_in},${record.check_out},${record.regular_hours},${record.overtime_hours},${record.night_diff_hours},${record.holiday_bonus},${record.total_paid_hours}\n`;
            });
        }
        
        // Create and download file using Blob
        const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        const fileName = `helport_${reportType}_${scope}_${filterValue || 'all'}_${startDate}.csv`;
        link.setAttribute("download", fileName);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
    }

    // === PDF EXPORT FUNCTION (Existing, keep as is) ===
    function exportToPDF(data, reportType, startDate, scope, filterValue) {
        const { jsPDF } = window.jspdf;
        const doc = new jsPDF();
        
        // Set title based on report type and scope
        let reportTitle = "Attendance Report";
        if (reportType === 'leave') reportTitle = "Leave Summary Report";
        if (reportType === 'payroll') reportTitle = "Payroll Report";
        if (scope === 'department') reportTitle += ` - ${filterValue}`;
        if (scope === 'employee') reportTitle += ` - ${filterValue}`;
        
        doc.setFontSize(18);
        doc.text(reportTitle, 20, 20);
        doc.setFontSize(10);
        doc.setTextColor(100);
        doc.text('Trackcurate.', 20, 26);
        doc.setFontSize(18);
        doc.setTextColor(0);
        doc.setFontSize(12);
        doc.text(`Period: ${new Date(startDate).toLocaleDateString()} to ${new Date(endDate).toLocaleDateString()}`, 20, 30);
        
        // Add table based on report type
        if (reportType === 'attendance') {
            const tableData = data.map(record => [
                record.employee_id,
                record.name,
                record.department,
                record.check_in ? new Date(record.check_in).toLocaleTimeString() : '',
                record.check_out ? new Date(record.check_out).toLocaleTimeString() : '',
                record.regular_hours,
                record.overtime_hours
            ]);
            
            doc.autoTable({
                head: [['EID', 'Name', 'Dept', 'In', 'Out', 'Regular', 'OT']],
                body: tableData,
                startY: 40,
                theme: 'striped',
                styles: { fontSize: 9 },
                headStyles: { fillColor: [25, 211, 197] }
            });
        }
        
        const fileName = `helport_${reportType}_${scope}_${filterValue || 'all'}_${startDate}.pdf`;
        doc.save(fileName);
    }
    // Make sure this is OUTSIDE any DOMContentLoaded wrapper
    function togglePassword() {
        const passwordInput = document.getElementById('password');
        const toggleIcon = document.getElementById('togglePasswordIcon');
        
        if (!passwordInput || !toggleIcon) {
            console.error('Password input or toggle icon not found');
            return;
        }
        
        if (passwordInput.type === 'password') {
            passwordInput.type = 'text';
            toggleIcon.classList.remove('fa-eye');
            toggleIcon.classList.add('fa-eye-slash');
        } else {
            passwordInput.type = 'password';
            toggleIcon.classList.remove('fa-eye-slash');
            toggleIcon.classList.add('fa-eye');
        }
    }
