    function showToast(message, type = 'info') {
    const container = document.getElementById('toast-container');
    const toast = document.createElement('div');
    toast.className = `toast ${type}`;
    toast.innerHTML = `<span>${message}</span><button class="toast-close" onclick="this.parentElement.remove()">&times;</button>`;
    container.appendChild(toast);
    setTimeout(() => { if(toast.parentElement) toast.remove(); }, 5000);
    }
    function showConfirm(message, callback) {
    const modal = document.createElement('div');
    modal.className = 'modal';
    modal.style.display = 'block';
    modal.style.zIndex = '10000';
    modal.innerHTML = `
    <div class="modal-content" style="max-width: 400px; text-align: center; background: var(--panel-bg);">
    <div class="modal-header">
    <h3>Confirm Action</h3>
    <span class="close-modal" onclick="this.closest('.modal').remove()">&times;</span>
    </div>
    <p style="margin: 20px 0; color: var(--text-primary);">${message}</p>
    <div style="display: flex; gap: 10px; justify-content: center; padding-bottom: 20px;">
    <button class="btn" style="background: var(--panel-bg); color: var(--text-primary); border: 1px solid var(--border-color);" onclick="this.closest('.modal').remove()">Cancel</button>
    <button class="btn btn-primary" id="confirmActionBtn">Confirm</button>
    </div>
    </div>
    `;
    document.body.appendChild(modal);
    const confirmBtn = modal.querySelector('#confirmActionBtn');
    confirmBtn.onclick = () => {
    modal.remove();
    if(callback) callback();
    };
    window.tempConfirmCallback = callback;
    }
    window.alert = showToast;
    window.confirm = (msg) => { return confirm(msg); };


// === FIXED: TOGGLE LEAVE FORM ===
function toggleLeaveForm() {
    const form = document.getElementById('newLeaveForm');
    const btn = document.querySelector('.btn-new-request');
    
    if (form.style.display === 'none' || form.style.display === '') {
        form.style.display = 'block';
        if (btn) {
            btn.innerHTML = '<i class="fas fa-times"></i> Cancel';
        }
        form.scrollIntoView({ behavior: 'smooth', block: 'start' });
    } else {
        form.style.display = 'none';
        if (btn) {
            btn.innerHTML = '<i class="fas fa-plus"></i> New Leave Request';
        }
        document.getElementById('leaveRequestForm').reset();
        document.getElementById('currentChars').textContent = '0';
    }
}
function switchEmployeeTab(tabName) {
    // Remove active class from all nav tabs
    document.querySelectorAll('.nav-tab').forEach(tab => tab.classList.remove('active'));
    
    // Add active class to matching tab
    document.querySelectorAll(`.nav-tab[data-tab="${tabName}"]`).forEach(tab => tab.classList.add('active'));
    
    // Hide ALL employee sections first
    ['Overview', 'Schedule', 'Leaves', 'Leave', 'Attendance'].forEach(section => {
        const el = document.getElementById(`employee${section}Section`);
        if(el) el.style.display = 'none';
    });
    
    // Show target section
    const target = document.getElementById(`employee${tabName.charAt(0).toUpperCase() + tabName.slice(1)}Section`);
    if(target) {
        target.style.display = 'block';
        
        // === AUTO-LOAD DATA BASED ON TAB ===
        if (tabName === 'schedule') {
            console.log("📅 Schedule tab opened, loading live data...");
            currentCalendarDate = new Date();
            loadEmployeeSchedule();
            startScheduleAutoRefresh();
        } 
        else if (tabName === 'leave') {
            console.log("📋 Leave tab opened, loading requests...");
            loadLeaveRequests();
            loadLeaveBalanceInModule();
        } 
        else if (tabName === 'leaves') {  // ✅ DAY OFF TAB
            console.log("📅 Day Off tab opened, loading requests...");
            loadDayOffRequests();  // ✅ THIS LOADS LIVE DATA
        } 
        else {
            stopScheduleAutoRefresh();
        }
    }
    
    // Update URL
    const newUrl = window.location.protocol + "//" + window.location.host + window.location.pathname + '?emp_view=' + tabName;
    window.history.pushState({path:newUrl},'',newUrl);
    
    // Persist view
    try { localStorage.setItem('lastEmpView', tabName); } catch(e) {}
    document.cookie = 'last_emp_view=' + tabName + '; path=/';
}

    // === LEAVE REQUEST AJAX SUBMISSION ===
function submitLeaveRequest(event) {
    event.preventDefault();
    const btn = document.getElementById('leaveSubmitBtn');
    const originalText = btn.innerHTML;
    
    // Validate
    const startDate = document.getElementById('leaveStartDate').value;
    const endDate = document.getElementById('leaveEndDate').value;
    const reason = document.getElementById('leaveReason').value;
    
    if (!startDate || !endDate) {
        showToast('Please select start and end dates', 'error');
        return;
    }
    if (reason.length < 20) {
        showToast('Reason must be at least 20 characters', 'error');
        return;
    }
    
    // Disable button
    btn.disabled = true;
    btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Submitting...';
    
    // Create FormData
    const formData = new FormData();
    formData.append('action', 'submit_leave_request');
    formData.append('csrf_token', document.querySelector('input[name="csrf_token"]')?.value || '');
    formData.append('startDate', startDate);
    formData.append('endDate', endDate);
    formData.append('leave_type', document.getElementById('leaveTypeSelect').value.split(' ')[0]);
    formData.append('reason', reason);

    // Attach file if uploaded
    if (typeof uploadedFile !== 'undefined' && uploadedFile) {
        formData.append('attachment', uploadedFile);
    }
    
    fetch('', {
        method: 'POST',
        body: formData,
        headers: { 'X-Requested-With': 'XMLHttpRequest' }
    })
    .then(r => r.json())
    .then(data => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        
        if (data.success) {
            showToast('Leave request submitted successfully!', 'success');
            
            // Clear form
            document.getElementById('leaveRequestForm').reset();
            document.getElementById('currentChars').textContent = '0';
            
            // Hide form
            toggleLeaveForm();
            
            // ✅ CRITICAL: Reload the leave requests list immediately
            loadLeaveRequests();
            
        } else {
            showToast('Error: ' + (data.message || 'Failed to submit request'), 'error');
        }
    })
    .catch(e => {
        btn.disabled = false;
        btn.innerHTML = originalText;
        showToast('Network error: ' + e.message, 'error');
        console.error('Leave request error:', e);
    });
}

    // === SCHEDULE AUTO-REFRESH LOGIC ===
    let scheduleRefreshInterval = null;

    function startScheduleAutoRefresh() {
        // Clear any existing interval first
        if (scheduleRefreshInterval) clearInterval(scheduleRefreshInterval);
        
        // Set new interval to fetch data every 30 seconds
        scheduleRefreshInterval = setInterval(() => {
            const scheduleSection = document.getElementById('employeeScheduleSection');
            // Only refresh if the section is actually visible
            if (scheduleSection && scheduleSection.style.display !== 'none') {
                loadEmployeeSchedule();
            }
        }, 30000); // 30000ms = 30 seconds
    }

    function stopScheduleAutoRefresh() {
        if (scheduleRefreshInterval) {
            clearInterval(scheduleRefreshInterval);
            scheduleRefreshInterval = null;
        }
    }

    function toggleEmployeeDropdown() {
    const dropdown = document.getElementById('employeeDropdown');
    const isVisible = dropdown.style.display === 'block';
    document.querySelectorAll('.notification-dropdown').forEach(d => d.style.display = 'none');
    if (isVisible) {
    dropdown.style.display = 'none';
    document.body.style.overflow = '';
    } else {
    dropdown.style.display = 'block';
    document.body.style.overflow = 'hidden';
    }
    }
    function submitDayOffRequest(event) {
        event.preventDefault();
        const date = document.getElementById('dayOffDate').value;
        const type = document.getElementById('dayOffType').value;
        const reason = document.getElementById('dayOffReason').value;
        
        if (!date || !type) {
            showToast('Please fill in all required fields', 'error');
            return;
        }
        
        // Calculate End Date based on Type
        let endDate = date;
        let durationText = "1 Day";
        if (type === 'Half Day (AM)' || type === 'Half Day (PM)') {
            durationText = "Half Day";
        } else if (type === 'Full Day') {
            durationText = "1 Day";
        }
        
        const formData = new FormData();
        formData.append('action', 'submit_day_off');
        formData.append('csrf_token', document.querySelector('input[name="csrf_token"]')?.value || '');
        formData.append('date', date);
        formData.append('end_date', endDate);
        formData.append('type', type);
        formData.append('reason', reason);
        
        fetch('', { 
            method: 'POST', 
            body: formData,
            headers: {
                'X-Requested-With': 'XMLHttpRequest'
            }
        })
        .then(r => {
            // Check if response is JSON
            const contentType = r.headers.get('content-type');
            if (contentType && contentType.includes('application/json')) {
                return r.json();
            } else {
                // If not JSON, get text and show error
                return r.text().then(text => {
                    throw new Error('Server returned HTML instead of JSON. Check for PHP errors.');
                });
            }
        })
        .then(data => {
            if (data.success) {
                showToast('Day off request submitted successfully!', 'success');
                // Clear form
                document.getElementById('dayOffDate').value = '';
                document.getElementById('dayOffType').value = '';
                document.getElementById('dayOffReason').value = '';
                // Reload requests
                loadDayOffRequests();
            } else {
                showToast('Error: ' + (data.message || 'Failed to submit request'), 'error');
            }
        })
        .catch(e => {
            console.error('Submit error:', e);
            showToast('Error submitting request: ' + e.message, 'error');
        });
    }




function loadDayOffRequests() {
    const container = document.getElementById('dayOffList');
    if(!container) return;
    
    container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--text-muted);"><i class="fas fa-spinner fa-spin"></i><div>Loading...</div></div>';
    
    fetch('?action=get_day_off_requests')
    .then(r => r.json())
    .then(data => {
        if (data.success && data.requests && data.requests.length > 0) {
            let html = '';
            data.requests.forEach(req => {
                let statusClass = 'pending';
                let statusLabel = 'PENDING';
                if(req.status === 'Approved') { statusClass = 'approved'; statusLabel = 'APPROVED'; }
                else if(req.status === 'Rejected') { statusClass = 'rejected'; statusLabel = 'REJECTED'; }
                
                const startDate = new Date(req.start_date).toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });
                
                html += `
                <div class="request-card-item ${statusClass}">
                    <div class="request-info">
                        <div class="request-date">${startDate}</div>
                        <div class="request-details">
                            <span style="color: var(--text-secondary);">Type:</span> ${req.type || 'Full Day'}
                            ${req.reason ? `• <span style="color: var(--text-secondary);">Reason:</span> ${req.reason}` : ''}
                        </div>
                    </div>
                    <div class="request-status-badge status-${statusClass}">${statusLabel}</div>
                </div>
                `;
            });
            container.innerHTML = html;
        } else {
            container.innerHTML = '<div style="text-align: center;">No day off requests found.</div>';
        }
    })
    .catch(e => console.log('Error:', e));
}

