    // === GLOBAL VARIABLE (Initialize to TODAY) ===
    var currentCalendarDate = new Date(); 

// === FIXED CALENDAR RENDER FUNCTION ===
function loadEmployeeSchedule() {
    const grid = document.getElementById('scheduleCalendarGrid');
    const titleEl = document.getElementById('calendarMonthYear');
    
    // CRITICAL: Verify element exists before proceeding
    if (!grid) {
        console.error("❌ CRITICAL: Schedule Grid Element Not Found! Waiting for DOM...");
        // Wait for DOM and retry
        setTimeout(() => {
            loadEmployeeSchedule();
        }, 500);
        return;
    }
    
    // Show Loading State Immediately
    grid.innerHTML = '<div style="grid-column: 1/-1; text-align: center; padding: 60px; color: var(--text-muted);"><i class="fas fa-circle-notch fa-spin" style="font-size: 32px; margin-bottom: 15px; color: var(--primary-accent);"></i><div style="font-size: 14px; font-weight: 600;">Loading Schedule...</div></div>';
    
    // Ensure we are using the current date
    const now = currentCalendarDate || new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();
    const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
    
    // Update Header Title Immediately (Before fetch completes)
    if(titleEl) {
        titleEl.textContent = `${monthNames[currentMonth]} ${currentYear}`;
    }
    
    let schedule = {
        monday: 'Day Shift', tuesday: 'Day Shift', wednesday: 'Day Shift',
        thursday: 'Day Shift', friday: 'Day Shift', saturday: 'Off', sunday: 'Off'
    };
    
    // Fetch Schedule
    fetch('?action=get_employee_schedule')
    .then(response => {
        if (!response.ok) {
            throw new Error('HTTP ' + response.status);
        }
        return response.json();
    })
    .then(data => {
        console.log('📅 Schedule data received:', data);
        if(data.success && data.schedule) {
            schedule = { ...schedule, ...data.schedule };
        }
        
        // Fetch Holidays for this Month
        fetch(`?action=get_holidays_month&month=${currentMonth + 1}&year=${currentYear}`)
        .then(r => r.json())
        .then(holData => {
            const holidays = holData.success ? holData.holidays : [];
            console.log('🎉 Holidays loaded:', holidays.length);
            renderCalendarGrid(schedule, holidays);
        })
        .catch(err => {
            console.warn("⚠️ Holiday fetch failed, rendering schedule only.", err);
            renderCalendarGrid(schedule, []);
        });
    })
    .catch(err => {
        console.warn("⚠️ Schedule fetch failed, using default schedule.", err);
        renderCalendarGrid(schedule, []);
    });
}
    // === 2. RENDER CALENDAR GRID (WITH HOLIDAY BADGES) ===
    function renderCalendarGrid(scheduleData, holidays = []) {
        const grid = document.getElementById('scheduleCalendarGrid');
        if(!grid) return;
        
        const dayNames = ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'];
        const scheduleKeys = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
        const now = currentCalendarDate;
        const currentMonth = now.getMonth();
        const currentYear = now.getFullYear();
        const today = new Date();
        const firstDay = new Date(currentYear, currentMonth, 1).getDay();
        const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
        
    const shiftConfig = {
    'Morning Shift': { time: '8:00 AM - 5:00 PM', color: '#00ff88', bg: 'rgba(0, 255, 136, 0.05)', icon: 'fa-sun' },
    'Day Shift':     { time: '8:00 AM - 5:00 PM', color: '#00ff88', bg: 'rgba(0, 255, 136, 0.05)', icon: 'fa-sun' },
    'Early Shift':   { time: '7:00 AM - 4:00 PM', color: '#00d4ff', bg: 'rgba(0, 212, 255, 0.05)', icon: 'fa-sun' },
    'Mid Shift':     { time: '9:00 AM - 6:00 PM', color: '#ff9f43', bg: 'rgba(255, 159, 67, 0.05)', icon: 'fa-cloud-sun' },
    'Afternoon Shift': { time: '2:00 PM - 11:00 PM', color: '#ffcc00', bg: 'rgba(255, 204, 0, 0.05)', icon: 'fa-cloud-sun' },
    'Night Shift':   { time: '10:00 PM - 7:00 AM', color: '#6c5ce7', bg: 'rgba(108, 92, 231, 0.05)', icon: 'fa-moon' },
    'Flexible':      { time: 'Flexible Hours', color: '#00d2d3', bg: 'rgba(0, 210, 211, 0.05)', icon: 'fa-clock' },
    'Off':           { time: 'Day Off', color: '#6c757d', bg: 'rgba(108, 117, 125, 0.05)', icon: 'fa-bed' }
    };
        
        let html = ``;
        
        // Day Headers
        html += `<div style="display: grid; grid-template-columns: repeat(7, 1fr); gap: 15px; margin-bottom: 15px;">`;
        dayNames.forEach((day) => {
            html += `<div style="text-align: center; font-weight: 700; color: var(--primary-accent); text-transform: uppercase; font-size: 12px; padding: 10px;">${day}</div>`;
        });
        html += `</div>`;
        
        // Grid Container
        html += `<div style="display: grid; grid-template-columns: repeat(7, 1fr); gap: 15px;">`;
        
        // Empty Cells
        for(let i = 0; i < firstDay; i++) {
            html += `<div style="min-height: 140px;"></div>`;
        }
        
        // Calendar Days
        for(let day = 1; day <= daysInMonth; day++) {
            const dayOfWeek = new Date(currentYear, currentMonth, day).getDay();
            const scheduleKey = scheduleKeys[dayOfWeek];
            
           // Inside renderCalendarGrid function
const startCol = scheduleKey + '_start';
const endCol = scheduleKey + '_end';

let shiftName = 'Off';
let shiftTime = 'Day Off';
let shiftColor = '#6c757d';
let shiftIcon = 'fa-bed';

// 1. CHECK FOR CUSTOM HOURS FIRST
if (scheduleData[startCol] && scheduleData[endCol] && scheduleData[startCol] !== '00:00:00') {
    shiftName = 'Custom Shift';
    const start = formatTime12Hour(scheduleData[startCol]);
    const end = formatTime12Hour(scheduleData[endCol]);
    shiftTime = `${start} - ${end}`;
    shiftColor = '#00ff88';
    shiftIcon = 'fa-clock';
}
// 2. CHECK PRESET SHIFTS SECOND
else {
    const presetType = scheduleData[scheduleKey] || 'Off';
    const config = shiftConfig[presetType] || shiftConfig['Off'];
    shiftName = presetType;
    shiftTime = config.time;
    shiftColor = config.color;
    shiftIcon = config.icon;
}
            
            // === NEW: CHECK FOR HOLIDAY ===
            const currentDateStr = `${currentYear}-${String(currentMonth + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
            const holiday = holidays.find(h => h.date === currentDateStr);
            let holidayBadge = '';
            
            if (holiday) {
                let hColor = holiday.type === 'regular' ? '#dc3545' : (holiday.type === 'special_non_working' ? '#ffc107' : '#17a2b8');
                let hText = holiday.type === 'regular' ? 'Reg. Holiday' : (holiday.type === 'special_non_working' ? 'Special' : 'Special Work');
                holidayBadge = `<div style="font-size:9px; color:${hColor}; font-weight:bold; margin-top:4px; border:1px solid ${hColor}; padding:2px 4px; border-radius:4px;">${hText}</div>`;
                
                if(holiday.type !== 'special_working') {
                    shiftName = holiday.name; 
                    shiftTime = 'Holiday';
                }
            }
            
            const isToday = (day === today.getDate() && currentMonth === today.getMonth() && currentYear === today.getFullYear());
            let cardClass = 'schedule-day-card';
            if (isToday) cardClass += ' is-today';
            
            html += `
            <div class="${cardClass}" onmouseover="this.style.transform='scale(1.02)'" onmouseout="this.style.transform='scale(1)'">
                <div class="day-number">
                    <span>${day}</span>
                    ${isToday ? '<span class="today-badge">Today</span>' : ''}
                </div>
                <div class="shift-info">
                    <i class="fas ${shiftIcon} shift-icon" style="color: ${shiftColor}"></i>
                    <div class="shift-name" style="color: ${shiftColor}">${shiftName}</div>
                    <div class="shift-time">${shiftTime}</div>
                    ${holidayBadge}
                </div>
            </div>
            `;
        }
        
        html += `</div>`;
        grid.innerHTML = html;
    }

    // === HELPER: FORMAT 24H TO 12H ===
    function formatTime12Hour(time24) {
        if (!time24) return '';
        const [hours, minutes] = time24.split(':');
        let h = parseInt(hours);
        const ampm = h >= 12 ? 'PM' : 'AM';
        h = h % 12;
        h = h ? h : 12; // the hour '0' should be '12'
        return `${h}:${minutes} ${ampm}`;
    }

    // === MONTH NAVIGATION ===
    function changeMonth(offset) {
        currentCalendarDate.setMonth(currentCalendarDate.getMonth() + offset);
        loadEmployeeSchedule();
    }

