    const adminMenuToggle = document.getElementById('adminMenuToggle');
    const adminMenuList = document.getElementById('adminMenuList');
    if (adminMenuToggle && adminMenuList) {
        const closeAdminMenu = () => {
            adminMenuList.style.display = 'none';
            adminMenuToggle.setAttribute('aria-expanded', 'false');
            adminMenuList.setAttribute('aria-hidden', 'true');
        };

        const openAdminMenu = () => {
            adminMenuList.style.display = 'block';
            adminMenuToggle.setAttribute('aria-expanded', 'true');
            adminMenuList.setAttribute('aria-hidden', 'false');
        };

        adminMenuToggle.addEventListener('click', function(e) {
            e.stopPropagation();
            const isOpen = window.getComputedStyle(adminMenuList).display !== 'none';
            if (isOpen) {
                closeAdminMenu();
            } else {
                // Ensure any other open dropdowns are closed first
                document.querySelectorAll('.admin-menu-list').forEach(el => el.style.display = 'none');
                openAdminMenu();
            }
        });

        adminMenuList.addEventListener('click', function(e) {
            e.stopPropagation();
            const item = e.target.closest('.admin-menu-item');
            if (!item) return;
            const tab = item.dataset.tab;
            if (tab) {
                switchTab(tab);
                closeAdminMenu();
            }
        });

        document.addEventListener('click', function() {
            closeAdminMenu();
        });

        document.addEventListener('keydown', function(e) {
            if (e.key === 'Escape') {
                closeAdminMenu();
            }
        });
    }
