    // === AI CHATBOT - GEMINI API INTEGRATION ===

    // Initialize on Page Load
    document.addEventListener('DOMContentLoaded', function() {
        console.log('✅ AI Chatbot with Gemini API initialized!');
        
        // Add clear button to AI panel if not exists
        const panelHeader = document.querySelector('.panel-header .panel-controls');
        if (panelHeader && !document.querySelector('.clear-chat-btn')) {
            const clearBtn = document.createElement('button');
            clearBtn.className = 'panel-control-btn clear-chat-btn';
            clearBtn.title = 'Clear Chat';
