    // Send Message to Gemini API
    async function sendMessage() {
        const input = document.getElementById('userMessage');
        const message = input.value.trim();
        const sendBtn = document.querySelector('.chat-send-btn');
        
        if (!message) return;
        
        // Add user message to chat
        addMessageToChat(message, 'user');
        input.value = '';
        
        // Show typing indicator
        showTypingIndicator();
        
        // Disable send button while processing
        if (sendBtn) sendBtn.disabled = true;
        
        try {
            // Get conversation history for context
            const conversationHistory = getConversationHistory();
            
            // Call Gemini API
            const response = await fetchGeminiResponse(message, conversationHistory);
            
            // Remove typing indicator
            removeTypingIndicator();
            
            // Add AI response to chat
            if (response) {
                addMessageToChat(response, 'assistant');
            } else {
                addMessageToChat("I'm sorry, I couldn't process your request. Please try again.", 'assistant');
            }
        } catch (error) {
            console.error('Chat error:', error);
            removeTypingIndicator();
            addMessageToChat("Sorry, I'm having trouble connecting right now. Please try again later.", 'assistant');
        } finally {
            if (sendBtn) sendBtn.disabled = false;
        }
    }

    // Fetch Response from Gemini API
    async function fetchGeminiResponse(message, history) {
        // Prepare the request body
        const requestBody = {
            message: message,
            history: history.slice(-10) // Last 10 messages for context
        };
        
        // Call your PHP proxy
        const response = await fetch('gemini_proxy.php', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(requestBody)
        });
        
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        
        const data = await response.json();
        
        if (data.success && data.reply) {
            return data.reply;
        } else {
            throw new Error(data.error || 'No response from AI');
        }
    }

    // Add Message to Chat Display
    function addMessageToChat(text, sender) {
        const container = document.getElementById('chatMessages');
        if (!container) return;
        
        const messageDiv = document.createElement('div');
        messageDiv.className = `message message-${sender}`;
        
        const time = new Date().toLocaleTimeString([], { 
            hour: '2-digit', 
            minute: '2-digit' 
        });
        
        // Format text with line breaks
        const formattedText = text.replace(/\n/g, '<br>');
        
        messageDiv.innerHTML = `
            ${formattedText}
            <div class="message-time">${time}</div>
        `;
        
        container.appendChild(messageDiv);
        container.scrollTop = container.scrollHeight;
    }

    // Show Typing Indicator
    function showTypingIndicator() {
        const container = document.getElementById('chatMessages');
        if (!container) return;
        
        const typingDiv = document.createElement('div');
        typingDiv.className = 'message message-assistant typing-indicator';
        typingDiv.id = 'typingIndicator';
        
        typingDiv.innerHTML = `
            <div class="typing-indicator">
                <div class="dot"></div>
                <div class="dot"></div>
                <div class="dot"></div>
            </div>
        `;
        
        container.appendChild(typingDiv);
        container.scrollTop = container.scrollHeight;
    }

    // Remove Typing Indicator
    function removeTypingIndicator() {
        const typingIndicator = document.getElementById('typingIndicator');
        if (typingIndicator) {
            typingIndicator.remove();
        }
    }

    // Get Conversation History
    function getConversationHistory() {
        const messages = document.querySelectorAll('#chatMessages .message');
        const history = [];
        
        messages.forEach(msg => {
            const text = msg.textContent.replace(/Just now|\d{1,2}:\d{2}\s?(AM|PM)/gi, '').trim();
            if (msg.classList.contains('message-user')) {
                history.push({ role: 'user', text: text });
            } else if (msg.classList.contains('message-assistant') && !msg.classList.contains('typing-indicator')) {
                history.push({ role: 'assistant', text: text });
            }
        });
        
        return history;
    }

    // Clear Chat History
    function clearChatHistory() {
        const container = document.getElementById('chatMessages');
        if (!container) return;
        
        if (confirm('Are you sure you want to clear the chat history?')) {
            container.innerHTML = `
                <div class="message message-assistant">
                    Hello! I'm your HELPORT TRAACURATE assistant. How can I help you today? 🎉
                    <div class="message-time">Just now</div>
                </div>
            `;
        }
    }

    // Send Quick Action
    function sendQuickAction(message) {
        const input = document.getElementById('userMessage');
        if (input) {
            input.value = message;
            sendMessage();
        }
    }

    // Handle Enter Key Press
    function handleKeyPress(event) {
        if (event.key === 'Enter' && !event.shiftKey) {
            event.preventDefault();
            sendMessage();
        }
    }

    // Toggle AI Assistant Panel
    function toggleAIAssistant() {
        const panel = document.getElementById('aiPanel');
        if (!panel) return;
        
        if (panel.style.display === 'none' || panel.style.display === '') {
            panel.style.display = 'flex';
            // Focus on input when opening
            setTimeout(() => {
                const input = document.getElementById('userMessage');
                if (input) input.focus();
            }, 100);
        } else {
            panel.style.display = 'none';
        }
    }

