    function toggleReportFilterInput() {
        const scope = document.getElementById('reportScope').value;
        const group = document.getElementById('reportFilterValueGroup');
        const input = document.getElementById('reportFilterValue');
        
        if(scope === 'all') {
            group.style.display = 'none';
            input.required = false;
        } else {
            group.style.display = 'flex';
            input.required = true;
            // Change placeholder based on selection
            if(scope === 'department') {
                input.placeholder = "Enter Department Name (e.g. IT)";
            } else if (scope === 'employee') {
                input.placeholder = "Enter Employee ID (e.g. 2025001)";
            }
        }
    }

    // Form Submission Handler
    document.getElementById('employeeForm').addEventListener('submit', function(e) {
    e.preventDefault();
    const formData = new FormData(this);
    const isEdit = !!document.getElementById('employeeIdInput').value;
    formData.append('action', isEdit ? 'update_employee' : 'add_employee');
    fetch('', { 
        method: 'POST', 
        body: formData,  // ← CHANGED: Send FormData directly (NOT URLSearchParams)
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(response => response.json())

        .then(data => {
            if (data.success) {
                if (!isEdit) {
                    // ADD NEW EMPLOYEE
                    const newRow = document.createElement('tr');
                    newRow.setAttribute('data-id', data.employee.id);
                    
                    // Handle photo display
                    const photoHtml = data.employee.photo_path && data.employee.photo_path !== '' 
                        ? `<img src="${data.employee.photo_path}" style="width: 100%; height: 100%; object-fit: cover;">`
                        : '<i class="fas fa-user"></i>';
                    
                    newRow.innerHTML = `
                        <td class="col-id">${data.employee.employee_id}</td>
                        <td class="col-name">
                            <div class="emp-avatar-wrapper">
                                <div class="emp-avatar">${photoHtml}</div>
                                <span class="emp-name-text">${data.employee.name}</span>
                            </div>
                        </td>
                        <td class="col-position">${data.employee.position}</td>
                        <td class="col-dept">${data.employee.department}</td>
                        <td class="col-birthday">${data.employee.birthday ? new Date(data.employee.birthday).toLocaleDateString() : '-'}</td>
                        <td class="col-finger">${data.employee.finger_id || '-'}</td>
                        <td class="col-role"><span class="role-badge ${data.employee.role.toLowerCase()}">${data.employee.role}</span></td>
                        <td class="col-actions">
                            <div class="action-btn-group">
                                <button class="action-icon-btn" style="color: #17a2b8;" onclick="openScheduleModal(${data.employee.id})">
                                    <i class="fas fa-calendar-alt"></i>
                                </button>
                                <button class="action-icon-btn edit" onclick="openEditEmployeeModal(${data.employee.id}, '${data.employee.name.replace(/'/g, "\\'")}', '${data.employee.employee_id}', '${data.employee.position.replace(/'/g, "\\'")}', '${data.employee.department.replace(/'/g, "\\'")}', '${data.employee.role}', '${data.employee.birthday || ''}', '${data.employee.finger_id || ''}', '${data.employee.photo_path || ''}', '${(data.employee.twofa_email || '').replace(/'/g, "\\'")}')">
                                    <i class="fas fa-pen-to-square"></i>
                                </button>
                                <button class="action-icon-btn delete" onclick="deleteEmployee(${data.employee.id})">
                                    <i class="fas fa-trash"></i>
                                </button>
                            </div>
                        </td>
                    `;
                    newRow.style.opacity = '0';
                    newRow.style.transform = 'translateX(-20px)';
                    document.getElementById('employeesTableBody').appendChild(newRow);
                    setTimeout(() => {
                        newRow.style.opacity = '1';
                        newRow.style.transform = 'translateX(0)';
                        newRow.style.transition = 'all 0.3s ease';
                    }, 50);
                } else {
                    // UPDATE EXISTING EMPLOYEE
                    const employeeId = data.employee?.id || document.getElementById('employeeIdInput').value;
                    const row = document.querySelector(`tr[data-id="${employeeId}"]`);
                    
                    if (row) {
                        // Get updated values from form
                        const name = document.getElementById('empName').value;
                        const eid = document.getElementById('empEid').value;
                        const position = document.getElementById('empPosition').value;
                        const dept = document.getElementById('empDept').value;
                        const role = document.getElementById('empRole').value;
                        const twofaEmail = document.getElementById('empTwofaEmail').value;
                        const birthday = document.getElementById('empBirthday').value;
                        const fingerId = document.getElementById('empFingerId').value;
    const photoPreview = document.getElementById('empPhotoPreview');
    const isPhotoUpdated = photoPreview && 
        photoPreview.src && 
        !photoPreview.src.includes('default-avatar') && 
        !photoPreview.src.includes('data:image/svg+xml');

    const photoPath = data.employee?.photo_path || (isPhotoUpdated ? photoPreview.src : '');
    const photoHtml = photoPath 
        ? `<img src="${photoPath}?t=${new Date().getTime()}" style="width: 100%; height: 100%; object-fit: cover;">`
        : '<i class="fas fa-user"></i>';
                        
                        // Update row content with animation
                        row.style.opacity = '0';
                        row.style.transform = 'scale(0.95)';
                        
                        setTimeout(() => {
                            row.querySelector('.emp-name-text').textContent = name;
                            row.querySelector('.emp-avatar').innerHTML = photoHtml;
                            row.querySelector('.col-id').textContent = eid;
                            row.querySelector('.col-position').textContent = position;
                            row.querySelector('.col-dept').textContent = dept;
                            row.querySelector('.col-birthday').textContent = birthday ? new Date(birthday).toLocaleDateString() : '-';
                            row.querySelector('.col-finger').textContent = fingerId || '-';
                            row.querySelector('.role-badge').textContent = role;
                            row.querySelector('.role-badge').className = `role-badge ${role.toLowerCase()}`;
                            
                            // Update edit button onclick with new photo path
                            const editBtn = row.querySelector('.action-icon-btn.edit');
                            const newPhotoPath = isPhotoUpdated ? photoPreview : (data.employee?.photo_path || '');
                            editBtn.setAttribute('onclick', 
                                `openEditEmployeeModal(${employeeId}, '${name.replace(/'/g, "\\'")}', '${eid}', '${position.replace(/'/g, "\\'")}', '${dept.replace(/'/g, "\\'")}', '${role}', '${birthday || ''}', '${fingerId || ''}', '${newPhotoPath.replace(/'/g, "\\'")}', '${twofaEmail.replace(/'/g, "\\'")}')`
                            );
                            
                            row.style.opacity = '1';
                            row.style.transform = 'scale(1)';
                            row.style.transition = 'all 0.3s ease';
                        }, 300);
                    }
                }
                
                showToast(isEdit ? 'Employee updated successfully!' : 'Employee added successfully!', 'success');
                closeEmployeeModal();
            } else {
                showToast('Error: ' + (data.message || 'Failed to save.'), 'error');
            }
        })
        .catch(err => {
            console.error(err);
            showToast('An error occurred.', 'error');
        });
    });

function approveLeave(requestId) {
    // Get the remark from the new textarea
    const remarkInput = document.getElementById('adminRemark_' + requestId);
    const adminRemark = remarkInput ? remarkInput.value : '';
    
    showConfirm('Are you sure you want to approve this leave request?', () => {
        const formData = new FormData();
        formData.append('action', 'approve_leave');
        formData.append('request_id', requestId);
        formData.append('admin_remark', adminRemark); // Send the remark
        formData.append('csrf_token', getCSRFToken());
        
        fetch('', {
            method: 'POST',
            credentials: 'same-origin',
            body: formData
        })
        .then(r => r.json())
        .then(data => {
            if (data.success) {
                showToast('Leave request approved successfully!', 'success');
                // Refresh the list to show the remark
                setTimeout(() => location.reload(), 1000); 
            } else {
                showToast('Failed to approve: ' + (data.message || 'Unknown error'), 'error');
            }
        })
        .catch(err => {
            console.error('Approve error:', err);
            showToast('Error approving request', 'error');
        });
    });
}

function rejectLeave(requestId) {
    // Get the remark from the new textarea
    const remarkInput = document.getElementById('adminRemark_' + requestId);
    const adminRemark = remarkInput ? remarkInput.value : '';
    
    showConfirm('Are you sure you want to reject this leave request?', () => {
        const formData = new FormData();
        formData.append('action', 'reject_leave');
        formData.append('request_id', requestId);
        formData.append('admin_remark', adminRemark); // Send the remark
        formData.append('csrf_token', getCSRFToken());
        
        fetch('', {
            method: 'POST',
            credentials: 'same-origin',
            body: formData
        })
        .then(r => r.json())
        .then(data => {
            if (data.success) {
                showToast('Leave request rejected successfully!', 'success');
                // Refresh the list to show the remark
                setTimeout(() => location.reload(), 1000);
            } else {
                showToast('Failed to reject: ' + (data.message || 'Unknown error'), 'error');
            }
        })
        .catch(err => {
            console.error('Reject error:', err);
            showToast('Error rejecting request', 'error');
        });
    });
}

// Add this new function to update the card UI with remark
function updateLeaveCardUI(requestId, newStatus, adminRemark = '') {
    const card = document.querySelector(`.leave-card[data-status="${newStatus.toLowerCase()}"]`);
    if (!card) {
        // Reload the section if card not found
        setTimeout(() => location.reload(), 1000);
        return;
    }
    
    // Update status badge
    const statusBadge = card.querySelector('.status-badge');
    if (statusBadge) {
        statusBadge.className = `status-badge status-${newStatus.toLowerCase()}`;
        statusBadge.innerHTML = `<i class="fas ${newStatus === 'Approved' ? 'fa-check-circle' : 'fa-times-circle'}"></i> ${newStatus}`;
    }
    
    // Update actions section
    const actionsDiv = card.querySelector('.leave-card-actions');
    if (actionsDiv) {
        let html = '';
        
        // Show admin remark
        if (adminRemark) {
            html += `
                <div style="background: rgba(25,211,197,0.1); border: 1px solid rgba(25,211,197,0.3); border-radius: 8px; padding: 10px; margin-bottom: 10px; width: 100%;">
                    <div style="font-size: 11px; color: var(--text-muted); margin-bottom: 5px;">
                        <i class="fas fa-comment"></i> Admin Remark:
                    </div>
                    <div style="font-size: 12px; color: var(--text-primary);">${escapeHtml(adminRemark)}</div>
                </div>
            `;
        }
        
        // Show attachment if exists
        const attachmentLink = card.querySelector('a[href*="attachment"]');
        if (attachmentLink) {
            html += attachmentLink.outerHTML;
        }
        
        // Show resolved status
        html += `
            <div class="action-resolved" style="width: 100%; justify-content: center;">
                <i class="fas ${newStatus === 'Approved' ? 'fa-check-circle' : 'fa-ban'}"></i>
                ${newStatus}
            </div>
        `;
        
        actionsDiv.innerHTML = html;
    }
    
    // Update data-status attribute
    card.setAttribute('data-status', newStatus.toLowerCase());
}


    // ADD THIS HELPER TO RECALCULATE COUNTERS
    function updateLeaveCounters() {
        const cards = document.querySelectorAll('.leave-request-card');
        let pending = 0, approved = 0, rejected = 0;
        
        cards.forEach(card => {
            const status = card.getAttribute('data-status');
            if (status === 'pending') pending++;
            else if (status === 'approved') approved++;
            else if (status === 'rejected') rejected++;
        });

        // Update the number displays
        const pendingEl = document.getElementById('count-pending');
        const approvedEl = document.getElementById('count-approved');
        const rejectedEl = document.getElementById('count-rejected');

        if(pendingEl) pendingEl.textContent = pending;
        if(approvedEl) approvedEl.textContent = approved;
        if(rejectedEl) rejectedEl.textContent = rejected;
    }

    // Add this new function to update the card status
    function updateLeaveCardStatus(requestId, newStatus) {
    // Find the card with this request ID
    const card = document.querySelector(`.leave-request-card[onclick*="${requestId}"], .record-item[data-status][onclick*="${requestId}"]`);
    if (!card) {
    // If we can't find the specific card, just refresh the leave section
    const leaveSection = document.getElementById('leaveadministrationSection');
    if (leaveSection && leaveSection.style.display !== 'none') {
    // Re-fetch the leave requests
    fetch('?action=get_day_off_requests')
    .then(r => r.json())
    .then(data => {
    if (data.success) {
    // You can reload just this section if needed
    location.reload();
    }
    });
    }
    return;
    }
    /* === DEPARTMENTS MODULE LOGIC === */
    function loadDepartmentsData() {
        const grid = document.getElementById('departmentsGrid');
        if(!grid) return;
        
        // Show loading state
        grid.innerHTML = `<div style="grid-column: 1/-1; text-align: center; padding: 40px; color: var(--text-muted);">
            <i class="fas fa-spinner fa-spin" style="font-size: 24px;"></i>
            <div style="margin-top: 10px;">Loading department data...</div>
        </div>`;

        fetch('?action=get_department_stats')
        .then(r => r.json())
        .then(data => {
            if(data.labels && data.labels.length > 0) {
                let html = '';
                data.labels.forEach((dept, index) => {
                    const total = data.total ? data.total[index] : 0; // Fallback if API changes
                    const present = data.values[index];
                    const rate = total > 0 ? Math.round((present / total) * 100) : 0;
                    
                    // Determine color based on rate
                    let color = '#28a745'; // Green
                    if(rate < 50) color = '#dc3545'; // Red
                    else if(rate < 80) color = '#ffc107'; // Yellow

                    html += `
                    <div class="dept-card">
                        <div class="dept-header">
                            <div class="dept-name">
                                <div class="dept-icon"><i class="fas fa-building"></i></div>
                                ${dept}
                            </div>
                        </div>
                        <div class="dept-stats">
                            <div class="dept-stat-item">
                                <div class="dept-stat-value">${present}</div>
                                <div class="dept-stat-label">Present</div>
                            </div>
                            <div class="dept-stat-item">
                                <div class="dept-stat-value">${total}</div>
                                <div class="dept-stat-label">Total</div>
                            </div>
                        </div>
                        <div style="display:flex; justify-content:space-between; font-size:11px; color:var(--text-muted);">
                            <span>Attendance Rate</span>
                            <span class="dept-attendance-rate" style="color:${color}">${rate}%</span>
                        </div>
                        <div class="dept-progress">
                            <div class="dept-progress-bar" style="width: ${rate}%; background: ${color};"></div>
                        </div>
                    </div>
                    `;
                });
                grid.innerHTML = html;
            } else {
                grid.innerHTML = `<div style="grid-column: 1/-1; text-align: center; padding: 40px; color: var(--text-muted);">No department data available.</div>`;
            }
        })
        .catch(e => {
            console.error(e);
            grid.innerHTML = `<div style="grid-column: 1/-1; text-align: center; padding: 40px; color: #dc3545;">Error loading data.</div>`;
        });
    }

    // Ensure the existing switchTab function handles these new IDs
    const originalSwitchTab = window.switchTab;
    window.switchTab = function(tabName) {
        // Call original logic first
        if(typeof originalSwitchTab === 'function') {
            originalSwitchTab(tabName);
        }
        
        // Handle specific module initialization
        if(tabName === 'departments') {
            loadDepartmentsData();
        }
        if(tabName === 'analytics') {
            updateAnalytics();
        }
    };
    // Update the status badge
    const actionButtons = card.querySelector('.action-buttons');
    if (actionButtons) {
    const statusColors = {
    'Approved': { bg: 'rgba(40,167,69,0.1)', color: '#28a745', icon: 'fa-check-circle' },
    'Rejected': { bg: 'rgba(220,53,69,0.1)', color: '#dc3545', icon: 'fa-times-circle' }
    };
    const colors = statusColors[newStatus];
    actionButtons.innerHTML = `
    <div style="display: flex; align-items: center; gap: 8px; padding: 8px 16px; background: ${colors.bg}; border-radius: 8px; border: 1px solid ${colors.color}; color: ${colors.color}; font-weight: 600; font-size: 13px;">
    <i class="fas ${colors.icon}"></i>
    ${newStatus}
    </div>
    `;
    }

    // Update data-status attribute
    card.setAttribute('data-status', newStatus.toLowerCase());

    // Update stats counters
    updateLeaveStats();
    }

    function deleteEmployee(employeeId) {
        showConfirm('Are you sure you want to delete this employee? They will be moved to archives.', () => {
            const formData = new FormData();
            formData.append('action', 'delete_employee');
            formData.append('id', employeeId);
            formData.append('csrf_token', getCSRFToken());
            
            fetch('', {
                method: 'POST',
                body: formData
            })
            .then(r => r.json())
            .then(data => {
                if (data.success) {
                    // Remove the row from the table immediately
                    const row = document.querySelector(`tr[data-id="${employeeId}"]`);
                    if(row) {
                        row.style.opacity = '0';
                        row.style.transform = 'translateX(-20px)';
                        row.style.transition = 'all 0.3s ease';
                        setTimeout(() => row.remove(), 300);
                    }
                    showToast('Employee moved to archives successfully!', 'success');
                } else {
                    showToast('Failed to delete employee: ' + (data.message || 'Unknown error'), 'error');
                }
            })
            .catch(err => {
                console.error('Delete error:', err);
                showToast('Network error: ' + err.message, 'error');
            });
        });
    }
// === ARCHIVE: REFRESH ARCHIVES TABLE ONLY (FIXED) ===
function refreshArchivesTable() {
    const tbody = document.getElementById('archivesTableBody');
    if(!tbody) {
        console.error("❌ Error: archivesTableBody element not found!");
        return;
    }

    // Show loading state
    tbody.innerHTML = '<tr><td colspan="7" style="text-align:center; padding:40px; color:var(--text-muted);"><i class="fas fa-spinner fa-spin"></i><div style="margin-top:10px;">Refreshing...</div></td></tr>';

    fetch('?action=get_archives')
    .then(r => {
        if (!r.ok) throw new Error('Server error: ' + r.status);
        return r.json();
    })
    .then(data => {
        if(data.success && data.archives) {
            if(data.archives.length === 0) {
                tbody.innerHTML = '<tr><td colspan="7" style="text-align:center; padding:40px; color:var(--text-muted);">No archived employees found.</td></tr>';
            } else {
                let html = '';
                data.archives.forEach(arch => {
                    html += `<tr data-archived-id="${arch.id}">
                        <td class="col-id">#${arch.id}</td>
                        <td class="col-name">${arch.name}</td>
                        <td class="col-position">${arch.position}</td>
                        <td class="col-dept">${arch.department}</td>
                        <td class="col-finger">${arch.employee_id}</td>
                        <td class="col-birthday">${new Date(arch.archived_at).toLocaleDateString()}</td>
                        <td class="col-actions">
                            <div class="action-btn-group">
                                <button class="action-icon-btn" style="color: #4ade80;" title="Restore to System" onclick="restoreEmployee(${arch.id}, '${arch.name.replace(/'/g, "\\'")}')">
                                    <i class="fas fa-undo"></i>
                                </button>
                                <button class="action-icon-btn" style="color: #ef4444;" title="Delete Permanently" onclick="deleteEmployeePermanently(${arch.id}, '${arch.name.replace(/'/g, "\\'")}')">
                                    <i class="fas fa-trash-can"></i>
                                </button>
                            </div>
                        </td>
                    </tr>`;
                });
                tbody.innerHTML = html;
            }
        } else {
            throw new Error(data.message || 'Invalid response format');
        }
    })
    .catch(e => {
        console.error("❌ Refresh Error:", e); // Check Console (F12) for details
        tbody.innerHTML = '<tr><td colspan="7" style="text-align:center; padding:40px; color:#ef4444;">Error refreshing archives: ' + e.message + '</td></tr>';
    });
}

// === ARCHIVE: RESTORE EMPLOYEE (UPDATED - NO PAGE RELOAD) ===
function restoreEmployee(archivedId, name) {
showConfirm(`Are you sure you want to restore <strong>${name}</strong> to the active employee list?`, () => {
const formData = new FormData();
formData.append('action', 'restore_employee');
formData.append('archived_id', archivedId);
formData.append('csrf_token', getCSRFToken());
fetch('', {
method: 'POST',
body: formData,
headers: {
'X-Requested-With': 'XMLHttpRequest'
}
})
.then(r => {
if (!r.ok) throw new Error('Server error: ' + r.status);
return r.json();
})
.then(data => {
if (data.success) {
showToast(data.message, 'success');
// Remove the row from table immediately
const row = document.querySelector(`tr[data-archived-id="${archivedId}"]`);
if(row) {
row.style.opacity = '0';
row.style.transform = 'translateX(-20px)';
row.style.transition = 'all 0.3s ease';
setTimeout(() => {
row.remove();
// ✅ REFRESH ARCHIVES TABLE ONLY (instead of location.reload())
refreshArchivesTable();
}, 300);
} else {
// If row not found, still refresh the table
refreshArchivesTable();
}
} else {
showToast('Error: ' + data.message, 'error');
}
})
.catch(err => {
console.error('Restore error:', err);
showToast('Network error: ' + err.message, 'error');
});
});
}

// === ARCHIVE: DELETE PERMANENTLY (UPDATED - NO PAGE RELOAD) ===
function deleteEmployeePermanently(archivedId, name) {
showConfirm(`⚠️ WARNING: This will PERMANENTLY delete <strong>${name}</strong> from the database. This cannot be undone. Continue?`, () => {
const formData = new FormData();
formData.append('action', 'delete_employee_permanently');
formData.append('archived_id', archivedId);
formData.append('csrf_token', getCSRFToken());
fetch('', {
method: 'POST',
body: formData,
headers: {
'X-Requested-With': 'XMLHttpRequest'
}
})
.then(r => {
if (!r.ok) throw new Error('Server error: ' + r.status);
return r.json();
})
.then(data => {
if (data.success) {
showToast(data.message, 'success');
// Remove the row from table immediately
const row = document.querySelector(`tr[data-archived-id="${archivedId}"]`);
if(row) {
row.style.opacity = '0';
row.style.transform = 'translateX(-20px)';
row.style.transition = 'all 0.3s ease';
setTimeout(() => {
row.remove();
// ✅ REFRESH ARCHIVES TABLE ONLY (instead of location.reload())
refreshArchivesTable();
}, 300);
} else {
// If row not found, still refresh the table
refreshArchivesTable();
}
} else {
showToast('Error: ' + data.message, 'error');
}
})
.catch(err => {
console.error('Delete error:', err);
showToast('Network error: ' + err.message, 'error');
});
});
}


    function showAttendanceList(type) {
    const today = '<?= date('Y-m-d') ?>';
    let url = '';
    let title = '';
    if (type === 'present') {
    url = `?action=get_attendance_list&type=present&date=${today}`;
    title = 'Employees Present Today';
    } else if (type === 'late') {
    url = `?action=get_attendance_list&type=late&date=${today}`;
    title = 'Employees Late Today';
    } else if (type === 'absent') {
    url = `?action=get_attendance_list&type=absent&date=${today}`;
    title = 'Employees Absent Today';
    } else {
    showToast('Invalid attendance type.', 'error');
    return;
    }
    fetch(url)
    .then(response => response.json())
    .then(data => {
    if (data.success) {
    let html = '<div style="padding: 10px;">';
    if (data.employees.length === 0) {
    html += '<p style="text-align: center; color: var(--text-muted); padding: 20px;">No employees found.</p>';
    } else {
    data.employees.forEach(emp => {
    html += `<div style="padding: 8px; border-bottom: 1px solid var(--border-color);">
    <strong>${emp.name}</strong><br>
    <small>EID: ${emp.employee_id} • ${emp.department}</small>
    </div>`;
    });
    }
    html += '</div>';
    document.getElementById('attendanceListContent').innerHTML = html;
    document.getElementById('attendanceListTitle').textContent = title;
    document.getElementById('attendanceListModal').style.display = 'block';
    } else {
    showToast('Failed to fetch attendance list.', 'error');
    }
    })
    .catch(error => {
    console.error('Error:', error);
    showToast('An error occurred while fetching attendance data.', 'error');
    });
    }
