    // === LIVE EMPLOYEE SEARCH ===
    function filterEmployeesTable(searchTerm) {
        const search = searchTerm.toLowerCase().trim();
        const rows = document.querySelectorAll('#employeesTableBody tr');
        let visibleCount = 0;
        
        rows.forEach(row => {
            const name = row.getAttribute('data-name')?.toLowerCase() || '';
            const eid = row.getAttribute('data-eid')?.toLowerCase() || '';
            const dept = row.querySelector('.col-dept')?.textContent.toLowerCase() || '';
            
            const matches = name.includes(search) || eid.includes(search) || dept.includes(search);
            row.style.display = matches ? '' : 'none';
            if (matches) visibleCount++;
        });
        
        const countEl = document.getElementById('employeeSearchCount');
        if (countEl) countEl.textContent = search ? `${visibleCount} found` : '';
    }

    // === HOLIDAY EMPLOYEE SEARCH - LIVE FILTER ===
    // === FILTER HOLIDAY EMPLOYEES BY SEARCH ===
    function filterHolidayEmployees(searchTerm) {
        const search = searchTerm.toLowerCase().trim();
        const rows = document.querySelectorAll('.holiday-employee-row');
        let visibleCount = 0;
        
        rows.forEach(row => {
            const name = row.getAttribute('data-name') || '';
            const eid = row.getAttribute('data-eid') || '';
            const dept = row.getAttribute('data-dept') || '';
            
            const matches = name.includes(search) || eid.includes(search) || dept.includes(search);
            row.style.display = matches ? '' : 'none';
            
            if (matches) visibleCount++;
        });
        
        const countEl = document.getElementById('holidaySearchCount');
        if (countEl) {
            countEl.textContent = search ? `${visibleCount} found` : '';
        }
    }

