    // === ADMIN: Toggle Manual Check-in ===
    function toggleManualCheckin() {
        const btn = document.getElementById('toggleManualBtn');
        const icon = document.getElementById('manualToggleIcon');
        const iconContainer = icon?.parentElement;
        const statusText = document.getElementById('manualStatusText');
        
        if (!btn || !icon || !statusText) {
            console.error("❌ Error: Could not find manual check-in elements!");
            return;
        }
        
        // 1. Identify current state from icon class
        const isCurrentlyEnabled = icon.classList.contains('fa-toggle-on');
        const newState = isCurrentlyEnabled ? '0' : '1';
        
        // 2. Optimistic UI Update
        btn.disabled = true;
        btn.style.opacity = '0.7';
        btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Updating...';
        
        if (iconContainer) {
            iconContainer.style.pointerEvents = 'none';
            iconContainer.style.opacity = '0.7';
        }
        
        // Update icon and text immediately
        if (isCurrentlyEnabled) {
            icon.className = 'fas fa-toggle-off';
            icon.style.color = 'var(--text-muted)';
            statusText.innerHTML = 'Manual Attendance is currently <span style="color:#ef4444">DISABLED</span>';
        } else {
            icon.className = 'fas fa-toggle-on';
            icon.style.color = 'var(--primary-accent)';
            statusText.innerHTML = 'Manual Attendance is currently <span style="color:#28a745">ENABLED</span>';
        }
        
        // 3. Send Request to Server
        const formData = new FormData();
        formData.append('action', 'toggle_manual_checkin');
        formData.append('status', newState);
        
        const csrfToken = document.querySelector('input[name="csrf_token"]')?.value || '';
        if(csrfToken) {
            formData.append('csrf_token', csrfToken);
        }
        
        fetch('', {
            method: 'POST',
            body: formData,
            headers: {
                'X-Requested-With': 'XMLHttpRequest'
            }
        })
        .then(r => r.json())
        .then(data => {
            btn.disabled = false;
            btn.style.opacity = '1';
            if (iconContainer) {
                iconContainer.style.pointerEvents = 'auto';
                iconContainer.style.opacity = '1';
            }
            
            btn.textContent = newState === '1' ? 'Disable Feature' : 'Enable Feature';
            
            if(data.success) {
                showToast('Setting updated successfully', 'success');
            } else {
                showToast('Failed: ' + (data.message || 'Unknown error'), 'error');
                // Revert on error
                location.reload();
            }
        })
        .catch(err => {
            btn.disabled = false;
            btn.style.opacity = '1';
            if (iconContainer) {
                iconContainer.style.pointerEvents = 'auto';
                iconContainer.style.opacity = '1';
            }
            showToast('Network error: ' + err.message, 'error');
            location.reload();
        });
    }
