    document.addEventListener('DOMContentLoaded', function() {
        const loginForm = document.getElementById('loginForm');
        console.log('[2FA] DOM Content Loaded. Form found:', !!loginForm);
        
        if(!loginForm) {
            console.error('[2FA] Could not find login form!');
            return;
        }
        
        const hasPending2FA = <?= !empty($_SESSION['pending_2fa']) ? 'true' : 'false' ?>;
        const credentialFields = document.getElementById('credentialFields');
        const passwordField = document.getElementById('passwordField');
        const twofaFields = document.getElementById('twofaFields');
        const forgotLink = document.getElementById('forgotPasswordLink');
        const submitText = document.getElementById('loginSubmitText');
        const submitBtn = document.getElementById('loginSubmitBtn');
        const loginActionInput = document.getElementById('loginAction');
        const verificationInput = document.getElementById('verificationCode');
        const employeeInput = document.getElementById('employeeId');
        const passwordInput = document.getElementById('password');
        const errorDiv = document.getElementById('loginError');
        
        console.log('[2FA] Elements found:', {
            credentialFields: !!credentialFields,
            passwordField: !!passwordField,
            twofaFields: !!twofaFields,
            verificationInput: !!verificationInput,
            submitBtn: !!submitBtn
        });
        
        if (!twofaFields || !verificationInput) {
            console.error('[2FA] Missing critical 2FA elements!');
            return;
        }
        
        let twofaMode = false;

        function set2FAMode(enabled) {
            twofaMode = enabled;
            console.log('[2FA] Switching to 2FA mode:', enabled);
            
            // Show/hide credential fields
            if (credentialFields) {
                credentialFields.style.display = enabled ? 'none' : 'block';
                console.log('[2FA] credentialFields display set to:', credentialFields.style.display);
            }
            if (passwordField) {
                passwordField.style.display = enabled ? 'none' : 'block';
                console.log('[2FA] passwordField display set to:', passwordField.style.display);
            }
            if (forgotLink) {
                forgotLink.style.display = enabled ? 'none' : 'block';
            }
            
            // Show/hide 2FA form
            if (twofaFields) {
                twofaFields.style.display = enabled ? 'block' : 'none';
                twofaFields.style.visibility = 'visible';
                twofaFields.style.opacity = enabled ? '1' : '';
                twofaFields.style.pointerEvents = enabled ? 'auto' : '';
                console.log('[2FA] twofaFields display set to:', twofaFields.style.display);
            }
            
            // Update button text and form fields
            if (submitText) {
                submitText.textContent = enabled ? 'Verify Code' : 'Sign In';
            }
            if (loginActionInput) {
                loginActionInput.name = enabled ? 'action' : 'login';
                loginActionInput.value = enabled ? 'verify_2fa' : '1';
            }
            if (verificationInput) {
                verificationInput.required = enabled;
                verificationInput.disabled = false;
                verificationInput.readOnly = false;
                verificationInput.style.pointerEvents = 'auto';
                verificationInput.tabIndex = enabled ? 0 : -1;
            }
            if (employeeInput) {
                employeeInput.required = !enabled;
            }
            if (passwordInput) {
                passwordInput.required = !enabled;
            }
        }
        
        // Initialize on first load if pending 2FA
        if (hasPending2FA) {
            console.log('[2FA] Pending 2FA session detected');
            set2FAMode(true);
            verificationInput?.focus();
        }

            // === 2FA STATE MANAGEMENT ===
            let resendCooldownActive = false;
            let lastResendTime = 0;
            let codeExpiryTime = null;
            let expiryTimerInterval = null;

            // Format time remaining for display
            function formatTimeRemaining(seconds) {
                const mins = Math.floor(seconds / 60);
                const secs = seconds % 60;
                return `${String(mins).padStart(2, '0')}:${String(secs).padStart(2, '0')}`;
            }

            // Start expiry countdown timer
            function startExpiryTimer() {
                if (expiryTimerInterval) clearInterval(expiryTimerInterval);
                
                const timerDisplay = document.getElementById('codeExpiryTimer');
                if (!timerDisplay) return;
                
                // Code expires in 10 minutes from now
                codeExpiryTime = Date.now() + (10 * 60 * 1000);
                
                expiryTimerInterval = setInterval(() => {
                    const now = Date.now();
                    const remaining = Math.max(0, Math.floor((codeExpiryTime - now) / 1000));
                    
                    if (timerDisplay) {
                        timerDisplay.textContent = formatTimeRemaining(remaining);
                        
                        // Change color to red when 2 minutes or less
                        if (remaining <= 120) {
                            timerDisplay.style.color = '#fca5a5';
                        } else {
                            timerDisplay.style.color = '#00FFE0';
                        }
                    }
                    
                    if (remaining <= 0) {
                        clearInterval(expiryTimerInterval);
                        if (timerDisplay) timerDisplay.textContent = '00:00';
                    }
                }, 1000);
            }

            // Start resend button cooldown
            function startResendCooldown() {
                resendCooldownActive = true;
                lastResendTime = Date.now();
                const resendBtn = document.getElementById('resendCodeBtn');
                const cooldownDisplay = document.getElementById('resendCooldownDisplay');
                const countdownSpan = document.getElementById('resendCountdown');
                
                if (!resendBtn || !cooldownDisplay) return;
                
                resendBtn.disabled = true;
                cooldownDisplay.style.display = 'inline';
                
                let remaining = 60;
                const cooldownInterval = setInterval(() => {
                    remaining--;
                    if (countdownSpan) countdownSpan.textContent = remaining;
                    
                    if (remaining <= 0) {
                        clearInterval(cooldownInterval);
                        resendCooldownActive = false;
                        resendBtn.disabled = false;
                        cooldownDisplay.style.display = 'none';
                    }
                }, 1000);
            }

            // Update masked email display
            function updateMaskedEmail(email) {
                const display = document.getElementById('maskingEmail_display');
                if (!display || !email) return;
                
                const parts = email.split('@');
                if (parts.length !== 2) {
                    display.textContent = 'your email';
                    return;
                }
                
                const [local, domain] = parts;
                const localMasked = local.length <= 2 ? local.substring(0, 1) + '*' : local.substring(0, 2) + '*'.repeat(Math.max(1, local.length - 2));
                display.textContent = localMasked + '@' + domain;
            }

            // Enhanced form submission
            loginForm.addEventListener('submit', function(e) {
                e.preventDefault();
                e.stopPropagation();
                
                // Validate code input in 2FA mode
                if (twofaMode) {
                    const codeInput = verificationInput.value.trim();
                    if (!codeInput) {
                        showErrorMessage('Please enter the verification code.', 'warning');
                        verificationInput.focus();
                        return false;
                    }
                    if (!/^\d{6}$/.test(codeInput)) {
                        showErrorMessage('Please enter a valid 6-digit code.', 'warning');
                        verificationInput.focus();
                        verificationInput.select();
                        return false;
                    }
                }
                
                const formData = new FormData(this);
                if (twofaMode) {
                    formData.set('action', 'verify_2fa');
                    formData.delete('login');
                } else {
                    formData.set('login', '1');
                    formData.delete('action');
                }
                formData.append('is_ajax', '1');
                
                const errorDiv = document.getElementById('loginError');
                const statusMsg = twofaMode ? 'Verifying code...' : 'Signing in...';
                showStatusMessage(statusMsg, 'info');
                
                // Disable submit button during request
                const submitBtn = document.getElementById('loginSubmitBtn');
                const originalText = submitBtn.innerHTML;
                submitBtn.disabled = true;
                submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> ' + statusMsg;
                
                fetch('', {
                    method: 'POST',
                    body: formData,
                    headers: { 'X-Requested-With': 'XMLHttpRequest' }
                })
                .then(response => response.json())
                .then(data => {
                    console.log('Login response received:', data);
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = originalText;
                    
                    if (data.success && data.requires_2fa) {
                        console.log('2FA required, switching mode...');
                        // Credentials valid, now waiting for 2FA code
                        set2FAMode(true);
                        startExpiryTimer();
                        startResendCooldown();
                        
                        // Extract and mask email from message
                        if (data.message && data.message.includes('@')) {
                            const emailMatch = data.message.match(/([a-zA-Z0-9.*@\-_]+@[a-zA-Z0-9.\-]+)/);
                            if (emailMatch) {
                                console.log('Email found:', emailMatch[0]);
                                updateMaskedEmail(emailMatch[0]);
                            }
                        }
                        
                        showStatusMessage(data.message || 'Verification code sent. Check your email.', 'success');
                        verificationInput.value = '';
                        verificationInput.focus();
                        
                        // Clear any "too many attempts" alert
                        const alertDiv = document.getElementById('tooManyAttemptsAlert');
                        if (alertDiv) alertDiv.style.display = 'none';
                    } 
                    else if (data.success) {
                        console.log('Login successful!');
                        // Login successful
                        showStatusMessage('Login successful! Redirecting...', 'success');
                        
                        setTimeout(() => {
                            let target = data.redirect || window.location.pathname;
                            if (!data.redirect) {
                                try {
                                    const last = localStorage.getItem('lastAdminView');
                                    if (last) {
                                        target = window.location.pathname + '?view=' + last;
                                    }
                                } catch (e) {}
                                const cookieMatch = document.cookie.match(/(?:^|; )last_admin_view=([^;]+)/);
                                if (!target.includes('view=') && cookieMatch) {
                                    target = window.location.pathname + '?view=' + cookieMatch[1];
                                }
                            }
                            window.location.href = target;
                        }, 800);
                    }
                    else {
                        console.log('Login failed:', data.error);
                        // Handle different error types
                        let errorMsg = data.error || 'Login failed';
                        let errorType = 'error';
                        const alertDiv = document.getElementById('tooManyAttemptsAlert');
                        
                        if (errorMsg.includes('Too many') || errorMsg.includes('too many')) {
                            errorType = 'warning';
                            if (alertDiv) alertDiv.style.display = 'block';
                        } else if (alertDiv) {
                            alertDiv.style.display = 'none';
                        }
                        
                        showErrorMessage(errorMsg, errorType);
                        
                        if (twofaMode) {
                            verificationInput.value = '';
                            if (!errorMsg.includes('Too many')) {
                                verificationInput.focus();
                            }
                        }
                    }
                })
                .catch(err => {
                    submitBtn.disabled = false;
                    submitBtn.innerHTML = originalText;
                    showErrorMessage('Network error: ' + err.message, 'error');
                });
                
                return false;
            });

            // Enhanced resend code handler with cooldown
            document.getElementById('resendCodeBtn')?.addEventListener('click', function(e) {
                e.preventDefault();
                e.stopPropagation();
                
                if (resendCooldownActive) {
                    showStatusMessage('Please wait before requesting a new code.', 'warning');
                    return;
                }
                
                this.disabled = true;
                const originalText = this.innerHTML;
                this.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Sending...';
                
                const formData = new FormData();
                formData.append('action', 'resend_2fa_code');
                formData.append('csrf_token', document.querySelector('input[name="csrf_token"]')?.value || '');
                
                fetch('', {
                    method: 'POST',
                    body: formData,
                    headers: { 'X-Requested-With': 'XMLHttpRequest' }
                })
                .then(r => r.json())
                .then(data => {
                    if (data.success) {
                        showStatusMessage(data.message || 'Verification code resent. Check your email.', 'success');
                        startExpiryTimer();
                        startResendCooldown();
                    } else {
                        showErrorMessage(data.error || 'Failed to resend code.', 'error');
                        this.disabled = false;
                        this.innerHTML = originalText;
                    }
                })
                .catch(err => {
                    showErrorMessage('Network error: ' + err.message, 'error');
                    this.disabled = false;
                    this.innerHTML = originalText;
                });
            });

            // Back to login button
            document.getElementById('backToLoginBtn')?.addEventListener('click', function(e) {
                e.preventDefault();
                e.stopPropagation();
                
                if (expiryTimerInterval) clearInterval(expiryTimerInterval);
                
                set2FAMode(false);
                verificationInput.value = '';
                
                const errorDiv = document.getElementById('loginError');
                if (errorDiv) {
                    errorDiv.style.display = 'none';
                    errorDiv.textContent = '';
                }
                
                employeeInput.focus();
            });

            // Helper function to show error message
            function showErrorMessage(msg, type = 'error') {
                const errorDiv = document.getElementById('loginError');
                if (!errorDiv) return;
                
                errorDiv.style.display = 'block';
                errorDiv.textContent = msg;
                
                if (type === 'error') {
                    errorDiv.style.background = 'rgba(239, 68, 68, 0.1)';
                    errorDiv.style.color = '#ff6b6b';
                    errorDiv.style.borderColor = 'rgba(239, 68, 68, 0.2)';
                } else if (type === 'warning') {
                    errorDiv.style.background = 'rgba(245, 158, 11, 0.1)';
                    errorDiv.style.color = '#fbbf24';
                    errorDiv.style.borderColor = 'rgba(245, 158, 11, 0.2)';
                }
            }

            // Helper function to show status message
            function showStatusMessage(msg, type = 'info') {
                const errorDiv = document.getElementById('loginError');
                if (!errorDiv) return;
                
                errorDiv.style.display = 'block';
                errorDiv.textContent = msg;
                
                if (type === 'success') {
                    errorDiv.style.background = 'rgba(34, 197, 94, 0.1)';
                    errorDiv.style.color = '#4ade80';
                    errorDiv.style.borderColor = 'rgba(34, 197, 94, 0.2)';
                } else if (type === 'info') {
                    errorDiv.style.background = 'rgba(25, 211, 197, 0.1)';
                    errorDiv.style.color = '#19D3C5';
                    errorDiv.style.borderColor = 'rgba(25, 211, 197, 0.2)';
                } else if (type === 'warning') {
                    errorDiv.style.background = 'rgba(245, 158, 11, 0.1)';
                    errorDiv.style.color = '#fbbf24';
                    errorDiv.style.borderColor = 'rgba(245, 158, 11, 0.2)';
                }
            }

            // If we already have a pending 2FA session, initialize timers
            if (hasPending2FA) {
                set2FAMode(true);
                startExpiryTimer();
                // Don't start cooldown since we don't know when the code was sent
                verificationInput.focus();
            }
    });


