    function displayFPEmployeeTable(employees) {
        const tbody = document.getElementById('fingerprintTableBody');
        if (!tbody) return;
        if (employees.length === 0) {
            tbody.innerHTML = '<tr><td colspan="6" style="text-align: center; padding: 40px; color: var(--text-muted);">No employees found.</td></tr>';
            return;
        }
        tbody.innerHTML = employees.map(emp => `
            <tr data-name="${emp.name.toLowerCase()}" data-eid="${emp.employee_id.toLowerCase()}">
                <td>${emp.photo_path ? `<img src="${emp.photo_path}" style="width: 50px; height: 50px; border-radius: 50%; object-fit: cover;">` : '<div style="width: 50px; height: 50px; border-radius: 50%; background: var(--primary-accent); display: flex; align-items: center; justify-content: center;"><i class="fas fa-user"></i></div>'}</td>
                <td><strong>${emp.name}</strong></td>
                <td>${emp.employee_id}</td>
                <td>${emp.department || '-'}</td>
                <td>${emp.finger_id ? `<span style="background: var(--primary-accent); color: #00110f; padding: 4px 12px; border-radius: 20px; font-weight: 600; font-size: 12px;">${emp.finger_id}</span>` : '<span style="color: var(--text-muted);">Not set</span>'}</td>
                <td><div class="action-btn-group"><button class="action-icon-btn delete" onclick="removeFingerprintEnrollment(${emp.id}, '${emp.name.replace(/'/g, "\\'")}')"><i class="fas fa-trash"></i></button></div></td>
            </tr>
        `).join('');
    }

    function displayFingerprintScans(scans) {
        const container = document.getElementById('fingerprintScansList');
        if (!container) return;
        if (scans.length === 0) {
            container.innerHTML = '<div style="padding: 20px; text-align: center; color: var(--text-muted);">No fingerprint scans recorded yet</div>';
            return;
        }
        container.innerHTML = scans.map(scan => `
            <div class="record-item">
                <div class="record-info">
                    <div class="record-icon present"><i class="fas fa-fingerprint"></i></div>
                    <div class="record-details">
                        <div class="record-name">${scan.name}</div>
                        <div class="record-id">Finger ID: ${scan.finger_id || 'N/A'} • ${scan.employee_id}</div>
                    </div>
                </div>
                <div class="record-time">
                    <div>${new Date(scan.check_in).toLocaleDateString()}</div>
                    <div>${new Date(scan.check_in).toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', second: '2-digit', hour12: true })}</div>
                </div>
            </div>
        `).join('');
    }

    function filterFingerprintTable(searchTerm) {
        const search = searchTerm.toLowerCase();
        const rows = document.querySelectorAll('#fingerprintTableBody tr[data-name]');
        rows.forEach(row => {
            const name = row.getAttribute('data-name');
            const eid = row.getAttribute('data-eid');
            row.style.display = (name.includes(search) || eid.includes(search)) ? '' : 'none';
        });
    }

function removeFingerprintEnrollment(employeeId, employeeName) {
showConfirm(`Remove fingerprint enrollment for <strong>${employeeName}</strong>?<br>They will need to re-enroll to scan attendance.`, () => {
const formData = new FormData();
formData.append('action', 'remove_fingerprint');
formData.append('employee_id', employeeId);

// Get CSRF Token
const csrfToken = document.querySelector('input[name="csrf_token"]')?.value || 
                  document.querySelector('meta[name="csrf-token"]')?.content || '';
if(csrfToken) {
formData.append('csrf_token', csrfToken);
}

fetch('', {
method: 'POST',
body: formData,
headers: {
'X-Requested-With': 'XMLHttpRequest'
}
})
.then(r => r.json())
.then(data => {
if (data.success) {
// Find and animate the row removal
const row = document.querySelector(`#fingerprintTableBody tr[data-emp-id="${employeeId}"]`);
if(row) {
row.style.transition = 'all 0.3s ease';
row.style.opacity = '0';
row.style.transform = 'translateX(-20px)';
setTimeout(() => {
row.remove();
loadFingerprintData();
}, 300);
} else {
loadFingerprintData();
}
showToast('Fingerprint enrollment removed successfully', 'success');
} else {
showToast('Failed: ' + (data.message || 'Unknown error'), 'error');
}
})
.catch(e => {
console.error('Delete error:', e);
showToast('Network error: ' + e.message, 'error');
});
});
}
    // === ADMIN: Toggle Manual Check-in (With Persistence) ===
    function toggleManualCheckin() {
        const btn = document.getElementById('toggleManualBtn');
        const icon = document.getElementById('manualToggleIcon');
        const iconContainer = icon?.parentElement;
        const statusText = document.getElementById('manualStatusText');
        
        if (!btn || !icon || !statusText) {
            console.error("❌ Error: Could not find manual check-in elements!");
            return;
        }

        // 1. Identify current state from icon class
        const isCurrentlyEnabled = icon.classList.contains('fa-toggle-on');
        const newState = isCurrentlyEnabled ? '0' : '1';
        
        console.log(`Current state: ${isCurrentlyEnabled ? 'ENABLED' : 'DISABLED'}`);
        console.log(`Switching to: ${newState === '1' ? 'ENABLED' : 'DISABLED'}`);

        // 2. Optimistic UI Update (Change UI immediately for better UX)
        btn.disabled = true;
        btn.style.opacity = '0.7';
        btn.style.cursor = 'not-allowed';
        if (iconContainer) {
            iconContainer.style.pointerEvents = 'none'; // Prevent double-clicks
            iconContainer.style.opacity = '0.7';
        }
        btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Updating...';
        
        // Update icon and text immediately
        if (isCurrentlyEnabled) {
            // Switching to DISABLED
            icon.className = 'fas fa-toggle-off';
            icon.style.color = 'var(--text-muted)';
            statusText.innerHTML = 'Manual Attendance is currently <span style="color:#ef4444">DISABLED</span>';
        } else {
            // Switching to ENABLED
            icon.className = 'fas fa-toggle-on';
            icon.style.color = 'var(--primary-accent)';
            statusText.innerHTML = 'Manual Attendance is currently <span style="color:#28a745">ENABLED</span>';
        }

        // 3. Send Request to Server
    const formData = new FormData();
    formData.append('action', 'toggle_manual_checkin');
    formData.append('status', newState);  // Should be '0' or '1'
        
        // Get CSRF Token
        const csrfToken = document.querySelector('input[name="csrf_token"]')?.value ||
                        document.querySelector('meta[name="csrf-token"]')?.content || '';
        if(csrfToken) {
            formData.append('csrf_token', csrfToken);
        }
        
        fetch('', {
            method: 'POST',
            body: formData,
            headers: {
                'X-Requested-With': 'XMLHttpRequest'
            }
        })
        .then(r => {
            if (!r.ok) throw new Error(`HTTP ${r.status}`);
            return r.json();
        })
        .then(data => {
            console.log("✅ Server Response:", data);
            // Re-enable button
            btn.disabled = false;
            btn.style.opacity = '1';
            btn.style.cursor = 'pointer';
            if (iconContainer) {
                iconContainer.style.pointerEvents = 'auto';
                iconContainer.style.opacity = '1';
            }
            // Update button text to reflect the NEW state
            btn.textContent = newState === '1' ? 'Disable Feature' : 'Enable Feature';
            
            if(data.success) {
                showToast('Setting updated successfully', 'success');
            } else {
                // If server fails, revert the UI
                showToast('Failed to update setting: ' + (data.message || 'Unknown error'), 'error');
                revertUI(isCurrentlyEnabled, btn, icon, statusText, iconContainer);
            }
        })
        .catch(err => {
            console.error("❌ Network Error:", err);
            btn.disabled = false;
            btn.style.opacity = '1';
            btn.style.cursor = 'pointer';
            btn.textContent = isCurrentlyEnabled ? 'Disable Feature' : 'Enable Feature';
            if (iconContainer) {
                iconContainer.style.pointerEvents = 'auto';
                iconContainer.style.opacity = '1';
            }
            showToast('Network error: ' + err.message, 'error');
            revertUI(isCurrentlyEnabled, btn, icon, statusText, iconContainer);
        });
    }

    // Helper function to revert UI on error
    function revertUI(originalState, btn, icon, statusText, iconContainer) {
        if (btn) {
            btn.disabled = false;
            btn.style.opacity = '1';
            btn.style.cursor = 'pointer';
        }
        if (iconContainer) {
            iconContainer.style.pointerEvents = 'auto';
            iconContainer.style.opacity = '1';
        }
        if (originalState) {
            icon.className = 'fas fa-toggle-on';
            icon.style.color = 'var(--primary-accent)';
            statusText.innerHTML = 'Manual Attendance is currently <span style="color:#28a745">ENABLED</span>';
            if (btn) btn.textContent = 'Disable Feature';
        } else {
            icon.className = 'fas fa-toggle-off';
            icon.style.color = 'var(--text-muted)';
            statusText.innerHTML = 'Manual Attendance is currently <span style="color:#ef4444">DISABLED</span>';
            if (btn) btn.textContent = 'Enable Feature';
        }
    }


    function exportAttendanceData() {
        // Get current filters from the UI
        const dateInput = document.getElementById('attendanceDateFilter');
        const searchInput = document.getElementById('attendanceSearchInput');
        const date = dateInput ? dateInput.value : new Date().toISOString().split('T')[0];
        const search = searchInput ? searchInput.value : '';
        
        showToast('Fetching live data...', 'info');
        
        // 1. Fetch FRESH data from the server based on current filters
        let apiUrl = `?action=get_export_data&type=attendance&start_date=${date}&end_date=${date}`;
        if(search) {
            apiUrl += `&search=${encodeURIComponent(search)}`;
        }
        
        fetch(apiUrl)
        .then(response => response.json())
        .then(data => {
            if (!data.success || !data.data || data.data.length === 0) {
                showToast('No data found for this selection.', 'warning');
                return;
            }
            
            // 2. Build the CSV Content with CORRECT column mapping
            // Header Row
            let csvContent = "Date,Employee ID,Name,Department,Check In,Check Out,Regular Hours,Overtime Hours,Night Diff Hours,Status\n";
            
            // Data Rows
            data.data.forEach(row => {
                // Parse dates properly
                const checkInDate = row.check_in ? new Date(row.check_in) : null;
                const checkOutDate = row.check_out ? new Date(row.check_out) : null;
                
                // Extract just the date (YYYY-MM-DD)
                const dateStr = checkInDate ? checkInDate.toLocaleDateString('en-US', {
                    year: 'numeric', month: '2-digit', day: '2-digit'
                }) : '';
                
                // Format Check In time (HH:MM AM/PM)
                const checkInTime = checkInDate ? checkInDate.toLocaleTimeString('en-US', {
                    hour: '2-digit', minute: '2-digit', hour12: true
                }) : '';
                
                // Format Check Out time (HH:MM AM/PM)
                const checkOutTime = checkOutDate ? checkOutDate.toLocaleTimeString('en-US', {
                    hour: '2-digit', minute: '2-digit', hour12: true
                }) : '';
                
                // Calculate working hours if both check-in and check-out exist
                let workingHours = '';
                if (checkInDate && checkOutDate) {
                    const diffMs = checkOutDate - checkInDate;
                    const diffHrs = Math.floor(diffMs / 3600000);
                    const diffMins = Math.floor((diffMs % 3600000) / 60000);
                    workingHours = `${diffHrs}h ${diffMins}m`;
                } else {
                    workingHours = row.regular_hours ? `${row.regular_hours}h` : '-';
                }
                
                // Escape commas and quotes in text fields to prevent CSV breaking
                const safeName = `"${(row.name || '').replace(/"/g, '""')}"`;
                const safeDept = `"${(row.department || '').replace(/"/g, '""')}"`;
                const safeStatus = `"${(row.status || '').replace(/"/g, '""')}"`;
                
                // Build the row with CORRECT column order
                csvContent += `${dateStr},${row.employee_id},${safeName},${safeDept},${checkInTime},${checkOutTime},${workingHours},${row.overtime_hours || '0'},${row.night_diff_hours || '0'},${safeStatus}\n`;
            });
            
            // 3. Create and Download the File
            const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement("a");
            link.setAttribute("href", url);
            
            // Generate filename with date
            const fileName = `Attendance_Report_${date}${search ? '_'+search.replace(/[^a-z0-9]/gi, '_') : ''}.csv`;
            link.setAttribute("download", fileName);
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            
            showToast('Report downloaded successfully!', 'success');
        })
        .catch(error => {
            console.error('Error:', error);
            showToast('Failed to generate report.', 'error');
        });
    }
    // === EMPLOYEE: Submit Manual Attendance ===
    function submitManualAttendance(type) {
        const btn = type === 'IN' ? document.getElementById('manualCheckInBtn') : document.getElementById('manualCheckOutBtn');
        const msg = document.getElementById('manualMsg');
        
        if(!btn || btn.disabled) {
            console.log('Button not found or disabled:', btn);
            return;
        }
        
        const originalText = btn.innerHTML;
        btn.disabled = true;
        btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Processing...';
        if(msg) {
            msg.textContent = 'Processing your request...';
            msg.style.color = 'var(--text-muted)';
        }
        
        const formData = new FormData();
        formData.append('action', 'manual_attendance');
        formData.append('type', type);
        
        // Get CSRF Token
        const csrfToken = document.querySelector('input[name="csrf_token"]')?.value || 
                        document.querySelector('meta[name="csrf-token"]')?.content || '';
        if(csrfToken) {
            formData.append('csrf_token', csrfToken);
        }
        
        console.log('Submitting manual attendance:', type);
        
        fetch('', { 
            method: 'POST', 
            body: formData,
            headers: {
                'X-Requested-With': 'XMLHttpRequest'
            }
        })
        .then(r => {
            console.log('Response status:', r.status);
            if (!r.ok) {
                throw new Error('Server error: ' + r.status);
            }
            return r.json();
        })
        .then(data => {
            console.log('Response data:', data);
            btn.disabled = false;
            btn.innerHTML = originalText;
            
            if(data.success) {
                if(msg) {
                    msg.textContent = `✓ ${data.message} at ${data.time || new Date().toLocaleTimeString()}`;
                    msg.style.color = '#28a745';
                }
                
                // Toggle Buttons
                const checkInBtn = document.getElementById('manualCheckInBtn');
                const checkOutBtn = document.getElementById('manualCheckOutBtn');
                
                if (type === 'IN') {
                    if(checkInBtn) {
                        checkInBtn.disabled = true; 
                        checkInBtn.style.opacity = '0.5';
                    }
                    if(checkOutBtn) {
                        checkOutBtn.disabled = false; 
                        checkOutBtn.style.opacity = '1';
                    }
                    // Enable Lunch Buttons
                    const btnLunchOut = document.getElementById('btnLunchOut');
                    if(btnLunchOut) {
                        btnLunchOut.disabled = false;
                        btnLunchOut.style.opacity = '1';
                    }
                } else {
                    if(checkOutBtn) {
                        checkOutBtn.disabled = true; 
                        checkOutBtn.style.opacity = '0.5';
                    }
                    // Disable all buttons after checkout
                    if(checkInBtn) {
                        checkInBtn.disabled = true;
                        checkInBtn.style.opacity = '0.5';
                    }
                    const btnLunchOut = document.getElementById('btnLunchOut');
                    const btnLunchIn = document.getElementById('btnLunchIn');
                    if(btnLunchOut) {
                        btnLunchOut.disabled = true;
                        btnLunchOut.style.opacity = '0.5';
                    }
                    if(btnLunchIn) {
                        btnLunchIn.disabled = true;
                        btnLunchIn.style.opacity = '0.5';
                    }
                }
                
                // Update Status Badge
                const statusBadge = document.getElementById('currentStatusBadge');
                if(statusBadge) {
                    if(type === 'IN') {
                        statusBadge.className = 'status-pill active';
                        statusBadge.innerHTML = '<i class="fas fa-check-circle"></i> Currently Working';
                    } else {
                        statusBadge.className = 'status-pill inactive';
                        statusBadge.innerHTML = '<i class="fas fa-times-circle"></i> Shift Completed';
                    }
                }
                
                // Reload page after 2 seconds to update all data
                setTimeout(() => {
                    location.reload();
                }, 2000);
                
            } else {
                if(msg) {
                    msg.textContent = '✗ Error: ' + (data.message || 'Failed to process request');
                    msg.style.color = '#dc3545';
                }
                console.error('Server error:', data.message);
            }
        })
        .catch(err => {
            console.error('Network Error:', err);
            btn.disabled = false;
            btn.innerHTML = originalText;
            if(msg) {
                msg.textContent = '✗ Network error: ' + err.message;
                msg.style.color = '#dc3545';
            }
        });
    }

    // === INITIALIZATION: Set Button States on Page Load ===
    document.addEventListener('DOMContentLoaded', function() {
        // Get PHP variables passed to JS
        const isCheckedIn = <?= $attendanceInfo && $attendanceInfo['check_in'] && !$attendanceInfo['check_out'] ? 'true' : 'false' ?>;
        const isCompleted = <?= $attendanceInfo && $attendanceInfo['check_out'] ? 'true' : 'false' ?>;
        const lunchOut = <?= $attendanceInfo && $attendanceInfo['lunch_out'] ? 'true' : 'false' ?>;
        const lunchIn = <?= $attendanceInfo && $attendanceInfo['lunch_in'] ? 'true' : 'false' ?>;
        const checkInBtn = document.getElementById('manualCheckInBtn');
        const checkOutBtn = document.getElementById('manualCheckOutBtn');
        const btnLunchOut = document.getElementById('btnLunchOut');
        const btnLunchIn = document.getElementById('btnLunchIn');
        
        if(checkInBtn && checkOutBtn) {
            if (isCompleted) {
                // Shift Done
                checkInBtn.disabled = true; checkInBtn.style.opacity = '0.5';
                checkOutBtn.disabled = true; checkOutBtn.style.opacity = '0.5';
                if(btnLunchOut) btnLunchOut.disabled = true;
                if(btnLunchIn) btnLunchIn.disabled = true;
            } else if (isCheckedIn) {
                // Currently Working
                checkInBtn.disabled = true; checkInBtn.style.opacity = '0.5';
                checkOutBtn.disabled = false; checkOutBtn.style.opacity = '1';
                if(btnLunchOut) {
                    btnLunchOut.disabled = false;
                    btnLunchOut.style.opacity = '1';
                }
                if(btnLunchIn) {
                    btnLunchIn.disabled = true;
                    btnLunchIn.style.opacity = '0.5';
                }
                // If already on lunch
                if(lunchOut && !lunchIn) {
                    if(btnLunchOut) { btnLunchOut.disabled = true; btnLunchOut.style.opacity = '0.5'; }
                    if(btnLunchIn) { btnLunchIn.disabled = false; btnLunchIn.style.opacity = '1'; }
                }
            } else {
                // Not Checked In
                checkInBtn.disabled = false; checkInBtn.style.opacity = '1';
                checkOutBtn.disabled = true; checkOutBtn.style.opacity = '0.5';
                if(btnLunchOut) btnLunchOut.disabled = true;
                if(btnLunchIn) btnLunchIn.disabled = true;
            }
        }
    });
// === ADMIN: ASSIGN LEAVE CREDITS ===
function assignLeaveCredits(event) {
    event.preventDefault();
    
    const employeeId = document.getElementById('assignEmployee').value;
    const leaveType = document.getElementById('assignLeaveType').value;
    const days = document.getElementById('assignDays').value;
    const messageDiv = document.getElementById('assignLeaveMessage');
    
    if (!employeeId) {
        messageDiv.innerHTML = '<span style="color: #ef4444;">Please select an employee</span>';
        return;
    }
    
    const formData = new FormData();
    formData.append('action', 'assign_leave_credits');
    formData.append('employee_id', employeeId);
    formData.append('leave_type', leaveType);
    formData.append('days', days);
    formData.append('csrf_token', getCSRFToken());
    
    messageDiv.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Assigning...';
    
    fetch('', {
        method: 'POST',
        body: formData
    })
    .then(r => r.json())
    .then(data => {
        if (data.success) {
            messageDiv.innerHTML = '<span style="color: #28a745;">✓ ' + data.message + '</span>';
            // Clear form
            document.getElementById('assignEmployee').value = '';
            document.getElementById('assignDays').value = '15';
            
            // Show success toast
            showToast(data.message, 'success');
            
            // Refresh leave management section to show updated balances
            setTimeout(() => {
                if (typeof refreshLeaveRequests === 'function') {
                    refreshLeaveRequests();
                }
            }, 1000);
        } else {
            messageDiv.innerHTML = '<span style="color: #ef4444;">✗ ' + data.message + '</span>';
        }
    })
    .catch(e => {
        messageDiv.innerHTML = '<span style="color: #ef4444;">✗ Network error: ' + e.message + '</span>';
    });
}
    // === LEAVE MODULE: Filter Function (ADMIN) - FIXED ===
function filterLeaveRequests() {
    // 1. Get the search term from the correct input
    const searchInput = document.getElementById('leaveAdminSearch');
    const search = searchInput ? searchInput.value.toLowerCase().trim() : '';
    
    // 2. Get the status filter value
    const statusFilter = document.getElementById('leaveStatusFilter');
    const selectedStatus = statusFilter ? statusFilter.value : 'All Requests';
    
    // 3. Select all leave cards
    const cards = document.querySelectorAll('#leaveRequestsList .leave-card');
    let visibleCount = 0;
    let pendingCount = 0;
    let approvedCount = 0;
    let rejectedCount = 0;
    
    cards.forEach(card => {
        // Get card data attributes
        const cardStatus = card.getAttribute('data-status'); // e.g., 'pending', 'approved', 'rejected'
        const cardName = card.getAttribute('data-name') || '';
        const cardEid = card.getAttribute('data-eid') || '';
        const cardText = card.textContent.toLowerCase();
        
        // 4. Determine if card should be visible
        let show = true;
        
        // Check Status Filter (only if not "All Requests")
        if (selectedStatus !== 'All Requests') {
            // Convert filter to lowercase to match data-status
            if (cardStatus !== selectedStatus.toLowerCase()) {
                show = false;
            }
        }
        
        // Check Search Filter (search in name, EID, or full text)
        if (search && !cardText.includes(search)) {
            show = false;
        }
        
        // 5. Apply visibility with animation
        if (show) {
            card.style.display = 'flex';
            card.style.animation = 'slideIn 0.3s ease';
            visibleCount++;
            
            // Count for stats
            if (cardStatus === 'pending') pendingCount++;
            else if (cardStatus === 'approved') approvedCount++;
            else if (cardStatus === 'rejected') rejectedCount++;
        } else {
            card.style.display = 'none';
            card.style.animation = 'none';
        }
    });
    
    // 6. Update counters with filtered results
    updateLeaveCounters(pendingCount, approvedCount, rejectedCount);
    
    // 7. Show/hide empty state
    const listContainer = document.getElementById('leaveRequestsList');
    if (visibleCount === 0 && cards.length > 0) {
        if (!document.querySelector('.filter-empty-state')) {
            const emptyState = document.createElement('div');
            emptyState.className = 'filter-empty-state';
            emptyState.innerHTML = `
                <div style="text-align: center; padding: 40px; grid-column: 1/-1;">
                    <div style="font-size: 48px; margin-bottom: 15px; opacity: 0.5;">🔍</div>
                    <div style="color: var(--text-muted);">No requests match your filters</div>
                </div>
            `;
            listContainer.appendChild(emptyState);
        }
    } else {
        const existingEmpty = listContainer.querySelector('.filter-empty-state');
        if (existingEmpty) existingEmpty.remove();
    }
}

// === LEAVE MODULE: Update Counters - FIXED ===
function updateLeaveCounters(pending = null, approved = null, rejected = null) {
    // If counts are provided (from filter), use them
    // Otherwise, count from visible cards
    if (pending === null) {
        const cards = document.querySelectorAll('#leaveRequestsList .leave-card');
        pending = 0;
        approved = 0;
        rejected = 0;
        
        cards.forEach(card => {
            if (card.style.display !== 'none') {
                const status = card.getAttribute('data-status');
                if (status === 'pending') pending++;
                else if (status === 'approved') approved++;
                else if (status === 'rejected') rejected++;
            }
        });
    }
    
    // Update the stat cards
    const pendingEl = document.getElementById('count-pending');
    const approvedEl = document.getElementById('count-approved');
    const rejectedEl = document.getElementById('count-rejected');
    
    if(pendingEl) pendingEl.textContent = pending;
    if(approvedEl) approvedEl.textContent = approved;
    if(rejectedEl) rejectedEl.textContent = rejected;
}

// === LEAVE MODULE: Refresh Function - FIXED ===
function refreshLeaveRequests() {
    const btn = document.querySelector('button[onclick="refreshLeaveRequests()"] i');
    if(btn) btn.classList.add('fa-spin');
    
    showToast('Refreshing leave requests...', 'info');
    
    // Reset filters
    const statusFilter = document.getElementById('leaveStatusFilter');
    const searchInput = document.getElementById('leaveAdminSearch');
    
    if(statusFilter) statusFilter.value = 'All Requests';
    if(searchInput) searchInput.value = '';
    
    // Reload the page data
    fetch('?action=get_leave_requests_admin&status=All Requests')
    .then(r => r.json())
    .then(data => {
        if(btn) btn.classList.remove('fa-spin');
        if(data.success) {
            showToast('Leave requests refreshed', 'success');
            // The page will auto-update via the existing PHP rendering
            setTimeout(() => location.reload(), 500);
        }
    })
    .catch(e => {
        if(btn) btn.classList.remove('fa-spin');
        showToast('Refresh error: ' + e.message, 'error');
    });
}
// === FIXED: LOAD LEAVE REQUESTS ===
function loadLeaveRequests() {
    const container = document.getElementById('employeeLeaveRequestsList');
    if (!container) {
        console.error('❌ Leave requests container not found!');
        return;
    }

    // Show loading state
    container.innerHTML = `
        <div class="loading-state">
            <i class="fas fa-spinner fa-spin"></i>
            <span>Loading your requests...</span>
        </div>
    `;

    fetch('?action=get_leave_requests')
        .then(r => r.json())
        .then(data => {
            if (data.success && data.requests && data.requests.length > 0) {
                let html = '';
                data.requests.forEach(req => {
                    const statusClass = req.status.toLowerCase();
                    const statusIcon = statusClass === 'approved' ? 'fa-check-circle' :
                                      (statusClass === 'rejected' ? 'fa-times-circle' : 'fa-clock');
                    
                    const startDate = new Date(req.start_date).toLocaleDateString('en-US', {
                        year: 'numeric', month: 'short', day: 'numeric'
                    });
                    const endDate = new Date(req.end_date).toLocaleDateString('en-US', {
                        year: 'numeric', month: 'short', day: 'numeric'
                    });
                    
                    const start = new Date(req.start_date);
                    const end = new Date(req.end_date);
                    const diffTime = Math.abs(end - start);
                    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
                    
                    const hasAttachment = req.attachment_path && req.attachment_path !== '';
                    
                    html += `
                    <div class="leave-request-card" data-status="${statusClass}">
                        <div class="leave-card-header">
                            <div class="leave-type-badge">
                                <span class="leave-type">${req.type || 'Leave'} Request</span>
                            </div>
                            <span class="leave-status ${statusClass}">
                                <i class="fas ${statusIcon}"></i> ${req.status}
                            </span>
                        </div>
                        <div class="leave-card-body">
                            <div class="leave-info-item">
                                <i class="fas fa-calendar-alt"></i>
                                <div>
                                    <div class="leave-info-label">Start Date</div>
                                    <div class="leave-info-value">${startDate}</div>
                                </div>
                            </div>
                            <div class="leave-info-item">
                                <i class="fas fa-calendar-check"></i>
                                <div>
                                    <div class="leave-info-label">End Date</div>
                                    <div class="leave-info-value">${endDate}</div>
                                </div>
                            </div>
                            <div class="leave-info-item">
                                <i class="fas fa-clock"></i>
                                <div>
                                    <div class="leave-info-label">Duration</div>
                                    <div class="leave-info-value">${diffDays} day${diffDays > 1 ? 's' : ''}</div>
                                </div>
                            </div>
                            <div class="leave-info-item">
                                <i class="fas fa-calendar-day"></i>
                                <div>
                                    <div class="leave-info-label">Submitted</div>
                                    <div class="leave-info-value">${new Date(req.created_at).toLocaleDateString()}</div>
                                </div>
                            </div>
                        </div>
                        ${req.reason ? `
                        <div class="leave-reason-box">
                            <div class="leave-reason-label"><i class="fas fa-comment-alt"></i> Reason</div>
                            <div class="leave-reason-text">${req.reason}</div>
                        </div>
                        ` : ''}
                        ${hasAttachment ? `
                        <div class="leave-attachment">
                            <i class="fas fa-paperclip"></i>
                            <span class="leave-attachment-text">Attachment: ${req.attachment_path.split('/').pop()}</span>
                        </div>
                        ` : ''}
                        <div class="leave-footer">
                            <span><i class="fas fa-info-circle"></i> Request ID: #${req.id}</span>
                            ${req.admin_response ? `<span><i class="fas fa-comment"></i> ${req.admin_response}</span>` : ''}
                        </div>
                    </div>
                    `;
                });
                container.innerHTML = html;
            } else {
                container.innerHTML = `
                <div class="empty-state">
                    <i class="fas fa-inbox"></i>
                    <h4>No leave requests found</h4>
                    <p>Click "New Leave Request" to submit your first request</p>
                </div>
                `;
            }
        })
        .catch(e => {
            console.error('Load leave requests error:', e);
            container.innerHTML = `
            <div class="empty-state">
                <i class="fas fa-exclamation-triangle"></i>
                <h4>Error loading requests</h4>
                <p>Please try again later</p>
                <button class="btn-submit" onclick="loadLeaveRequests()" style="margin-top:15px;">
                    <i class="fas fa-redo"></i> Retry
                </button>
            </div>
            `;
        });
}

