                let html = '';
                data.holidays.forEach(h => {
                    let badgeColor = h.type === 'regular' ? '#dc3545' : (h.type === 'special_non_working' ? '#ffc107' : '#17a2b8');
                    let typeName = h.type === 'regular' ? 'Regular' : (h.type === 'special_non_working' ? 'Special Holiday' : 'Special Working');
                    
                    html += `
