    function openHolidayAssignment(id, name, date) {
        console.log("Opening holiday assignment:", id, name, date); // Debug log
        
        const modal = document.getElementById('holidayAssignmentModal');
        const list = document.getElementById('holidayEmployeeList');
        const titleEl = document.getElementById('modalHolidayName');
        const holidayIdInput = document.getElementById('modalHolidayId');
        
        if(!modal || !list || !titleEl || !holidayIdInput) {
            console.error("❌ Modal elements not found!");
            showToast('Modal error: Elements not found', 'error');
            return;
        }
        
        // Set modal data
        titleEl.textContent = 'Assign: ' + name;
        holidayIdInput.value = id;
        modal.style.display = 'block';
        
        // Show loading state
        list.innerHTML = '<div style="text-align:center; padding:20px;"><i class="fas fa-spinner fa-spin" style="font-size: 24px; color: var(--primary-accent);"></i><div style="margin-top:10px; color: var(--text-muted);">Loading employees...</div></div>';
        
        // Fetch employees with error handling
        fetch('?action=get_all_employees_for_holiday&holiday_id=' + id)
        .then(response => {
            console.log("Response status:", response.status); // Debug log
            if (!response.ok) {
                throw new Error('HTTP error! status: ' + response.status);
            }
            return response.json();
        })
        .then(data => {
            console.log("Response data:", data); // Debug log
            
            if(data.success && data.employees) {
                let html = '';
                
                if(data.employees.length === 0) {
                    html = '<div style="text-align:center; padding:20px; color: var(--text-muted);">No active employees found</div>';
                } else {
                    data.employees.forEach(emp => {
                        const checked = emp.assigned ? 'checked' : '';
                        const dept = emp.department ? emp.department : 'No Department';
                        
                        html += `<div class="holiday-employee-row" 
                            data-name="${emp.name.toLowerCase()}" 
                            data-eid="${emp.employee_id.toLowerCase()}" 
                            data-dept="${dept.toLowerCase()}">
                            <input type="checkbox" class="holiday-checkbox emp-holiday-check" value="${emp.id}" id="emp_${emp.id}" ${checked}>
                            <label for="emp_${emp.id}" style="flex: 1; cursor: pointer; margin-left: 12px;">
                                <div style="font-weight: 600; color: var(--text-primary);">${emp.name}</div>
                                <div style="font-size: 12px; color: var(--text-muted);">${emp.employee_id} • ${dept}</div>
                            </label>
                        </div>`;
                    });
                }
                
                list.innerHTML = html;
            } else {
                throw new Error(data.message || 'No employees returned');
            }
        })
        .catch(e => {
            console.error('❌ Employee load error:', e);
            list.innerHTML = `<div style="text-align:center; padding:20px; color: #dc3545;">
                <i class="fas fa-exclamation-triangle" style="font-size: 24px; margin-bottom: 10px;"></i>
                <div>Error loading employees</div>
                <div style="font-size: 11px; margin-top: 5px; opacity: 0.7;">${e.message}</div>
                <button onclick="openHolidayAssignment(${id}, '${name.replace(/'/g, "\\'")}', '${date}')" style="margin-top: 10px; padding: 6px 12px; background: var(--primary-accent); border: none; border-radius: 4px; color: #000; cursor: pointer;">
                    <i class="fas fa-redo"></i> Retry
                </button>
            </div>`;
            showToast('Failed to load employees: ' + e.message, 'error');
        });
    }

    function toggleAllEmployees(state) {
