    function saveHolidayAssignments() {
        const holidayId = document.getElementById('modalHolidayId').value;
        const employees = [];
        document.querySelectorAll('.emp-holiday-check:checked').forEach(cb => employees.push(cb.value));
        
        const formData = new FormData();
        formData.append('action', 'save_holiday_assignments');
        formData.append('holiday_id', holidayId);
        formData.append('employees', JSON.stringify(employees));
        
        const csrfToken = document.querySelector('input[name="csrf_token"]')?.value || 
                        document.querySelector('meta[name="csrf-token"]')?.content || '';
        if(csrfToken) {
            formData.append('csrf_token', csrfToken);
        }
        
        const btn = document.querySelector('#holidayAssignmentModal .btn-primary-modern');
        if(btn) {
            btn.disabled = true;
            btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Saving...';
        }
        
        fetch('', { method: 'POST', body: formData })
        .then(r => r.json())
        .then(data => {
            if(btn) {
                btn.disabled = false;
                btn.innerHTML = '<i class="fas fa-save"></i> Save Assignments';
            }
            if(data.success) {
                showToast('Assignments saved successfully', 'success');
                closeHolidayModal();
                loadHolidays();
            } else {
                showToast('Error: ' + (data.message || 'Failed to save'), 'error');
            }
        })
        .catch(e => {
            if(btn) {
                btn.disabled = false;
                btn.innerHTML = '<i class="fas fa-save"></i> Save Assignments';
            }
            showToast('Network error: ' + e.message, 'error');
        });
    }

    function closeHolidayModal() {
        const modal = document.getElementById('holidayAssignmentModal');
        if(modal) {
            modal.style.display = 'none';
        }
    }

