    // === LIVE LEAVE SEARCH ===
    function filterLeaveRequests(searchTerm) {
        const search = searchTerm.toLowerCase().trim();
        const items = document.querySelectorAll('#leaveadministrationSection .record-item, #leaveadministrationSection .leave-request-card');
        let visibleCount = 0;
        
        items.forEach(item => {
            const name = item.getAttribute('data-name')?.toLowerCase() || '';
            const eid = item.getAttribute('data-eid')?.toLowerCase() || '';
            const reason = item.querySelector('.reason-text')?.textContent.toLowerCase() || '';
            
            const matches = name.includes(search) || eid.includes(search) || reason.includes(search);
            item.style.display = matches ? '' : 'none';
            if (matches) visibleCount++;
        });
        
        const countEl = document.getElementById('leaveSearchCount');
        if (countEl) countEl.textContent = search ? `${visibleCount} found` : '';
    }
    // === LIVE DAY-OFF SEARCH ===
    function filterDayOffRequests(searchTerm) {
        const search = searchTerm.toLowerCase().trim();
        const items = document.querySelectorAll('#dayoffSection .record-item, #dayoffSection .dayoff-request-card');
        let visibleCount = 0;
        
        items.forEach(item => {
            const name = item.getAttribute('data-name')?.toLowerCase() || '';
            const eid = item.getAttribute('data-eid')?.toLowerCase() || '';
            const type = item.getAttribute('data-type')?.toLowerCase() || '';
            
            const matches = name.includes(search) || eid.includes(search) || type.includes(search);
            item.style.display = matches ? '' : 'none';
            if (matches) visibleCount++;
        });
        
        const countEl = document.getElementById('dayOffSearchCount');
        if (countEl) countEl.textContent = search ? `${visibleCount} found` : '';
    }
    // === ATTENDANCE MODULE: Search Filter ===
    function filterAttendanceRecords(searchTerm) {
        const search = searchTerm.toLowerCase();
        const records = document.querySelectorAll('.modern-attendance-card');
        records.forEach(record => {
            const name = record.querySelector('.emp-details h5')?.textContent.toLowerCase() || '';
            const eid = record.querySelector('.emp-details span')?.textContent.toLowerCase() || '';
            // Show if name OR employee ID matches
            record.style.display = (name.includes(search) || eid.includes(search)) ? 'flex' : 'none';
        });
    }
    // === LIVE SCHEDULE EMPLOYEE SEARCH ===
    function filterScheduleEmployees(searchTerm) {
        const search = searchTerm.toLowerCase().trim();
        const rows = document.querySelectorAll('#scheduleEmployeeTable tr, .schedule-employee-row');
        
        rows.forEach(row => {
            const name = row.getAttribute('data-name')?.toLowerCase() || '';
            const eid = row.getAttribute('data-eid')?.toLowerCase() || '';
            const dept = row.getAttribute('data-dept')?.toLowerCase() || '';
            
            const matches = name.includes(search) || eid.includes(search) || dept.includes(search);
            row.style.display = matches ? '' : 'none';
        });
    }
