// === DAY OFF HISTORY: CLEAR ALL RECORDS (FIXED) ===
function purgeOldDayOffRecords() {
    console.log("🔴 Clear All Button Clicked"); // Debug log
    
    // 1. Stronger Warning since we are clearing EVERYTHING now
    const confirmed = confirm("🚨 CRITICAL WARNING: This will permanently delete ALL Day Off Request History shown in this modal.\n\nThis action CANNOT be undone.\n\nAre you sure you want to CLEAR EVERYTHING?");
    if (!confirmed) {
        console.log("❌ User cancelled deletion");
        return;
    }
    
    const listContainer = document.getElementById('dayOffHistoryList');
    
    // 2. Optimistic UI: Clear the list IMMEDIATELY before server responds
    if(listContainer) {
        listContainer.innerHTML = `
            <div style="text-align: center; padding: 40px; color: var(--text-muted);">
                <i class="fas fa-spinner fa-spin" style="font-size: 24px; color: var(--primary-accent);"></i>
                <div style="margin-top: 10px;">Clearing records...</div>
            </div>`;
    }
    
    // 3. Get CSRF Token (CRITICAL FIX)
    const csrfToken = document.querySelector('meta[name="csrf-token"]')?.content ||
                      document.querySelector('input[name="csrf_token"]')?.value || '';
    
    if(!csrfToken) {
        console.error("❌ CSRF Token not found!");
        showToast('Security token missing. Please refresh the page.', 'error');
        loadDayOffHistoryData(); // Reload to show error
        return;
    }
    
    console.log("✅ CSRF Token found:", csrfToken.substring(0, 10) + "...");
    
    // 4. Create FormData
    const formData = new FormData();
    formData.append('action', 'purge_old_day_off_records');
    formData.append('csrf_token', csrfToken); // ✅ CRITICAL: Add CSRF token
    
    console.log("📤 Sending delete request...");
    
    // 5. Make the request
    fetch('', {
        method: 'POST',
        body: formData,
        headers: {
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(r => {
        console.log("📥 Response status:", r.status);
        if (!r.ok) {
            throw new Error('HTTP error! status: ' + r.status);
        }
        return r.json();
    })
    .then(data => {
        console.log("📦 Response data:", data);
        
        if (data.success) {
            console.log("✅ Deletion successful!");
            showToast(data.message, 'success');
            
            // 6. Force Empty State UI
            if(listContainer) {
                listContainer.innerHTML = `
                    <div style="text-align: center; padding: 40px; color: var(--text-muted);">
                        <i class="fas fa-check-circle" style="font-size: 48px; margin-bottom: 15px; opacity: 0.5; color: #28a745;"></i>
                        <div style="font-size: 16px; color: #28a745;">All history cleared successfully!</div>
                        <div style="font-size: 12px; margin-top: 10px;">${data.message}</div>
                    </div>`;
            }
            
            // 7. Close modal after 2 seconds (optional, or keep open to show empty state)
            setTimeout(() => {
                closeDayOffHistoryModal();
            }, 2000);
            
        } else {
            console.error("❌ Server returned error:", data.message);
            showToast('Error: ' + (data.message || 'Failed to purge records'), 'error');
            // Reload data if failed
            loadDayOffHistoryData();
        }
    })
    .catch(e => {
        console.error("❌ Fetch error:", e);
        console.error("Error name:", e.name);
        console.error("Error message:", e.message);
        console.error("Error stack:", e.stack);
        showToast('Network error: ' + e.message, 'error');
        loadDayOffHistoryData();
    });
}

    // Update window onclick to handle day off history modal
    const originalWindowOnclickDayOff = window.onclick || function() {};
