    // === LIVE SYNC: MANUAL CHECKIN STATUS ===
    function pollManualCheckinStatus() {
        fetch('?action=get_manual_checkin_status')
        .then(r => r.json())
        .then(data => {
            if(data.success) {
                const isActive = data.status === '1';
                const activeDiv = document.getElementById('manualCheckinActive');
                const disabledDiv = document.getElementById('manualCheckinDisabled');
                
                if(activeDiv && disabledDiv) {
                    // Show/Hide based on admin setting
                    activeDiv.style.display = isActive ? 'block' : 'none';
                    disabledDiv.style.display = isActive ? 'none' : 'block';
                }
            }
        })
        .catch(e => console.log('Polling error:', e));
    }

    // Start polling every 5 seconds when employee portal is loaded
    document.addEventListener('DOMContentLoaded', function() {
        if(document.getElementById('employeePortal')) {
            // Initial check
            pollManualCheckinStatus();
            // Then check every 5 seconds
            setInterval(pollManualCheckinStatus, 5000);
            console.log('✅ Manual Check-in Live Sync Started');
        }
    });

    // === REPORTS MODULE: Import Functions ===
    function closeImportModal() {
        document.getElementById('importModal').style.display = 'none';
        document.getElementById('importFile').value = '';
        document.getElementById('importProgress').style.display = 'none';
        document.getElementById('importResults').style.display = 'none';
