    function toggleReportFilterInput() {
        const scope = document.getElementById('reportScope').value;
        const group = document.getElementById('reportFilterValueGroup');
        const input = document.getElementById('reportFilterValue');
        
        if(scope === 'all') {
            group.style.display = 'none';
            input.required = false;
        } else {
            group.style.display = 'flex';
            input.required = true;
            input.placeholder = scope === 'department' ? 'Enter Department Name (e.g. IT)' : 'Enter Employee ID (e.g. EMP001)';
        }
        loadReportPreview();
    }

    function loadReportPreview() {
        const container = document.getElementById('reportPreview');
        const startDateInput = document.getElementById('reportStartDate');
        const endDateInput = document.getElementById('reportEndDate');
        
        // === FORCE DEFAULT TO TODAY IF EMPTY ===
        const today = new Date().toISOString().split('T')[0];
        if (!startDateInput.value) startDateInput.value = today;
        if (!endDateInput.value) endDateInput.value = today;
        // ========================================

        const startDate = startDateInput.value;
        const endDate = endDateInput.value;
        const type = document.getElementById('reportType').value;
        const scope = document.getElementById('reportScope').value;
        const filterValue = document.getElementById('reportFilterValue').value;

        container.innerHTML = '<div style="text-align: center; padding: 40px;"><i class="fas fa-spinner fa-spin" style="font-size: 24px; color: var(--primary-accent);"></i><div style="margin-top: 10px; color: var(--text-muted);">Loading preview...</div></div>';
        
        let url = `?action=get_report_preview&start_date=${startDate}&end_date=${endDate}&type=${type}&scope=${scope}`;
        if(scope !== 'all' && filterValue) {
            url += `&filter_value=${encodeURIComponent(filterValue)}`;
        }
        
        fetch(url)
        .then(r => r.json())
        .then(data => {
            if (data.success && data.records) {
                // Update Summary Stats
                document.getElementById('reportPresentCount').textContent = data.summary.present || 0;
                document.getElementById('reportLateCount').textContent = data.summary.late || 0;
                document.getElementById('reportTotalCount').textContent = data.summary.total || 0;
                
                // Display Records
                if (data.records.length === 0) {
                    container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--text-muted);"><i class="fas fa-inbox" style="font-size: 48px; margin-bottom: 15px; opacity: 0.5;"></i><div>No records found for selected filters</div></div>';
                } else {
                    let html = '';
                    data.records.forEach(record => {
                        const checkIn = new Date(record.check_in).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true });
                        const checkOut = record.check_out ? new Date(record.check_out).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true }) : '--:--';
                        const statusClass = record.is_late == 1 ? 'late' : 'present';
                        const statusColor = record.is_late == 1 ? '#ffc107' : '#28a745';
                        
                        html += `
                        <div class="record-item" style="border-left: 3px solid ${statusColor}; padding-left: 15px;">
                            <div class="record-info">
                                <div class="record-icon ${statusClass}"><i class="fas fa-user-clock"></i></div>
                                <div class="record-details">
                                    <div class="record-name">${record.name}</div>
                                    <div class="record-id">EID: ${record.employee_id} • ${record.department}</div>
                                </div>
                            </div>
                            <div class="record-time" style="text-align: right;">
                                <div style="font-size: 12px; color: var(--text-muted);">${new Date(record.check_in).toLocaleDateString()}</div>
                                <div style="font-size: 13px; color: var(--text-primary);">${checkIn} - ${checkOut}</div>
                                <span class="record-badge ${statusClass}" style="margin-top: 5px;">${record.is_late == 1 ? 'Late' : 'Present'}</span>
                            </div>
                        </div>`;
                    });
                    container.innerHTML = html;
                }
            } else {
                container.innerHTML = `<div style="text-align: center; padding: 40px; color: #dc3545;">Error: ${data.message || 'Failed to load preview'}</div>`;
            }
        })
        .catch(e => {
            console.error('Preview error:', e);
            container.innerHTML = '<div style="text-align: center; padding: 40px; color: #dc3545;">Connection error. Please try again.</div>';
        });
    }

    // === FILTER VALUE CHANGE LISTENER ===
    document.addEventListener('DOMContentLoaded', function() {
        const filterValueInput = document.getElementById('reportFilterValue');
        const scopeSelect = document.getElementById('reportScope');
        
        if (filterValueInput) {
            // Auto-refresh on Enter key
            filterValueInput.addEventListener('keypress', function(e) {
                if (e.key === 'Enter') {
                    loadReportPreview();
                }
            });
            
            // Auto-refresh after 1 second of no typing (debounce)
            let debounceTimer;
            filterValueInput.addEventListener('input', function() {
                clearTimeout(debounceTimer);
                debounceTimer = setTimeout(() => {
                    loadReportPreview();
                }, 1000);
            });
        }
        
        // Refresh when scope changes
        if (scopeSelect) {
            scopeSelect.addEventListener('change', function() {
                // Show/hide filter value input based on scope
                const filterGroup = document.getElementById('reportFilterValueGroup');
                if (filterGroup) {
                    if (this.value === 'all') {
                        filterGroup.style.display = 'none';
                    } else {
                        filterGroup.style.display = 'flex';
                        // Update placeholder based on selection
                        const filterInput = document.getElementById('reportFilterValue');
                        if (filterInput) {
                            filterInput.placeholder = this.value === 'department' 
                                ? 'Enter Department Name (e.g. IT)' 
                                : 'Enter Employee ID (e.g. 2025001)';
                        }
                    }
                }
                loadReportPreview();
            });
        }
    });
    function processImport() {
        const fileInput = document.getElementById('importFile');
        const progressDiv = document.getElementById('importProgress');
        const progressBar = document.getElementById('importProgressBar');
        const resultsDiv = document.getElementById('importResults');
        const importBtn = document.getElementById('importBtn');
        
        if (!fileInput.files || fileInput.files.length === 0) {
            showToast('Please select a CSV or PDF file', 'error');
            return;
        }
        
        const file = fileInput.files[0];
        const fileName = file.name.toLowerCase();
        
        if (!fileName.endsWith('.csv') && !fileName.endsWith('.pdf')) {
            showToast('Please select a valid CSV or PDF file', 'error');
            return;
        }
        
        // Show Progress
        importBtn.disabled = true;
        importBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Processing...';
        progressDiv.style.display = 'block';
        progressBar.style.width = '20%';
        
        const startTime = Date.now();
        
        const formData = new FormData();
        formData.append('action', 'import_attendance');
        formData.append('import_file', file);
        formData.append('csrf_token', getCSRFToken());
        
        fetch('', {
            method: 'POST',
            body: formData
        })
        .then(r => {
            progressBar.style.width = '60%';
            return r.json();
        })
        .then(data => {
            const endTime = Date.now();
            const duration = ((endTime - startTime) / 1000).toFixed(2);
            
            progressBar.style.width = '100%';
            
            if (data.success) {
                document.getElementById('importSuccessCount').textContent = data.details.successful || 0;
                
                const errorsDiv = document.getElementById('importErrors');
                if (data.details.errors && data.details.errors.length > 0) {
                    errorsDiv.innerHTML = '<div style="font-weight: 600; margin-bottom: 10px; color: #ffc107;"><i class="fas fa-exclamation-triangle"></i> Errors & Warnings:</div>' +
                        data.details.errors.map(err => `<div style="padding: 5px 0; font-size: 12px; border-bottom: 1px solid rgba(255,255,255,0.05);">• ${err}</div>`).join('');
                    errorsDiv.style.display = 'block';
                } else {
                    errorsDiv.style.display = 'none';
                }
                
                // Show extracted fields
                if (data.details.fields_extracted) {
                    const fieldsHtml = `<div style="font-size: 11px; color: var(--text-muted); margin-top: 10px;">
                        <strong>Fields Extracted (${data.details.fields_extracted.length}):</strong> ${data.details.fields_extracted.join(', ')}
                    </div>`;
                    resultsDiv.innerHTML += fieldsHtml;
                }
                
                // Show total columns
                if (data.details.total_columns_in_csv) {
                    const columnsHtml = `<div style="font-size: 11px; color: var(--primary-accent); margin-top: 5px;">
                        <strong>Total CSV Columns:</strong> ${data.details.total_columns_in_csv}
                    </div>`;
                    resultsDiv.innerHTML += columnsHtml;
                }
                
                // Show sample records
                if (data.details.records && data.details.records.length > 0) {
                    let recordsHtml = '<div style="font-weight: 600; margin: 10px 0 5px; color: var(--primary-accent);"><i class="fas fa-check-circle"></i> Sample Imported Records:</div>';
                    recordsHtml += '<div style="max-height: 150px; overflow-y: auto; font-size: 11px; background: rgba(0,0,0,0.2); padding: 10px; border-radius: 6px;">';
                    data.details.records.slice(0, 5).forEach(rec => {
                        recordsHtml += `<div style="padding: 3px 0; color: var(--text-secondary); border-bottom: 1px solid rgba(255,255,255,0.05);">
                            ${rec.employee_id} - ${rec.name} (${rec.date}) | In: ${rec.check_in} | Out: ${rec.check_out || '--:--'} | OT: ${rec.overtime}h | Total: ${rec.total_hours}h
                        </div>`;
                    });
                    recordsHtml += '</div>';
                    resultsDiv.innerHTML += recordsHtml;
                }
                
                resultsDiv.style.display = 'block';
                
                // Show processing time and details
                const timeMsg = `<div style="font-size: 11px; color: var(--text-muted); margin-top: 10px; padding: 10px; background: rgba(25,211,197,0.1); border-radius: 6px;">
                    ⚡ Processed in <strong>${duration}s</strong> | 
                    ✅ ${data.details.successful} imported | 
                    ⚠️ ${data.details.skipped} skipped | 
                    🔄 ${data.details.updates?.length || 0} updated |
                    📊 ${data.details.fields_extracted?.length || 0} fields extracted
                </div>`;
                resultsDiv.innerHTML += timeMsg;
                
                showToast(`✅ Import Successful! ${data.details.successful} records in ${duration}s - ALL DATA EXTRACTED`, 'success');
                
                // Refresh all modules
                setTimeout(() => {
                    refreshAllModules();
                }, 1000);
                
            } else {
                showToast('❌ Import Failed: ' + data.message, 'error');
                progressDiv.style.display = 'none';
            }
        })
        .catch(e => {
            console.error('Import error:', e);
            showToast('❌ Network Error: ' + e.message, 'error');
            progressDiv.style.display = 'none';
        })
        .finally(() => {
            importBtn.disabled = false;
            importBtn.innerHTML = '<i class="fas fa-upload"></i> Import';
        });
    }
