                document.getElementById('importSuccessCount').textContent = data.details.successful || 0;
                
                const errorsDiv = document.getElementById('importErrors');
                if (data.details.errors && data.details.errors.length > 0) {
                    errorsDiv.innerHTML = '<div style="font-weight: 600; margin-bottom: 10px; color: #ffc107;"><i class="fas fa-exclamation-triangle"></i> Errors:</div>' +
                        data.details.errors.map(err => `<div style="padding: 5px 0; font-size: 12px;">• ${err}</div>`).join('');
                    errorsDiv.style.display = 'block';
                } else {
                    errorsDiv.style.display = 'none';
                }
                
                resultsDiv.style.display = 'block';
                
                // Show processing time
                const timeMsg = `<div style="font-size: 11px; color: var(--text-muted); margin-top: 10px;">
                    ⚡ Processed in <strong>${duration}s</strong> | ${data.details.successful} records
                </div>`;
                resultsDiv.innerHTML += timeMsg;
                
                showToast(`✅ Import Successful! ${data.details.successful} records in ${duration}s`, 'success');
                
                // Refresh all modules
                setTimeout(() => {
                    refreshAllModules();
                }, 1000);
                
            } else {
                showToast('❌ Import Failed: ' + data.message, 'error');
            }
        })
        .catch(e => {
            console.error('Import error:', e);
            showToast('❌ Network Error: ' + e.message, 'error');
        })
        .finally(() => {
            importBtn.disabled = false;
            importBtn.innerHTML = '<i class="fas fa-upload"></i> Import';
        });
    }

    function startSyncMonitoring() {
        if (importSyncInterval) clearInterval(importSyncInterval);
        
        importSyncInterval = setInterval(() => {
            fetch('?action=check_sync_status')
            .then(r => r.json())
            .then(data => {
                if (data.success && data.needs_refresh) {
                    const progressDiv = document.getElementById('importProgress');
                    if (progressDiv) {
                        progressDiv.innerHTML = `
                            <div style="display: flex; align-items: center; gap: 10px; margin-bottom: 10px;">
                                <i class="fas fa-sync fa-spin" style="color: var(--primary-accent);"></i>
                                <span style="color: var(--text-secondary);">System-wide sync in progress...</span>
                            </div>
                            <div style="height: 6px; background: rgba(255,255,255,0.1); border-radius: 3px; overflow: hidden;">
                                <div id="syncProgressBar" style="height: 100%; width: 0%; background: var(--gradient-primary); transition: width 0.3s;"></div>
                            </div>
                        `;
                        
                        const syncBar = document.getElementById('syncProgressBar');
                        if (syncBar) {
                            let width = 0;
                            const syncInterval = setInterval(() => {
                                if (width >= 100) clearInterval(syncInterval);
                                else {
                                    width += 5;
                                    syncBar.style.width = width + '%';
                                }
                            }, 200);
                        }
                    }
                }
            })
            .catch(e => console.log('Sync check error:', e));
        }, 2000);
        
        setTimeout(() => {
            if (importSyncInterval) {
                clearInterval(importSyncInterval);
                importSyncInterval = null;
            }
        }, 30000);
    }

    function refreshAllModules() {
        console.log('🔄 Refreshing all modules after import...');
        
        const refreshTasks = [
            { name: 'Attendance', fn: () => { if(typeof loadAttendanceHistory === 'function') loadAttendanceHistory(); } },
            { name: 'Reports', fn: () => { if(typeof loadReportPreview === 'function') loadReportPreview(); } },
            { name: 'Analytics', fn: () => { if(typeof updateAnalytics === 'function') updateAnalytics(); } },
            { name: 'Dashboard', fn: () => { if(typeof refreshRealtimeStats === 'function') refreshRealtimeStats(); } },
            { name: 'Overtime', fn: () => { if(typeof loadOvertimeData === 'function') loadOvertimeData(); } }
        ];
        
        let completed = 0;
        
        refreshTasks.forEach(task => {
            try {
                task.fn();
                console.log(`✅ ${task.name} refreshed`);
                completed++;
            } catch (e) {
                console.error(`❌ ${task.name} refresh failed:`, e);
            }
        });
        
        setTimeout(() => {
            showToast(`✅ System Sync Complete! ${completed}/${refreshTasks.length} modules updated`, 'success');
            updateAllCounters();
        }, 1000);
    }

    function updateAllCounters() {
        if(typeof refreshRealtimeStats === 'function') refreshRealtimeStats();
        if(typeof updateAnalytics === 'function') updateAnalytics();
        if(typeof loadOvertimeData === 'function') loadOvertimeData();
        console.log('📊 All counters updated');
    }

