// === NOTIFICATION POLLING ===
var notificationPollingInterval = null;
var lastNotificationCount = 0;

function startNotificationPolling() {
    if (notificationPollingInterval) clearInterval(notificationPollingInterval);
    notificationPollingInterval = setInterval(() => pollNotifications(), 5000);
    pollNotifications();
}

function pollNotifications() {
    const bell = document.getElementById('notificationBell');
    if (!bell) return;

    fetch('?action=get_notifications')
    .then(r => r.json())
    .then(data => {
        if (data.success) {
            updateNotificationBadge(data.count);
            updateNotificationDropdown(data.notifications);
        }
    })
    .catch(console.error);
}

function updateNotificationBadge(count) {
    const bell = document.getElementById('notificationBell');
    if (!bell) return;
    let badge = bell.querySelector('.notification-badge');
    if (count > 0) {
        if (!badge) {
            badge = document.createElement('span');
            badge.className = 'notification-badge';
            bell.appendChild(badge);
        }
        badge.textContent = count > 99 ? '99+' : count;
        if (count > lastNotificationCount) {
            bell.classList.add('notification-pulse');
            setTimeout(() => bell.classList.remove('notification-pulse'), 2000);
        }
    } else if (badge) {
        badge.remove();
    }
    lastNotificationCount = count;
}

function updateNotificationDropdown(notifications) {
    const dropdown = document.getElementById('notificationDropdown');
    if (!dropdown) return;
    if (dropdown.style.display !== 'block') return;

    if (!notifications || notifications.length === 0) {
        dropdown.innerHTML = `
        <div class="notification-header">
            <span>Notifications</span>
            <button class="clear-all-btn" onclick="clearAllNotifications(event)">
                <i class="fas fa-trash-alt"></i> Clear All
            </button>
        </div>
        <div class="notification-empty">No notifications</div>
        `;
        return;
    }

    let html = `
    <div class="notification-header">
        <span>Notifications (${notifications.length})</span>
        <button class="clear-all-btn" onclick="clearAllNotifications(event)">
            <i class="fas fa-trash-alt"></i> Clear All
        </button>
    </div>
    `;

    notifications.forEach(notif => {
        const isRead = notif.is_read == 1 || notif.is_read == true;
        html += `
        <div class="notification-item ${isRead ? 'read' : 'unread'}"
            data-id="${notif.id}"
            data-module="${notif.redirect_module || 'overview'}">
            <div class="notification-content" onclick="handleNotificationClick(${notif.id}, '${notif.redirect_module || 'overview'}')">
                <div class="notification-title">${escapeHtml(notif.title)}</div>
                <div class="notification-message">${escapeHtml(notif.message)}</div>
                <div class="notification-time">
                    <i class="far fa-clock"></i> ${notif.formatted_date || notif.time_ago || ''}
                </div>
            </div>
            <button class="notification-clear" onclick="clearSingleNotification(${notif.id}, event)" title="Clear">
                <i class="fas fa-times"></i>
            </button>
        </div>
        `;
    });

    dropdown.innerHTML = html;
}

function handleNotificationClick(notifId, redirectModule) {
    fetch('', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `action=mark_notification_read&notification_id=${notifId}`
    })
    .then(() => {
        const dropdown = document.getElementById('notificationDropdown');
        if (dropdown) dropdown.style.display = 'none';
        
        // REDIRECT BASED ON MODULE
        if (redirectModule) {
            if (document.getElementById('adminDashboard')) {
                if (redirectModule === 'leaveadministration') {
                    window.location.href = '?view=leaveadministration';
                } else if (redirectModule === 'dayoff') {
                    window.location.href = '?view=dayoff';
                } else if (redirectModule === 'overtime') {
                    window.location.href = '?view=overtime';
                } else if (redirectModule === 'attendance') {
                    window.location.href = '?view=attendance';
                } else if (redirectModule === 'employees') {
                    window.location.href = '?view=employees';
                } else if (redirectModule === 'reports') {
                    window.location.href = '?view=reports';
                } else if (redirectModule === 'analytics') {
                    window.location.href = '?view=analytics';
                } else if (redirectModule === 'audittrail') {
                    window.location.href = '?view=audittrail';
                } else if (redirectModule === 'fingerprint') {
                    window.location.href = '?view=fingerprint';
                } else if (redirectModule === 'departments') {
                    window.location.href = '?view=departments';
                } else if (redirectModule === 'holiday') {
                    window.location.href = '?view=holiday';
                } else if (redirectModule === 'archives') {
                    window.location.href = '?view=archives';
                } else if (redirectModule === 'manualcheckin') {
                    window.location.href = '?view=manualcheckin';
                } else {
                    window.location.href = '?view=overview';
                }
            } else if (document.getElementById('employeePortal')) {
                if (redirectModule === 'leaveadministration' || redirectModule === 'leave') {
                    window.location.href = '?emp_view=leave';
                } else if (redirectModule === 'dayoff' || redirectModule === 'leaves') {
                    window.location.href = '?emp_view=leaves';
                } else if (redirectModule === 'attendance') {
                    window.location.href = '?emp_view=attendance';
                } else if (redirectModule === 'schedule') {
                    window.location.href = '?emp_view=schedule';
                } else {
                    window.location.href = '?emp_view=overview';
                }
            }
        }

        setTimeout(() => pollNotifications(), 500);
    })
    .catch(console.error);
}

function clearSingleNotification(notifId, event) {
    if (event && event.stopPropagation) {
        event.stopPropagation();
    }

    fetch('', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `action=clear_notification&notification_id=${notifId}`
    })
    .then(r => r.json())
    .then(data => {
        if (data.success) {
            const notifElement = document.querySelector(`.notification-item[data-id="${notifId}"]`);
            if (notifElement) {
                notifElement.style.opacity = '0';
                notifElement.style.transform = 'translateX(20px)';
                setTimeout(() => notifElement.remove(), 300);
            }
            pollNotifications();
            showToast('Notification cleared', 'success');
        }
    })
    .catch(console.error);
}

function clearAllNotifications(event) {
    if(event) event.stopPropagation();
    if (!confirm('Clear all notifications? This cannot be undone.')) return;

    fetch('', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: 'action=clear_all_notifications'
    })
    .then(r => r.json())
    .then(data => {
        if (data.success) {
            const dropdown = document.getElementById('notificationDropdown');
            if (dropdown) {
                dropdown.innerHTML = `
                <div class="notification-header">
                    <span>Notifications</span>
                    <button class="clear-all-btn" onclick="clearAllNotifications(event)">
                        <i class="fas fa-trash-alt"></i> Clear All
                    </button>
                </div>
                <div class="notification-empty">All notifications cleared</div>
                `;
            }
            const bell = document.getElementById('notificationBell');
            if (bell) {
                const badge = bell.querySelector('.notification-badge');
                if (badge) badge.remove();
            }
            lastNotificationCount = 0;
            showToast(`Cleared ${data.cleared || 0} notification(s)`, 'success');
            setTimeout(() => pollNotifications(), 500);
        }
    })
    .catch(console.error);
}

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}
// === INITIALIZE ON PAGE LOAD ===
document.addEventListener('DOMContentLoaded', function() {
    const bell = document.getElementById('notificationBell');
    const dropdown = document.getElementById('notificationDropdown');
    
    if (bell && dropdown) {
        bell.addEventListener('click', function(e) {
            e.stopPropagation();
            const isVisible = dropdown.style.display === 'block';
            
            // Close other dropdowns
            document.querySelectorAll('.notification-dropdown').forEach(d => {
                if (d !== dropdown) d.style.display = 'none';
            });
            
            dropdown.style.display = isVisible ? 'none' : 'block';
            
            if (!isVisible) {
                pollNotifications();
            }
        });
        
        document.addEventListener('click', function() {
            dropdown.style.display = 'none';
        });
    }
    
    // Start polling
    startNotificationPolling();
});


