    // === ATTACHMENT PREVIEW FUNCTIONS ===
function openAttachmentPreview(filePath, type) {
    const modal = document.getElementById('attachmentPreviewModal');
    const content = document.getElementById('attachmentPreviewContent');
    const downloadBtn = document.getElementById('attachmentDownloadBtn');
    
    if (!modal || !content) {
        console.error('Attachment preview modal not found!');
        return;
    }
    
    // Set download link
    if (downloadBtn) {
        downloadBtn.href = filePath;
    }
    
    // Show loading state
    content.innerHTML = '<div style="text-align: center;"><i class="fas fa-spinner fa-spin" style="font-size: 48px; color: var(--primary-accent);"></i><div style="margin-top: 15px; color: var(--text-muted);">Loading attachment...</div></div>';
    modal.style.display = 'block';
    
    // Load content based on type
    if (type === 'image') {
        content.innerHTML = `
            <img src="${filePath}?t=${Date.now()}" 
                 alt="Attachment" 
                 style="max-width: 100%; max-height: 70vh; border-radius: 8px; box-shadow: 0 4px 20px rgba(0,0,0,0.5);"
                 onload="this.style.opacity='1'"
                 onerror="this.parentElement.innerHTML='<div style=\'color: #ef4444;\'><i class=\'fas fa-exclamation-triangle\'></i> Failed to load image</div>'">
        `;
    } else if (type === 'pdf') {
        content.innerHTML = `
            <iframe src="${filePath}" 
                    style="width: 100%; height: 600px; border: 1px solid var(--border-color); border-radius: 8px;"
                    onload="this.style.opacity='1'"
                    onerror="this.parentElement.innerHTML='<div style=\'color: #ef4444;\'><i class=\'fas fa-exclamation-triangle\'></i> Failed to load PDF. <a href=\'${filePath}\' target=\'_blank\' style=\'color: var(--primary-accent);\'>Click here to open</a></div>'">
            </iframe>
        `;
    }
}

function closeAttachmentPreviewModal() {
    const modal = document.getElementById('attachmentPreviewModal');
    const content = document.getElementById('attachmentPreviewContent');
    if (modal) {
        modal.style.display = 'none';
    }
    if (content) {
        content.innerHTML = '';
    }
}

