          </div>
          <div class="form-row" style="display: flex; flex-direction: column; gap: 8px; margin-bottom: 18px;">
            <label class="form-label" for="newPassword">New Password <span style="color:#dc3545">*</span></label>
            <div style="display: flex; align-items: center; position: relative;">
              <input type="password" id="newPassword" name="new_password" class="form-select" required minlength="6" style="flex:1; padding-right:36px;" />
              <span class="eye-icon" onclick="togglePasswordVisibility('newPassword', this)" style="position:absolute; right:10px; cursor:pointer;">
                <i class="fas fa-eye-slash"></i>
              </span>
            </div>
          </div>
          <div class="form-row" style="display: flex; flex-direction: column; gap: 8px; margin-bottom: 18px;">
            <label class="form-label" for="confirmPassword">Confirm New Password <span style="color:#dc3545">*</span></label>
            <div style="display: flex; align-items: center; position: relative;">
              <input type="password" id="confirmPassword" name="confirm_password" class="form-select" required minlength="6" style="flex:1; padding-right:36px;" />
              <span class="eye-icon" onclick="togglePasswordVisibility('confirmPassword', this)" style="position:absolute; right:10px; cursor:pointer;">
                <i class="fas fa-eye-slash"></i>
              </span>
            </div>
          </div>
          <div style="display: flex; gap: 10px; margin-top: 20px;">
            <button type="submit" class="btn btn-primary" style="flex: 1;">Change Password</button>
            <button type="button" class="btn" style="flex: 1; background: var(--panel-bg); color: var(--text-primary); border: 1px solid var(--border-color);" onclick="closePasswordModal()">Cancel</button>
          </div>
        </form>
      </div>
    </div>
    <script>
    // Toggle password visibility for Change Password modal
    function togglePasswordVisibility(inputId, iconSpan) {
      const input = document.getElementById(inputId);
      const icon = iconSpan.querySelector('i');
      if (input.type === 'password') {
        input.type = 'text';
        icon.classList.remove('fa-eye-slash');
        icon.classList.add('fa-eye');
      } else {
        input.type = 'password';
        icon.classList.remove('fa-eye');
        icon.classList.add('fa-eye-slash');
      }
    }
    // === CRITICAL FIX: MY SCHEDULE INSTANT LOAD ===
// This ensures the calendar loads immediately when the tab is opened

(function() {
    // Store original function
    const originalSwitchEmployeeTab = window.switchEmployeeTab || function() {};
    
    // Override the tab switching function
    window.switchEmployeeTab = function(tabName) {
        // Call original logic first
        originalSwitchEmployeeTab(tabName);
        
        // Handle schedule tab specifically
        if (tabName === 'schedule') {
            console.log('📅 Schedule tab opened - Loading calendar immediately...');
            
            // Ensure the schedule section is visible
            const scheduleSection = document.getElementById('employeeScheduleSection');
            if (scheduleSection) {
                scheduleSection.style.display = 'block';
            }
            
            // Reset calendar date to current month
            if (typeof currentCalendarDate !== 'undefined') {
                currentCalendarDate = new Date();
            }
            
            // CRITICAL: Load schedule immediately with small delay to ensure DOM is ready
            setTimeout(() => {
                if (typeof loadEmployeeSchedule === 'function') {
                    console.log('🔄 Calling loadEmployeeSchedule()...');
                    loadEmployeeSchedule();
                } else {
                    console.error('❌ loadEmployeeSchedule function not found!');
                }
            }, 100);
            
            // Start auto-refresh for live updates
            if (typeof startScheduleAutoRefresh === 'function') {
                startScheduleAutoRefresh();
            }
        } else if (tabName !== 'schedule') {
            // Stop auto-refresh when leaving schedule tab
            if (typeof stopScheduleAutoRefresh === 'function') {
                stopScheduleAutoRefresh();
            }
        }
    };
    
    // Also ensure schedule loads on initial page load if schedule tab is active
    document.addEventListener('DOMContentLoaded', function() {
// ✅ AUTO-LOAD DAY OFF IF TAB IS ACTIVE ON PAGE LOAD
    const urlParams = new URLSearchParams(window.location.search);
    const currentView = urlParams.get('emp_view');
    
    if (currentView === 'leaves') {
        console.log("📅 Day Off tab active on page load");
        setTimeout(() => {
            loadDayOffRequests();
        }, 300);
    }
    
    // ✅ ALSO CHECK LOCALSTORAGE FOR LAST VIEWED TAB
    try {
        const lastView = localStorage.getItem('lastEmpView');
        if (lastView === 'leaves') {
            console.log("📅 Last viewed tab was Day Off");
            setTimeout(() => {
                loadDayOffRequests();
            }, 300);
        }
    } catch(e) {
        console.log("Could not check last view preference");
    }
        
        // Also check localStorage/cookie for last viewed tab
        try {
            const lastView = localStorage.getItem('lastEmpView') || 
                            document.cookie.split('; ').find(row => row.startsWith('last_emp_view='))?.split('=')[1];
            if (lastView === 'schedule') {
                setTimeout(() => {
                    if (typeof loadEmployeeSchedule === 'function') {
                        loadEmployeeSchedule();
                    }
                }, 200);
            }
        } catch(e) {
            console.log('Could not check last view preference');
        }
    });
    
    console.log('✅ My Schedule Instant Load Fix Applied');
})();
// === ATTACHMENT MODAL FUNCTIONS ===
function openAttachmentModal(filePath, type) {
    const modal = document.getElementById('attachmentModal'); // Ensure this ID exists in your HTML
    const img = document.getElementById('attachmentModalImage');
    if (modal && img) {
        img.src = filePath;
        modal.style.display = 'block';
    }
}

function closeAttachmentModal() {
    const modal = document.getElementById('attachmentModal');
    if (modal) {
        modal.style.display = 'none';
        document.getElementById('attachmentModalImage').src = '';
    }
}
// Ensure clicking outside closes it
window.onclick = function(event) {
    const modal = document.getElementById('attachmentModal');
    if (event.target == modal) {
        closeAttachmentModal();
    }
}

// ============================================
// UI IMPROVEMENTS: UTILITY FUNCTIONS
// ============================================

// Loading overlay functions
function showLoadingOverlay(message = 'Loading...') {
    const overlay = document.getElementById('loadingOverlay');
    if (overlay) {
        const p = overlay.querySelector('p');
        if (p) p.textContent = message;
        overlay.classList.add('active');
    }
}

function hideLoadingOverlay() {
    const overlay = document.getElementById('loadingOverlay');
    if (overlay) {
        overlay.classList.remove('active');
    }
}

// Ripple effect for buttons
function initRippleEffect() {
    document.querySelectorAll('.ripple, .btn-primary, .btn-secondary, .action-button').forEach(button => {
        button.addEventListener('click', function(e) {
            // Skip if already has ripple span
            if (this.querySelector('.ripple-span')) return;
            
            const ripple = document.createElement('span');
            ripple.className = 'ripple-span';
            
            const rect = this.getBoundingClientRect();
            const size = Math.max(rect.width, rect.height);
            const x = e.clientX - rect.left - size / 2;
            const y = e.clientY - rect.top - size / 2;
            
            ripple.style.width = ripple.style.height = size + 'px';
            ripple.style.left = x + 'px';
            ripple.style.top = y + 'px';
            
            this.appendChild(ripple);
            
            setTimeout(() => ripple.remove(), 600);
        });
    });
}

// Floating label initialization
function initFloatingLabels() {
    document.querySelectorAll('.form-group-floating input, .form-group-floating textarea, .form-group-floating select').forEach(input => {
        // Add placeholder if not exists to enable CSS :placeholder-shown
        if (!input.hasAttribute('placeholder')) {
            input.setAttribute('placeholder', ' ');
        }
    });
}

// Password toggle functionality
function initPasswordToggles() {
    document.querySelectorAll('.password-toggle').forEach(toggle => {
        toggle.addEventListener('click', function() {
            const wrapper = this.closest('.password-wrapper');
            if (!wrapper) return;
            
            const input = wrapper.querySelector('input[type="password"], input[type="text"]');
            if (!input) return;
            
            const isPassword = input.type === 'password';
            input.type = isPassword ? 'text' : 'password';
            
            // Toggle icon
            const eyeIcon = this.querySelector('.fa-eye');
            const eyeSlashIcon = this.querySelector('.fa-eye-slash');
            
            if (eyeIcon && eyeSlashIcon) {
                eyeIcon.style.display = isPassword ? 'none' : 'block';
                eyeSlashIcon.style.display = isPassword ? 'block' : 'none';
            }
        });
    });
}

// Auto-resize textareas
function initAutoResizeTextareas() {
    document.querySelectorAll('textarea.auto-resize').forEach(textarea => {
        textarea.addEventListener('input', function() {
            this.style.height = 'auto';
            this.style.height = (this.scrollHeight) + 'px';
        });
        // Initial resize
        this.style.height = 'auto';
        this.style.height = (textarea.scrollHeight) + 'px';
    });
}

// Character counter
function initCharCounters() {
    document.querySelectorAll('textarea[data-maxlength], input[data-maxlength]').forEach(input => {
        const maxLength = input.getAttribute('data-maxlength');
        if (!maxLength) return;
        
        const counter = document.createElement('div');
        counter.className = 'char-counter';
        input.parentNode.appendChild(counter);
        
        const updateCounter = () => {
            const remaining = maxLength - input.value.length;
            counter.textContent = `${remaining} characters remaining`;
            
            if (remaining < 20) counter.classList.add('danger');
            else if (remaining < 50) counter.classList.add('warning');
            else {
                counter.classList.remove('warning', 'danger');
            }
        };
        
        input.addEventListener('input', updateCounter);
        updateCounter();
    });
}

// Initialize all UI improvements on DOM load
document.addEventListener('DOMContentLoaded', function() {
    initRippleEffect();
    initFloatingLabels();
    initPasswordToggles();
    initAutoResizeTextareas();
    initCharCounters();
    
    // Add main content id for skip link
    const mainContent = document.querySelector('.main-content, #content, .dashboard-container');
    if (mainContent && !mainContent.id) {
        mainContent.id = 'main-content';
    }
});

// Toast notification enhancement
const originalShowToast = window.showToast;
window.showToast = function(message, type = 'info') {
    // Create toast with improved styling
    const toastContainer = document.getElementById('toast-container');
    if (!toastContainer) return;
    
    const toast = document.createElement('div');
    toast.className = `toast ${type}`;
    
    let icon = 'info-circle';
    if (type === 'success') icon = 'check-circle';
    if (type === 'error') icon = 'exclamation-circle';
    if (type === 'warning') icon = 'exclamation-triangle';
    
    toast.innerHTML = `
        <i class="fas fa-${icon}" style="color: var(--primary-color); font-size: 18px;"></i>
        <span>${message}</span>
    `;
    
    toastContainer.appendChild(toast);
    
    // Auto remove after 4 seconds
    setTimeout(() => {
        toast.classList.add('toast-hide');
        setTimeout(() => toast.remove(), 300);
    }, 4000);
};
    </script>
    </html> 
